      SUBROUTINE DPLAB(IANS,IANSLC,IWIDTH,IHARG,IHARG2,NUMARG,   &
                       IX1LTE,NCX1LA,IX1AUT,   &
                       IX2LTE,NCX2LA,IX2AUT,   &
                       IX3LTE,NCX3LA,IX3AUT,   &
                       IY1LTE,NCY1LA,IY1AUT,   &
                       IY2LTE,NCY2LA,IY2AUT,   &
                       IBUGP2,IFOUND,IERROR)
!
!     PURPOSE--EXTRACT THE STRING TO BE USED AS ONE
!              ON THE 5 LABELS AVAILABLE AROUND A PLOT--
!                 1 TO THE LEFT  OF THE LEFT  VERTICAL FRAME LINE;
!                 1 TO THE RIGHT OF THE RIGHT VERTICAL FRAME LINE;
!                 3 BELOW THE BOTTOM HORIZONTAL FRAME LINE.
!     INPUT  ARGUMENTS--IANS   (A  CHARACTER VECTOR)
!                     --IWIDTH
!                     --IHARG  (A  CHARACTER VECTOR)
!                     --IHARG2  (A  CHARACTER VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--ILX1TE (A CHARACTER ARRAY
!                       CONTAINING THE FIRST  HORIZONTAL LABEL).
!                     --NCX1LA (AN INTEGER VARIABLE
!                       CONTAINING THE NUMBER OF CHARACTERS IN ILX1TE).
!                     --ILX2TE (A CHARACTER ARRAY
!                       CONTAINING THE SECOND HORIZONTAL LABEL).
!                     --NCX2LA (AN INTEGER VARIABLE
!                       CONTAINING THE NUMBER OF CHARACTERS IN ILX2TE).
!                     --ILX3TE (A CHARACTER ARRAY
!                       CONTAINING THE THIRD HORIZONTAL LABEL).
!                     --NCX3LA (AN INTEGER VARIABLE
!                       CONTAINING THE NUMBER OF CHARACTERS IN ILX3TE).
!                     --ILY1TE (A CHARACTER ARRAY
!                       CONTAINING THE FIRST VERTICAL LABEL).
!                     --NCY1LA (AN INTEGER VARIABLE
!                       CONTAINING THE NUMBER OF CHARACTERS IN ILY1TE).
!                     --ILY2TE (A CHARACTER ARRAY
!                       CONTAINING THE SECOND VERTICAL LABEL).
!                     --NCY2LA (AN INTEGER VARIABLE
!                       CONTAINING THE NUMBER OF CHARACTERS IN ILY2TE).
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JANUARY    1978.
!     UPDATED         --JUNE      1978.
!     UPDATED         --MARCH     1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --AUGUST    1992. ADD SWITCHES FOR AUTOMATIC
!     UPDATED         --SEPTEMBER 1993. ALLOW LOWER CASE
!     UPDATED         --SEPTEMBER 1993. ACTIVATE   LABEL AUTOMATIC
!     UPDATED         --APRIL     2017. IN FEEDBACK MESSAGE, CHECK
!                                       FOR MAXIMUM STRING LENGTH
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IANS
!CCCC THE FOLLOWING LINE WAS CHANGED     SEPTEMBER 1993
!CCCC TO ALLOW FOR LOWER CASE            SEPTEMBER 1993
      CHARACTER*4 IANSLC
      CHARACTER*4 IHARG
!CCCC THE FOLLOWING LINE WAS ADDED AUGUST 1992
      CHARACTER*4 IHARG2
!
      CHARACTER*4 IX1LTE
      CHARACTER*4 IX2LTE
      CHARACTER*4 IX3LTE
      CHARACTER*4 IY1LTE
      CHARACTER*4 IY2LTE
!
!CCCC FOLLOWING LINES ADDED AUGUST 1992.
      CHARACTER*4 IX1AUT
      CHARACTER*4 IX2AUT
      CHARACTER*4 IX3AUT
      CHARACTER*4 IY1AUT
      CHARACTER*4 IY2AUT
!
      CHARACTER*4 IBUGP2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ILABT
!
!---------------------------------------------------------------------
!
      DIMENSION IANS(*)
!CCCC THE FOLLOWING LINE WAS CHANGED     SEPTEMBER 1993
!CCCC TO ALLOW FOR LOWER CASE            SEPTEMBER 1993
      DIMENSION IANSLC(*)
      DIMENSION IHARG(*)
!CCCC THE FOLLOWING LINE WAS ADDED AUGUST 1992
      DIMENSION IHARG2(*)
!
      DIMENSION IX1LTE(*)
      DIMENSION IX2LTE(*)
      DIMENSION IX3LTE(*)
      DIMENSION IY1LTE(*)
      DIMENSION IY2LTE(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(IBUGP2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF DPLAB--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)NCX1LA,NCX2LA,NCX3LA,NCY1LA,NCY2LA
   53   FORMAT('NCX1LA,NCX2LA,NCX3LA,NCY1LA,NCY2LA = ',5I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)(IX1LTE(I),I=1,MIN(NCX1LA,100))
   61   FORMAT('(IX1LTE(I),I=1,NCX1LA) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)(IX2LTE(I),I=1,MIN(NCX2LA,100))
   62   FORMAT('(IX2LTE(I),I=1,NCX2LA) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)(IX3LTE(I),I=1,MIN(NCX3LA,100))
   63   FORMAT('(IX3LTE(I),I=1,NCX3LA) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,64)(IY1LTE(I),I=1,MIN(NCY1LA,100))
   64   FORMAT('(IY1LTE(I),I=1,NCY1LA) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)(IY2LTE(I),I=1,MIN(NCY2LA,100))
   65   FORMAT('(IY2LTE(I),I=1,NCY2LA) = ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************************
!               **  STEP 1--                               **
!               **  DETERMINE THE COMMAND                  **
!               **  (       YLABEL = Y1LABEL, Y2LABEL,     **
!               **  XLABEL = X1LABEL, X2LABEL, X3LABEL)    **
!               **  AND DEFINE THE START POSITION (ISTART) **
!               **  FOR THE STRING.                        **
!               *********************************************
!
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'COLO')GO TO 9000
      IF(NUMARG.EQ.2.AND.IHARG(1).EQ.'COLO')GO TO 9000
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'SIZE')GO TO 9000
      IF(NUMARG.EQ.2.AND.IHARG(1).EQ.'SIZE')GO TO 9000
!
      DO 1000 I=1,IWIDTH
        I2=I
        IP1=I+1
        IP2=I+2
        IP3=I+3
        IP4=I+4
        IP5=I+5
        IP6=I+6
        IF(IANS(I).EQ.'Y'.AND.IANS(IP1).EQ.'L'.AND.   &
           IANS(IP2).EQ.'A'.AND.IANS(IP3).EQ.'B'.AND.   &
           IANS(IP4).EQ.'E'.AND.IANS(IP5).EQ.'L'.AND.IANS(IP6).EQ.' ')   &
           THEN
             ISTART=I2+7
             ILABT='Y'
             GO TO 300
        ELSEIF(IANS(I).EQ.'Y'.AND.IANS(IP1).EQ.'1'.AND.   &
           IANS(IP2).EQ.'L'.AND.IANS(IP3).EQ.'A'.AND.   &
           IANS(IP4).EQ.'B'.AND.IANS(IP5).EQ.'E'.AND.IANS(IP6).EQ.'L')   &
           THEN
             ISTART=I2+8
             ILABT='Y1'
             GO TO 300
        ELSEIF(IANS(I).EQ.'Y'.AND.IANS(IP1).EQ.'2'.AND.   &
           IANS(IP2).EQ.'L'.AND.IANS(IP3).EQ.'A'.AND.   &
           IANS(IP4).EQ.'B'.AND.IANS(IP5).EQ.'E'.AND.IANS(IP6).EQ.'L')   &
           THEN
             ISTART=I2+8
             ILABT='Y2'
             GO TO 300
        ELSEIF(IANS(I).EQ.'X'.AND.IANS(IP1).EQ.'L'.AND.   &
           IANS(IP2).EQ.'A'.AND.IANS(IP3).EQ.'B'.AND.   &
           IANS(IP4).EQ.'E'.AND.IANS(IP5).EQ.'L'.AND.IANS(IP6).EQ.' ')   &
           THEN
             ISTART=I2+7
             ILABT='X1'
             GO TO 300
        ELSEIF(IANS(I).EQ.'X'.AND.IANS(IP1).EQ.'1'.AND.   &
           IANS(IP2).EQ.'L'.AND.IANS(IP3).EQ.'A'.AND.   &
           IANS(IP4).EQ.'B'.AND.IANS(IP5).EQ.'E'.AND.IANS(IP6).EQ.'L')   &
           THEN
             ISTART=I2+8
             ILABT='X1'
             GO TO 300
        ELSEIF(IANS(I).EQ.'X'.AND.IANS(IP1).EQ.'2'.AND.   &
           IANS(IP2).EQ.'L'.AND.IANS(IP3).EQ.'A'.AND.   &
           IANS(IP4).EQ.'B'.AND.IANS(IP5).EQ.'E'.AND.IANS(IP6).EQ.'L')   &
           THEN
             ISTART=I2+8
             ILABT='X2'
             GO TO 300
        ELSEIF(IANS(I).EQ.'X'.AND.IANS(IP1).EQ.'3'.AND.   &
           IANS(IP2).EQ.'L'.AND.IANS(IP3).EQ.'A'.AND.   &
           IANS(IP4).EQ.'B'.AND.IANS(IP5).EQ.'E'.AND.IANS(IP6).EQ.'L')   &
           THEN
             ISTART=I2+8
             ILABT='X3'
             GO TO 300
!
        ELSEIF(IANS(I).EQ.'L'.AND.IANS(IP1).EQ.'A'.AND.   &
           IANS(IP2).EQ.'B'.AND.IANS(IP3).EQ.'E'.AND.   &
           IANS(IP4).EQ.'L'.AND.IANS(IP5).EQ.' ')   &
           THEN
             ISTART=I2+6
             ILABT='ALL'
             GO TO 300
        ELSEIF(IANS(I).EQ.'L'.AND.IANS(IP1).EQ.'A'.AND.   &
           IANS(IP2).EQ.'B'.AND.IANS(IP3).EQ.'E'.AND.   &
           IANS(IP4).EQ.'L'.AND.IANS(IP5).EQ.'S')   &
           THEN
             ISTART=I2+7
             ILABT='ALL'
             GO TO 300
        ENDIF
!
 1000 CONTINUE
      WRITE(ICOUT,1001)
 1001 FORMAT('***** ERROR IN DPLAB--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1002)
 1002 FORMAT('      NO MATCH FOR COMMAND.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
!
!               ********************************************************
!               **  STEP 3--                                          **
!               **  DEFINE THE STOP POSITION (ISTOP) FOR THE STRING.  **
!               ********************************************************
!
  300 CONTINUE
      ISTOP=0
      IF(ISTART.GT.IWIDTH)GO TO 329
      DO 320 I=ISTART,IWIDTH
        IREV=IWIDTH-I+ISTART
        IF(IANS(IREV).NE.' ')THEN
           ISTOP=IREV
           GO TO 329
        ENDIF
  320 CONTINUE
  329 CONTINUE
!
!               *****************************************
!               **  STEP 4--                           **
!               **  COPY OVER THE STRING OF INTEREST.  **
!               *****************************************
!
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'ON')GO TO 359
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'OFF')GO TO 359
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'DEFA')GO TO 359
      IF(NUMARG.EQ.0)GO TO 359
!
      IF(ISTART.GT.ISTOP)GO TO 359
      IF(ISTOP.EQ.0)GO TO 359
      J=0
      DO 350 I=ISTART,ISTOP
        J=J+1
!
!CCCC   THE FOLLOWING LINES WERE CHANGED   SEPTEMBER 1993
!CCCC   TO ALLOW FOR LOWER CASE            SEPTEMBER 1993
!CCCC   IF(ILABT.EQ.'Y1')IY1LTE(J)=IANS(I)
!CCCC   IF(ILABT.EQ.'Y2')IY2LTE(J)=IANS(I)
!CCCC   IF(ILABT.EQ.'X1')IX1LTE(J)=IANS(I)
!CCCC   IF(ILABT.EQ.'X2')IX2LTE(J)=IANS(I)
!CCCC   IF(ILABT.EQ.'X3')IX3LTE(J)=IANS(I)
!CCCC   IF(ILABT.EQ.'Y')IY1LTE(J)=IANS(I)
!CCCC   IF(ILABT.EQ.'Y')IY2LTE(J)=IANS(I)
!CCCC   IF(ILABT.EQ.'ALL')IY1LTE(J)=IANS(I)
!CCCC   IF(ILABT.EQ.'ALL')IY2LTE(J)=IANS(I)
!CCCC   IF(ILABT.EQ.'ALL')IX1LTE(J)=IANS(I)
!CCCC   IF(ILABT.EQ.'ALL')IX2LTE(J)=IANS(I)
!CCCC   IF(ILABT.EQ.'ALL')IX3LTE(J)=IANS(I)
!
        IF(ILABT.EQ.'Y1')IY1LTE(J)=IANSLC(I)
        IF(ILABT.EQ.'Y2')IY2LTE(J)=IANSLC(I)
        IF(ILABT.EQ.'X1')IX1LTE(J)=IANSLC(I)
        IF(ILABT.EQ.'X2')IX2LTE(J)=IANSLC(I)
        IF(ILABT.EQ.'X3')IX3LTE(J)=IANSLC(I)
        IF(ILABT.EQ.'Y')IY1LTE(J)=IANSLC(I)
        IF(ILABT.EQ.'Y')IY2LTE(J)=IANSLC(I)
        IF(ILABT.EQ.'ALL')IY1LTE(J)=IANSLC(I)
        IF(ILABT.EQ.'ALL')IY2LTE(J)=IANSLC(I)
        IF(ILABT.EQ.'ALL')IX1LTE(J)=IANSLC(I)
        IF(ILABT.EQ.'ALL')IX2LTE(J)=IANSLC(I)
        IF(ILABT.EQ.'ALL')IX3LTE(J)=IANSLC(I)
!
  350 CONTINUE
!
      IF(ILABT.EQ.'Y1')NCY1LA=J
      IF(ILABT.EQ.'Y2')NCY2LA=J
      IF(ILABT.EQ.'X1')NCX1LA=J
      IF(ILABT.EQ.'X2')NCX2LA=J
      IF(ILABT.EQ.'X3')NCX3LA=J
      IF(ILABT.EQ.'Y')NCY1LA=J
      IF(ILABT.EQ.'Y')NCY2LA=J
      IF(ILABT.EQ.'ALL')NCY1LA=J
      IF(ILABT.EQ.'ALL')NCY2LA=J
      IF(ILABT.EQ.'ALL')NCX1LA=J
      IF(ILABT.EQ.'ALL')NCX2LA=J
      IF(ILABT.EQ.'ALL')NCX3LA=J
!
      GO TO 800
  359 CONTINUE
!
!               ************************************
!               **  STEP 5--                      **
!               **  TREAT THE EMPTY-STRING CASE.  **
!               ************************************
!
      IF(ILABT.EQ.'Y1')NCY1LA=0
      IF(ILABT.EQ.'Y2')NCY2LA=0
      IF(ILABT.EQ.'X1')NCX1LA=0
      IF(ILABT.EQ.'X2')NCX2LA=0
      IF(ILABT.EQ.'X3')NCX3LA=0
      IF(ILABT.EQ.'Y')NCY1LA=0
      IF(ILABT.EQ.'Y')NCY2LA=0
      IF(ILABT.EQ.'ALL')NCY1LA=0
      IF(ILABT.EQ.'ALL')NCY2LA=0
      IF(ILABT.EQ.'ALL')NCX1LA=0
      IF(ILABT.EQ.'ALL')NCX2LA=0
      IF(ILABT.EQ.'ALL')NCX3LA=0
      GO TO 800
!
!               ***************************
!               **  STEP 6--             **
!               **  PRINT OUT A MESSAGE  **
!               ***************************
!
  800 CONTINUE
      IF(ILABT.EQ.'Y1')THEN
        IFOUND='YES'
        IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'AUTO'.AND.   &
           IHARG2(1).EQ.'MATI')THEN
          IY1AUT='ON'
        ELSE
           IY1AUT='OFF'
        ENDIF
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,811)
  811     FORMAT('THE LEFT   VERTICAL AXIS LABEL HAS JUST BEEN ',   &
                 'SET TO')
          CALL DPWRST('XXX','BUG ')
          IF(NCY1LA.EQ.0)THEN
             WRITE(ICOUT,999)
             CALL DPWRST('XXX','BUG ')
          ELSE
            WRITE(ICOUT,812)(IY1LTE(I),I=1,MIN(119,NCY1LA))
  812       FORMAT(11X,119A1)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ELSEIF(ILABT.EQ.'Y2')THEN
        IFOUND='YES'
        IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'AUTO'.AND.   &
           IHARG2(1).EQ.'MATI')THEN
          IY2AUT='ON'
        ELSE
          IY2AUT='OFF'
        ENDIF
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,821)
  821     FORMAT('THE RIGHT  VERTICAL AXIS LABEL HAS JUST BEEN ',   &
                 'SET TO')
          CALL DPWRST('XXX','BUG ')
          IF(NCY2LA.EQ.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ELSE
            WRITE(ICOUT,812)(IY2LTE(I),I=1,MIN(119,NCY2LA))
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ELSEIF(ILABT.EQ.'X1')THEN
        IFOUND='YES'
        IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'AUTO'.AND.   &
           IHARG2(1).EQ.'MATI')THEN
          IX1AUT='ON'
        ELSE
          IX1AUT='OFF'
        ENDIF
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,831)
  831     FORMAT('THE FIRST  HORIZONTAL AXIS LABEL HAS JUST BEEN ',   &
                 'SET TO')
          CALL DPWRST('XXX','BUG ')
          IF(NCX1LA.EQ.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ELSE
            WRITE(ICOUT,812)(IX1LTE(I),I=1,MIN(119,NCX1LA))
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ELSEIF(ILABT.EQ.'X2')THEN
        IFOUND='YES'
        IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'AUTO'.AND.   &
           IHARG2(1).EQ.'MATI')THEN
          IX2AUT='ON'
        ELSE
          IX2AUT='OFF'
        ENDIF
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,841)
  841     FORMAT('THE SECOND HORIZONTAL AXIS LABEL HAS JUST BEEN ',   &
                 'SET TO')
          CALL DPWRST('XXX','BUG ')
          IF(NCX2LA.EQ.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ELSE
            WRITE(ICOUT,812)(IX2LTE(I),I=1,MIN(119,NCX2LA))
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ELSEIF(ILABT.EQ.'X3')THEN
        IFOUND='YES'
        IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'AUTO'.AND.   &
           IHARG2(1).EQ.'MATI')THEN
          IX3AUT='ON'
        ELSE
          IX3AUT='OFF'
        ENDIF
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,851)
  851     FORMAT('THE THIRD  HORIZONTAL AXIS LABEL HAS JUST BEEN ',   &
                 'SET TO')
          CALL DPWRST('XXX','BUG ')
          IF(NCX3LA.EQ.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ELSE
            WRITE(ICOUT,812)(IX3LTE(I),I=1,MIN(119,NCX3LA))
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ELSEIF(ILABT.EQ.'Y')THEN
        IFOUND='YES'
        IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'AUTO'.AND.   &
           IHARG2(1).EQ.'MATI')THEN
          IY1AUT='ON'
          IY2AUT='ON'
        ELSE
          IY1AUT='OFF'
          IY2AUT='OFF'
        ENDIF
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,861)
  861     FORMAT('THE LEFT AND RIGHT VERTICAL AXIS LABELS ',   &
                 'HAVE JUST BEEN SET TO')
          CALL DPWRST('XXX','BUG ')
          IF(NCY1LA.EQ.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ELSE
            WRITE(ICOUT,812)(IY1LTE(I),I=1,MIN(119,NCY1LA))
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ELSEIF(ILABT.EQ.'ALL')THEN
        IFOUND='YES'
        IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'AUTO'.AND.   &
           IHARG2(1).EQ.'MATI')THEN
          IY1AUT='ON'
          IY2AUT='ON'
          IX1AUT='ON'
          IX2AUT='ON'
          IX3AUT='ON'
        ELSE
          IY1AUT='OFF'
          IY2AUT='OFF'
          IX1AUT='OFF'
          IX2AUT='OFF'
          IX3AUT='OFF'
        ENDIF
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,871)
  871     FORMAT('ALL 5 LABELS (THE 2 VERTICAL AND THE 3 BOTTOM ',   &
                 'HORIZONTAL)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,872)
  872     FORMAT('HAVE JUST BEEN SET TO')
          CALL DPWRST('XXX','BUG ')
          IF(NCY1LA.EQ.0)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
          ELSE
            WRITE(ICOUT,812)(IY1LTE(I),I=1,MIN(119,NCY1LA))
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ENDIF
!
!               ****************
!               **  STEP 90-- **
!               **  EXIT      **
!               ****************
!
 9000 CONTINUE
      IF(IBUGP2.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('AT THE END       OF DPLAB--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NCX1LA,NCX2LA,NCX3LA,NCY1LA,NCY2LA
 9013   FORMAT('NCX1LA,NCX2LA,NCX3LA,NCY1LA,NCY2LA = ',5I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9021)(IX1LTE(I),I=1,NCX1LA)
 9021   FORMAT('(IX1LTE(I),I=1,NCX1LA) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9022)(IX2LTE(I),I=1,NCX2LA)
 9022   FORMAT('(IX2LTE(I),I=1,NCX2LA) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9023)(IX3LTE(I),I=1,NCX3LA)
 9023   FORMAT('(IX3LTE(I),I=1,NCX3LA) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9024)(IY1LTE(I),I=1,NCY1LA)
 9024   FORMAT('(IY1LTE(I),I=1,NCY1LA) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9025)(IY2LTE(I),I=1,NCY2LA)
 9025   FORMAT('(IY2LTE(I),I=1,NCY2LA) = ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLAB
      SUBROUTINE DPLAAN(ICOM,IHARG,IARGT,ARG,NUMARG,   &
      PDEFAN,   &
      PX1LAN,PX2LAN,PX3LAN,PY1LAN,PY2LAN,   &
      IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LABEL ANGLES
!              FOR ANY OF THE 5 LABELS.
!              THE LABEL ANGLE SWITCHES FOR THE LABELS
!              ARE CONTAINED IN THE VARIABLES--
!                    PX1LAN,PX2LAN,PX3LAN,PY1LAN,PY2LAN
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG
!                     --PDEFAN (DEFAULT ANGLE)
!     OUTPUT ARGUMENTS--PX1LAN,
!                       PX2LAN,
!                       PX3LAN,
!                       PY1LAN,
!                       PY2LAN
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/11
!     ORIGINAL VERSION--NOVEMBER  1999.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
