      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.LE.0)GO TO 1900
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'ANGL')GO TO 1090
      GO TO 1900
 1090 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE FIRST  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'XLAB')GO TO 1100
      IF(ICOM.EQ.'X1LA')GO TO 1100
      GO TO 1199
!
 1100 CONTINUE
