      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1150
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
      IF(IHARG(NUMARG).EQ.'ANGL')GO TO 1150
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1160
      IERROR='YES'
      GO TO 9000
!
 1150 CONTINUE
      HOLD1=PDEFAN
      GO TO 1180
!
 1160 CONTINUE
      HOLD1=ARG(NUMARG)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      PX1LAN=HOLD1
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('THE LABEL ANGLE (FOR THE FIRST  HORIZONTAL ',   &
      'LABEL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)HOLD1
 1182 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1900
!
 1199 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
