!
 1200 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1250
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1250
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1250
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1250
      IF(IHARG(NUMARG).EQ.'ANGL')GO TO 1250
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1260
      IERROR='YES'
      GO TO 9000
!
 1250 CONTINUE
      HOLD1=PDEFAN
      GO TO 1280
!
 1260 CONTINUE
      HOLD1=ARG(NUMARG)
      GO TO 1280
!
 1280 CONTINUE
      IFOUND='YES'
      PX2LAN=HOLD1
!
      IF(IFEEDB.EQ.'OFF')GO TO 1289
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1281)
 1281 FORMAT('THE LABEL ANGLE (FOR THE SECOND HORIZONTAL ',   &
      'LABEL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1282)HOLD1
 1282 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1289 CONTINUE
      GO TO 1900
!
 1299 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE THIRD  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'X3LA')GO TO 1300
      GO TO 1399
!
 1300 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1350
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1350
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1350
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1350
      IF(IHARG(NUMARG).EQ.'ANGL')GO TO 1350
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1360
      IERROR='YES'
      GO TO 9000
!
 1350 CONTINUE
      HOLD1=PDEFAN
      GO TO 1380
!
 1360 CONTINUE
      HOLD1=ARG(NUMARG)
      GO TO 1380
!
 1380 CONTINUE
      IFOUND='YES'
      PX3LAN=HOLD1
!
      IF(IFEEDB.EQ.'OFF')GO TO 1389
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
