 1381 FORMAT('THE LABEL ANGLE (FOR THE THIRD  HORIZONTAL ',   &
      'LABEL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1382)HOLD1
 1382 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1389 CONTINUE
      GO TO 1900
!
 1399 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE LEFT   VERTICAL   LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'Y1LA')GO TO 1400
