 1786 FORMAT('THE LABEL ANGLE FOR BOTH VERTICAL LABELS')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1787)HOLD2
 1787 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1789 CONTINUE
      GO TO 1900
!
 1799 CONTINUE
!
 1900 CONTINUE
!
 9000 CONTINUE
