      SUBROUTINE DPLACA(ICOM,IHARG,NUMARG,   &
      IDEFCA,   &
      IX1LCA,IX2LCA,IX3LCA,IY1LCA,IY2LCA,   &
      IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LABEL CASE SWITCHES
!              FOR ANY OF THE 5 LABELS.
!              SUCH LABEL CASE SWITCHES DEFINE THE CASE
!              FOR EACH OF THE 5 LABELS.
!              THE CONTENTS OF A LABEL CASE SWITCH ARE
!              A CASE.
!              THE LABEL CASE SWITCHES FOR THE 5 LABELS
!              ARE CONTAINED IN IX1LCA,IX2LCA,IX3LCA,IY1LCA,IY2LCA.
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFCA
!     OUTPUT ARGUMENTS--IX1LCA (A HOLLERITH VARIABLE
!                       DENOTING THE CASE OF THE FIRST HORIZ. LABEL
!                     --IX2LCA (A HOLLERITH VARIABLE
!                       DENOTING THE CASE OF THE SECOND HORIZ. LABEL
!                     --IX3LCA (A HOLLERITH VARIABLE
!                       DENOTING THE CASE OF THE THIRD HORIZ. LABEL
!                     --IY1LCA (A HOLLERITH VARIABLE
!                       DENOTING THE CASE OF THE FIRST VERT. LABEL
!                     --IY2LCA (A HOLLERITH VARIABLE
!                       DENOTING THE CASE OF THE SECOND VERT. LABEL
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
