!
 1500 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1550
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1550
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1550
