      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1750
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1750
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1750
      IF(IHARG(NUMARG).EQ.'CASE')GO TO 1750
      GO TO 1760
!
 1750 CONTINUE
      IHOLD=IDEFCA
      GO TO 1780
!
 1760 CONTINUE
      IHOLD=IHARG(NUMARG)
      GO TO 1780
!
 1780 CONTINUE
      IFOUND='YES'
      IY1LCA=IHOLD
      IY2LCA=IHOLD
      IX1LCA=IHOLD
      IX2LCA=IHOLD
      IX3LCA=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1789
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1781)
 1781 FORMAT('THE LABEL CASE (FOR ALL 5 ',   &
      'LABELS--3 HORIZONTAL AND 2 VERTICAL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1782)IHOLD
 1782 FORMAT('HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1789 CONTINUE
      GO TO 1900
!
 1799 CONTINUE
!
 1900 CONTINUE
      RETURN
      END SUBROUTINE DPLACA
      SUBROUTINE DPLACL(ICOM,IARG,IHARG,NUMARG,IDEFCO,   &
                        IX1LCO,IX2LCO,IX3LCO,IY1LCO,IY2LCO,   &
                        IX1LC2,IX2LC2,IX3LC2,IY1LC2,IY2LC2,IRGBMX,   &
                        IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LABEL COLOR SWITCHES
!              FOR ANY OF THE 5 LABELS.
!              SUCH LABEL COLOR SWITCHES DEFINE THE COLOR
!              FOR EACH OF THE 5 LABELS.
!              THE CONTENTS OF A LABEL COLOR SWITCH ARE
!              A COLOR.
!              THE LABEL COLOR SWITCHES FOR THE 5 LABELS
!              ARE CONTAINED IN IX1LCO,IX2LCO,IX3LCO,IY1LCO,IY2LCO.
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFCO
!     OUTPUT ARGUMENTS--IX1LCO (A HOLLERITH VARIABLE
!                       DENOTING THE COLOR OF THE FIRST HORIZ. LABEL
!                     --IX2LCO (A HOLLERITH VARIABLE
!                       DENOTING THE COLOR OF THE SECOND HORIZ. LABEL
!                     --IX3LCO (A HOLLERITH VARIABLE
!                       DENOTING THE COLOR OF THE THIRD HORIZ. LABEL
!                     --IY1LCO (A HOLLERITH VARIABLE
!                       DENOTING THE COLOR OF THE FIRST VERT. LABEL
!                     --IY2LCO (A HOLLERITH VARIABLE
!                       DENOTING THE COLOR OF THE SECOND VERT. LABEL
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--OCTOBER   1980.
!     UPDATED         --MARCH     1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --OCTOBER   2020.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
      CHARACTER*4 IDEFCO
      CHARACTER*4 IX1LCO
      CHARACTER*4 IX2LCO
      CHARACTER*4 IX3LCO
      CHARACTER*4 IY1LCO
      CHARACTER*4 IY2LCO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARG(*)
      DIMENSION IX1LC2(*)
      DIMENSION IX2LC2(*)
      DIMENSION IX3LC2(*)
      DIMENSION IY1LC2(*)
      DIMENSION IY2LC2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      IHOLD=IDEFCO
!
      IF(NUMARG.LE.0)GO TO 9000
      IF(IHARG(1).EQ.'RGB ' .AND. IHARG(2).EQ.'COLO')GO TO 2000
      IF(IHARG(1).EQ.'MARK' .AND. IHARG(2).EQ.'RGB ' .AND.   &
         IHARG(3).EQ.'COLO')GO TO 2000
!
      IF((NUMARG.GE.1.AND.IHARG(1).EQ.'COLO') .OR.   &
         (NUMARG.GE.2.AND.IHARG(1).EQ.'MARK'.AND.   &
          IHARG(2).EQ.'COLO'))GO TO 1090
!
      GO TO 9000
!
 1090 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE FIRST  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'XLAB' .OR. ICOM.EQ.'X1LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'COLO')THEN
          IHOLD=IDEFCO
        ELSE
          IHOLD=IHARG(NUMARG)
        ENDIF
!
        IFOUND='YES'
        IX1LCO=IHOLD
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
  999     FORMAT(1X)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1181)
 1181     FORMAT('THE LABEL COLOR (FOR THE FIRST  HORIZONTAL LABEL)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)IHOLD
 1182     FORMAT('HAS JUST BEEN SET TO ',A4)
          CALL DPWRST('XXX','BUG ')
