!
      ELSEIF(ICOM.EQ.'X2LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'COLO')THEN
          IHOLD=IDEFCO
        ELSE
          IHOLD=IHARG(NUMARG)
        ENDIF
!
        IFOUND='YES'
        IX2LCO=IHOLD
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1281)
 1281     FORMAT('THE LABEL COLOR (FOR THE SECOND HORIZONTAL LABEL)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1282)IHOLD
 1282     FORMAT('HAS JUST BEEN SET TO ',A4)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 9000
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE THIRD  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'X3LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'COLO')THEN
          IHOLD=IDEFCO
        ELSE
          IHOLD=IHARG(NUMARG)
        ENDIF
!
        IFOUND='YES'
        IX3LCO=IHOLD
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
