          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1582)IHOLD
 1582     FORMAT('HAS JUST BEEN SET TO ',A4)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 9000
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  BOTH LEFT AND RIGHT VERTICAL LABELS ARE TO BE CHANGED   **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'YLAB')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'COLO')THEN
          IHOLD=IDEFCO
        ELSE
          IHOLD=IHARG(NUMARG)
        ENDIF
!
        IFOUND='YES'
        IY1LCO=IHOLD
        IY2LCO=IHOLD
