          JHOLD3=IARG(NUMARG)
          IF(JHOLD1.LT.0 .OR. JHOLD1.GT.IRGBMX)JHOLD1=-1
          IF(JHOLD2.LT.0 .OR. JHOLD2.GT.IRGBMX)JHOLD2=-1
          IF(JHOLD3.LT.0 .OR. JHOLD3.GT.IRGBMX)JHOLD3=-1
        ENDIF
!
        IFOUND='YES'
        IX1LC2(1)=JHOLD1
        IX1LC2(2)=JHOLD2
        IX1LC2(3)=JHOLD3
        IX2LC2(1)=JHOLD1
        IX2LC2(2)=JHOLD2
        IX2LC2(3)=JHOLD3
        IX3LC2(1)=JHOLD1
        IX3LC2(2)=JHOLD2
        IX3LC2(3)=JHOLD3
        IY1LC2(1)=JHOLD1
        IY1LC2(2)=JHOLD2
        IY1LC2(3)=JHOLD3
        IY2LC2(1)=JHOLD1
        IY2LC2(2)=JHOLD2
        IY2LC2(3)=JHOLD3
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2781)
 2781     FORMAT('THE LABEL RGB COLOR (FOR ALL 5 LABELS--3 HORIZONTAL ',   &
                 'AND 2 VERTICAL)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2782)JHOLD1,JHOLD2,JHOLD3
 2782     FORMAT('HAS JUST BEEN SET TO ',3I5)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 9000
      ENDIF
      GO TO 9000
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPLACL
      SUBROUTINE DPLACO(ICOM,IHARG,IARGT,ARG,NUMARG,   &
                        PX1LXC,PX1LYC,PX2LXC,PX2LYC,PX3LXC,PX3LYC,   &
                        PY1LXC,PY1LYC,PY2LXC,PY2LYC,   &
                        IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LABEL COORDINATES FOR ANY OF THE 5 LABELS.
!              THE LABEL COORDINATE SWITCHES FOR THE LABELS
!              ARE CONTAINED IN THE VARIABLES--
!                    PX1LXC,PX1LYC,PX2LXC,PX2LYC,PX3LXC,PX3LYC,
!                    PY1LXC,PY1LYC,PY2LXC,PY2LYC,
!              THIS COMMAND IS PRIMARILY USED IN CERTAIN MACROS BY THE
!              DATAPLOT DEVELOPERS, BUT IT CAN BE USED GENERALLY.  BY
!              DEFAULT, AXIS LABELS ARE CENTER JUSTIFIED AT THE
!              MID-POINT OF THE FRAME CORNER COORDINATES.  JUSTIFICATION
!              (CENTER, LEFT, RIGHT) IS RELATIVE TO THAT POINT.  THE
!              MOST COMMON USAGE OF THIS COMMAND WOULD BE LEFT
!              JUSTIFICATION NEAR THE LEFT (BOTTOM) FRAME POINT OR
!              RIGHT JUSTIFICATION NEAR THE RIGHT (TOP) FRAME POINT.
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--PX1LXC,PX1LYC,PX2LXC,PX2LYC,PX3LXC,PX3LYC,
!                       PY1LXC,PY1LYC,PY2LXC,PY2LYC,
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2018/10
!     ORIGINAL VERSION--OCTOBER   2018.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'COOR')GO TO 1090
      GO TO 9000
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE FIRST  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
 1090 CONTINUE
!
      IF(ICOM.EQ.'XLAB' .OR. ICOM.EQ.'X1LA')THEN
        IF(NUMARG.EQ.1)THEN
          PX1LXC=CPUMIN
          PX1LYC=CPUMIN
        ELSEIF(NUMARG.GE.2)THEN
          IF(IHARG(2).EQ.'ON'   .OR. IHARG(2).EQ.'OFF'  .OR.   &
             IHARG(2).EQ.'AUTO' .OR. IHARG(2).EQ.'DEFA')THEN
            PX1LXC=CPUMIN
          ELSEIF(IARGT(2).EQ.'NUMB')THEN
            PX1LXC=ARG(2)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IF(NUMARG.GE.3)THEN
          IF(IHARG(3).EQ.'ON'   .OR. IHARG(3).EQ.'OFF'  .OR.   &
             IHARG(3).EQ.'AUTO' .OR. IHARG(3).EQ.'DEFA')THEN
            PX1LYC=CPUMIN
          ELSEIF(IARGT(3).EQ.'NUMB')THEN
            PX1LYC=ARG(3)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IFOUND='YES'
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
  999     FORMAT(1X)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1181)
 1181     FORMAT('THE LABEL COORDINATES (FOR THE FIRST  ',   &
                 'HORIZONTAL LABEL) ARE:')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)PX1LXC
 1182     FORMAT('     X COORDINATE: ',G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1183)PX1LYC
 1183     FORMAT('     Y COORDINATE: ',G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE SECOND HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'X2LA')THEN
        IF(NUMARG.EQ.1)THEN
          PX2LXC=CPUMIN
          PX2LYC=CPUMIN
        ELSEIF(NUMARG.GE.2)THEN
          IF(IHARG(2).EQ.'ON'   .OR. IHARG(2).EQ.'OFF'  .OR.   &
             IHARG(2).EQ.'AUTO' .OR. IHARG(2).EQ.'DEFA')THEN
            PX2LXC=CPUMIN
          ELSEIF(IARGT(2).EQ.'NUMB')THEN
            PX2LXC=ARG(2)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IF(NUMARG.GE.3)THEN
          IF(IHARG(3).EQ.'ON'   .OR. IHARG(3).EQ.'OFF'  .OR.   &
             IHARG(3).EQ.'AUTO' .OR. IHARG(3).EQ.'DEFA')THEN
            PX2LYC=CPUMIN
          ELSEIF(IARGT(3).EQ.'NUMB')THEN
            PX2LYC=ARG(3)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IFOUND='YES'
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1281)
 1281     FORMAT('THE LABEL COORDINATES (FOR THE SECOND ',   &
                 'HORIZONTAL LABEL) ARE:')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)PX2LXC
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1183)PX2LYC
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE THIRD  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'X3LA')THEN
        IF(NUMARG.EQ.1)THEN
          PX3LXC=CPUMIN
          PX3LYC=CPUMIN
        ELSEIF(NUMARG.GE.2)THEN
          IF(IHARG(2).EQ.'ON'   .OR. IHARG(2).EQ.'OFF'  .OR.   &
             IHARG(2).EQ.'AUTO' .OR. IHARG(2).EQ.'DEFA')THEN
            PX3LXC=CPUMIN
          ELSEIF(IARGT(2).EQ.'NUMB')THEN
            PX3LXC=ARG(2)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IF(NUMARG.GE.3)THEN
          IF(IHARG(3).EQ.'ON'   .OR. IHARG(3).EQ.'OFF'  .OR.   &
             IHARG(3).EQ.'AUTO' .OR. IHARG(3).EQ.'DEFA')THEN
            PX3LYC=CPUMIN
          ELSEIF(IARGT(3).EQ.'NUMB')THEN
            PX3LYC=ARG(3)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IFOUND='YES'
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1381)
 1381     FORMAT('THE LABEL COORDINATES (FOR THE THIRD  ',   &
                 'HORIZONTAL LABEL) ARE:')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)PX3LXC
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1183)PX3LYC
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE LEFT   VERTICAL   LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'Y1LA')THEN
        IF(NUMARG.EQ.1)THEN
          PY1LXC=CPUMIN
          PY1LYC=CPUMIN
        ELSEIF(NUMARG.GE.2)THEN
          IF(IHARG(2).EQ.'ON'   .OR. IHARG(2).EQ.'OFF'  .OR.   &
             IHARG(2).EQ.'AUTO' .OR. IHARG(2).EQ.'DEFA')THEN
            PY1LXC=CPUMIN
          ELSEIF(IARGT(2).EQ.'NUMB')THEN
            PY1LXC=ARG(2)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IF(NUMARG.GE.3)THEN
          IF(IHARG(3).EQ.'ON'   .OR. IHARG(3).EQ.'OFF'  .OR.   &
             IHARG(3).EQ.'AUTO' .OR. IHARG(3).EQ.'DEFA')THEN
            PY1LYC=CPUMIN
          ELSEIF(IARGT(3).EQ.'NUMB')THEN
            PY1LYC=ARG(3)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IFOUND='YES'
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1481)
 1481     FORMAT('THE LABEL COORDINATES (FOR THE LEFT   ',   &
                 'VERTICAL LABEL) ARE:')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)PY1LXC
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1183)PY1LYC
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE RIGHT  VERTICAL   LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'Y2LA')THEN
        IF(NUMARG.EQ.1)THEN
          PY2LXC=CPUMIN
          PY2LYC=CPUMIN
        ELSEIF(NUMARG.GE.2)THEN
          IF(IHARG(2).EQ.'ON'   .OR. IHARG(2).EQ.'OFF'  .OR.   &
             IHARG(2).EQ.'AUTO' .OR. IHARG(2).EQ.'DEFA')THEN
            PY2LXC=CPUMIN
          ELSEIF(IARGT(2).EQ.'NUMB')THEN
            PY2LXC=ARG(2)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IF(NUMARG.GE.3)THEN
          IF(IHARG(3).EQ.'ON'   .OR. IHARG(3).EQ.'OFF'  .OR.   &
             IHARG(3).EQ.'AUTO' .OR. IHARG(3).EQ.'DEFA')THEN
            PY2LYC=CPUMIN
          ELSEIF(IARGT(3).EQ.'NUMB')THEN
            PY2LYC=ARG(3)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IFOUND='YES'
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1581)
 1581     FORMAT('THE LABEL COORDINATES (FOR THE RIGHT  ',   &
                 'VERTICAL LABEL) ARE:')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)PY2LXC
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1183)PY2LYC
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  BOTH VERTICAL AXIS LABELS ARE TO BE CHANGED             **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'YLAB')THEN
        IF(NUMARG.EQ.1)THEN
          PY1LXC=CPUMIN
          PY1LYC=CPUMIN
          PY2LXC=CPUMIN
          PY2LYC=CPUMIN
        ELSEIF(NUMARG.GE.2)THEN
          IF(IHARG(2).EQ.'ON'   .OR. IHARG(2).EQ.'OFF'  .OR.   &
             IHARG(2).EQ.'AUTO' .OR. IHARG(2).EQ.'DEFA')THEN
            PY1LXC=CPUMIN
            PY2LXC=CPUMIN
          ELSEIF(IARGT(2).EQ.'NUMB')THEN
            PY1LXC=ARG(2)
            PY2LXC=ARG(2)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IF(NUMARG.GE.3)THEN
          IF(IHARG(3).EQ.'ON'   .OR. IHARG(3).EQ.'OFF'  .OR.   &
             IHARG(3).EQ.'AUTO' .OR. IHARG(3).EQ.'DEFA')THEN
            PY1LYC=CPUMIN
            PY2LYC=CPUMIN
          ELSEIF(IARGT(3).EQ.'NUMB')THEN
            PY1LYC=ARG(3)
            PY2LYC=ARG(3)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IFOUND='YES'
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1681)
 1681     FORMAT('THE LABEL COORDINATES (FOR THE BOTH   ',   &
                 'VERTICAL LABELS) ARE:')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)PY1LXC
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1183)PY1LYC
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY ALL  5 LABELS ARE                   TO BE CHANGED  **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'LABE' .OR. ICOM.EQ.'XYLA' .OR.   &
             ICOM.EQ.'YXLA')THEN
        IF(NUMARG.EQ.1)THEN
          PX1LXC=CPUMIN
          PX1LYC=CPUMIN
          PX2LXC=CPUMIN
          PX2LYC=CPUMIN
          PX3LXC=CPUMIN
          PX3LYC=CPUMIN
          PY1LXC=CPUMIN
          PY1LYC=CPUMIN
          PY2LXC=CPUMIN
          PY2LYC=CPUMIN
        ELSEIF(NUMARG.GE.2)THEN
          IF(IHARG(2).EQ.'ON'   .OR. IHARG(2).EQ.'OFF'  .OR.   &
             IHARG(2).EQ.'AUTO' .OR. IHARG(2).EQ.'DEFA')THEN
            PX1LXC=CPUMIN
            PX1LYC=CPUMIN
            PX2LXC=CPUMIN
            PX2LYC=CPUMIN
            PX3LXC=CPUMIN
            PX3LYC=CPUMIN
            PY1LXC=CPUMIN
            PY1LYC=CPUMIN
            PY2LXC=CPUMIN
            PY2LYC=CPUMIN
          ELSEIF(IARGT(2).EQ.'NUMB')THEN
            PX1LXC=ARG(2)
            PX2LXC=ARG(2)
            PX3LXC=ARG(2)
            PY1LXC=ARG(2)
            PY2LXC=ARG(2)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IF(NUMARG.GE.3)THEN
          IF(IHARG(3).EQ.'ON'   .OR. IHARG(3).EQ.'OFF'  .OR.   &
             IHARG(3).EQ.'AUTO' .OR. IHARG(3).EQ.'DEFA')THEN
            PX1LYC=CPUMIN
            PX2LYC=CPUMIN
            PX3LYC=CPUMIN
            PY1LYC=CPUMIN
            PY2LYC=CPUMIN
          ELSEIF(IARGT(3).EQ.'NUMB')THEN
            PX1LYC=ARG(3)
            PX2LYC=ARG(3)
            PX3LYC=ARG(3)
            PY1LYC=ARG(3)
            PY2LYC=ARG(3)
          ELSE
            IERROR='YES'
            GO TO 9000
          ENDIF
        ENDIF
!
        IFOUND='YES'
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1781)
 1781     FORMAT('THE LABEL COORDINATES FOR ALL LABELS--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1783)
 1783     FORMAT('(THREE HORIZONTAL AND TWO VERTICAL)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)PX1LXC
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1183)PX1LYC
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      ENDIF
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPLACO
      SUBROUTINE DPLADI(ICOM,IHARG,NUMARG,   &
      IDEFDI,   &
      IX1LDI,IX2LDI,IX3LDI,IY1LDI,IY2LDI,   &
      IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LABEL DIRECTION SWITCHES
!              FOR ANY OF THE 5 LABELS.
!              SUCH LABEL DIRECTION SWITCHES DEFINE THE
!              DIRECTION FOR EACH OF THE 5 LABELS.
!              THE CONTENTS OF A LABEL DIRECTION SWITCH ARE
!              A DIRECTION.
!              THE LABEL DIRECTION SWITCHES FOR THE 5 LABELS
!              ARE CONTAINED IN IX1LDI,IX2LDI,IX3LDI,IY1LDI,IY2LDI.
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFFO
!     OUTPUT ARGUMENTS--IX1LDI (A HOLLERITH VARIABLE
!                       DENOTING THE DIRECTION OF THE FIRST HORIZ. LABEL
!                     --IX2LDI (A HOLLERITH VARIABLE
!                       DENOTING THE DIRECTION OF THE SECOND HORIZ. LABEL
!                     --IX3LDI (A HOLLERITH VARIABLE
!                       DENOTING THE DIRECTION OF THE THIRD HORIZ. LABEL
!                     --IY1LDI (A HOLLERITH VARIABLE
!                       DENOTING THE DIRECTION OF THE FIRST VERT. LABEL
!                     --IY2LDI (A HOLLERITH VARIABLE
!                       DENOTING THE DIRECTION OF THE SECOND VERT. LABEL
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/10
!     ORIGINAL VERSION--OCTOBER   1999.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
!
      CHARACTER*4 IDEFDI
!
      CHARACTER*4 IX1LDI
      CHARACTER*4 IX2LDI
      CHARACTER*4 IX3LDI
      CHARACTER*4 IY1LDI
      CHARACTER*4 IY2LDI
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
      CHARACTER*4 IHOL2
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.LE.0)GO TO 1900
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'DIRE')GO TO 1090
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'MARK'.AND.   &
      IHARG(2).EQ.'DIRE')GO TO 1090
      GO TO 1900
 1090 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE FIRST  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'XLAB')GO TO 1100
      IF(ICOM.EQ.'X1LA')GO TO 1100
      GO TO 1199
!
 1100 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1150
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DIRE')GO TO 1150
      GO TO 1160
!
 1150 CONTINUE
      IHOLD=IDEFDI
      GO TO 1180
!
 1160 CONTINUE
      IHOLD=IHARG(NUMARG)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      IX1LDI=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('THE LABEL DIRECTION (FOR THE FIRST  HORIZONTAL ',   &
      'LABEL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)IHOLD
 1182 FORMAT('HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1900
!
 1199 CONTINUE
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE SECOND HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'X2LA')GO TO 1200
      GO TO 1299
!
 1200 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1250
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1250
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1250
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1250
      IF(IHARG(NUMARG).EQ.'DIRE')GO TO 1250
      GO TO 1260
!
 1250 CONTINUE
      IHOLD=IDEFDI
      GO TO 1280
!
 1260 CONTINUE
      IHOLD=IHARG(NUMARG)
      GO TO 1280
!
 1280 CONTINUE
      IFOUND='YES'
      IX2LDI=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1289
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1281)
 1281 FORMAT('THE LABEL DIRECTION (FOR THE SECOND HORIZONTAL ',   &
      'LABEL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1282)IHOLD
