      SUBROUTINE DPLADS(ICOM,IHARG,ARG,NUMARG,   &
      PDEFDS,   &
      PX1LDS,PX2LDS,PX3LDS,PY1LDS,PY2LDS,   &
      IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LABEL DISPLACEMENT SWITCHES
!              FOR ANY OF THE 5 LABELS.
!              SUCH LABEL DISPLACEMENT SWITCHES DEFINE THE DISPLACEMENT
!              FOR EACH OF THE 5 LABELS.
!              THE CONTENTS OF A LABEL DISPLACEMENT SWITCH ARE
!              A DISPLACEMENT.
!              THE LABEL DISPLACEMENT SWITCHES FOR THE 5 LABELS
!              ARE CONTAINED IN PX1LDS,PX2LDS,PX3LDS,PY1LDS,PY2LDS.
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --ARG    (A REAL VECTOR)
!                     --NUMARG
!                     --PDEFDS
!     OUTPUT ARGUMENTS--PX1LDS (A REAL VARIABLE
!                       DENOTING THE DISPLACEMENT OF THE FIRST HORIZ. LABEL
!                     --PX2LDS (A REAL VARIABLE
!                       DENOTING THE DISPLACEMENT OF THE SECOND HORIZ. LABEL
!                     --PX3LDS (A REAL VARIABLE
!                       DENOTING THE DISPLACEMENT OF THE THIRD HORIZ. LABEL
!                     --PY1LDS (A REAL VARIABLE
!                       DENOTING THE DISPLACEMENT OF THE FIRST VERT. LABEL
!                     --PY2LDS (A REAL VARIABLE
!                       DENOTING THE DISPLACEMENT OF THE SECOND VERT. LABEL
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/8
!     ORIGINAL VERSION--JULY      1989.
!     UPDATED         --MAY       1992.   FIX DEFAULT VALUES
!     UPDATED         --DECEMBER  1992.   FIX MESSAGE FOR DEFAULT VALUE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION ARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
