!CCCC LABEL OFFSET NOW REFERS TO HORIZONTAL POSITIONING.
!CCCC IF(NUMARG.GE.1.AND.IHARG(1).EQ.'OFFS')GO TO 1090
      GO TO 1900
 1090 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE FIRST  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'XLAB')GO TO 1100
      IF(ICOM.EQ.'X1LA')GO TO 1100
      GO TO 1199
!
 1100 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1150
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DISP')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFFS')GO TO 1150
      GO TO 1160
!
 1150 CONTINUE
!CCCC THE FOLLOWING LINE WAS FIXED MAY 1992 (JJF)
!CCCC PHOLD=PDEFDS
      PHOLD=2.0+2.0*PDEFDS
      GO TO 1180
!
 1160 CONTINUE
      PHOLD=ARG(NUMARG)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      PX1LDS=PHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('THE LABEL DISPLACEMENT (FOR THE FIRST  HORIZONTAL ',   &
      'LABEL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)PHOLD
 1182 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1900
!
 1199 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE SECOND HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
