!
 1580 CONTINUE
      IFOUND='YES'
      PY2LDS=PHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1589
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1581)
 1581 FORMAT('THE LABEL DISPLACEMENT (FOR THE RIGHT  VERTICAL   ',   &
