      SUBROUTINE DPLAFI(ICOM,IHARG,NUMARG,   &
      IDEFFI,   &
      IX1LFI,IX2LFI,IX3LFI,IY1LFI,IY2LFI,   &
      IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LABEL FILL SWITCHES
!              FOR ANY OF THE 5 LABELS.
!              SUCH LABEL FILL SWITCHES DEFINE THE FILL
!              FOR EACH OF THE 5 LABELS.
!              THE CONTENTS OF A LABEL FILL SWITCH ARE
!              A FILL.
!              THE LABEL FILL SWITCHES FOR THE 5 LABELS
!              ARE CONTAINED IN IX1LFI,IX2LFI,IX3LFI,IY1LFI,IY2LFI.
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFFI
!     OUTPUT ARGUMENTS--IX1LFI (A HOLLERITH VARIABLE
!                       DENOTING THE FILL OF THE FIRST HORIZ. LABEL
!                     --IX2LFI (A HOLLERITH VARIABLE
!                       DENOTING THE FILL OF THE SECOND HORIZ. LABEL
!                     --IX3LFI (A HOLLERITH VARIABLE
