!
 1500 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1540
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1550
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1550
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1550
      IF(IHARG(NUMARG).EQ.'FILL')GO TO 1550
      GO TO 1560
!
 1540 CONTINUE
      IHOLD='SOLI'
