      SUBROUTINE DPLAFO(ICOM,IHARG,NUMARG,IDEFFO,   &
                        IX1LFO,IX2LFO,IX3LFO,IY1LFO,IY2LFO,   &
                        IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LABEL FONT SWITCHES FOR ANY OF THE 5 LABELS.
!              SUCH LABEL FONT SWITCHES DEFINE THE FONT FOR EACH OF
!              THE 5 LABELS.  THE CONTENTS OF A LABEL FONT SWITCH ARE
!              A FONT.  THE LABEL FONT SWITCHES FOR THE 5 LABELS
!              ARE CONTAINED IN IX1LFO,IX2LFO,IX3LJU,IY1LFO,IY2LJU.
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFFO
!     OUTPUT ARGUMENTS--IX1LFO (A HOLLERITH VARIABLE
!                       DENOTING THE FONT OF THE FIRST HORIZ. LABEL
!                     --IX2LFO (A HOLLERITH VARIABLE
!                       DENOTING THE FONT OF THE SECOND HORIZ. LABEL
!                     --IX3LJU (A HOLLERITH VARIABLE
!                       DENOTING THE FONT OF THE THIRD HORIZ. LABEL
!                     --IY1LFO (A HOLLERITH VARIABLE
!                       DENOTING THE FONT OF THE FIRST VERT. LABEL
!                     --IY2LJU (A HOLLERITH VARIABLE
!                       DENOTING THE FONT OF THE SECOND VERT. LABEL
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--FEBRUARY  1989.
!     UPDATED         --JULY      2021. "HARDWARE" AS SYNONYM FOR
!                                       "TEKTRONIX
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
!
      CHARACTER*4 IDEFFO
!
      CHARACTER*4 IX1LFO
      CHARACTER*4 IX2LFO
      CHARACTER*4 IX3LFO
      CHARACTER*4 IY1LFO
      CHARACTER*4 IY2LFO
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.LE.0)GO TO 1900
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'FONT')GO TO 1090
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'MARK'.AND.   &
      IHARG(2).EQ.'FONT')GO TO 1090
      GO TO 1900
!
 1090 CONTINUE
!
!               ********************************************
!               **  TREAT THE CASE WHEN ONLY THE FIRST    **
!               **  HORIZONTAL LABEL IS TO BE CHANGED     **
!               ********************************************
!
      IF(ICOM.EQ.'XLAB' .OR. ICOM.EQ.'X1LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'FONT')THEN
          IHOLD=IDEFFO
          GO TO 1180
        ELSE
          IHOLD=IHARG(NUMARG)
          GO TO 1180
        ENDIF
      ELSE
        GO TO 1199
      ENDIF
!
 1180 CONTINUE
      IFOUND='YES'
      IX1LFO=IHOLD
      IF(IX1LFO.EQ.'HARD')IX1LFO='TEKT'
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1181)
 1181   FORMAT('THE LABEL FONT (FOR THE FIRST  HORIZONTAL LABEL)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1182)IX1LFO
 1182   FORMAT('HAS JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 1900
!
 1199 CONTINUE
!               **********************************************
!               **  TREAT THE CASE WHEN ONLY THE SECOND     **
!               **  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **********************************************
!
      IF(ICOM.EQ.'X2LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'FONT')THEN
          IHOLD=IDEFFO
          GO TO 1280
        ELSE
          IHOLD=IHARG(NUMARG)
          GO TO 1280
        ENDIF
      ELSE
        GO TO 1299
      ENDIF
!
 1280 CONTINUE
      IFOUND='YES'
      IX2LFO=IHOLD
      IF(IX2LFO.EQ.'HARD')IX2LFO='TEKT'
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1281)
 1281   FORMAT('THE LABEL FONT (FOR THE SECOND HORIZONTAL LABEL)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1282)IX2LFO
 1282   FORMAT('HAS JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 1900
!
 1299 CONTINUE
!
!               **********************************************
!               **  TREAT THE CASE WHEN ONLY THE THIRD      **
!               **  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **********************************************
!
      IF(ICOM.EQ.'X3LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'FONT')THEN
          IHOLD=IDEFFO
          GO TO 1380
        ELSE
          IHOLD=IHARG(NUMARG)
          GO TO 1380
        ENDIF
      ELSE
        GO TO 1399
      ENDIF
!
 1380 CONTINUE
      IFOUND='YES'
      IX3LFO=IHOLD
      IF(IX3LFO.EQ.'HARD')IX3LFO='TEKT'
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1381)
 1381   FORMAT('THE LABEL FONT (FOR THE THIRD  HORIZONTAL LABEL)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1382)IX3LFO
 1382   FORMAT('HAS JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 1900
!
 1399 CONTINUE
!
!               **********************************************
!               **  TREAT THE CASE WHEN ONLY THE LEFT       **
!               **  VERTICAL   LABEL IS      TO BE CHANGED  **
!               **********************************************
!
      IF(ICOM.EQ.'Y1LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'FONT')THEN
          IHOLD=IDEFFO
          GO TO 1480
        ELSE
          IHOLD=IHARG(NUMARG)
          GO TO 1480
        ENDIF
      ELSE
        GO TO 1499
      ENDIF
!
 1480 CONTINUE
      IFOUND='YES'
      IY1LFO=IHOLD
      IF(IY1LFO.EQ.'HARD')IY1LFO='TEKT'
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1481)
 1481   FORMAT('THE LABEL FONT (FOR THE LEFT   VERTICAL   LABEL)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1482)IY1LFO
 1482   FORMAT('HAS JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 1900
!
 1499 CONTINUE
!
!               *****************************************************
!               **  TREAT THE CASE WHEN ONLY THE                   **
!               **  RIGHT  VERTICAL   LABEL IS      TO BE CHANGED  **
!               *****************************************************
!
      IF(ICOM.EQ.'Y2LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'FONT')THEN
          IHOLD=IDEFFO
          GO TO 1580
        ELSE
          IHOLD=IHARG(NUMARG)
          GO TO 1580
        ENDIF
      ELSE
        GO TO 1599
      ENDIF
!
 1580 CONTINUE
      IFOUND='YES'
      IY2LFO=IHOLD
      IF(IY2LFO.EQ.'HARD')IY2LFO='TEKT'
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1581)
 1581   FORMAT('THE LABEL FONT (FOR THE RIGHT  VERTICAL   LABEL)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1582)IY2LFO
 1582   FORMAT('HAS JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 1900
!
 1599 CONTINUE
!
!               *******************************************************
!               **  TREAT THE CASE WHEN BOTH                         **
!               **  LEFT AND RIGHT VERTICAL LABELS ARE TO BE CHANGED **
!               *******************************************************
!
      IF(ICOM.EQ.'YLAB')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'FONT')THEN
          IHOLD=IDEFFO
          GO TO 1680
        ELSE
          IHOLD=IHARG(NUMARG)
          GO TO 1680
        ENDIF
      ELSE
        GO TO 1699
      ENDIF
!
 1680 CONTINUE
      IFOUND='YES'
      IF(IHOLD.EQ.'HARD')IHOLD='TEKT'
      IY1LFO=IHOLD
      IY2LFO=IHOLD
      IF(IY1LFO.EQ.'HARD')IY1LFO='TEKT'
      IF(IY2LFO.EQ.'HARD')IY2LFO='TEKT'
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1681)
 1681   FORMAT('THE LABEL FONT (FOR THE LEFT AND RIGHT VERTICAL ',   &
               'LABELS)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1682)IHOLD
 1682   FORMAT('HAS JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 1900
!
 1699 CONTINUE
!               **********************************************
!               **  TREAT THE CASE WHEN ALL  5 LABELS ARE   **
!               **  TO BE CHANGED                           **
!               **********************************************
!
      IF(ICOM.EQ.'LABE' .OR. ICOM.EQ.'XYLA' .OR.   &
         ICOM.EQ.'YXLA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'FONT')THEN
          IHOLD=IDEFFO
          GO TO 1780
        ELSE
          IHOLD=IHARG(NUMARG)
          GO TO 1780
        ENDIF
      ELSE
        GO TO 1799
      ENDIF
!
 1780 CONTINUE
      IFOUND='YES'
      IF(IHOLD.EQ.'HARD')IHOLD='TEKT'
      IY1LFO=IHOLD
      IY2LFO=IHOLD
      IX1LFO=IHOLD
      IX2LFO=IHOLD
      IX3LFO=IHOLD
      IF(IY1LFO.EQ.'HARD')IY1LFO='TEKT'
      IF(IY2LFO.EQ.'HARD')IY2LFO='TEKT'
      IF(IX1LFO.EQ.'HARD')IX1LFO='TEKT'
      IF(IX2LFO.EQ.'HARD')IX2LFO='TEKT'
      IF(IX3LFO.EQ.'HARD')IX3LFO='TEKT'
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1781)
 1781   FORMAT('THE LABEL FONT (FOR ALL 5 LABELS--3 HORIZONTAL AND ',   &
               '2 VERTICAL)')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1782)IHOLD
 1782   FORMAT('HAS JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 1900
!
 1799 CONTINUE
!
 1900 CONTINUE
      RETURN
      END SUBROUTINE DPLAFO
      SUBROUTINE DPLAG(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                       IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--GENERATE THE FOLLOWING PLOT--
!              A LAG PLOT;
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1978.
!     UPDATED         --JUNE      1978.
!     UPDATED         --JULY      1978.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --APRIL     1979.
!     UPDATED         --JANUARY   1981.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --AUGUST    1993. FIX FORMAT STATEMENT
!     UPDATED         --MAY       2011. USE DPPARS, DPPAR3
!     UPDATED         --MAY       2011. SUPPORT FOR "HIGHLIGHTED" OPTION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASE
      CHARACTER*4 IHIGH
      PARAMETER (MAXSPN=10)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
      CHARACTER*40 INAME
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION XHIGH(MAXOBV)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),Y2(1))
      EQUIVALENCE (GARBAG(IGARB3),XHIGH(1))
      EQUIVALENCE (GARBAG(IGARB4),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB5),TEMP2(1))
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      ISUBN1='DPLA'
      ISUBN2='G   '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!               *******************************
!               **  TREAT THE LAG PLOT CASE  **
!               *******************************
!
      IF(IBUGG2.EQ.'ON' .OR. ISUBRO.EQ.'PLAG')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLAG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASPL,IAND1,IAND2
   52   FORMAT('ICASPL,IAND1,IAND2 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGG2,IBUGG3,IBUGQ,ISUBRO
   53   FORMAT('IBUGG2,IBUGG3,IBUGQ,ISUBRO = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLAG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IHIGH='OFF'
      IF(ICOM.EQ.'LAG'.AND.IARGT(1).EQ.'NUMB'.AND.   &
        IHARG(2).EQ.'PLOT')THEN
        LAG=IARG(1)
        ILASTC=2
      ELSEIF(ICOM.EQ.'LAG'.AND.IHARG(1).EQ.'PLOT')THEN
        LAG=1
        ILASTC=1
      ELSEIF(ICOM.EQ.'LAG'.AND.IARGT(1).EQ.'NUMB'.AND.   &
        (IHARG(2).EQ.'HIGH'.OR.IHARG(2).EQ.'SUBS').AND.   &
        IHARG(3).EQ.'PLOT')THEN
        LAG=IARG(1)
        ILASTC=3
        IHIGH='ON'
      ELSEIF((ICOM.EQ.'HIGH'.OR.ICOM.EQ.'SUBS').AND.   &
        IHARG(1).EQ.'LAG '.AND.IARGT(2).EQ.'NUMB'.AND.   &
        IHARG(3).EQ.'PLOT')THEN
        LAG=IARG(2)
        ILASTC=3
        IHIGH='ON'
      ELSEIF(ICOM.EQ.'LAG'.AND.   &
        (IHARG(1).EQ.'HIGH'.OR.IHARG(1).EQ.'SUBS').AND.   &
        IHARG(2).EQ.'PLOT')THEN
        LAG=1
        ILASTC=2
        IHIGH='ON'
      ELSEIF((ICOM.EQ.'HIGH'.OR.ICOM.EQ.'SUBS').AND.   &
        IHARG(1).EQ.'LAG '.AND.IHARG(2).EQ.'PLOT')THEN
        LAG=1
        ILASTC=2
        IHIGH='ON'
      ELSE
        IFOUND='NO'
        GO TO 9000
      ENDIF
!
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      IFOUND='YES'
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLAG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='LAG PLOT'
      MINNA=1
      MAXNA=100
      MINN2=1
      IFLAGE=1
      IFLAGM=1
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=1
      MAXNVA=2
      IF(IHIGH.EQ.'ON')THEN
        MINNVA=2
        MAXNVA=3
      ENDIF
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLAG')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
      DO 290 I=1,NRIGHT(1)
        Y2(I)=1.0
        XHIGH(I)=1.0
  290 CONTINUE
      ICOL=1
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y1,Y2,XHIGH,NS,NLOCA2,NLOCA3,ICASE,   &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IHIGH.EQ.'ON' .AND. NUMVAR.EQ.2)THEN
        DO 299 I=1,NS
          XHIGH(I)=Y2(I)
          Y2(I)=1.0
  299   CONTINUE
      ENDIF
      IF(IHIGH.EQ.'OFF')THEN
        IF(NUMVAR.EQ.1)ICASPL='LAG1'
        IF(NUMVAR.EQ.2)ICASPL='LAG2'
      ELSE
        IF(NUMVAR.EQ.2)ICASPL='LAG1'
        IF(NUMVAR.EQ.3)ICASPL='LAG2'
      ENDIF
!
!               *******************************************************
!               **  STEP 9--                                          *
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS VARIABLES   *
!               **  (Y(.) AND X(.), RESPECTIVELY) FOR THE PLOT.       *
!               **  FORM THE CURVE DESIGNATION VARIABLE D(.)  .       *
!               **  THIS WILL BE BOTH ONES FOR BOTH CASES             *
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).     *
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).     *
!               *******************************************************
!
      ISTEPN='9'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'PLAG')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPLAG2(Y1,Y2,XHIGH,NS,ICASPL,IHIGH,LAG,   &
                  TEMP1,TEMP2,   &
                  Y,X,D,NPLOTP,NPLOTV,   &
                  IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON' .AND. ISUBRO.EQ.'PLAG')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLAG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR,ICASPL
 9012   FORMAT('IFOUND,IERROR,ICASPL = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,LAG
 9013   FORMAT('NPLOTV,NPLOTP,NS,LAG = ',4I8)
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GT.0)THEN
          DO 9015 I=1,NPLOTP
            WRITE(ICOUT,9016)I,Y(I),X(I),D(I)
 9016       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9015     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPLAG
      SUBROUTINE DPLAG2(Y1,Y2,XHIGH,N,ICASPL,IHIGH,LAG,   &
                        TEMP1,TEMP2,   &
                        Y,X,D,NPLOTP,NPLOTV,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A PAIR OF COORDINATE VECTORS
!              THAT WILL DEFINE
!                   1) A 1-VARIABLE LAG PLOT
!                   2) A 2-VARIABLE LAG PLOT
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1978.
!     UPDATED         --MAY       1978.
!     UPDATED         --JUNE      1978.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --MARCH     1979.
!     UPDATED         --APRIL     1979.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   2009. SWITCH ORDER OF AXES.
!     UPDATED         --MAY       2011. HIGHLIGHT OPTION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IHIGH
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IWRITE
!
!---------------------------------------------------------------------
!
      DIMENSION Y1(*)
      DIMENSION Y2(*)
      DIMENSION XHIGH(*)
      DIMENSION Y(*)
      DIMENSION X(*)
      DIMENSION D(*)
      DIMENSION TEMP1(*)
      DIMENSION TEMP2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLA'
      ISUBN2='G2  '
      IERROR='NO'
!
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'LAG2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,70)
   70   FORMAT('***** AT THE BEGINNING OF DPLAG2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)N,LAG,ICASPL
   71   FORMAT('N,LAG,ICASPL = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 73 I=1,N
          WRITE(ICOUT,74)I,Y1(I),Y2(I),XHIGH(I)
   74     FORMAT('I,Y1(I),Y2(I),XHIGH(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   73   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN LAG PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 2;')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************************
!               **  STEP 2--                                          **
!               **  CHECK THAT THE SPECIFIED LAG IS                   **
!               **  STRICTLY SMALLER THAN THE NUMBER OF OBSERVATIONS  **
!               ********************************************************
!
      LAG2=LAG
      IF(LAG.LT.0)LAG2=-LAG
!
      IF(LAG2.GE.N)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE SPECIFIED LAG EXCEEDS THE NUMBER OF ',   &
               'OBSERVATIONS')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,114)LAG
  114   FORMAT('      THE SPECIFIED LAG            = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,115)N
  115   FORMAT('      THE NUMBER OF OBSERVATIONS N = ',I8)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(IHIGH.EQ.'ON')THEN
        IWRITE='OFF'
        CALL CODE(XHIGH,N,IWRITE,TEMP1,TEMP2,N,IBUGG3,IERROR)
        DO 150 I=1,N
          XHIGH(I)=TEMP1(I)
  150   CONTINUE
      ENDIF
!
!               **************************************
!               **  STEP 3--                        **
!               **  BRANCH TO THE APPROPRIATE CASE  **
!               **  AND DETERMINE PLOT COORDINATES  **
!               **************************************
!
      IF(ICASPL.EQ.'LAG1')THEN
!
!               ************************************
!               **  STEP 4.1--                    **
!               **  FORM THE 1-VARIABLE LAG PLOT  **
!               ************************************
!
        IMIN=1
        IMAX=N-LAG2
        IF(LAG.LT.0)IMIN=1+LAG2
        IF(LAG.LT.0)IMAX=N
        J=0
        IF(IHIGH.EQ.'OFF')THEN
          DO 1110 I=IMIN,IMAX
            J=J+1
            IPLAG=I+LAG
            X(J)=Y1(I)
            Y(J)=Y1(IPLAG)
            D(J)=1.0
 1110     CONTINUE
        ELSE
          DO 1120 I=IMIN,IMAX
            J=J+1
            IPLAG=I+LAG
            X(J)=Y1(I)
            Y(J)=Y1(IPLAG)
!CCCC       IF(XHIGH(I).LE.0.5)THEN
!CCCC         D(J)=1.0
!CCCC       ELSE
!CCCC         D(J)=2.0
!CCCC       ENDIF
            D(J)=XHIGH(I)
 1120     CONTINUE
        ENDIF
        NPLOTP=J
        NPLOTV=2
      ELSEIF(ICASPL.EQ.'LAG2')THEN
!
!               ************************************
!               **  STEP 4.2--                    **
!               **  FORM THE 2-VARIABLE LAG PLOT  **
!               ************************************
!
        IMIN=1
        IMAX=N-LAG2
        IF(LAG.LT.0)IMIN=1+LAG2
        IF(LAG.LT.0)IMAX=N
        J=0
        IF(IHIGH.EQ.'OFF')THEN
          DO 1210 I=IMIN,IMAX
            J=J+1
            IPLAG=I+LAG
            X(J)=Y1(I)
            Y(J)=Y2(IPLAG)
            D(J)=1.0
 1210     CONTINUE
        ELSE
          DO 1220 I=IMIN,IMAX
            J=J+1
            IPLAG=I+LAG
            X(J)=Y1(I)
            Y(J)=Y2(IPLAG)
            D(J)=XHIGH(I)
!CCCC       IF(XHIGH(I).LE.0.5)THEN
!CCCC         D(J)=1.0
!CCCC       ELSE
!CCCC         D(J)=2.0
!CCCC       ENDIF
 1220     CONTINUE
        ENDIF
        NPLOTP=J
        NPLOTV=2
      ELSE
!
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1012)
 1012   FORMAT('      ICASPL SHOULD BE EITHER  LAG1   OR  LAG2, ',   &
               'BUT IS NEITHER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1014)ICASPL
 1014   FORMAT('      ICASPL = ',A4)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!
!               ******************
!               **   STEP 90--  **
!               **   EXIT       **
!               ******************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'ON' .OR. ISUBRO.EQ.'LAG2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLAG2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASPL,IERROR,LAG,N,NPLOTP
 9012   FORMAT('ICASPL,IERROR,LAG,N,NPLOTP = ',2(A4,2X),3I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NPLOTP
          WRITE(ICOUT,9016)I,Y(I),X(I),D(I)
 9016     FORMAT('I,Y(I),X(I),D(I) = ',I8,2G15.7,F9.2)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPLAG2
      SUBROUTINE DPLAJU(ICOM,IHARG,NUMARG,   &
                        IDEFJU,   &
                        IX1LJU,IX2LJU,IX3LJU,IY1LJU,IY2LJU,   &
                        IBUGPC,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LABEL JUSTIFICATION SWITCHES
!              FOR ANY OF THE 5 LABELS.
!              SUCH LABEL JUSTIFICATION SWITCHES DEFINE THE
!              JUSTIFICATION FOR EACH OF THE 5 LABELS.
!              THE CONTENTS OF A LABEL JUSTIFICATION SWITCH ARE
!              A JUSTIFICATION.
!              THE LABEL JUSTIFICATION SWITCHES FOR THE 5 LABELS
!              ARE CONTAINED IN IX1LJU,IX2LJU,IX3LJU,IY1LJU,IY2LJU.
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFFO
!     OUTPUT ARGUMENTS--IX1LJU (A HOLLERITH VARIABLE
!                       DENOTING THE JUSTIFICATION OF THE FIRST HORIZ. LABEL
!                     --IX2LJU (A HOLLERITH VARIABLE
!                       DENOTING THE JUSTIFICATION OF THE SECOND HORIZ. LABEL
!                     --IX3LJU (A HOLLERITH VARIABLE
!                       DENOTING THE JUSTIFICATION OF THE THIRD HORIZ. LABEL
!                     --IY1LJU (A HOLLERITH VARIABLE
!                       DENOTING THE JUSTIFICATION OF THE FIRST VERT. LABEL
!                     --IY2LJU (A HOLLERITH VARIABLE
!                       DENOTING THE JUSTIFICATION OF THE SECOND VERT. LABEL
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/10
!     ORIGINAL VERSION--OCTOBER   1999.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
