      IF(IFEEDB.EQ.'OFF')GO TO 1489
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1481)
 1481 FORMAT('THE LABEL JUSTIFICATION (FOR THE LEFT   VERTICAL   ',   &
