      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1482)IHOLD
 1482 FORMAT('HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1489 CONTINUE
      GO TO 1900
!
 1499 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE RIGHT  VERTICAL   LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'Y2LA')GO TO 1500
