      SUBROUTINE DPLAOF(ICOM,IHARG,IARGT,ARG,NUMARG,   &
      PDEFOF,   &
      PX1LOF,PX2LOF,PX3LOF,PY1LOF,PY2LOF,   &
      IFOUND,IERROR)
