      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1750
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1750
      IF(IHARG(NUMARG).EQ.'OFFS')GO TO 1750
      IF(IARGT(NUMARG).EQ.'NUMB')GO TO 1760
      IERROR='YES'
      GO TO 9000
!
 1750 CONTINUE
      HOLD1=PDEFOF
      GO TO 1780
!
 1760 CONTINUE
      HOLD1=ARG(NUMARG)
      GO TO 1780
!
 1780 CONTINUE
      IFOUND='YES'
      PX1LOF=HOLD1
      PX2LOF=HOLD1
      PX3LOF=HOLD1
      PY1LOF=HOLD1
      PY2LOF=HOLD1
!
      IF(IFEEDB.EQ.'OFF')GO TO 1789
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1781)
 1781 FORMAT('THE LABEL OFFSET (FOR ALL 5 ',   &
      'LABELS--3 HORIZONTAL AND 2 VERTICAL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1782)HOLD1
 1782 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1789 CONTINUE
      GO TO 1900
!
 1799 CONTINUE
!
 1900 CONTINUE
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPLAOF
      SUBROUTINE DPLARG(X,N,NMAX,XOUT,NOUT,ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--THIS SUBROUTINE RETURNS THE "NMAX" LARGEST ELEMENTS
!              OF THE DATA IN THE INPUT VECTOR X.
!     INPUT  ARGUMENTS--X      = THE SINGLE PRECISION VECTOR OF
!                                (UNSORTED OR SORTED) OBSERVATIONS.
!                     --N      = THE INTEGER NUMBER OF OBSERVATIONS
!                                IN THE VECTOR X.
!                     --NMAX   = THE NUMBER OF ELEMENTS TO RETURN
!     OUTPUT ARGUMENTS--XOUT   = THE SINGLE PRECISION VECTOR TO
!                                CONTAIN THE LARGEST VALUES
!     OUTPUT--THE NMAX LARGEST VALUES IN X.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER DATAPAC   SUBROUTINES NEEDED--SORT.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2018.10
!     ORIGINAL VERSION--OCTOBER   2018.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
      DIMENSION XOUT(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLA'
      ISUBN2='RG  '
      IERROR='NO'
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LARG')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLARG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA3,ISUBRO,N
   52   FORMAT('IBUGA3,ISUBRO,N = ',2(A4,2X),I10)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,X(I)
   56     FORMAT('I,X(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ***************************
!               **  FIND LARGEST VALUES  **
!               ***************************
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,111)
  111   FORMAT('***** ERROR IN DPLARG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,112)
  112   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IN THE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,113)
  113   FORMAT('      IN THE RESPONSE VARIABLE MUST BE 1 OR LARGER.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,116)
  116   FORMAT('      SUCH WAS NOT THE CASE HERE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,117)N
  117   FORMAT('      THE NUMBER OF OBSERVATIONS = ',I8,'.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!               ***********************************
!               **  STEP 2--                     **
!               **  SORT THE DATA AND EXTRACT    **
!               **  THE LARGEST                  **
!               ***********************************
!
      CALL SORT(X,N,X)
      NSTRT=N-NMAX+1
      IF(NSTRT.LT.1)NSTRT=1
      NOUT=0
      DO 200 I=NSTRT,N
        NOUT=NOUT+1
        XOUT(NOUT)=X(I)
  200 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LARG')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLARG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,NOUT
 9012   FORMAT('IERROR,NOUT = ',A4,2X,I10)
        CALL DPWRST('XXX','BUG ')
        IF(NOUT.GE.1)THEN
          DO 9014 I=1,NOUT
            WRITE(ICOUT,9015)I,XOUT(I)
 9015       FORMAT('I,XOUT(I) = ',I10,2X,G15.7)
            CALL DPWRST('XXX','BUG ')
 9014     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPLARG
      SUBROUTINE DPLASZ(ICOM,IHARG,IARGT,ARG,NUMARG,   &
                        PDEFHE,PDEFWI,   &
                        PX1LHE,PX1LWI,PX1LVG,PX1LHG,   &
                        PX2LHE,PX2LWI,PX2LVG,PX2LHG,   &
                        PX3LHE,PX3LWI,PX3LVG,PX3LHG,   &
                        PY1LHE,PY1LWI,PY1LVG,PY1LHG,   &
                        PY2LHE,PY2LWI,PY2LVG,PY2LHG,   &
                        IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LABEL SIZES
!              FOR ANY OF THE 5 LABELS.
!              THE LABEL SIZE SWITCHES FOR THE LABELS
!              ARE CONTAINED IN THE VARIABLES--
!                    PX1LHE,PX1LWI,PX1LVG,PX1LHG,
!                    PX2LHE,PX2LWI,PX2LVG,PX2LHG,
!                    PX3LHE,PX3LWI,PX3LVG,PX3LHG,
!                    PY1LHE,PY1LWI,PY1LVG,PY1LHG,
!                    PY2LHE,PY2LWI,PY2LVG,PY2LHG,
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG
!                     --PDEFHE
!     OUTPUT ARGUMENTS--
!                           PX1LHE,PX1LWI,PX1LVG,PX1LHG,
!                           PX2LHE,PX2LWI,PX2LVG,PX2LHG,
!                           PX3LHE,PX3LWI,PX3LVG,PX3LHG,
!                           PY1LHE,PY1LWI,PY1LVG,PY1LHG,
!                           PY2LHE,PY2LWI,PY2LVG,PY2LHG,
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--OCTOBER   1980.
!     UPDATED         --MARCH     1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.LE.0)GO TO 1900
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'SIZE')GO TO 1090
      GO TO 1900
 1090 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE FIRST  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'XLAB' .OR. ICOM.EQ.'X1LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'SIZE')THEN
          HOLD1=PDEFHE
          HOLD2=PDEFWI
        ELSEIF(IARGT(NUMARG).EQ.'NUMB')THEN
          HOLD1=ARG(NUMARG)
          HOLD2=HOLD1*0.5
        ELSE
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IFOUND='YES'
        PX1LHE=HOLD1
        PX1LWI=HOLD2
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
  999     FORMAT(1X)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1181)
 1181     FORMAT('THE LABEL SIZE (FOR THE FIRST  HORIZONTAL LABEL)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)HOLD1
 1182     FORMAT('HAS JUST BEEN SET TO ',E15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 1900
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE SECOND HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'X2LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'SIZE')THEN
          HOLD1=PDEFHE
          HOLD2=PDEFWI
        ELSEIF(IARGT(NUMARG).EQ.'NUMB')THEN
          HOLD1=ARG(NUMARG)
          HOLD2=HOLD1*0.5
        ELSE
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IFOUND='YES'
        PX2LHE=HOLD1
        PX2LWI=HOLD2
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1281)
 1281     FORMAT('THE LABEL SIZE (FOR THE SECOND HORIZONTAL LABEL)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)HOLD1
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 1900
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE THIRD  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'X3LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'SIZE')THEN
          HOLD1=PDEFHE
          HOLD2=PDEFWI
        ELSEIF(IARGT(NUMARG).EQ.'NUMB')THEN
          HOLD1=ARG(NUMARG)
          HOLD2=HOLD1*0.5
        ELSE
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IFOUND='YES'
        PX3LHE=HOLD1
        PX3LWI=HOLD2
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1381)
 1381     FORMAT('THE LABEL SIZE (FOR THE THIRD  HORIZONTAL LABEL)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)HOLD1
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 1900
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE LEFT   VERTICAL   LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'Y1LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'SIZE')THEN
          HOLD1=PDEFHE
          HOLD2=PDEFWI
        ELSEIF(IARGT(NUMARG).EQ.'NUMB')THEN
          HOLD1=ARG(NUMARG)
          HOLD2=HOLD1*0.5
        ELSE
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IFOUND='YES'
        PY1LHE=HOLD1
        PY1LWI=HOLD2
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1481)
 1481     FORMAT('THE LABEL SIZE (FOR THE LEFT   VERTICAL   LABEL)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)HOLD1
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 1900
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE RIGHT  VERTICAL   LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'Y2LA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'SIZE')THEN
          HOLD1=PDEFHE
          HOLD2=PDEFWI
        ELSEIF(IARGT(NUMARG).EQ.'NUMB')THEN
          HOLD1=ARG(NUMARG)
          HOLD2=HOLD1*0.5
        ELSE
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IFOUND='YES'
        PY2LHE=HOLD1
        PY2LWI=HOLD2
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1581)
 1581     FORMAT('THE LABEL SIZE (FOR THE RIGHT  VERTICAL   LABEL)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)HOLD1
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 1900
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  BOTH VERTICAL AXIS LABELS ARE TO BE CHANGED             **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'YLAB')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'SIZE')THEN
          HOLD1=PDEFHE
          HOLD2=PDEFWI
        ELSEIF(IARGT(NUMARG).EQ.'NUMB')THEN
          HOLD1=ARG(NUMARG)
          HOLD2=HOLD1*0.5
        ELSE
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IFOUND='YES'
        PY1LHE=HOLD1
        PY2LHE=HOLD1
        PY1LWI=HOLD2
        PY2LWI=HOLD2
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1681)
 1681     FORMAT('THE LABEL SIZE (FOR THE LEFT AND RIGHT VERTICAL ',   &
                 'LABELS)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)HOLD1
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 1900
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY ALL  5 LABELS ARE                   TO BE CHANGED  **
!               **************************************************************
!
      ELSEIF(ICOM.EQ.'LABE' .OR. ICOM.EQ.'XYLA' .OR.   &
             ICOM.EQ.'YXLA')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF'  .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA' .OR.   &
           IHARG(NUMARG).EQ.'SIZE')THEN
          HOLD1=PDEFHE
          HOLD2=PDEFWI
        ELSEIF(IARGT(NUMARG).EQ.'NUMB')THEN
          HOLD1=ARG(NUMARG)
          HOLD2=HOLD1*0.5
        ELSE
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        IFOUND='YES'
        PY1LHE=HOLD1
        PY2LHE=HOLD1
        PX1LHE=HOLD1
        PX2LHE=HOLD1
        PX3LHE=HOLD1
        PY1LWI=HOLD2
        PY2LWI=HOLD2
        PX1LWI=HOLD2
        PX2LWI=HOLD2
        PX3LWI=HOLD2
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1781)
 1781     FORMAT('THE LABEL SIZE (FOR ALL 5 LABELS--3 HORIZONTAL ',   &
                 'AND 2 VERTICAL)')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1182)HOLD1
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 1900
!
      ENDIF
!
 1900 CONTINUE
!
      PX1LVG=PX1LHE*0.375
      PX2LVG=PX2LHE*0.375
      PX3LVG=PX3LHE*0.375
      PY1LVG=PY1LHE*0.375
      PY2LVG=PY2LHE*0.375
!
      PX1LHG=PX1LHE*0.125
      PX2LHG=PX2LHE*0.125
      PX3LHG=PX3LHE*0.125
      PY1LHG=PY1LHE*0.125
      PY2LHG=PY2LHE*0.125
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPLASZ
      SUBROUTINE DPLAT1(IHEAD,NHEAD,CAPTN,NCAP,IFLAG1)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS USED TO INITIATE
!              THE LATEX OUTPUT AND STARTS THE FIRST TABLE.
!              THE ONLY OPTIONAL ELEMENT IS THE CAPTION.
!     INPUT  ARGUMENTS--IHEAD  = THE CHARACTER STRING CONTAINING
!                                THE TEXT FOR THE HEADER
!                     --NHEAD  = THE INTEGER NUMBER THAT SPECIFIES
!                                THE NUMBER OF CHARACTERS IN THE
!                                HEADER.
!                     --CAPTN  = THE CHARACTER STRING CONTAINING
!                                THE CAPTION.
!                     --NCAP   = THE INTEGER NUMBER THAT SPECIFIES
!                                THE NUMBER OF CHARACTERS IN THE
!                                CAPTION.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/2
!     ORIGINAL VERSION--FEBRUARY  2005.
!     UPDATED         --AUGUST    2014. ADD [hbtp]
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*(*) CAPTN
      CHARACTER*(*) IHEAD
!
      LOGICAL IFLAG1
!
      CHARACTER*1  IBASLC
      CHARACTER*10 IFORMT
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: END ASIS MODE AND WRITE A HEADER
!
      CALL DPCONA(92,IBASLC)
  999 FORMAT(1X)
 8003 FORMAT(A1,'begin{table}[hbtp]')
 8007 FORMAT('$ ',A1,1X,A1,' $ ',A1,A1,' ')
 8009 FORMAT(A1,'begin{center}')
 8013 FORMAT(A1,'end{center}')
!
      IF(IFLAG1)THEN
        WRITE(ICOUT,8003)IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IF(NHEAD.GE.1)THEN
        WRITE(ICOUT,8009)IBASLC
        CALL DPWRST('XXX','WRIT')
        IFORMT=' '
        IFORMT(1:5)='(A  )'
        WRITE(IFORMT(3:4),'(I2)')NHEAD
        WRITE(ICOUT,8005)IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,IFORMT)IHEAD(1:NHEAD)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8006)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8013)IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!  STEP 2: START TABLE AND DEFINE A CAPTION
!
 8005 FORMAT('{',A1,'bf ')
 8006 FORMAT(' }')
 8011 FORMAT('{',A1,'bf ')
!8015 FORMAT('} ',A1,A1)
!
      IF(NCAP.GT.0)THEN
        WRITE(ICOUT,8009)IBASLC
        CALL DPWRST('XXX','WRIT')
        IFORMT=' '
        IF(NCAP.LE.99)THEN
          IFORMT(1:5)='(A  )'
          WRITE(IFORMT(3:4),'(I2)')NCAP
        ELSE
          IFORMT(1:6)='(A   )'
          WRITE(IFORMT(3:5),'(I3)')NCAP
        ENDIF
        WRITE(ICOUT,8011)IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,IFORMT)CAPTN(1:NCAP)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8006)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8007)IBASLC,IBASLC,IBASLC,IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8007)IBASLC,IBASLC,IBASLC,IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8013)IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLAT1
      SUBROUTINE DPLATZ(IFLAG1,IFLAG2,IFLAG3,NHEAD)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS USED TO CLOSE THE
!              CURRENT TABLE AND TERMINATE THE LATEX OUTPUT.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/2
!     ORIGINAL VERSION--FEBRUARY  2005.
!     UPDATED         --AUGUST    2014. RESIZE OPTION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      LOGICAL IFLAG1
      LOGICAL IFLAG2
      LOGICAL IFLAG3
!
      CHARACTER*1 IBASLC
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: END THE CURRENT TABLE
!
      IF(ISUBG4.EQ.'ON')THEN
        WRITE(ICOUT,11)NHEAD,IFLAG1,IFLAG2,IFLAG3
   11   FORMAT('DPLATZ: NHEAD,IFLAG1,IFLAG2,IFLAG3 = ',I5,3L5)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
  999 FORMAT(1X)
 8091 FORMAT(A1,'end{tabular}')
 8096 FORMAT('}')
 8092 FORMAT(A1,'end{center}')
 8093 FORMAT(A1,'end{table}')
      CALL DPCONA(92,IBASLC)
      IF(IFLAG1)THEN
        WRITE(ICOUT,8091)IBASLC
        CALL DPWRST('XXX','WRIT')
        IF(ILATRS.EQ.'ON')THEN
          WRITE(ICOUT,8096)
          CALL DPWRST('XXX','WRIT')
        ENDIF
        WRITE(ICOUT,8092)IBASLC
        CALL DPWRST('XXX','WRIT')
      ENDIF
      IF(IFLAG3)THEN
        WRITE(ICOUT,8093)IBASLC
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!  STEP 2: RESET "ASIS" MODE
!
 8099 FORMAT(A1,'begin{verbatim}')
      IF(IFLAG2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8099)IBASLC
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLATZ
      SUBROUTINE DPLAT4(IVALUE,NCHAR,NHEAD,IFLAG1,IFLAG2,IFLAG3)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS USED TO GENERATE
!              A HEADER ROW FOR A TABLE.  YOU CAN ALSO OPTIONALLY
!              ADD A RULE LINE BEFORE OR AFTER THE HEADER.
!
!     INPUT  ARGUMENTS--IVALUE  = THE CHARACTER STRING ARRAY
!                                 CONTAINING THE TEXT FOR THE
!                                 HEADER VALUES.
!                     --NCHAR   = THE INTEGER ARRAY THAT SPECIFIES
!                                 THE NUMBER OF CHARACTERS IN THE
!                                 HEADER VALUES.
!                     --NHEAD   = THE INTEGER VALUE THAT SPECIFIES
!                                 THE NUMBER OF HEADER VALUES.
!                     --IFLAG1  = A LOGICAL VALUE THAT SPECIFIES
!                                 WHETHER A RULE LINE IS DRAWN BEFORE
!                                 THE HEADER.
!                     --IFLAG2  = A LOGICAL VALUE THAT SPECIFIES
!                                 WHETHER A RULE LINE IS DRAWN AFTER
!                                 THE HEADER.
!                     --IFLAG3  = A LOGICAL VALUE THAT SPECIFIES
!                                 WHETHER THE "CENTER" AND "TABULAR"
!                                 FIELDS ARE WRITTEN (SET TO FALSE FOR
!                                 SECOND AND GREATER LINES OF MULIT-LINE
!                                 HEADERS.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/2
!     ORIGINAL VERSION--FEBRUARY  2005.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*(*) IVALUE(NHEAD)
      INTEGER NCHAR(NHEAD)
!
      PARAMETER (MAXHED=1024)
      INTEGER IWIDTH(MAXHED)
      INTEGER NUMDIG(MAXHED)
      CHARACTER*8 ALIGN(MAXHED)
      CHARACTER*8 VALIGN(MAXHED)
      COMMON/HTML4/IWIDTH,NUMDIG,ALIGN,VALIGN
!
      INCLUDE 'DPCOST.INC'
!
      LOGICAL IFLAG1
      LOGICAL IFLAG2
      LOGICAL IFLAG3
!
      CHARACTER*1  IBASLC
      CHARACTER*1  IAMP
      CHARACTER*1  IQUOTE
      CHARACTER*20 IFORMT
      CHARACTER*132 ISTR
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!C999 FORMAT(1X)
      CALL DPCONA(92,IBASLC)
      CALL DPCONA(39,IQUOTE)
      IAMP='&'
!
!  STEP 2: GENERATE THE HEADER ROW
!
 8020 FORMAT(A1,'begin{center}')
 8022 FORMAT(A1,'resizebox{',A1,'linewidth}{!} {')
!8021 FORMAT(A1,'begin{tabular}')
 8040 FORMAT(A1,'hline')
 8050 FORMAT(2X,A1,A1)
 8060 FORMAT(2X,A1)
      IF(NHEAD.GE.1)THEN
        IF(IFLAG3)THEN
          WRITE(ICOUT,8020)IBASLC
          CALL DPWRST('XXX','WRIT')
          IF(ILATRS.EQ.'ON')THEN
            WRITE(ICOUT,8022)IBASLC,IBASLC
            CALL DPWRST('XXX','WRIT')
          ENDIF
!CCCC     WRITE(ICOUT,8021)IBASLC
!CCCC     CALL DPWRST('XXX','WRIT')
          ISTR=' '
          ISTR(1:1)=IBASLC
          ISTR(2:16)='begin{tabular}{'
          ICNT=16
          DO 8110 I=1,NHEAD
            ICNT=ICNT+1
            ISTR(ICNT:ICNT)=ALIGN(I)(1:1)
 8110     CONTINUE
          ICNT=ICNT+1
          ISTR(ICNT:ICNT)='}'
          IFORMT='(A  )'
          WRITE(IFORMT(3:4),'(I2)')ICNT
          WRITE(ICOUT,IFORMT)ISTR(1:ICNT)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
        IF(IFLAG1)THEN
          WRITE(ICOUT,8040)IBASLC
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
        DO 8120 I=1,NHEAD
          IFORMT=' '
          IF(I.LT.NHEAD)THEN
            IF(NCHAR(I).LE.0)THEN
              WRITE(ICOUT,8060)IAMP
              CALL DPWRST('XXX','WRIT')
            ELSE
              IFORMT(1:11)='(A  ,1X,A1)'
              WRITE(IFORMT(3:4),'(I2)')NCHAR(I)
              WRITE(ICOUT,IFORMT)IVALUE(I)(1:NCHAR(I)),IAMP
              CALL DPWRST('XXX','WRIT')
            ENDIF
          ELSE
            IF(NCHAR(I).GT.0)THEN
              IFORMT(1:14)='(A  ,2X,A1,A1)'
              WRITE(IFORMT(3:4),'(I2)')NCHAR(I)
              WRITE(ICOUT,IFORMT)IVALUE(I)(1:NCHAR(I)),IBASLC,IBASLC
              CALL DPWRST('XXX','WRIT')
            ELSE
              WRITE(ICOUT,8050)IBASLC,IBASLC
              CALL DPWRST('XXX','WRIT')
            ENDIF
          ENDIF
 8120   CONTINUE
        IF(IFLAG2)THEN
          WRITE(ICOUT,8040)IBASLC
          CALL DPWRST('XXX','WRIT')
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPLAT4
      SUBROUTINE DPLA4B(IVALUE,NCHAR,NHEAD,NCOLSP,IFLAG1,IFLAG2,IFLAG3)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS USED TO GENERATE
!              A HEADER ROW FOR A TABLE.  YOU CAN ALSO OPTIONALLY
!              ADD A RULE LINE BEFORE OR AFTER THE HEADER.
!
!              THIS IS A MODIFIED VERSION OF DPLAT4 THAT ADDS
!              AN ARGUMENT TO SPECIFY THE COLUMN SPAN FOR A GIVEN
!              COLUMN.
!
!     INPUT  ARGUMENTS--IVALUE  = THE CHARACTER STRING ARRAY
!                                 CONTAINING THE TEXT FOR THE
!                                 HEADER VALUES.
!                     --NCHAR   = THE INTEGER ARRAY THAT SPECIFIES
!                                 THE NUMBER OF CHARACTERS IN THE
!                                 HEADER VALUES.
!                     --NHEAD   = THE INTEGER VALUE THAT SPECIFIES
!                                 THE NUMBER OF HEADER VALUES.
!                     --NCOLSP  = THE INTEGER ARRAY THAT SPECIFIES
!                                 THE COLUMN SPAN FOR THE GIVEN COLUMN.
!                     --IFLAG1  = A LOGICAL VALUE THAT SPECIFIES
!                                 WHETHER A RULE LINE IS DRAWN BEFORE
!                                 THE HEADER.
!                     --IFLAG2  = A LOGICAL VALUE THAT SPECIFIES
!                                 WHETHER A RULE LINE IS DRAWN AFTER
!                                 THE HEADER.
!                     --IFLAG3  = A LOGICAL VALUE THAT SPECIFIES
!                                 WHETHER THE "CENTER" AND "TABULAR"
!                                 FIELDS ARE WRITTEN (SET TO FALSE FOR
!                                 SECOND AND GREATER LINES OF MULIT-LINE
!                                 HEADERS.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/1
!     ORIGINAL VERSION--JANUARY   2011.
!     UPDATED         --AUGUST    2014. RESIZE OPTION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*(*) IVALUE(NHEAD)
      INTEGER NCHAR(NHEAD)
      INTEGER NCOLSP(NHEAD)
!
      PARAMETER (MAXHED=1024)
      INTEGER IWIDTH(MAXHED)
      INTEGER NUMDIG(MAXHED)
      CHARACTER*8 ALIGN(MAXHED)
      CHARACTER*8 VALIGN(MAXHED)
      COMMON/HTML4/IWIDTH,NUMDIG,ALIGN,VALIGN
!
      INCLUDE 'DPCOST.INC'
!
      LOGICAL IFLAG1
      LOGICAL IFLAG2
      LOGICAL IFLAG3
!
      CHARACTER*1  IBASLC
      CHARACTER*1  IAMP
      CHARACTER*1  IQUOTE
      CHARACTER*20 IFORMT
      CHARACTER*132 ISTR
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!C999 FORMAT(1X)
      CALL DPCONA(92,IBASLC)
      CALL DPCONA(39,IQUOTE)
      IAMP='&'
!
!  STEP 2: GENERATE THE HEADER ROW
!
 8020 FORMAT(A1,'begin{center}')
 8022 FORMAT(A1,'resizebox{',A1,'linewidth}{!} {')
!8021 FORMAT(A1,'begin{tabular}')
 8040 FORMAT(A1,'hline')
 8050 FORMAT(2X,A1,A1)
 8060 FORMAT(2X,A1)
      IF(NHEAD.GE.1)THEN
        IF(IFLAG3)THEN
          WRITE(ICOUT,8020)IBASLC
          CALL DPWRST('XXX','WRIT')
          IF(ILATRS.EQ.'ON')THEN
            WRITE(ICOUT,8022)IBASLC,IBASLC
            CALL DPWRST('XXX','WRIT')
          ENDIF
!CCCC     WRITE(ICOUT,8021)IBASLC
!CCCC     CALL DPWRST('XXX','WRIT')
          ISTR=' '
          ISTR(1:1)=IBASLC
          ISTR(2:16)='begin{tabular}{'
          ICNT=16
          DO 8110 I=1,NHEAD
            ICNT=ICNT+1
            ISTR(ICNT:ICNT)=ALIGN(I)(1:1)
 8110     CONTINUE
          ICNT=ICNT+1
          ISTR(ICNT:ICNT)='}'
          IFORMT='(A  )'
          WRITE(IFORMT(3:4),'(I2)')ICNT
          WRITE(ICOUT,IFORMT)ISTR(1:ICNT)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
        IF(IFLAG1)THEN
          WRITE(ICOUT,8040)IBASLC
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
        DO 8120 I=1,NHEAD
          IF(NCOLSP(I).LE.0)GO TO 8120
          IFORMT=' '
          IF(NCOLSP(I).EQ.1)THEN
            IF(I.LT.NHEAD)THEN
              IF(NCHAR(I).LE.0)THEN
                WRITE(ICOUT,8060)IAMP
                CALL DPWRST('XXX','WRIT')
              ELSE
                IFORMT(1:11)='(A  ,1X,A1)'
                WRITE(IFORMT(3:4),'(I2)')NCHAR(I)
                WRITE(ICOUT,IFORMT)IVALUE(I)(1:NCHAR(I)),IAMP
                CALL DPWRST('XXX','WRIT')
              ENDIF
            ELSE
              IF(NCHAR(I).GT.0)THEN
                IFORMT(1:14)='(A  ,2X,A1,A1)'
                WRITE(IFORMT(3:4),'(I2)')NCHAR(I)
                WRITE(ICOUT,IFORMT)IVALUE(I)(1:NCHAR(I)),IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ELSE
                WRITE(ICOUT,8050)IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ENDIF
            ENDIF
          ELSE
            NCOL=NCOLSP(I)
            WRITE(ICOUT,8070)IBASLC,NCOL
 8070       FORMAT(A1,'multicolumn{',I2,'}{c}{')
            CALL DPWRST('XXX','WRIT')
            IF(I+NCOL-1.LT.NHEAD)THEN
              IF(NCHAR(I).LE.0)THEN
                WRITE(ICOUT,8071)IAMP
 8071           FORMAT(2X,'} ',A1)
                CALL DPWRST('XXX','WRIT')
              ELSE
                IFORMT(1:14)='(A  ,A2,1X,A1)'
                WRITE(IFORMT(3:4),'(I2)')NCHAR(I)
                WRITE(ICOUT,IFORMT)IVALUE(I)(1:NCHAR(I)),'} ',IAMP
                CALL DPWRST('XXX','WRIT')
              ENDIF
            ELSE
              IF(NCHAR(I).GT.0)THEN
                IFORMT(1:17)='(A  ,A2,2X,A1,A1)'
                WRITE(IFORMT(3:4),'(I2)')NCHAR(I)
                WRITE(ICOUT,IFORMT)IVALUE(I)(1:NCHAR(I)),'} ',   &
                                   IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ELSE
                WRITE(ICOUT,8050)IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ENDIF
            ENDIF
          ENDIF
 8120   CONTINUE
        IF(IFLAG2)THEN
          WRITE(ICOUT,8040)IBASLC
          CALL DPWRST('XXX','WRIT')
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPLA4B
      SUBROUTINE DPLAT5(IVALUE,NCHAR,AVALUE,NHEAD,IFLAG1)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS USED TO GENERATE
!              A DATA ROW FOR A TABLE.  THE FIRST FIELD CAN
!              BE A TEXT VALUE (FOR A ROW LABEL).
!
!     INPUT  ARGUMENTS--IVALUE  = THE CHARACTER STRING CONTAINING
!                                 THE TEXT FOR THE FIRST COLUMN.
!                     --NCHAR   = THE INTEGER ARRAY THAT SPECIFIES
!                                 THE NUMBER OF CHARACTERS IN THE
!                                 FIRST TEXT FIELD.
!                     --AVALUE  = A REAL ARRAY CONTAINING THE DATA
!                                 TO BE GENERATED.
!                     --NHEAD   = THE INTEGER VALUE THAT SPECIFIES
!                                 THE NUMBER OF NUMERIC VALUES.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/2
!     ORIGINAL VERSION--FEBRUARY  2005.
!     UPDATED         --APRIL     2009. ADDITIONAL FORMATTING OPTIONS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*(*) IVALUE
      REAL AVALUE(*)
      INTEGER NCHAR
!
      LOGICAL IFLAG1
!
      PARAMETER (MAXHED=1024)
      INTEGER IWIDTH(MAXHED)
      INTEGER NUMDIG(MAXHED)
      CHARACTER*8 ALIGN(MAXHED)
      CHARACTER*8 VALIGN(MAXHED)
      COMMON/HTML4/IWIDTH,NUMDIG,ALIGN,VALIGN
!
      CHARACTER*20 IFORMT
      CHARACTER*1  IBASLC
      CHARACTER*1  IAMP
      CHARACTER*1  ISPACE
      CHARACTER*1  ITEMP1
      CHARACTER*1  ITEMP2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 3: DEFINE A DATA ROW
!
      CALL DPCONA(92,IBASLC)
      IAMP='&'
      ISPACE=' '
!
!  STEP 1: FIRST COLUMN MAY BE A ROW LABEL
!
      IF(NCHAR.GT.0)THEN
        IFORMT=' '
        IFORMT(1:11)='(A  ,A1)'
        WRITE(IFORMT(3:4),'(I2)')NCHAR
        WRITE(ICOUT,IFORMT)IVALUE(1:NCHAR),IAMP
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
!     APRIL 2009: SUPPORT THE FOLLOWING FORMATTING OPTIONS
!
!                  NUMDIG(I) > 0          => Fyy.xx FORMAT
!                  NUMDIG(I) = 0          => I12 FORMAT
!                  NUMDIG(I) = -1         => BLANK
!                  NUMDIG(I) = -2         => G15.7
!                  NUMDIG(I) = -3 to -20  => Eyy.xx
!                  NUMDIG(I) = -99        => '**'
!
 8031 FORMAT(G15.7,2X,A1,A1)
 8033 FORMAT(I12,2X,A1,A1)
 8035 FORMAT(' ',2X,A1,A1)
 8037 FORMAT(' ** ',A1,A1)
!8231 FORMAT(2X,A1,A1)
 8040 FORMAT(A1,'hline')
      IF(NHEAD.GE.1)THEN
        DO 100 I=1,NHEAD
          IFORMT=' '
          IF(I.LT.NHEAD)THEN
            ITEMP1=IAMP
            ITEMP2=ISPACE
          ELSE
            ITEMP1=IBASLC
            ITEMP2=IBASLC
          ENDIF
          IF(NUMDIG(I).GT.0)THEN
            IXX=NUMDIG(I)
            IYY=IXX+10
            IFORMT(1:17)='(F  .  ,1X,A1,A1)'
            WRITE(IFORMT(3:4),'(I2)')IYY
            WRITE(IFORMT(6:7),'(I2)')IXX
            WRITE(ICOUT,IFORMT)AVALUE(I),ITEMP1,ITEMP2
            CALL DPWRST('XXX','WRIT')
          ELSEIF(NUMDIG(I).EQ.0)THEN
            IF(AVALUE(I).GE.0.0)THEN
              WRITE(ICOUT,8033)INT(AVALUE(I)+0.5),ITEMP1,ITEMP2
            ELSE
              WRITE(ICOUT,8033)INT(AVALUE(I)-0.5),ITEMP1,ITEMP2
            ENDIF
            CALL DPWRST('XXX','WRIT')
          ELSEIF(NUMDIG(I).EQ.-1)THEN
            WRITE(ICOUT,8035)ITEMP1,ITEMP2
            CALL DPWRST('XXX','WRIT')
          ELSEIF(NUMDIG(I).EQ.-99)THEN
            WRITE(ICOUT,8037)ITEMP1,ITEMP2
            CALL DPWRST('XXX','WRIT')
          ELSEIF(NUMDIG(I).EQ.-2)THEN
            WRITE(ICOUT,8031)AVALUE(I),ITEMP1,ITEMP2
            CALL DPWRST('XXX','WRIT')
          ELSEIF(NUMDIG(I).LT.-2 .AND. NUMDIG(I).GT.-20)THEN
            IXX=ABS(NUMDIG(I))
            IYY=IXX+8
            IFORMT(1:17)='(E  .  ,1X,A1,A1)'
            WRITE(IFORMT(3:4),'(I2)')IYY
            WRITE(IFORMT(6:7),'(I2)')IXX
            WRITE(ICOUT,IFORMT)AVALUE(I),ITEMP1,ITEMP2
            CALL DPWRST('XXX','WRIT')
          ELSE
            WRITE(ICOUT,8035)ITEMP1,ITEMP2
            CALL DPWRST('XXX','WRIT')
          ENDIF
  100   CONTINUE
!
        IF(IFLAG1)THEN
          WRITE(ICOUT,8040)IBASLC
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
      ENDIF
!
      RETURN
      END SUBROUTINE DPLAT5
      SUBROUTINE DPLAT6(IFLAG1,IFLAG2,IFLAG3)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS USED TO EITHER
!              INITIATE OR END A TABLE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/2
!     ORIGINAL VERSION--FEBRUARY  2005.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      LOGICAL IFLAG1
      LOGICAL IFLAG2
      LOGICAL IFLAG3
!
      CHARACTER*1 IBASLC
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  FOLLOWING ADDS A RULE LINE
!
 8001 FORMAT(A1,'end{verbatim}')
 8020 FORMAT(A1,'begin{table}')
 8040 FORMAT(A1,'end{table}')
      CALL DPCONA(92,IBASLC)
!
      IF(IFLAG3)THEN
        WRITE(ICOUT,8001)IBASLC
        CALL DPWRST('XXX','WRIT')
      ENDIF
      IF(IFLAG1)THEN
        WRITE(ICOUT,8020)IBASLC
        CALL DPWRST('XXX','WRIT')
      ENDIF
      IF(IFLAG2)THEN
        WRITE(ICOUT,8040)IBASLC
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLAT6
      SUBROUTINE DPLAT7(IHEAD,NHEAD,AVAL,NUMDIG)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS USED TO WRITE A
!              A SINGLE LINE OF OUTPUT.
!     INPUT  ARGUMENTS--IHEAD  = THE CHARACTER STRING CONTAINING
!                                THE TEXT FOR THE LINE
!                     --NHEAD  = THE INTEGER NUMBER THAT SPECIFIES
!                                THE NUMBER OF CHARACTERS IN THE
!                                LINE.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/2
!     ORIGINAL VERSION--FEBRUARY  2005.
!     UPDATED         --DECEMBER  2014. SPECIFY NUMBER OF DIGITS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*(*) IHEAD
!
      CHARACTER*1  IBASLC
      CHARACTER*25 IFORMT
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: END ASIS MODE AND WRITE A HEADER
!
!C999 FORMAT(1X)
      CALL DPCONA(92,IBASLC)
!
!  STEP 2: START TABLE AND DEFINE A CAPTION
!
 8005 FORMAT('{',A1,'bf ')
 8006 FORMAT(' }',2X,A1,A1)
!8007 FORMAT('{',A1,'bf ',A1,'space } ',A1,A1)
 8007 FORMAT('$ ',A1,' $ ',A1,A1)
!
      IF(NHEAD.GE.1)THEN
        IFORMT=' '
        IF(AVAL.NE.CPUMIN)THEN
          IF(NUMDIG.GT.0)THEN
            AVALT=RND(AVAL,NUMDIG)
            IXX=NUMDIG
            IYY=IXX+8
            IFORMT(1:15)='(A  ,2X,F  .  )'
            WRITE(IFORMT(10:11),'(I2)')IYY
            WRITE(IFORMT(13:14),'(I2)')IXX
            WRITE(IFORMT(3:4),'(I2)')NHEAD
            WRITE(ICOUT,8005)IBASLC
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,IFORMT)IHEAD(1:NHEAD),AVALT
            CALL DPWRST('XXX','WRIT')
          ELSEIF(NUMDIG.LT.0)THEN
            NUMDI2=-NUMDIG
            AVALT=RND(AVAL,NUMDI2)
            IXX=-NUMDIG
            IYY=IXX+8
            IFORMT(1:15)='(A  ,2X,E  .  )'
            WRITE(IFORMT(10:11),'(I2)')IYY
            WRITE(IFORMT(13:14),'(I2)')IXX
            WRITE(IFORMT(3:4),'(I2)')NHEAD
            WRITE(ICOUT,8005)IBASLC
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,IFORMT)IHEAD(1:NHEAD),AVALT
            CALL DPWRST('XXX','WRIT')
          ELSEIF(NUMDIG.EQ.0)THEN
            IF(AVAL.GE.0.0)THEN
              IVALT=INT(AVAL + 0.5)
            ELSE
              IVALT=INT(AVAL - 0.5)
            ENDIF
            IFORMT(1:23)='(A  ,2X,I10)'
            WRITE(IFORMT(3:4),'(I2)')NHEAD
            WRITE(ICOUT,8005)IBASLC
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,IFORMT)IHEAD(1:NHEAD),IVALT
            CALL DPWRST('XXX','WRIT')
          ENDIF
          WRITE(ICOUT,8006)IBASLC,IBASLC
          CALL DPWRST('XXX','WRIT')
        ELSE
          IF(NHEAD.EQ.1 .AND. IHEAD(1:1).EQ.' ')THEN
            WRITE(ICOUT,8007)IBASLC,IBASLC,IBASLC
            CALL DPWRST('XXX','WRIT')
          ELSE
            IFORMT(1:14)='(A  ,2X,A1,A1)'
            WRITE(IFORMT(3:4),'(I2)')NHEAD
            WRITE(ICOUT,8005)IBASLC
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,IFORMT)IHEAD(1:NHEAD)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,8006)IBASLC,IBASLC
            CALL DPWRST('XXX','WRIT')
          ENDIF
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPLAT7
      SUBROUTINE DPLAT8(IHEAD,NHEAD,IFLAG1,IFLAG2)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS USED TO INITIATE
!              THE LATEX OUTPUT AND GENERATE AN OVERALL TITLE.
!     INPUT  ARGUMENTS--IHEAD  = THE CHARACTER STRING CONTAINING
!                                THE TEXT FOR THE HEADER
!                     --NHEAD  = THE INTEGER NUMBER THAT SPECIFIES
!                                THE NUMBER OF CHARACTERS IN THE
!                                HEADER.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2005/2
!     ORIGINAL VERSION--FEBRUARY  2005.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      LOGICAL IFLAG1
      LOGICAL IFLAG2
!
      CHARACTER*(*) IHEAD
!
      CHARACTER*1  IBASLC
      CHARACTER*10 IFORMT
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: END ASIS MODE AND WRITE A HEADER
!
      IF(ISUBG4.EQ.'ON')THEN
        WRITE(ICOUT,11)NHEAD,IFLAG1,IFLAG2
   11   FORMAT('DPLAT8: NHEAD,IFLAG1,IFLAG2 = ',I5,2L5)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      CALL DPCONA(92,IBASLC)
  999 FORMAT(1X)
 8001 FORMAT(A1,'end{verbatim}')
 8005 FORMAT('{',A1,'bf ')
 8006 FORMAT(' }')
 8007 FORMAT('$ ',A1,1X,A1,' $ ',A1,A1,' ')
 8009 FORMAT(A1,'begin{center}')
 8013 FORMAT(A1,'end{center}')
!8019 FORMAT(A1,'begin{verbatim}')
      IF(IFLAG1)THEN
        WRITE(ICOUT,8001)IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IF(NHEAD.GE.1)THEN
        WRITE(ICOUT,8009)IBASLC
        CALL DPWRST('XXX','WRIT')
        IFORMT=' '
        IFORMT(1:5)='(A  )'
        WRITE(IFORMT(3:4),'(I2)')NHEAD
        WRITE(ICOUT,8005)IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,IFORMT)IHEAD(1:NHEAD)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8006)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8007)IBASLC,IBASLC,IBASLC,IBASLC
        CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,8007)IBASLC,IBASLC,IBASLC,IBASLC
!CCCC   CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8013)IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLAT8
      SUBROUTINE DPLAT9(IVALUE,NCHAR,AVALUE,NHEAD,IFLAG1,IVAL2,NCHAR2)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS USED TO GENERATE
!              A DATA ROW FOR A TABLE.  THE FIRST FIELD CAN
!              BE A TEXT VALUE (FOR A ROW LABEL).
!
!     INPUT  ARGUMENTS--IVALUE  = THE CHARACTER STRING CONTAINING
!                                 THE TEXT FOR THE FIRST COLUMN.
!                     --NCHAR   = THE INTEGER ARRAY THAT SPECIFIES
!                                 THE NUMBER OF CHARACTERS IN THE
!                                 FIRST TEXT FIELD.
!                     --AVALUE  = A REAL ARRAY CONTAINING THE DATA
!                                 TO BE GENERATED.
!                     --NHEAD   = THE INTEGER VALUE THAT SPECIFIES
!                                 THE NUMBER OF NUMERIC VALUES.
!                     --IVAL2   = THE CHARACTER STRING CONTAINING
!                                 THE TEXT FOR THE LAST COLUMN.
!                     --NCHAR   = THE INTEGER ARRAY THAT SPECIFIES
!                                 THE NUMBER OF CHARACTERS IN THE
!                                 LAST TEXT FIELD.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2006/11
!     ORIGINAL VERSION--NOVEMBER  2006.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*(*) IVALUE
      CHARACTER*(*) IVAL2
      REAL AVALUE(NHEAD)
      INTEGER NCHAR
      INTEGER NCHAR2
!
      LOGICAL IFLAG1
!
      PARAMETER (MAXHED=1024)
      INTEGER IWIDTH(MAXHED)
      INTEGER NUMDIG(MAXHED)
      CHARACTER*8 ALIGN(MAXHED)
      CHARACTER*8 VALIGN(MAXHED)
      COMMON/HTML4/IWIDTH,NUMDIG,ALIGN,VALIGN
!
      CHARACTER*20 IFORMT
      CHARACTER*1  IBASLC
      CHARACTER*1  IAMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 3: DEFINE A DATA ROW
!
      CALL DPCONA(92,IBASLC)
      IAMP='&'
!
!  STEP 1: FIRST COLUMN MAY BE A ROW LABEL
!
      IF(NCHAR.GT.0)THEN
        IFORMT=' '
        IFORMT(1:11)='(A  ,A1)'
        WRITE(IFORMT(3:4),'(I2)')NCHAR
        WRITE(ICOUT,IFORMT)IVALUE(1:NCHAR),IAMP
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
 8031 FORMAT(G15.7,' & ')
 8033 FORMAT(I12,' & ')
 8035 FORMAT(' & ')
 8131 FORMAT(G15.7,2X,A1,A1)
 8231 FORMAT(2X,A1,A1)
 8133 FORMAT(I12,2X,A1,A1)
 8135 FORMAT(' ',2X,A1,A1)
 8235 FORMAT(' &  ')
 8040 FORMAT(A1,'hline')
      IF(NHEAD.GE.1)THEN
        DO 100 I=1,NHEAD
          IFORMT=' '
          IF(I.LE.NHEAD)THEN
            IF(NUMDIG(I).GT.0)THEN
              IFORMT(1:13)='(F15. ,1X,A1)'
              WRITE(IFORMT(6:6),'(I1)')MIN(NUMDIG(I),9)
              WRITE(ICOUT,IFORMT)AVALUE(I),IAMP
              CALL DPWRST('XXX','WRIT')
            ELSEIF(NUMDIG(I).EQ.0)THEN
              IF(AVALUE(I).GE.0.0)THEN
                WRITE(ICOUT,8033)INT(AVALUE(I)+0.5)
              ELSE
                WRITE(ICOUT,8033)INT(AVALUE(I)-0.5)
              ENDIF
              CALL DPWRST('XXX','WRIT')
            ELSEIF(NUMDIG(I).EQ.-1)THEN
              WRITE(ICOUT,8035)
              CALL DPWRST('XXX','WRIT')
            ELSEIF(NUMDIG(I).EQ.-2)THEN
              WRITE(ICOUT,8031)AVALUE(I)
              CALL DPWRST('XXX','WRIT')
            ELSE
              WRITE(ICOUT,8235)
              CALL DPWRST('XXX','WRIT')
            ENDIF
          ELSE
            IF(NUMDIG(I).GT.0)THEN
              IFORMT(1:16)='(F15. ,2X,A1,A1)'
              WRITE(IFORMT(6:6),'(I1)')MIN(NUMDIG(I),9)
              WRITE(ICOUT,IFORMT)AVALUE(I),IBASLC,IBASLC
              CALL DPWRST('XXX','WRIT')
            ELSEIF(NUMDIG(I).EQ.0)THEN
              WRITE(ICOUT,8133)INT(AVALUE(I)+0.5),IBASLC,IBASLC
              CALL DPWRST('XXX','WRIT')
            ELSEIF(NUMDIG(I).EQ.-1)THEN
              WRITE(ICOUT,8135)IBASLC,IBASLC
              CALL DPWRST('XXX','WRIT')
            ELSEIF(NUMDIG(I).EQ.-2)THEN
              WRITE(ICOUT,8131)AVALUE(I),IBASLC,IBASLC
              CALL DPWRST('XXX','WRIT')
            ELSE
              WRITE(ICOUT,8231)IBASLC,IBASLC
              CALL DPWRST('XXX','WRIT')
            ENDIF
          END IF
  100   CONTINUE
!
        IF(NCHAR2.GT.0)THEN
          IFORMT=' '
          IFORMT(1:11)='(A  ,A1,A1)'
          WRITE(IFORMT(3:4),'(I2)')NCHAR2
          WRITE(ICOUT,IFORMT)IVAL2(1:NCHAR2),IBASLC,IBASLC
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
        IF(IFLAG1)THEN
          WRITE(ICOUT,8040)IBASLC
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
      ENDIF
!
      RETURN
      END SUBROUTINE DPLAT9
      SUBROUTINE DPLATH(ICOM,IHARG,ARG,NUMARG,   &
      PDEFTH,   &
      PX1LTH,PX2LTH,PX3LTH,PY1LTH,PY2LTH,   &
      IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LABEL THICKNESS SWITCHES
!              FOR ANY OF THE 5 LABELS.
!              SUCH LABEL THICKNESS SWITCHES DEFINE THE THICKNESS
!              FOR EACH OF THE 5 LABELS.
!              THE CONTENTS OF A LABEL THICKNESS SWITCH ARE
!              A THICKNESS.
!              THE LABEL THICKNESS SWITCHES FOR THE 5 LABELS
!              ARE CONTAINED IN PX1LTH,PX2LTH,PX3LTH,PY1LTH,PY2LTH.
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --ARG    (A REAL VECTOR)
!                     --NUMARG
!                     --PDEFTH
!     OUTPUT ARGUMENTS--PX1LTH (A REAL VARIABLE
!                       DENOTING THE THICKNESS OF THE FIRST HORIZ. LABEL
!                     --PX2LTH (A REAL VARIABLE
!                       DENOTING THE THICKNESS OF THE SECOND HORIZ. LABEL
!                     --PX3LTH (A REAL VARIABLE
!                       DENOTING THE THICKNESS OF THE THIRD HORIZ. LABEL
!                     --PY1LTH (A REAL VARIABLE
!                       DENOTING THE THICKNESS OF THE FIRST VERT. LABEL
!                     --PY2LTH (A REAL VARIABLE
!                       DENOTING THE THICKNESS OF THE SECOND VERT. LABEL
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/2
!     ORIGINAL VERSION--JANUARY   1989.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION ARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.LE.0)GO TO 1900
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'THIC')GO TO 1090
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'MARK'.AND.   &
      IHARG(2).EQ.'THIC')GO TO 1090
      GO TO 1900
 1090 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE FIRST  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'XLAB')GO TO 1100
      IF(ICOM.EQ.'X1LA')GO TO 1100
      GO TO 1199
!
 1100 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1150
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1150
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1150
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1150
      IF(IHARG(NUMARG).EQ.'THIC')GO TO 1150
      GO TO 1160
!
 1150 CONTINUE
      PHOLD=PDEFTH
      GO TO 1180
!
 1160 CONTINUE
      PHOLD=ARG(NUMARG)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      PX1LTH=PHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('THE LABEL THICKNESS (FOR THE FIRST  HORIZONTAL ',   &
      'LABEL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)PHOLD
 1182 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1900
!
 1199 CONTINUE
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE SECOND HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'X2LA')GO TO 1200
      GO TO 1299
!
 1200 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1250
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1250
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1250
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1250
      IF(IHARG(NUMARG).EQ.'THIC')GO TO 1250
      GO TO 1260
!
 1250 CONTINUE
      PHOLD=PDEFTH
      GO TO 1280
!
 1260 CONTINUE
      PHOLD=ARG(NUMARG)
      GO TO 1280
!
 1280 CONTINUE
      IFOUND='YES'
      PX2LTH=PHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1289
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1281)
 1281 FORMAT('THE LABEL THICKNESS (FOR THE SECOND HORIZONTAL ',   &
      'LABEL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1282)PHOLD
 1282 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1289 CONTINUE
      GO TO 1900
!
 1299 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE THIRD  HORIZONTAL LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'X3LA')GO TO 1300
      GO TO 1399
!
 1300 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1350
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1350
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1350
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1350
      IF(IHARG(NUMARG).EQ.'THIC')GO TO 1350
      GO TO 1360
!
 1350 CONTINUE
      PHOLD=PDEFTH
      GO TO 1380
!
 1360 CONTINUE
      PHOLD=ARG(NUMARG)
      GO TO 1380
!
 1380 CONTINUE
      IFOUND='YES'
      PX3LTH=PHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1389
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1381)
 1381 FORMAT('THE LABEL THICKNESS (FOR THE THIRD  HORIZONTAL ',   &
      'LABEL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1382)PHOLD
 1382 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1389 CONTINUE
      GO TO 1900
!
 1399 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE LEFT   VERTICAL   LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'Y1LA')GO TO 1400
      GO TO 1499
!
 1400 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1450
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1450
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1450
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1450
      IF(IHARG(NUMARG).EQ.'THIC')GO TO 1450
      GO TO 1460
!
 1450 CONTINUE
      PHOLD=PDEFTH
      GO TO 1480
!
 1460 CONTINUE
      PHOLD=ARG(NUMARG)
      GO TO 1480
!
 1480 CONTINUE
      IFOUND='YES'
      PY1LTH=PHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1489
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1481)
 1481 FORMAT('THE LABEL THICKNESS (FOR THE LEFT   VERTICAL   ',   &
      'LABEL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1482)PHOLD
 1482 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1489 CONTINUE
      GO TO 1900
!
 1499 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY THE RIGHT  VERTICAL   LABEL IS      TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'Y2LA')GO TO 1500
      GO TO 1599
!
 1500 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1550
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1550
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1550
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1550
      IF(IHARG(NUMARG).EQ.'THIC')GO TO 1550
      GO TO 1560
!
 1550 CONTINUE
      PHOLD=PDEFTH
      GO TO 1580
!
 1560 CONTINUE
      PHOLD=ARG(NUMARG)
      GO TO 1580
!
 1580 CONTINUE
      IFOUND='YES'
      PY2LTH=PHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1589
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1581)
 1581 FORMAT('THE LABEL THICKNESS (FOR THE RIGHT  VERTICAL   ',   &
      'LABEL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1582)PHOLD
 1582 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1589 CONTINUE
      GO TO 1900
!
 1599 CONTINUE
!
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  BOTH LEFT AND RIGHT VERTICAL LABELS ARE TO BE CHANGED   **
!               **************************************************************
!
      IF(ICOM.EQ.'YLAB')GO TO 1600
      GO TO 1699
!
 1600 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1650
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1650
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1650
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1650
      IF(IHARG(NUMARG).EQ.'THIC')GO TO 1650
      GO TO 1660
!
 1650 CONTINUE
      PHOLD=PDEFTH
      GO TO 1680
!
 1660 CONTINUE
      PHOLD=ARG(NUMARG)
      GO TO 1680
!
 1680 CONTINUE
      IFOUND='YES'
      PY1LTH=PHOLD
      PY2LTH=PHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1689
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1681)
 1681 FORMAT('THE LABEL THICKNESS (FOR THE LEFT AND RIGHT VERTICAL ',   &
      'LABELS)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1682)PHOLD
 1682 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1689 CONTINUE
      GO TO 1900
!
 1699 CONTINUE
!               **************************************************************
!               **  TREAT THE CASE WHEN                                     **
!               **  ONLY ALL  5 LABELS ARE                   TO BE CHANGED  **
!               **************************************************************
!
      IF(ICOM.EQ.'LABE')GO TO 1700
      IF(ICOM.EQ.'XYLA')GO TO 1700
      IF(ICOM.EQ.'YXLA')GO TO 1700
      GO TO 1799
!
 1700 CONTINUE
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1750
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1750
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1750
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1750
      IF(IHARG(NUMARG).EQ.'THIC')GO TO 1750
      GO TO 1760
!
 1750 CONTINUE
      PHOLD=PDEFTH
      GO TO 1780
!
 1760 CONTINUE
      PHOLD=ARG(NUMARG)
      GO TO 1780
!
 1780 CONTINUE
      IFOUND='YES'
      PY1LTH=PHOLD
      PY2LTH=PHOLD
      PX1LTH=PHOLD
      PX2LTH=PHOLD
      PX3LTH=PHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1789
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1781)
 1781 FORMAT('THE LABEL THICKNESS (FOR ALL 5 ',   &
      'LABELS--3 HORIZONTAL AND 2 VERTICAL)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1782)PHOLD
 1782 FORMAT('HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1789 CONTINUE
      GO TO 1900
!
 1799 CONTINUE
!
 1900 CONTINUE
      RETURN
      END SUBROUTINE DPLATH
      SUBROUTINE DPLATT(IHARG,IARGT,ARG,NUMARG,   &
                        PXSTAR,PYSTAR,PXEND,PYEND,   &
                        ILINPA,ILINCO,ILINC2,MAXLNZ,PLINTH,   &
                        AREGBA,IREBLI,IREBCO,IREBC2,MAXRGZ,PREBTH,   &
                        IREFSW,IREFCO,IREFC2,   &
                        IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                        PTEXHE,PTEXWI,PTEXVG,PTEXHG,   &
                        IGRASW,IDIASW,   &
                        PGRAXF,PGRAYF,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
                        PDIAHE,PDIAWI,PDIAVG,PDIAHG,   &
                        NUMDEV,IDMANU,IDMODE,IDMOD2,IDMOD3,   &
                        IDPOWE,IDCONT,IDCOLO,IDNVPP,IDNHPP,IDUNIT,   &
                        IDNVOF,IDNHOF,IDFONT,UNITSW,PDSCAL,   &
                        IBACCO,IBACC2,   &
                        IBUGD2,IFOUND,IERROR)
!
!     PURPOSE--DRAW ONE OR MORE LATTICES (DEPENDING ON HOW MANY NUMBERS
!              ARE PROVIDED).  THE COORDINATES ARE IN STANDARDIZED UNITS
!              OF 0 TO 100.
!     NOTE--THE INPUT COORDINATES DEFINE THE VERTICES OF THE LOWER LEFT
!           CORNER OF THE LATTICE, THE X AND Y INCREMENTS OF THE LATTICE
!           AND THE UPPER RIGHT CORNER OF THE LATTICE.
!           LATTICE X1 Y1 XINC YINC X2 Y2
!     NOTE-THE USUAL INPUT NUMBER OF COORDINATES IS 3
!          AND THEREFORE THE USUAL INPUT NUMBER OF NUMBERS IS 2*3 = 6.
!     NOTE-- THE FOLLOWING GENERALIZATIONS AND COMMENTS NEED
!            CORRECTING 05/05/1987
!     NOTE--IF 4 NUMBERS ARE PROVIDED, THEN THE DRAWN LATTICE WILL GO
!           FROM THE LAST CURSOR POSITION (ASSUMED TO BE AT VERTEX 1)
!           THROUGH THE (X,Y) POINT (EITHER ABSOLUTE OR RELATIVE) AS
!           DEFINED BY THE FIRST AND SECOND NUMBERS (ASSUMED TO BE AT
!           VERTEX 2) TO THE (X,Y) POINT (EITHER ABSOLUTE OR RELATIVE)
!           AS DEFINED BY THE THIRD AND FOURTH NUMBERS (ASSUMED TO BE AT
!           VERTEX 3) AND CONTINUING BACK THE START POINT TO CLOSE THE
!           LATTICE.
!     NOTE--IF 6 NUMBERS ARE PROVIDED, THEN THE DRAWN LATTICE WILL GO
!           FROM THE ABSOLUTE (X,Y) POSITION AS RESULTING FORM THE FIRST
!           AND SECOND NUMBERS (ASSUMED TO BE AT VERTEX 1) THROUGH THE
!           (X,Y) POINT (EITHER ABSOLUTE OR RELATIVE) AS DEFINED BY THE
!           THIRD AND FOURTH NUMBERS (ASSUMED TO BE AT VERTEX 2) TO THE
!           (X,Y) POINT (EITHER ABSOLUTE OR RELATIVE) AS DEFINED BY THE
!           FIFTH AND SIXTH NUMBERS (ASSUMED TO BE AT VERTEX 3) AND
!           THEN CONTINUING BACK THE START POINT TO CLOSE THE LATTICE.
!     NOTE--AND SO FORTH FOR 10, 14, 18, ... NUMBERS.
!     INPUT  ARGUMENTS--IHARG
!                     --IARGT
!                     --ARG
!                     --NUMARG
!                     --PXSTAR
!                     --PYSTAR
!     OUTPUT ARGUMENTS--PXEND
!                     --PYEND
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1987.
!     UPDATED         --JANUARY   1989. CALL LIST FOR OFFSET VAR (ALAN)
!     UPDATED         --MARCH     1997. SUPPORT FOR DEVICE FONT (ALAN)
!     UPDATED         --JULY      1997. SUPPORT FOR "DATA" UNITS (ALAN)
!     UPDATED         --DECEMBER  2018. CHECK FOR DISCRETE, NULL, OR
!                                       NONE DEVICE
!     UPDATED         --DECEMBER  2018. SUPPORT FOR "DEVICE ... SCALE"
!                                       COMMAND
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLORS
!
!-----NON-COMMON VARIABLES-----------------------------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
      CHARACTER*4 ILINPA
      CHARACTER*4 ILINCO
!
      CHARACTER*4 IREBLI
      CHARACTER*4 IREBCO
      CHARACTER*4 IREFSW
      CHARACTER*4 IREFCO
      CHARACTER*4 IREPTY
      CHARACTER*4 IREPLI
      CHARACTER*4 IREPCO
!
      CHARACTER*4 IGRASW
      CHARACTER*4 IDIASW
!
      CHARACTER*4 IDMANU
      CHARACTER*4 IDMODE
      CHARACTER*4 IDMOD2
      CHARACTER*4 IDMOD3
      CHARACTER*4 IDPOWE
      CHARACTER*4 IDCONT
      CHARACTER*4 IDCOLO
!CCCC ADD FOLLOWING LINE MARCH 1997.
      CHARACTER*4 IDFONT
!CCCC ADD FOLLOWING LINE JULY 1997.
      CHARACTER*4 UNITSW
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IBUGD2
      CHARACTER*4 IERROR
      CHARACTER*4 ISUBRO
!
      CHARACTER*4 IFIG
      CHARACTER*4 IBELSW
      CHARACTER*4 IERASW
      CHARACTER*4 IBACCO
      CHARACTER*4 ICOPSW
      CHARACTER*4 ITYPEO
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
!
      DIMENSION ILINPA(*)
      DIMENSION ILINCO(*)
      DIMENSION ILINC2(MAXLNZ,3)
      DIMENSION PLINTH(*)
!
      DIMENSION AREGBA(*)
      DIMENSION IREBLI(*)
      DIMENSION IREBCO(*)
      DIMENSION IREBC2(MAXRGZ,3)
      DIMENSION PREBTH(*)
      DIMENSION IREFSW(*)
      DIMENSION IREFCO(*)
      DIMENSION IREFC2(MAXRGZ,3)
      DIMENSION IREPTY(*)
      DIMENSION IREPLI(*)
      DIMENSION IREPCO(*)
      DIMENSION IREPC2(MAXRGZ,3)
      DIMENSION PREPTH(*)
      DIMENSION PREPSP(*)
      DIMENSION PDSCAL(*)
!
      DIMENSION IDMANU(*)
      DIMENSION IDMODE(*)
      DIMENSION IDMOD2(*)
      DIMENSION IDMOD3(*)
      DIMENSION IDPOWE(*)
      DIMENSION IDCONT(*)
      DIMENSION IDCOLO(*)
!CCCC ADD FOLLOWING LINE MARCH 1997.
      DIMENSION IDFONT(*)
      DIMENSION IDNVPP(*)
      DIMENSION IDNHPP(*)
      DIMENSION IDUNIT(*)
!
      DIMENSION IDNVOF(*)
      DIMENSION IDNHOF(*)
      DIMENSION IBACC2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      IERRG4=IERROR
!CCCC IBUGG4=IBUGD2
!CCCC ISUBG4=ISUBRO
!
      ILOCFN=0
      NUMNUM=0
!
      X1=0.0
      Y1=0.0
      X2=0.0
      Y2=0.0
!
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'LATT')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPLATT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)NUMARG
   53 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NUMARG
      WRITE(ICOUT,56)I,IHARG(I),IARGT(I),ARG(I)
   56 FORMAT('I,IHARG(I),IARGT(I),ARG(I) = ',I8,2X,A4,2X,A4,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
      WRITE(ICOUT,57)PXSTAR,PYSTAR
   57 FORMAT('PXSTAR,PYSTAR = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,58)PXEND,PYEND
   58 FORMAT('PXEND,PYEND = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,61)ILINPA(1),ILINCO(1),PLINTH(1)
   61 FORMAT('ILINPA(1),ILINCO(1),PLINTH(1) = ',A4,2X,A4,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)AREGBA(1)
   62 FORMAT('AREGBA(1) = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,63)IREBLI(1),IREBCO(1),PREBTH(1)
   63 FORMAT('IREBLI(1),IREBCO(1),PREBTH(1) = ',A4,2X,A4,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,64)IREFSW(1),IREFCO(1)
   64 FORMAT('IREFSW(1),IREFCO(1) = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,65)IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1)
   65 FORMAT('IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1) = ',   &
      A4,2X,A4,2X,A4,2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,69)PTEXHE,PTEXWI
   69 FORMAT('PTEXHE,PTEXWI= ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,70)PTEXVG,PTEXHG
   70 FORMAT('PTEXVG,PTEXHG= ',2E15.6)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,76)IGRASW,IDIASW
   76 FORMAT('IGRASW,IDIASW = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,77)PGRAXF,PGRAYF,PDIAXC,PDIAYC
   77 FORMAT('PGRAXF,PGRAYF,PDIAXC,PDIAYC = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,78)PDIAHE,PDIAWI,PDIAVG,PDIAHG
   78 FORMAT('PDIAHE,PDIAWI,PDIAVG,PDIAHG = ',4E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,80)NUMDEV
   80 FORMAT('NUMDEV= ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 81 I=1,NUMDEV
      WRITE(ICOUT,82)IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I)
   82 FORMAT('IDMANU(I),IDMODE(I),IDMOD2(I),IDMOD3(I) = ',   &
      A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,83)IDPOWE(I),IDCONT(I),IDCOLO(I)
   83 FORMAT('IDPOWE(I),IDCONT(I),IDCOLO(I) = ',   &
      A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,84)IDNVPP(I),IDNHPP(I),IDUNIT(I)
   84 FORMAT('IDNVPP(I),IDNHPP(I),IDUNIT(I) = ',   &
      I8,I8,I8)
      CALL DPWRST('XXX','BUG ')
   81 CONTINUE
      WRITE(ICOUT,87)IFOUND
   87 FORMAT('IFOUND= ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,88)IBUGG4,ISUBG4,IERRG4
   88 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,89)IBUGD2,IERROR
   89 FORMAT('IBUGD2,IERROR= ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
      IFIG='LATT'
      NUMPT=3
      NUMPT2=2*NUMPT
!
!               ********************************
!               **  STEP 0--                  **
!               **  STEP THROUGH EACH DEVICE  **
!               ********************************
!
      IF(NUMDEV.LE.0)GO TO 9000
      DO 8000 IDEVIC=1,NUMDEV
!
      IF(IDPOWE(IDEVIC).EQ.'OFF')GO TO 8000
!
      IMANUF=IDMANU(IDEVIC)
      IMODEL=IDMODE(IDEVIC)
      IMODE2=IDMOD2(IDEVIC)
      IMODE3=IDMOD3(IDEVIC)
      IGCONT=IDCONT(IDEVIC)
      IGCOLO=IDCOLO(IDEVIC)
      IGFONT=IDFONT(IDEVIC)
      NUMVPP=IDNVPP(IDEVIC)
      NUMHPP=IDNHPP(IDEVIC)
      ANUMVP=NUMVPP
      ANUMHP=NUMHPP
      IOFFSV=IDNVOF(IDEVIC)
      IOFFSH=IDNHOF(IDEVIC)
      IGUNIT=IDUNIT(IDEVIC)
      PCHSCA=PDSCAL(IDEVIC)
!
!               ************************************
!               **  STEP 1--                      **
!               **  CARRY OUT OPENING OPERATIONS  **
!               **  ON THE GRAPHICS DEVICES       **
!               ************************************
!
      CALL DPOPDE
!
      IBELSW='OFF'
      NUMRIN=0
      IERASW='OFF'
      IBACCO='JUNK'
!
      CALL DPOPPL(IGRASW,IBELSW,NUMRIN,IERASW,IBACCO,IBACC2)
!
!               *****************************************
!               **  STEP 2--                           **
!               **  SEARCH FOR COMMAND SPECIFICATIONS  **
!               *****************************************
!
      IF(NUMARG.GE.2.AND.   &
      IARGT(1).EQ.'NUMB'.AND.IARGT(2).EQ.'NUMB')   &
      GO TO 1111
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'ABSO'.AND.   &
      IARGT(2).EQ.'NUMB'.AND.IARGT(3).EQ.'NUMB')   &
      GO TO 1112
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'RELA'.AND.   &
      IARGT(2).EQ.'NUMB'.AND.IARGT(3).EQ.'NUMB')   &
      GO TO 1113
      GO TO 1130
!
 1111 CONTINUE
      ITYPEO='ABSO'
      ILOCFN=1
      GO TO 1119
!
 1112 CONTINUE
      ITYPEO='ABSO'
      ILOCFN=2
      GO TO 1119
!
 1113 CONTINUE
      ITYPEO='RELA'
      ILOCFN=2
      GO TO 1119
 1119 CONTINUE
!
      IF(ILOCFN.GT.NUMARG)GO TO 1129
      DO 1120 I=ILOCFN,NUMARG
      IF(IARGT(I).EQ.'NUMB')GO TO 1120
      GO TO 1129
 1120 CONTINUE
      IFOUND='YES'
      GO TO 1149
 1129 CONTINUE
      GO TO 1130
!
 1130 CONTINUE
      IERRG4='YES'
      WRITE(ICOUT,1131)
 1131 FORMAT('***** ERROR IN DPLATT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1132)
 1132 FORMAT('      ILLEGAL FORM FOR DRAW ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1134)
 1134 FORMAT('      TEST EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1135)
 1135 FORMAT('      SUPPOSE IT IS DESIRED TO DRAW A LATTICE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1136)
 1136 FORMAT('      WITH VERTICES (20,20), (50,20), (35,40)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('      THEN ALLOWABLE FORMS ARE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      LATTICE 20 20 50 20 35 40')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      LATTICE ABSOLUTE 20 20 50 20 35 40')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
 1149 CONTINUE
!
!               ****************************
!               **  STEP 3--              **
!               **  DRAW OUT THE LINE(S)  **
!               ****************************
!
      NUMNUM=NUMARG-ILOCFN+1
      IF(NUMNUM.LT.NUMPT2)GO TO 1151
      GO TO 1152
!
 1151 CONTINUE
      J=ILOCFN-1
      X1=PXSTAR
      Y1=PYSTAR
      GO TO 1159
!
 1152 CONTINUE
      J=ILOCFN
      IF(J.GT.NUMARG)GO TO 1190
      X1=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('X',X1,X1,IBUGD2,ISUBRO,IERROR)
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      Y1=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('Y',Y1,Y1,IBUGD2,ISUBRO,IERROR)
      GO TO 1159
 1159 CONTINUE
!
 1160 CONTINUE
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      X2=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('X',X2,X2,IBUGD2,ISUBRO,IERROR)
      IF(ITYPEO.EQ.'RELA')X2=X1+X2
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      Y2=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('Y',Y2,Y2,IBUGD2,ISUBRO,IERROR)
      IF(ITYPEO.EQ.'RELA')Y2=Y1+Y2
!
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      X3=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('X',X3,X3,IBUGD2,ISUBRO,IERROR)
      IF(ITYPEO.EQ.'RELA')X3=X2+X3
      J=J+1
      IF(J.GT.NUMARG)GO TO 1190
      Y3=ARG(J)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1997
      IF(UNITSW.EQ.'DATA')CALL DPCODS('Y',Y3,Y3,IBUGD2,ISUBRO,IERROR)
      IF(ITYPEO.EQ.'RELA')Y3=Y2+Y3
!
      CALL DPLAT2(X1,Y1,X2,Y2,X3,Y3,   &
                  IFIG,   &
                  ILINPA,ILINCO,ILINC2,MAXLNZ,PLINTH,   &
                  AREGBA,IREBLI,IREBCO,IREBC2,MAXRGZ,PREBTH,   &
                  IREFSW,IREFCO,IREFC2,   &
                  IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                  PTEXHE,PTEXWI,PTEXVG,PTEXHG)
!
      X1=X3
      Y1=Y3
!
      GO TO 1160
 1190 CONTINUE
!
      PXEND=X3
      PYEND=Y3
!
!               ************************************
!               **  STEP 4--                      **
!               **  CARRY OUT CLOSING OPERATIONS  **
!               **  ON THE GRAPHICS DEVICES       **
!               ************************************
!
      ICOPSW='OFF'
      NUMCOP=0
      CALL DPCLPL(ICOPSW,NUMCOP,   &
      PGRAXF,PGRAYF,   &
      IGRASW,PDIAXC,PDIAYC,PDIAX2,PDIAY2,   &
      PDIAHE,PDIAWI,PDIAVG,PDIAHG)
!
      CALL DPCLDE
!
 8000 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG4.EQ.'OFF'.AND.ISUBG4.NE.'LATT')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPLATT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)ILOCFN,NUMNUM
 9012 FORMAT('ILOCFN,NUMNUM = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)X1,Y1,X2,Y2,X3,Y3
 9013 FORMAT('X1,Y1,X2,Y2,X3,Y3 = ',6E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)PXSTAR,PYSTAR
 9015 FORMAT('PXSTAR,PYSTAR = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9016)PXEND,PYEND
 9016 FORMAT('PXEND,PYEND = ',2E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)IFIG
 9017 FORMAT('IFIG = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9027)IFOUND
 9027 FORMAT('IFOUND = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9028)IBUGG4,ISUBG4,IERRG4
 9028 FORMAT('IBUGG4,ISUBG4,IERRG4 = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9029)IBUGD2,IERROR
 9029 FORMAT('IBUGD2,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPLATT
      SUBROUTINE DPLATV(IHEAD,NHEAD,AVAL,NUMDIG)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS USED TO WRITE A
!              A SINGLE LINE OF OUTPUT.
!     INPUT  ARGUMENTS--IHEAD  = THE CHARACTER STRING CONTAINING
!                                THE TEXT FOR THE LINE
!                     --NHEAD  = THE INTEGER NUMBER THAT SPECIFIES
!                                THE NUMBER OF CHARACTERS IN THE
!                                LINE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/4
!     ORIGINAL VERSION--APRIL     2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*(*) IHEAD
!
      CHARACTER*1  IBASLC
      CHARACTER*25 IFORMT
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 1: END ASIS MODE AND WRITE A HEADER
!
!C999 FORMAT(1X)
      CALL DPCONA(92,IBASLC)
!
!  STEP 2: START TABLE AND DEFINE A CAPTION
!
 8005 FORMAT('{',A1,'bf ')
 8006 FORMAT(' }',2X,A1,A1)
!
      IF(NHEAD.GE.1)THEN
        IFORMT=' '
        IF(AVAL.NE.CPUMIN)THEN
          IXX=NUMDIG
          IYY=IXX+8
          IFORMT(1:24)='(A  ,2X,Gyy.xx,2X,A1,A1)'
          WRITE(IFORMT(3:4),'(I2)')NHEAD
          WRITE(IFORMT(10:11),'(I2)')IYY
          WRITE(IFORMT(13:14),'(I2)')IXX
          WRITE(ICOUT,8005)IBASLC
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,IFORMT)IHEAD(1:NHEAD),AVAL
          CALL DPWRST('XXX','WRIT')
        ELSE
          IFORMT(1:14)='(A  ,2X,A1,A1)'
          WRITE(IFORMT(3:4),'(I2)')NHEAD
          WRITE(ICOUT,8005)IBASLC
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,IFORMT)IHEAD(1:NHEAD)
          CALL DPWRST('XXX','WRIT')
        ENDIF
        WRITE(ICOUT,8006)IBASLC,IBASLC
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLATV
      SUBROUTINE DPLATW(IVALUE,NCHAR,AVALUE,NHEAD,ITYPE,IFLAGA,IFLAGB)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS USED TO GENERATE
!              A DATA ROW FOR A TABLE WHERE THE FIELDS CAN BE A
!              MIX OF CHARACTER AND NUMERIC VALUES.
!
!     INPUT  ARGUMENTS--IVALUE  = AN ARRAY OF CHARACTER STRINGS.
!                     --NCHAR   = THE INTEGER ARRAY THAT SPECIFIES
!                                 THE NUMBER OF CHARACTERS IN THE
!                                 CHARACTER FIELDS.
!                     --AVALUE  = A REAL ARRAY CONTAINING THE DATA
!                                 TO BE GENERATED.
!                     --NHEAD   = THE INTEGER VALUE THAT SPECIFIES
!                                 THE NUMBER OF NUMERIC VALUES.
!                     --ITYPE   = A CHARACTER ARRAY THAT SPECIFIES
!                                 WHICH FIELDS ARE NUMERIC AND
!                                 WHICH ARE CHARACTER.
!                     --IFLAGA  = GENERATE A SEPARATOR LINE AFTER THE
!                                 CURRENT LINE.
!                     --IFLAGB  = GENERATE A SEPARATOR LINE BEFORE THE
!                                 CURRENT LINE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/10
!     ORIGINAL VERSION--OCTOBER   2009.
!     UPDATED         --AUGUST    2015. EXPONENTIAL CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*(*) IVALUE(*)
      CHARACTER*4   ITYPE(*)
      REAL AVALUE(*)
      INTEGER NCHAR(*)
!
      LOGICAL IFLAGA
      LOGICAL IFLAGB
!
      PARAMETER (MAXHED=1024)
      INTEGER IWIDTH(MAXHED)
      INTEGER NUMDIG(MAXHED)
      CHARACTER*8 ALIGN(MAXHED)
      CHARACTER*8 VALIGN(MAXHED)
      COMMON/HTML4/IWIDTH,NUMDIG,ALIGN,VALIGN
!
      CHARACTER*20 IFORMT
      CHARACTER*1  IBASLC
      CHARACTER*1  IAMP
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!  STEP 3: DEFINE A DATA ROW
!
      CALL DPCONA(92,IBASLC)
      IAMP='&'
!
      IF(IFLAGB)THEN
        WRITE(ICOUT,8040)IBASLC
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
 8031 FORMAT(G15.7,' & ')
 8033 FORMAT(I12,' & ')
 8035 FORMAT(' & ')
 8131 FORMAT(G15.7,2X,A1,A1)
 8231 FORMAT(2X,A1,A1)
 8133 FORMAT(I12,2X,A1,A1)
 8135 FORMAT(' ',2X,A1,A1)
 8235 FORMAT(' &  ')
 8040 FORMAT(A1,'hline')
      IF(NHEAD.GE.1)THEN
        ICNT=0
        DO 100 I=1,NHEAD
          IF(ITYPE(I).EQ.'ALPH')THEN
            ICNT=ICNT+1
            IF(NCHAR(ICNT).GT.0)THEN
              IFORMT=' '
              IF(I.LT.NHEAD)THEN
                IFORMT(1:11)='(A  ,1X,A1)'
                WRITE(IFORMT(3:4),'(I2)')NCHAR(ICNT)
                WRITE(ICOUT,IFORMT)IVALUE(ICNT)(1:NCHAR(ICNT)),   &
                                   IAMP
                CALL DPWRST('XXX','WRIT')
              ELSE
                IFORMT(1:14)='(A  ,1X,A1,A1)'
                WRITE(IFORMT(3:4),'(I2)')NCHAR(ICNT)
                WRITE(ICOUT,IFORMT)IVALUE(ICNT)(1:NCHAR(ICNT)),   &
                                   IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ENDIF
            ELSE
              WRITE(ICOUT,8035)
              CALL DPWRST('XXX','WRIT')
            ENDIF
          ELSE
            ICNT=ICNT+1
            IFORMT=' '
            IF(I.LT.NHEAD)THEN
              IF(NUMDIG(I).GT.0)THEN
                IFORMT(1:13)='(F15. ,1X,A1)'
                WRITE(IFORMT(6:6),'(I1)')MIN(NUMDIG(I),9)
                WRITE(ICOUT,IFORMT)AVALUE(ICNT),IAMP
                CALL DPWRST('XXX','WRIT')
              ELSEIF(NUMDIG(I).EQ.0)THEN
                WRITE(ICOUT,8033)INT(AVALUE(ICNT)+0.5)
                CALL DPWRST('XXX','WRIT')
              ELSEIF(NUMDIG(I).EQ.-1)THEN
                WRITE(ICOUT,8035)
                CALL DPWRST('XXX','WRIT')
              ELSEIF(NUMDIG(I).EQ.-2)THEN
                WRITE(ICOUT,8031)AVALUE(ICNT)
                CALL DPWRST('XXX','WRIT')
              ELSEIF(NUMDIG(I).LT.-2 .AND. NUMDIG(I).GT.-20)THEN
                IFORMT(1:13)='(E15. ,1X,A1)'
                IVALT=ABS(NUMDIG(I))
                IF(IVALT.GT.9)IVALT=9
                WRITE(IFORMT(6:6),'(I1)')IVALT
                WRITE(ICOUT,IFORMT)AVALUE(ICNT),IAMP
                CALL DPWRST('XXX','WRIT')
              ELSEIF(NUMDIG(I).EQ.-99)THEN
                WRITE(ICOUT,'(A2,2X,A1)')'**',IAMP
                CALL DPWRST('XXX','WRIT')
              ELSE
                WRITE(ICOUT,8235)
                CALL DPWRST('XXX','WRIT')
              ENDIF
            ELSE
              IF(NUMDIG(I).GT.0)THEN
                IFORMT(1:16)='(F15. ,2X,A1,A1)'
                WRITE(IFORMT(6:6),'(I1)')MIN(NUMDIG(I),9)
                WRITE(ICOUT,IFORMT)AVALUE(ICNT),IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ELSEIF(NUMDIG(I).EQ.0)THEN
                WRITE(ICOUT,8133)INT(AVALUE(ICNT)+0.5),IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ELSEIF(NUMDIG(I).EQ.-1)THEN
                WRITE(ICOUT,8135)IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ELSEIF(NUMDIG(I).EQ.-2)THEN
                WRITE(ICOUT,8131)AVALUE(ICNT),IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ELSEIF(NUMDIG(I).LT.-2 .AND. NUMDIG(I).GT.-20)THEN
                IFORMT(1:16)='(E15. ,1X,A1,A1)'
                IVALT=ABS(NUMDIG(I))
                IF(IVALT.GT.9)IVALT=9
                WRITE(IFORMT(6:6),'(I1)')IVALT
                WRITE(ICOUT,IFORMT)AVALUE(ICNT),IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ELSEIF(NUMDIG(I).EQ.-99)THEN
                WRITE(ICOUT,'(A2,2X,A1,A1)')'**',IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ELSE
                WRITE(ICOUT,8231)IBASLC,IBASLC
                CALL DPWRST('XXX','WRIT')
              ENDIF
            END IF
          END IF
  100   CONTINUE
!
        IF(IFLAGA)THEN
          WRITE(ICOUT,8040)IBASLC
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
      ENDIF
!
      RETURN
      END SUBROUTINE DPLATW
