      SUBROUTINE DPLATY(NHEAD)
!
!     PURPOSE--THIS ROUTINE IS A UTILUTY ROUTINE FOR CREATING
!              LATEX OUTPUT.  THIS ROUTINE IS ESSENTIALLY
!              DPLAT4.  HOWEVER, WE DO NOT ACTUALLY PRINT
!              A ROW.  THIS IS USED WHEN WE BREAK A TABLE
!              OVER MULTIPLE PAGES AND WE SIMPLY WANT TO
!              RE-ESTABLISH THE PROPER NUMBER OF COLUMS
!              (I.E., WE ARE NOT RE-PRINTING THE TABLE HEADER).
!
!     INPUT  ARGUMENTS--NHEAD   = THE INTEGER VALUE THAT SPECIFIES
!                                 THE NUMBER OF HEADER VALUES.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/10
!     ORIGINAL VERSION--OCTOBER   2008.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      PARAMETER (MAXHED=1024)
      INTEGER IWIDTH(MAXHED)
      INTEGER NUMDIG(MAXHED)
      CHARACTER*8 ALIGN(MAXHED)
      CHARACTER*8 VALIGN(MAXHED)
      COMMON/HTML4/IWIDTH,NUMDIG,ALIGN,VALIGN
!
      CHARACTER*1  IBASLC
      CHARACTER*1  IAMP
      CHARACTER*1  IQUOTE
      CHARACTER*20 IFORMT
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!C999 FORMAT(1X)
      CALL DPCONA(92,IBASLC)
      CALL DPCONA(39,IQUOTE)
      IAMP='&'
!
!  STEP 2: GENERATE THE HEADER ROW
!
 8020 FORMAT(A1,'begin{table}')
 8021 FORMAT(A1,'begin{center}')
 8022 FORMAT(A1,'begin{tabular}')
      IF(NHEAD.GE.1)THEN
        WRITE(ICOUT,8020)IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8021)IBASLC
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8022)IBASLC
        CALL DPWRST('XXX','WRIT')
        IFORMT=' '
        IFORMT(1:3)='( {'
        IFORMT(2:2)=IQUOTE
        ICNT=3
        DO 8110 I=1,NHEAD
          ICNT=ICNT+1
          IFORMT(ICNT:ICNT)=ALIGN(I)(1:1)
 8110   CONTINUE
        IFORMT(ICNT+1:ICNT+3)='} )'
        IFORMT(ICNT+2:ICNT+2)=IQUOTE
        WRITE(ICOUT,IFORMT)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLATY
      SUBROUTINE DPLAT2(X1,Y1,X2,Y2,X3,Y3,   &
                        IFIG,   &
                        ILINPA,ILINCO,ILINC2,MAXLN,PLINTH,   &
                        AREGBA,   &
                        IREBLI,IREBCO,IREBC2,MAXRG,PREBTH,   &
                        IREFSW,IREFCO,IREFC2,   &
                        IREPTY,IREPLI,IREPCO,IREPC2,PREPTH,PREPSP,   &
                        PTEXHE,PTEXWI,PTEXVG,PTEXHG)
!
!     PURPOSE--DRAW A LATTICE
!              WITH ONE CORNER AT (X1,Y1),
!              WITH GRID LINES SPACED AT DISTANCES OF X2 AND Y2,
!              AND WITH THE OPPOSING CORNER AT (X3,Y3).
!      NOTE--IF THE SPACING IS SET TO 0, THEN NO INTERMEDIATE
!            GRID LINES WILL RESULT.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/6
!     ORIGINAL VERSION--MAY       1987.
!     UPDATED         --JANUARY   1989. MODIFY CALLS TO DPDRPL (ALAN)
!     UPDATED         --JANUARY   1989. MODIFY CALL  TO DPFIRE (ALAN)
!     UPDATED         --OCTOBER   2020. SUPPORT RGB COLORS
!
!-----NON-COMMON VARIABLES-------------------------------------
!
      CHARACTER*4 IFIG
      CHARACTER*4 IPATT2
!
      CHARACTER*4 ILINPA
      CHARACTER*4 ILINCO
!
      CHARACTER*4 IREBLI
      CHARACTER*4 IREBCO
      CHARACTER*4 IREFSW
      CHARACTER*4 IREFCO
      CHARACTER*4 IREPTY
      CHARACTER*4 IREPLI
      CHARACTER*4 IREPCO
!
      CHARACTER*4 IPATT
      CHARACTER*4 ICOLF
      CHARACTER*4 ICOLP
      CHARACTER*4 ICOL
      CHARACTER*4 IFLAG
!
      DIMENSION PX(10)
      DIMENSION PY(10)
!CCCC DIMENSION PX3(10)
!CCCC DIMENSION PY3(10)
!
      DIMENSION ILINPA(*)
      DIMENSION ILINCO(*)
      DIMENSION ILINC2(MAXLN,3)
      DIMENSION PLINTH(*)
!
      DIMENSION AREGBA(*)
      DIMENSION IREBLI(*)
      DIMENSION IREBCO(*)
      DIMENSION IREBC2(MAXRG,3)
      DIMENSION PREBTH(*)
      DIMENSION IREFSW(*)
      DIMENSION IREFCO(*)
      DIMENSION IREFC2(MAXRG,3)
      DIMENSION IREPTY(*)
      DIMENSION IREPLI(*)
      DIMENSION IREPCO(*)
      DIMENSION IREPC2(MAXRG,3)
      DIMENSION PREPTH(*)
      DIMENSION PREPSP(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOGR.INC'
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
      PX31=(-999)
      PY31=(-999)
      PXINC=(-999)
      PYINC=(-999)
      PXCUT=(-999)
      PYCUT=(-999)
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'TRI2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLAT2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)X1,Y1,X2,Y2,X3,Y3
   53   FORMAT('X1,Y1,X2,Y2,X3,Y3 = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)ILINPA(1),ILINCO(1),PLINTH(1)
   61   FORMAT('ILINPA(1),ILINCO(1),PLINTH(1) = ',A4,2X,A4,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)IREBLI(1),IREBCO(1),PREBTH(1),AREGBA(1)
   63   FORMAT('IREBLI(1),IREBCO(1),PREBTH(1),AREGBA(1) = ',   &
               3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,64)IREFSW(1),IREFCO(1)
   64   FORMAT('IREFSW(1),IREFCO(1) = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,65)IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1)
   65   FORMAT('IREPTY(1),IREPLI(1),IREPCO(1),PREPTH(1),PREPSP(1) = ',   &
               3(A4,2X),2G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,69)PTEXHE,PTEXWI,PTEXVG,PTEXHG
   69   FORMAT('PTEXHE,PTEXWI,PTEXVG,PTEXHG = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,79)IFIG,IBUGG4,ISUBG4,IERRG4
   79   FORMAT('IFIG,IBUGG4,ISUBG4,IERRG4 = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 11--                  **
!               **  DETERMINE THE COORDINATES  **
!               **  AND                        **
!               **  FILL THE FIGURE            **
!               **  (IF CALLED FOR)            **
!               *********************************
!
      IF(IREFSW(1).EQ.'OFF')GO TO 1190
!
      PX(1)=X1
      PY(1)=Y1
!
      PX(2)=X3
      PY(2)=Y1
!
      PX(3)=X3
      PY(3)=Y3
!
      PX(4)=X1
      PY(4)=Y3
!
      PX(5)=X1
      PY(5)=Y1
!
      NP=5
!
      IPATT=IREPTY(1)
      IPATT2='SOLI'
      PTHICK=PREPTH(1)
      PXGAP=PREPSP(1)
      PYGAP=PREPSP(1)
      ICOLF=IREFCO(1)
      ICOLFR=IREFC2(1,1)
      ICOLFG=IREFC2(1,2)
      ICOLFB=IREFC2(1,3)
      ICOLP=IREPCO(1)
      ICOLPR=IREPC2(1,1)
      ICOLPG=IREPC2(1,2)
      ICOLPB=IREPC2(1,3)
      ICOLBR=IREBC2(1,1)
      ICOLBG=IREBC2(1,2)
      ICOLBB=IREBC2(1,3)
      IFIG='BOX'
      CALL DPFIRE(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,PXGAP,PYGAP,   &
                  ICOLF,ICOLFR,ICOLFG,ICOLFB,   &
                  ICOLP,ICOLPR,ICOLPG,ICOLPB,   &
                  IPATT2)
      IFIG='LATT'
!
 1190 CONTINUE
!
!               *********************************
!               **  STEP 20--                  **
!               **  DETERMINE THE COORDINATES  **
!               **  FOR THE LATTICE            **
!               **  AND                        **
!               **  DRAW OUT THE FIGURE        **
!               *********************************
!
      IPATT=ILINPA(1)
      PTHICK=PLINTH(1)
      ICOL=ILINCO(1)
      ICOLR=ILINC2(1,1)
      ICOLG=ILINC2(1,2)
      ICOLB=ILINC2(1,3)
      NP=2
!
!               ***********************************
!               **  STEP 21--                    **
!               **  DRAW OUT THE VERTICAL LINES  **
!               ***********************************
!
      IF(X2.EQ.0.0)GO TO 2100
      GO TO 2200
!
 2100 CONTINUE
      PX(1)=X1
      PY(1)=Y1
      PX(2)=X1
      PY(2)=Y3
      IFLAG='ON'
      CALL DPDRPL(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB,   &
                  JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
      PX(1)=X3
      PY(1)=Y1
      PX(2)=X3
      PY(2)=Y3
      CALL DPDRPL(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB,   &
                  JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
      GO TO 2900
!
 2200 CONTINUE
      PX31=X3-X1
      PXINC=X2
      IF(PX31.GT.0.0.AND.X2.LT.0.0)PXINC=(-X2)
      IF(PX31.LT.0.0.AND.X2.GT.0.0)PXINC=(-X2)
      IF(PX31.GT.0.0)PXCUT=X3+0.001
      IF(PX31.LT.0.0)PXCUT=X3-0.001
      NLOOP=INT(ABS(PX31/PXINC)+0.1)
      NLOOP=NLOOP+5
      DO 2210 I=1,NLOOP
        IM1=I-1
        AIM1=IM1
        PXNEW=X1+AIM1*PXINC
        PX(1)=PXNEW
        PY(1)=Y1
        PX(2)=PXNEW
        PY(2)=Y3
        IF(PX31.GT.0.0.AND.PXNEW.GT.PXCUT)GO TO 2290
        IF(PX31.LT.0.0.AND.PXNEW.LT.PXCUT)GO TO 2290
        IFLAG='ON'
        CALL DPDRPL(PX,PY,NP,   &
                    IFIG,IPATT,PTHICK,   &
                    ICOL,ICOLR,ICOLG,ICOLB,   &
                    JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
 2210 CONTINUE
 2290 CONTINUE
!
 2900 CONTINUE
!
!               *************************************
!               **  STEP 31--                      **
!               **  DRAW OUT THE HORIZONTAL LINES  **
!               *************************************
!
      IF(Y2.EQ.0.0)GO TO 3100
      GO TO 3200
!
 3100 CONTINUE
      PX(1)=X1
      PY(1)=Y1
      PX(2)=X3
      PY(2)=Y1
      IFLAG='ON'
      CALL DPDRPL(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB,   &
                  JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
      PX(1)=X1
      PY(1)=Y3
      PX(2)=X3
      PY(2)=Y3
      CALL DPDRPL(PX,PY,NP,   &
                  IFIG,IPATT,PTHICK,   &
                  ICOL,ICOLR,ICOLG,ICOLB,   &
                  JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
      GO TO 3900
!
 3200 CONTINUE
      PY31=Y3-Y1
      PYINC=Y2
      IF(PY31.GT.0.0.AND.Y2.LT.0.0)PYINC=(-Y2)
      IF(PY31.LT.0.0.AND.Y2.GT.0.0)PYINC=(-Y2)
      IF(PY31.GT.0.0)PYCUT=Y3+0.001
      IF(PY31.LT.0.0)PYCUT=Y3-0.001
      NLOOP=INT(ABS(PY31/PYINC)+0.1)
      NLOOP=NLOOP+5
      DO 3210 I=1,NLOOP
        IM1=I-1
        AIM1=IM1
        PYNEW=Y1+AIM1*PYINC
        PX(1)=X1
        PY(1)=PYNEW
        PX(2)=X3
        PY(2)=PYNEW
        IF(PY31.GT.0.0.AND.PYNEW.GT.PYCUT)GO TO 3290
        IF(PY31.LT.0.0.AND.PYNEW.LT.PYCUT)GO TO 3290
        IFLAG='ON'
        CALL DPDRPL(PX,PY,NP,   &
                    IFIG,IPATT,PTHICK,   &
                    ICOL,ICOLR,ICOLG,ICOLB,   &
                    JPATT,JTHICK,PTHIC2,JCOL,IFLAG)
 3210 CONTINUE
 3290 CONTINUE
!
 3900 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG4.EQ.'ON' .OR. ISUBG4.EQ.'LAT2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLAT2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERRG4,NP
 9013   FORMAT('IERRG4,NP = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        DO 9015 I=1,NP
          WRITE(ICOUT,9016)I,PX(I),PY(I)
 9016     FORMAT('I,PX(I),PY(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
        WRITE(ICOUT,9018)PX31,PY31,PXINC,PYINC
 9018   FORMAT('PX31,PY31,PXINC,PYINC = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLAT2
      SUBROUTINE DPLEAN(IHARG,IARGT,IARG,ARG,NUMARG,PDEFAN,   &
      MAXLEG,PLEGAN,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE ANGLE FOR A LEGEND.
!              THE ANGLE FOR LEGEND I WILL BE PLACED
!              IN THE I-TH ELEMENT OF THE REAL
!              VECTOR PLEGAN(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A HOLLERITH VECTOR)
!                     --IARG   (A HOLLERITH VECTOR)
!                     --ARG    (A REAL VECTOR)
!                     --NUMARG
!                     --PDEFAN
!                     --MAXLEG
!     OUTPUT ARGUMENTS--PLEGAN (A REAL VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              ANGLE FOR LEGEND I.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/2
!     ORIGINAL VERSION--JANUARY   1989.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
!
      DIMENSION PLEGAN(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)GO TO 1199
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'ANGL')GO TO 1110
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'ANGL')GO TO 1140
      GO TO 1199
!
 1110 CONTINUE
      IF(NUMARG.LE.1)GO TO 1120
      IF(IHARG(2).EQ.'ON')GO TO 1120
      IF(IHARG(2).EQ.'OFF')GO TO 1120
      IF(IHARG(2).EQ.'AUTO')GO TO 1120
      IF(IHARG(2).EQ.'DEFA')GO TO 1120
      GO TO 1125
!
 1120 CONTINUE
      PHOLD=PDEFAN
      GO TO 1130
!
 1125 CONTINUE
      PHOLD=ARG(2)
      GO TO 1130
!
 1130 CONTINUE
      IFOUND='YES'
      DO 1135 I=1,MAXLEG
      PLEGAN(I)=PHOLD
 1135 CONTINUE
!
      IF(IFEEDB.EQ.'OFF')GO TO 1139
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1136)PLEGAN(I)
 1136 FORMAT('ALL LEGEND ANGLES HAVE JUST BEEN SET TO ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
 1139 CONTINUE
      GO TO 1199
!
 1140 CONTINUE
      IF(IARGT(1).EQ.'NUMB')GO TO 1150
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('***** ERROR IN DPLEAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      IN THE LEGEND ... ANGLE COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      THE LEGEND IS IDENTIFIED BY A NUMBER, AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1144)
 1144 FORMAT('      LEGEND 3 ANGLE 45 ')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1150 CONTINUE
      I=IARG(1)
      IF(1.LE.I.AND.I.LE.MAXLEG)GO TO 1160
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN DPLEAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      IN THE LEGEND ... ANGLE COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      THE NUMBER OF LEGENDS MUST BE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)MAXLEG
 1154 FORMAT('      BETWEEN 1 AND ',I8,' (INCLUSIVELY);')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      SUCH WAS NOT THE CASE HERE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)I
 1156 FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH ',   &
      'LEGEND.')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1160 CONTINUE
      IF(NUMARG.LE.2)GO TO 1170
      IF(IHARG(3).EQ.'ON')GO TO 1170
      IF(IHARG(3).EQ.'OFF')GO TO 1170
      IF(IHARG(3).EQ.'AUTO')GO TO 1170
      IF(IHARG(3).EQ.'DEFA')GO TO 1170
      GO TO 1175
!
 1170 CONTINUE
      PHOLD=PDEFAN
      GO TO 1180
!
 1175 CONTINUE
      PHOLD=ARG(3)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      PLEGAN(I)=PHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1186)I,PLEGAN(I)
 1186 FORMAT('THE ANGLE FOR LEGEND ',I8,   &
      ' HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPLEAN
      SUBROUTINE DPLECA(IHARG,IARGT,IARG,NUMARG,IDEFCA,   &
