      END SUBROUTINE DPLECA
      SUBROUTINE DPLECL(IHARG,IHARG2,IARGT,IARG,ARG,NUMARG,   &
                        IDEFCO,MAXLEG,ILEGCO,ILEGC2,IRGBMX,   &
                        IBUGP2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE COLOR FOR A LEGEND.  THE COLOR FOR LEGEND I
!              WILL BE PLACED IN THE I-TH ELEMENT OF THE HOLLERITH
!              VECTOR ILEGCO(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A HOLLERITH VECTOR)
!                     --IARG   (A HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFCO
!                     --MAXLEG
!     OUTPUT ARGUMENTS--ILEGCO (A HOLLERITH VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              COLOR FOR LEGEND I.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--SEPTEMBER 1980.
!     UPDATED         --MAY       1982.
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLOR
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IDEFCO
      CHARACTER*4 IBUGP2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IHARG(*)
      CHARACTER*4 IHARG2(*)
      CHARACTER*4 IARGT(*)
      CHARACTER*4 ILEGCO(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
      DIMENSION ILEGC2(MAXLEG,3)
!
      CHARACTER*4 IHOLD
      CHARACTER*4 ICASCL
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ICASCL='STAN'
      ISUBN1='DPLE'
      ISUBN2='CL  '
      IHOLD='    '
      JHOLD1=-1
      JHOLD2=-1
      JHOLD3=-1
!
      IF(IBUGP2.EQ.'ON' .OR. ISUBRO.EQ.'LECL')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLECL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGP2,ISUBRO,IFOUND,IERROR
   52   FORMAT('IBUGP2,ISUBRO,IFOUND,IERROR = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IDEBCO,MAXLEG,NUMLEG,NUMARG,IRGBMX
   53   FORMAT('IDEBCO,MAXLEG,NUMLEG,NUMARG,IRGBMX = ',A4,2X,4I8)
        CALL DPWRST('XXX','BUG ')
        DO 65 I=1,NUMARG
          WRITE(ICOUT,66)I,IARG(I),IHARG(I)
   66     FORMAT('I,IARG(I),IHARG(I) = ',2I8,2X,A4)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
        DO 75 I=1,10
          WRITE(ICOUT,76)I,ILEGCO(I),ILEGC2(I,1),ILEGC2(I,2),ILEGC2(I,3)
   76     FORMAT('I,ILEGCO(I),ILEGC2(I,1),ILEGC2(I,2),ILEGC2(I,3) = ',   &
                 I8,2X,A4,2X,3I5)
          CALL DPWRST('XXX','BUG ')
   75   CONTINUE
      ENDIF
!
      ISTEPN='1'
      IF(IBUGP2.EQ.'ON' .OR. ISUBRO.EQ.'LECL')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.EQ.0)GO TO 9000
      IF(IHARG(1).EQ.'RGB ' .AND. IHARG(2).EQ.'COLO')THEN
        ICASCL='RGB '
        ISHIFT=1
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGP2,IERROR)
      ELSEIF(IHARG(2).EQ.'RGB ' .AND. IHARG(3).EQ.'COLO')THEN
        ICASCL='RGB '
        DO 45 II=2,NUMARG-1
          IHARG(II)=IHARG(II+1)
          IHARG2(II)=IHARG2(II+1)
          IARGT(II)=IARGT(II+1)
          IARG(II)=IARG(II+1)
          ARG(II)=ARG(II+1)
  45    CONTINUE
        IHARG(NUMARG)=IHARG(II+1)
        IHARG2(NUMARG)=IHARG2(II+1)
        IARGT(NUMARG)=IARGT(II+1)
        IARG(NUMARG)=IARG(II+1)
        ARG(NUMARG)=ARG(II+1)
        NUMARG=NUMARG-1
      ENDIF
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'COLO')THEN
!
      ISTEPN='2'
      IF(IBUGP2.EQ.'ON' .OR. ISUBRO.EQ.'LECL')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(NUMARG.LE.1        .OR. IHARG(2).EQ.'ON'   .OR.   &
           IHARG(2).EQ.'OFF'  .OR. IHARG(2).EQ.'AUTO' .OR.   &
           IHARG(2).EQ.'DEFA')THEN
          IF(ICASCL.EQ.'RGB ')THEN
            JHOLD1=-1
            JHOLD2=-1
            JHOLD3=-1
          ELSE
            IHOLD=IDEFCO
          ENDIF
        ELSE
          IF(ICASCL.EQ.'RGB ')THEN
            IF(NUMARG.GE.4)THEN
              JHOLD1=IARG(2)
              JHOLD2=IARG(3)
              JHOLD3=IARG(4)
              IF(JHOLD1.LT.0 .OR. JHOLD1.GT.IRGBMX)JHOLD1=-1
              IF(JHOLD2.LT.0 .OR. JHOLD2.GT.IRGBMX)JHOLD2=-1
              IF(JHOLD3.LT.0 .OR. JHOLD3.GT.IRGBMX)JHOLD3=-1
            ELSE
              JHOLD1=-1
              JHOLD2=-1
              JHOLD3=-1
            ENDIF
          ELSE
            IHOLD=IHARG(2)
          ENDIF
        ENDIF
!
        IFOUND='YES'
        IF(ICASCL.EQ.'RGB ')THEN
          DO 1138 I=1,MAXLEG
            ILEGC2(I,1)=JHOLD1
            ILEGC2(I,2)=JHOLD2
            ILEGC2(I,3)=JHOLD3
 1138     CONTINUE
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            I=1
            WRITE(ICOUT,1139)ILEGC2(I,1),ILEGC2(I,2),ILEGC2(I,3)
 1139       FORMAT('ALL LEGEND RGB COLORS HAVE JUST BEEN SET TO ',3I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSE
          DO 1135 I=1,MAXLEG
            ILEGCO(I)=IHOLD
 1135     CONTINUE
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            I=1
            WRITE(ICOUT,1136)ILEGCO(I)
 1136       FORMAT('ALL LEGEND COLORS HAVE JUST BEEN SET TO ',A4)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
        GO TO 9000
!
      ELSEIF(NUMARG.GE.2.AND.IHARG(2).EQ.'COLO')THEN
!
      ISTEPN='3'
      IF(IBUGP2.EQ.'ON' .OR. ISUBRO.EQ.'LECL')   &
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(IARGT(1).NE.'NUMB')THEN
          IERROR='YES'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1141)
 1141     FORMAT('***** ERROR IN LEGEND COLOR (DPLECL)--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1142)
 1142     FORMAT('      IN THE LEGEND ... COLOR COMMAND,')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1143)
 1143     FORMAT('      THE LEGEND IS IDENTIFIED BY A NUMBER, AS IN--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1144)
 1144     FORMAT('      LEGEND 3 COLOR GREEN')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
!
        I=IARG(1)
        IF(I.LT.1 .OR. I.GT.MAXLEG)THEN
          IERROR='YES'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1141)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1152)
 1152     FORMAT('      IN THE LEGEND ... COLOR COMMAND,THE NUMBER ',   &
                 'OF LEGENDS')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1154)MAXLEG
 1154     FORMAT('      MUST BE BETWEEN 1 AND ',I8,' (INCLUSIVELY);')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1155)
 1155     FORMAT('      SUCH WAS NOT THE CASE HERE--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1156)I
 1156     FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH LEGEND.')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
!
        IF(NUMARG.LE.2        .OR. IHARG(3).EQ.'ON'   .OR.   &
           IHARG(3).EQ.'OFF'  .OR. IHARG(3).EQ.'AUTO' .OR.   &
           IHARG(3).EQ.'DEFA')THEN
          IF(ICASCL.EQ.'RGB ')THEN
            JHOLD1=-1
            JHOLD2=-1
            JHOLD3=-1
          ELSE
            IHOLD=IDEFCO
          ENDIF
        ELSE
          IF(ICASCL.EQ.'RGB ')THEN
            JHOLD1=-1
            JHOLD2=-1
            JHOLD3=-1
            IF(NUMARG.GE.5)THEN
              JHOLD1=IARG(3)
              JHOLD2=IARG(4)
              JHOLD3=IARG(5)
              IF(JHOLD1.LT.0 .OR. JHOLD1.GT.IRGBMX)JHOLD1=-1
              IF(JHOLD2.LT.0 .OR. JHOLD2.GT.IRGBMX)JHOLD2=-1
              IF(JHOLD3.LT.0 .OR. JHOLD3.GT.IRGBMX)JHOLD3=-1
            ENDIF
          ELSE
            IHOLD=IHARG(3)
          ENDIF
        ENDIF
!
        IFOUND='YES'
        IF(ICASCL.EQ.'RGB ')THEN
          ILEGC2(I,1)=JHOLD1
          ILEGC2(I,2)=JHOLD2
          ILEGC2(I,3)=JHOLD3
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1286)I,ILEGC2(I,1),ILEGC2(I,2),ILEGC2(I,3)
 1286       FORMAT('THE RGB COLOR FOR LEGEND ',I8,   &
                   ' HAS JUST BEEN SET TO ',3I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSE
          ILEGCO(I)=IHOLD
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1186)I,ILEGCO(I)
 1186       FORMAT('THE COLOR FOR LEGEND ',I8,' HAS JUST BEEN SET TO ',   &
                   A4)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ENDIF
!
 9000 CONTINUE
!
      IF(IBUGP2.EQ.'ON' .OR. ISUBRO.EQ.'LECL')THEN
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLECL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR,NUMLEG
 9012   FORMAT('IFOUND,IERROR,NUMLEG = ',2(A4,2X),I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)IHOLD,JHOLD1,JHOLD2,JHOLD3
 9014   FORMAT('IHOLD,JHOLD1,JHOLD2,JHOLD3 = ',A4,2X,3I5)
        CALL DPWRST('XXX','BUG ')
        DO 9075 I=1,10
          WRITE(ICOUT,76)I,ILEGCO(I),ILEGC2(I,1),ILEGC2(I,2),ILEGC2(I,3)
          CALL DPWRST('XXX','BUG ')
 9075   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPLECL
      SUBROUTINE DPLECO(IHARG,IHARG2,IARGT,IARG,ARG,NUMARG,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,IANS,IWIDTH,   &
      MAXLEG,PLEGXC,PLEGYC,IBUGP2,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE (X,Y) COORDINATES FOR A LEGEND.
!              THE (X,Y) COORDINATES WILL BE PLACED IN THE
!              I-TH ELEMENT OF PLEGXC(.) AND PLEGYC(.) RESPECTIVELY.
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A HOLLERITH VECTOR)
!                     --IARG   (A HOLLERITH VECTOR)
!                     --ARG    (A HOLLERITH VECTOR)
!                     --NUMARG
!                     --MAXLEG
!     OUTPUT ARGUMENTS--PLEGXC (A FLOATING POINT VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              X COORDINATE FOR LEGEND I.
!                     --PLEGYC (A FLOATING POINT VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              Y COORDINATE FOR LEGEND I.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--SEPTEMBER 1980.
!     UPDATED         --MARCH     1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 IARGT
      CHARACTER*4 IHNAME
      CHARACTER*4 IHNAM2
      CHARACTER*4 IUSE
      CHARACTER*4 IANS
      CHARACTER*4 IBUGP2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASE
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IHWORD
      CHARACTER*4 IHWOR2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
!
      DIMENSION IHNAME(*)
      DIMENSION IHNAM2(*)
      DIMENSION IUSE(*)
      DIMENSION IN(*)
      DIMENSION IVALUE(*)
      DIMENSION VALUE(*)
      DIMENSION IANS(*)
!
      DIMENSION PLEGXC(*)
      DIMENSION PLEGYC(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLE'
      ISUBN2='CO  '
      IFOUND='NO'
      IERROR='NO'
!
      HOLD1=0.0
      HOLD2=0.0
!
      IF(NUMARG.EQ.0)GO TO 9000
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'COOR')GO TO 1110
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'COOR')GO TO 1140
      GO TO 9000
!
 1110 CONTINUE
      IF(NUMARG.LE.1)GO TO 1120
      IF(IHARG(2).EQ.'ON')GO TO 1120
      IF(IHARG(2).EQ.'OFF')GO TO 1120
      IF(IHARG(2).EQ.'AUTO')GO TO 1120
      IF(IHARG(2).EQ.'DEFA')GO TO 1120
      IF(NUMARG.GE.3)GO TO 1125
!
      IERROR='YES'
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1111)
 1111 FORMAT('***** ERROR IN DPLECO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)
 1112 FORMAT('      IN THE LEGEND ... COORDINATES COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1113)
 1113 FORMAT('      THE COORDINATES ARE SPECIFIED BY 2 NUMBERS, ',   &
      'AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1114)
 1114 FORMAT('      LEGEND 3 COORDINATES 30 80')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1120 CONTINUE
      ICASE='AUTO'
      GO TO 1130
!
 1125 CONTINUE
      ICASE='NORM'
      DO 1126 J=2,3
      IF(IARGT(J).EQ.'NUMB')GO TO 1127
      GO TO 1128
 1127 CONTINUE
      IF(J.EQ.2)HOLD1=ARG(J)
      IF(J.EQ.3)HOLD2=ARG(J)
      GO TO 1126
 1128 CONTINUE
      IHWORD=IHARG(J)
      IHWOR2=IHARG2(J)
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHWORD,IHWOR2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(J.EQ.2)HOLD1=VALUE(ILOC)
      IF(J.EQ.3)HOLD2=VALUE(ILOC)
 1126 CONTINUE
      GO TO 1130
!
 1130 CONTINUE
      IFOUND='YES'
      DO 1131 I=1,MAXLEG
      AI=I
      DEL=(AI-1.0)*4.0
      IF(ICASE.EQ.'AUTO')PLEGXC(I)=20.0
      IF(ICASE.EQ.'AUTO')PLEGYC(I)=84.0-DEL
      IF(ICASE.NE.'AUTO')PLEGXC(I)=HOLD1
      IF(ICASE.NE.'AUTO')PLEGYC(I)=HOLD2
 1131 CONTINUE
      IF(ICASE.EQ.'AUTO')GO TO 1135
!
      IF(IFEEDB.EQ.'OFF')GO TO 1134
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1132)
 1132 FORMAT('ALL LEGEND COORDINATES HAVE JUST BEEN SET TO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1133)PLEGXC(I),PLEGYC(I)
 1133 FORMAT('    X = ',E15.7,'           Y = ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1134 CONTINUE
      GO TO 9000
!
 1135 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1139
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1136)
 1136 FORMAT('ALL LEGEND COORDINATES HAVE BEEN AUTOMATICALLY SET ',   &
      'AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      DO 1137 I=1,4
      WRITE(ICOUT,1186)I
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1133)PLEGXC(I),PLEGYC(I)
      CALL DPWRST('XXX','BUG ')
 1137 CONTINUE
      WRITE(ICOUT,1138)MAXLEG
 1138 FORMAT('    ... AND SO ON FOR ALL ',I8,' LEGENDS')
      CALL DPWRST('XXX','BUG ')
 1139 CONTINUE
      GO TO 9000
!
 1140 CONTINUE
      IF(IARGT(1).EQ.'NUMB')GO TO 1150
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('***** ERROR IN DPLECO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      IN THE LEGEND ... COORDINATES COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      THE LEGEND IS IDENTIFIED BY A NUMBER, AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1144)
 1144 FORMAT('      LEGEND 3 COORDINATES 30 80')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1150 CONTINUE
      I=IARG(1)
      IF(1.LE.I.AND.I.LE.MAXLEG)GO TO 1160
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN DPLECO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      IN THE LEGEND ... COORDINATES COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      THE NUMBER OF LEGENDS MUST BE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)MAXLEG
 1154 FORMAT('      BETWEEN 1 AND ',I8,' (INCLUSIVELY);')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      SUCH WAS NOT THE CASE HERE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)I
 1156 FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH ',   &
      'LEGEND.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1160 CONTINUE
      IF(NUMARG.LE.2)GO TO 1170
      IF(IHARG(3).EQ.'ON')GO TO 1170
      IF(IHARG(3).EQ.'OFF')GO TO 1170
      IF(IHARG(3).EQ.'AUTO')GO TO 1170
      IF(IHARG(3).EQ.'DEFA')GO TO 1170
      IF(NUMARG.GE.4)GO TO 1175
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1111)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1113)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1114)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1170 CONTINUE
      AI=I
      DEL=(AI-1.0)*4.0
      HOLD1=20.0
      HOLD2=84.0-DEL
      GO TO 1180
!
 1175 CONTINUE
      DO 1176 J=3,4
      IF(IARGT(J).EQ.'NUMB')GO TO 1177
      GO TO 1178
 1177 CONTINUE
      IF(J.EQ.3)HOLD1=ARG(J)
      IF(J.EQ.4)HOLD2=ARG(J)
      GO TO 1176
 1178 CONTINUE
      IHWORD=IHARG(J)
      IHWOR2=IHARG2(J)
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHWORD,IHWOR2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOC,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      IF(J.EQ.3)HOLD1=VALUE(ILOC)
      IF(J.EQ.4)HOLD2=VALUE(ILOC)
 1176 CONTINUE
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      PLEGXC(I)=HOLD1
      PLEGYC(I)=HOLD2
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1186)I
 1186 FORMAT('THE COORDINATES FOR LEGEND ',I8,   &
      ' HAVE JUST BEEN SET TO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1133)PLEGXC(I),PLEGYC(I)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGP2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPLECO--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IFOUND,IERROR
 9012 FORMAT('IFOUND,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPLECO
      SUBROUTINE DPLEDI(IHARG,IHARG2,IARGT,IARG,NUMARG,IDEFDI,   &
      MAXLEG,ILEGDI,IFOUND,IERROR)
!CCCC THE FOLLOWING LINE WAS FIXED (SEE ABOVE) FEBRUARY 1992
!CCCC SUBROUTINE DPLEDI(IHARG,IARGT,IARG,NUMARG,IDEFDI,
!
!     PURPOSE--DEFINE THE DIRECTION FOR A LEGEND.
!              THE DIRECTION FOR LEGEND I WILL BE PLACED
!              IN THE I-TH ELEMENT OF THE HOLLERITH
!              VECTOR ILEGDI(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IHARG2 (A HOLLERITH VECTOR)
!                     --IARGT  (A HOLLERITH VECTOR)
!                     --IARG   (A HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFDI
!                     --MAXLEG
!     OUTPUT ARGUMENTS--ILEGDI (A HOLLERITH VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              DIRECTION FOR LEGEND I.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/2
!     ORIGINAL VERSION--JANUARY   1989.
!     UPDATED         --FEBRUARY  1992 FIX CONFLICT WITH LITERAL
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
!CCCC THE FOLLOWING LINE WAS ADDED FEBRUARY 1992
      CHARACTER*4 IHARG2
      CHARACTER*4 IARGT
      CHARACTER*4 IDEFDI
      CHARACTER*4 ILEGDI
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!CCCC THE FOLLOWING LINE WAS ADDED FEBRAURY 1992
      DIMENSION IHARG2(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
!
      DIMENSION ILEGDI(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)GO TO 1199
!CCCC THE FOLLOWING LINE WAS FIXED FEBRUARY 1992
!CCCC IF(NUMARG.GE.1.AND.IHARG(1).EQ.'DIRE')GO TO 1110
      IF(NUMARG.GE.1.AND.   &
         IHARG(1).EQ.'DIRE'.AND.IHARG2(1).EQ.'CTIO'.AND.   &
         NUMARG.EQ.2)GO TO 1110
!CCCC THE FOLLOWING LINE WAS FIXED FEBRUARY 1992
!CCCC IF(NUMARG.GE.2.AND.IHARG(2).EQ.'DIRE')GO TO 1140
      IF(NUMARG.GE.2.AND.   &
         IHARG(2).EQ.'DIRE'.AND.IHARG2(2).EQ.'CTIO'.AND.   &
         NUMARG.EQ.3)GO TO 1140
      GO TO 1199
!
 1110 CONTINUE
      IF(NUMARG.LE.1)GO TO 1120
      IF(IHARG(2).EQ.'ON')GO TO 1120
      IF(IHARG(2).EQ.'OFF')GO TO 1120
      IF(IHARG(2).EQ.'AUTO')GO TO 1120
      IF(IHARG(2).EQ.'DEFA')GO TO 1120
      GO TO 1125
!
 1120 CONTINUE
      IHOLD=IDEFDI
      GO TO 1130
!
 1125 CONTINUE
      IHOLD=IHARG(2)
      GO TO 1130
!
 1130 CONTINUE
      IFOUND='YES'
      DO 1135 I=1,MAXLEG
      ILEGDI(I)=IHOLD
 1135 CONTINUE
!
      IF(IFEEDB.EQ.'OFF')GO TO 1139
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1136)ILEGDI(I)
 1136 FORMAT('ALL LEGEND DIRECTIONS HAVE JUST BEEN SET TO ',   &
      A4)
      CALL DPWRST('XXX','BUG ')
 1139 CONTINUE
      GO TO 1199
!
 1140 CONTINUE
      IF(IARGT(1).EQ.'NUMB')GO TO 1150
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('***** ERROR IN DPLEDI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      IN THE LEGEND ... DIRECTION COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      THE LEGEND IS IDENTIFIED BY A NUMBER, AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1144)
 1144 FORMAT('      LEGEND 3 DIRECTION HORIZONTAL')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1150 CONTINUE
      I=IARG(1)
      IF(1.LE.I.AND.I.LE.MAXLEG)GO TO 1160
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN DPLEDI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      IN THE LEGEND ... DIRECTION COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      THE NUMBER OF LEGENDS MUST BE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)MAXLEG
 1154 FORMAT('      BETWEEN 1 AND ',I8,' (INCLUSIVELY);')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      SUCH WAS NOT THE CASE HERE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)I
 1156 FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH ',   &
      'LEGEND.')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1160 CONTINUE
      IF(NUMARG.LE.2)GO TO 1170
      IF(IHARG(3).EQ.'ON')GO TO 1170
      IF(IHARG(3).EQ.'OFF')GO TO 1170
      IF(IHARG(3).EQ.'AUTO')GO TO 1170
      IF(IHARG(3).EQ.'DEFA')GO TO 1170
      GO TO 1175
!
 1170 CONTINUE
      IHOLD=IDEFDI
      GO TO 1180
!
 1175 CONTINUE
      IHOLD=IHARG(3)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      ILEGDI(I)=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1186)I,ILEGDI(I)
 1186 FORMAT('THE DIRECTION FOR LEGEND ',I8,   &
      ' HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPLEDI
      SUBROUTINE DPLEFI(IHARG,IARGT,IARG,NUMARG,IDEFFI,   &
      MAXLEG,ILEGFI,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE FILL FOR A LEGEND.
!              THE FILL FOR LEGEND I WILL BE PLACED
!              IN THE I-TH ELEMENT OF THE HOLLERITH
!              VECTOR ILEGFI(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A HOLLERITH VECTOR)
!                     --IARG   (A HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFFI
!                     --MAXLEG
!     OUTPUT ARGUMENTS--ILEGFI (A HOLLERITH VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              FILL FOR LEGEND I.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/2
!     ORIGINAL VERSION--JANUARY   1989.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IDEFFI
      CHARACTER*4 ILEGFI
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
!
      DIMENSION ILEGFI(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)GO TO 1199
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'FILL')GO TO 1110
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'FILL')GO TO 1140
      GO TO 1199
!
 1110 CONTINUE
      IF(NUMARG.LE.1)GO TO 1120
      IF(IHARG(2).EQ.'ON')GO TO 1120
      IF(IHARG(2).EQ.'OFF')GO TO 1120
      IF(IHARG(2).EQ.'AUTO')GO TO 1120
      IF(IHARG(2).EQ.'DEFA')GO TO 1120
      GO TO 1125
!
 1120 CONTINUE
      IHOLD=IDEFFI
      GO TO 1130
!
 1125 CONTINUE
      IHOLD=IHARG(2)
      GO TO 1130
!
 1130 CONTINUE
      IFOUND='YES'
      DO 1135 I=1,MAXLEG
      ILEGFI(I)=IHOLD
 1135 CONTINUE
!
      IF(IFEEDB.EQ.'OFF')GO TO 1139
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1136)ILEGFI(I)
 1136 FORMAT('ALL LEGEND FILLS HAVE JUST BEEN SET TO ',   &
      A4)
      CALL DPWRST('XXX','BUG ')
 1139 CONTINUE
      GO TO 1199
!
 1140 CONTINUE
      IF(IARGT(1).EQ.'NUMB')GO TO 1150
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('***** ERROR IN DPLEFI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      IN THE LEGEND ... FILL COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      THE LEGEND IS IDENTIFIED BY A NUMBER, AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1144)
 1144 FORMAT('      LEGEND 3 FILL ON')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1150 CONTINUE
      I=IARG(1)
      IF(1.LE.I.AND.I.LE.MAXLEG)GO TO 1160
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN DPLEFI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      IN THE LEGEND ... FILL COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      THE NUMBER OF LEGENDS MUST BE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)MAXLEG
 1154 FORMAT('      BETWEEN 1 AND ',I8,' (INCLUSIVELY);')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      SUCH WAS NOT THE CASE HERE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)I
 1156 FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH ',   &
      'LEGEND.')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1160 CONTINUE
      IF(NUMARG.LE.2)GO TO 1170
      IF(IHARG(3).EQ.'ON')GO TO 1170
      IF(IHARG(3).EQ.'OFF')GO TO 1170
      IF(IHARG(3).EQ.'AUTO')GO TO 1170
      IF(IHARG(3).EQ.'DEFA')GO TO 1170
      GO TO 1175
!
 1170 CONTINUE
      IHOLD=IDEFFI
      GO TO 1180
!
 1175 CONTINUE
      IHOLD=IHARG(3)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      ILEGFI(I)=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1186)I,ILEGFI(I)
 1186 FORMAT('THE FILL FOR LEGEND ',I8,   &
      ' HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPLEFI
      SUBROUTINE DPLEFO(IHARG,IARGT,IARG,NUMARG,IDEFFO,   &
                        MAXLEG,ILEGFO,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE FONT FOR A LEGEND.  THE FONT FOR LEGEND I WILL
!              BE PLACED IN THE I-TH ELEMENT OF THE HOLLERITH VECTOR
!              ILEGFO(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A HOLLERITH VECTOR)
!                     --IARG   (A HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFFO
!                     --MAXLEG
!     OUTPUT ARGUMENTS--ILEGFO (A HOLLERITH VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              FONT FOR LEGEND I.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/2
!     ORIGINAL VERSION--JANUARY   1989.
!     UPDATED         --JULY      2021. "HARDWARE" AS SYNONYM FOR
!                                       "TEKTRONIX
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IDEFFO
      CHARACTER*4 ILEGFO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
!
      DIMENSION ILEGFO(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOBE.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(ISUBG4.EQ.'PLEG')THEN
        WRITE(ICOUT,11)NUMARG,IHARG(1),IARG(1)
   11   FORMAT('DPLEG: NUMARG,IHARG(1),IARG(1) = ',I8,2X,A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(NUMARG.EQ.0)GO TO 1199
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'FONT')GO TO 1110
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'FONT')GO TO 1140
      GO TO 1199
!
 1110 CONTINUE
      IF(NUMARG.LE.1)GO TO 1120
      IF(IHARG(2).EQ.'ON')GO TO 1120
      IF(IHARG(2).EQ.'OFF')GO TO 1120
      IF(IHARG(2).EQ.'AUTO')GO TO 1120
      IF(IHARG(2).EQ.'DEFA')GO TO 1120
      GO TO 1125
!
 1120 CONTINUE
      IHOLD=IDEFFO
      GO TO 1130
!
 1125 CONTINUE
      IHOLD=IHARG(2)
      GO TO 1130
!
 1130 CONTINUE
      IFOUND='YES'
      DO 1135 I=1,MAXLEG
        ILEGFO(I)=IHOLD
        IF(ILEGFO(I).EQ.'HARD')ILEGFO(I)='TEKT'
 1135 CONTINUE
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        I=1
        WRITE(ICOUT,1136)ILEGFO(I)
 1136   FORMAT('ALL LEGEND FONTS HAVE JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 1199
!
 1140 CONTINUE
      IF(IARGT(1).NE.'NUMB')THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1141)
 1141   FORMAT('***** ERROR IN LEGEND (DPLEFO)--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1142)
 1142   FORMAT('      IN THE LEGEND ... FONT COMMAND,')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1143)
 1143   FORMAT('      THE LEGEND IS IDENTIFIED BY A NUMBER, AS IN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1144)
 1144   FORMAT('      LEGEND 3 FONT SIMPLEX')
        CALL DPWRST('XXX','BUG ')
        GO TO 1199
      ENDIF
!
      I=IARG(1)
      IF(I.LT.1 .OR. I.GT.MAXLEG)THEN
        IERROR='YES'
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1141)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1152)
 1152   FORMAT('      IN THE LEGEND ... FONT COMMAND, THE NUMBER OF')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1154)MAXLEG
 1154   FORMAT('      LEGENDS MUST BE BETWEEN 1 AND ',I8,   &
               ' (INCLUSIVELY);')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1155)
 1155   FORMAT('      SUCH WAS NOT THE CASE HERE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1156)I
 1156   FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH LEGEND.')
        CALL DPWRST('XXX','BUG ')
        GO TO 1199
      ENDIF
!
      IF(NUMARG.LE.2        .OR. IHARG(3).EQ.'ON'   .OR.   &
         IHARG(3).EQ.'OFF'  .OR. IHARG(3).EQ.'AUTO' .OR.   &
         IHARG(3).EQ.'DEFA')THEN
        IHOLD=IDEFFO
        GO TO 1180
      ELSE
        IHOLD=IHARG(3)
        GO TO 1180
      ENDIF
!
 1180 CONTINUE
      IFOUND='YES'
      ILEGFO(I)=IHOLD
      IF(ILEGFO(I).EQ.'HARD')ILEGFO(I)='TEKT'
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1186)I,ILEGFO(I)
 1186   FORMAT('THE FONT FOR LEGEND ',I8,' HAS JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPLEFO
      SUBROUTINE DPLEG(IHARG,IARG,ARG,IARGT,NUMARG,IANS,IANSLC,   &
                       IWIDTH,   &
                       ILEGNA,ILEGST,ILEGSP,NUMLEG,MAXLEG,   &
                       ILEGTE,NCLEG,MXCLEG,IFOUND,IERROR,IBUGP2)
!
!     PURPOSE--DETERMINE THE LEGEND.
!              CONVERT A STRING TO BE USED AS A LEGEND
!              ON A TEKTRONIX (OR EQUIVALENT) PLOT INTO THE PROPER FORM
!              (ASCII INTEGER REPRESENTATION) FOR USE
!              BY THE TEKTRONIX (OR EQUIVALENT) SOFTWARE.
!              ALSO SAVE THE ORIGINAL STRING FOR USE
!              ON PRINTER PLOTS.
!     OUTPUT ARGUMENTS--ILEGNA (A  CHARACTER VECTOR)
!                     --ILEGST (AN INTEGER VECTOR)
!                     --ILEGSP (AN INTEGER VECTOR)
!                     --ILEGTE (A  CHARACTER VECTOR)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--MARCH     1979.
!     UPDATED         --JULY      1980.
!     UPDATED         --SEPTEMBER 1980.
!     UPDATED         --DECEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --SEPTEMBER 1993. ALLOW LOWER CASE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IANS
!CCCC THE FOLLOWING LINE WAS ADDED       SEPTEMBER 1993
!CCCC TO ALLOW FOR LOWER CASE            SEPTEMBER 1993
      CHARACTER*4 IANSLC
      CHARACTER*4 ILEGNA
      CHARACTER*4 ILEGTE
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
      CHARACTER*4 IBUGP2
!
      CHARACTER*4 ICASLE
      CHARACTER*4 ISTH
      CHARACTER*4 ILEGN2
!
!---------------------------------------------------------------------
!
      DIMENSION IANS(*)
!CCCC THE FOLLOWING LINE WAS ADDED SEPTEBMER 1993
!CCCC TO ALLOW FOR LOWER CASE      SEPTEMBER 1993
      DIMENSION IANSLC(*)
!
      DIMENSION IHARG(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
      DIMENSION IARGT(*)
!
      DIMENSION ILEGNA(*)
      DIMENSION ILEGST(*)
      DIMENSION ILEGSP(*)
!
      DIMENSION ILEGTE(*)
!
      DIMENSION ISTH(1000)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      ILEGNU=(-999)
!
      IF(IBUGP2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLEG--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N2,NCLEG,MXCLEG
   52   FORMAT('N2,NCLEG,MXCLEG = ',3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)(ILEGTE(I),I=1,MIN(100,NCLEG))
   55   FORMAT('ILEGTE(.) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)NUMLEG,MAXLEG,ARG(1)
   56   FORMAT('NUMLEG,MAXLEG,ARG(1) = ',2I8,G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 60 I=1,NUMLEG
          WRITE(ICOUT,61)I,ILEGNA(I),ILEGST(I),ILEGSP(I)
   61     FORMAT('I,ILEGNA(I),ILEGST(I),ILEGSP(I) = ',I4,3X,A4,2I8)
          CALL DPWRST('XXX','BUG ')
   60   CONTINUE
      ENDIF
!
      IF(NUMARG.EQ.0)GO TO 105
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'COLO')GO TO 9000
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'COOR')GO TO 9000
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'SIZE')GO TO 9000
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'HW')GO TO 9000
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'COLO')GO TO 9000
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'COOR')GO TO 9000
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'SIZE')GO TO 9000
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'HW')GO TO 9000
      GO TO 105
!
  105 CONTINUE
!
!               **********************************************************
!               **  STEP 1--                                            **
!               **  DETERMINE THE LOCATION OF THE WORD    LEGEND     .  **
!               **********************************************************
!
      ICASLE='1'
      IF(NUMARG.EQ.0)GO TO 110
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'ON')GO TO 110
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'OFF')GO TO 110
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'AUTO')GO TO 110
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'DEFA')GO TO 110
      GO TO 150
!
  110 CONTINUE
      ICASLE='ALL'
      NUMLEG=0
      DO 120 I=1,MAXLEG
      ILEGNA(I)=' '
      ILEGST(I)=0
      ILEGSP(I)=0
  120 CONTINUE
      NCLEG=0
      DO 130 I=1,MXCLEG
      ILEGTE(I)=' '
  130 CONTINUE
      GO TO 800
!
  150 CONTINUE
      DO 160 I=1,IWIDTH
      I2=I
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IP5=I+5
      IF(IP5.GT.IWIDTH)GO TO 169
      IF(IANS(I).EQ.'L'.AND.IANS(IP1).EQ.'E'   &
      .AND.IANS(IP2).EQ.'G'.AND.IANS(IP3).EQ.'E'   &
      .AND.IANS(IP4).EQ.'N'.AND.IANS(IP5).EQ.'D')   &
      GO TO 180
  160 CONTINUE
  169 CONTINUE
!
      WRITE(ICOUT,171)
  171 FORMAT('***** ERROR IN DPLEG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,172)
  172 FORMAT('      THE WORD     LEGEND    NOT FOUND.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
  180 CONTINUE
      ISTOPL=IP5
!
!               **********************************************
!               **  STEP 2--                                **
!               **  DETERMINE THE NAME ASSOCIATED WITH      **
!               **  THE LEGEND PRESENTLY BEING DEFINED.     **
!               **********************************************
!
      ISTART=ISTOPL+1
      IF(ISTART.GT.IWIDTH)GO TO 209
      DO 200 I=ISTART,IWIDTH
      I2=I
      IF(IANS(I).NE.' ')GO TO 220
  200 CONTINUE
  209 CONTINUE
!
      WRITE(ICOUT,211)
  211 FORMAT('***** ERROR IN DPLEG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,212)
  212 FORMAT('      NO NAME (E.G., 1, 2, 3, ...) FOUND')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,213)
  213 FORMAT('      FOR THE CURRENT LEGEND BEING DEFINED.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
  220 CONTINUE
      ISTARN=I2
!
      DO 230 I=ISTARN,IWIDTH
      I2=I
      IF(IANS(I).EQ.' ')GO TO 240
  230 CONTINUE
      I2=I2+1
  240 CONTINUE
      ISTOPN=I2-1
!
!CCCC CALL DP1H4H(ISTARN,ISTOPN,IANS,
!CCCC1IWORD1,IWORD2,IWORD3,NUMWD,NUMCH,IBUGP2,IERROR)
!
      IF(IARGT(1).EQ.'NUMB')GO TO 249
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,241)
  241 FORMAT('***** ERROR IN DPLEG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,242)
  242 FORMAT('      IN THE LEGEND ... COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,243)
  243 FORMAT('      THE LEGEND MUST BE IDENTIFIED BY A NUMBER,' )
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,244)
  244 FORMAT('      AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,245)
  245 FORMAT('         LEGEND 2 CARBON DIOXIDE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,246)
  246 FORMAT('      SUCH WAS NOT THE CASE HERE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,247)
  247 FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)WRITE(ICOUT,248)(IANS(I),I=1,IWIDTH)
  248 FORMAT(100A1)
      IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
      GO TO 9000
  249 CONTINUE
!
      ILEGN2=IHARG(1)
      ILEGNU=IARG(1)
      IF(1.LE.ILEGNU.AND.ILEGNU.LE.MAXLEG)GO TO 259
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,251)
  251 FORMAT('***** ERROR IN DPLEG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,252)
  252 FORMAT('      IN THE LEGEND ... COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,253)
  253 FORMAT('      THE NUMBER OF LEGENDS MUST BE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,254)MAXLEG
  254 FORMAT('      BETWEEN 1 AND ',I8,' (INCLUSIVELY);')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,255)
  255 FORMAT('      SUCH WAS NOT THE CASE HERE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,256)I
  256 FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH ',   &
      'LEGEND.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
  259 CONTINUE
!
!               *********************************************
!               **  STEP 3--                               **
!               **  DETERMINE THE START POSITION (ISTARS)  **
!               **  FOR THE LEGEND STRING.                 **
!               *********************************************
!
      ISTARS=ISTOPN+2
!
!               ********************************************
!               **  STEP 4--                              **
!               **  DETERMINE THE STOP POSITION (ISTOPS)  **
!               **  FOR THE LEGEND STRING.                **
!               ********************************************
!
      ISTOPS=IWIDTH
      IMIN=ISTARS
      IF(IMIN.GT.IWIDTH)GO TO 490
      DO 400 I=IMIN,IWIDTH
      IREV=IWIDTH-I+IMIN
      IF(IANS(IREV).NE.' ')GO TO 420
  400 CONTINUE
      GO TO 490
  420 CONTINUE
      ISTOPS=IREV
  490 CONTINUE
!
!               ***********************************************
!               **  STEP 5- -                                **
!               **  COPY OVER THE STRING OF INTEREST.        **
!               **  CONVERT TO ASCII NUMERIC REPRESENTATION. **
!               ***********************************************
!
      IF(NUMARG.EQ.2.AND.IHARG(2).EQ.'ON')GO TO 570
      IF(NUMARG.EQ.2.AND.IHARG(2).EQ.'OFF')GO TO 570
      IF(NUMARG.EQ.2.AND.IHARG(2).EQ.'AUTO')GO TO 570
      IF(NUMARG.EQ.2.AND.IHARG(2).EQ.'DEFA')GO TO 570
      IF(NUMARG.EQ.1)GO TO 570
      GO TO 540
!
  540 CONTINUE
      J=0
      IF(ISTARS.GT.ISTOPS)GO TO 570
      DO 550 I=ISTARS,ISTOPS
      J=J+1
!CCCC THE FOLLOWING LINE AS CHANGED      SEPTEMBER 1993
!CCCC TO ALLOW FOR LOWER CASE            SEPTEMBER 1993
!CCCC ISTH(J)=IANS(I)
      ISTH(J)=IANSLC(I)
  550 CONTINUE
      N2=J
      GO TO 590
!
  570 CONTINUE
      J=1
      ISTH(1)=' '
      N2=J
      GO TO 590
!
  590 CONTINUE
!
!               ****************************************************************
!               **  STEP 6--                                                   *
!               **  INSERT THE CHARACTER STRING IN LOCATIONS                   *
!               **  1 TO N2        OF ISTH(.) INTO THE                         *
!               **  PACKED  INTERNAL DATAPLOT TABLE ILEGTE(.).
!               **  UPDATE (IF NECESSARY) THE INTERNAL TABLES                  *
!               **  ILEGNA(.), ILEGST(.), AND ILEGSP(.).                       *
!               ****************************************************************
!
!CCCC MAY NEED TO ADD IANSLC TO THE ARG LIST BELOW???  SEPTEMBER 1993
      CALL DPINLE(ILEGN2,ISTH,N2,ILEGNA,ILEGST,ILEGSP,   &
      NUMLEG,MAXLEG,ILEGTE,NCLEG,MXCLEG,IANS,IWIDTH,IBUGP2,   &
      IERROR)
!
!               ***************************
!               **  STEP 7--             **
!               **  PRINT OUT A MESSAGE  **
!               ***************************
!
  800 CONTINUE
      IF(ICASLE.EQ.'ALL')GO TO 820
!
      IFOUND='YES'
!
      IF(IFEEDB.EQ.'OFF')GO TO 819
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,811)ILEGNA(ILEGNU)
  811 FORMAT('LEGEND ',A4,' HAS JUST BEEN SET TO')
      CALL DPWRST('XXX','BUG ')
      IF(N2.EQ.0)WRITE(ICOUT,999)
      IF(N2.EQ.0)CALL DPWRST('XXX','BUG ')
      IF(N2.GE.1)WRITE(ICOUT,812)(ISTH(I),I=1,N2)
  812 FORMAT(12X,118A1)
      IF(N2.GE.1)CALL DPWRST('XXX','BUG ')
  819 CONTINUE
      GO TO 9000
!
  820 CONTINUE
      IFOUND='YES'
!
      IF(IFEEDB.EQ.'OFF')GO TO 829
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,821)
  821 FORMAT('ALL LEGENDS HAVE JUST BEEN SET TO')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
  829 CONTINUE
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGP2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPLEG--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)N2,NCLEG,MXCLEG
 9012 FORMAT('N2,NCLEG,MXCLEG = ',3I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)(ISTH(I),I=1,N2)
 9013 FORMAT('ISTH(.) = ',100A1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)(ILEGTE(I),I=1,NCLEG)
 9015 FORMAT('ILEGTE(.) = ',100A1)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9017)ILEGNU,IARG(1),NUMLEG,MAXLEG
 9017 FORMAT('ILEGNU,IARG(1),NUMLEG,MAXLEG = ',4I8)
      CALL DPWRST('XXX','BUG ')
      DO 9020 I=1,NUMLEG
      WRITE(ICOUT,9021)I,ILEGNA(I),ILEGST(I),ILEGSP(I)
 9021 FORMAT('I,ILEGNA(I),ILEGST(I),ILEGSP(I) = ',I4,3X,A4,I8,I8)
      CALL DPWRST('XXX','BUG ')
 9020 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPLEG
      SUBROUTINE DPLEHW(IHARG,IARGT,IARG,ARG,NUMARG,   &
      PDEFHE,   &
      MAXLEG,   &
      PLEGHE,PLEGWI,PLEGVG,PLEGHG,   &
      IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE HEIGHT AND WIDTH FOR A LEGEND.
!              THE HEIGHT FOR LEGEND I WILL BE PLACED
!              IN THE I-TH ELEMENT OF THE FLOATING POINT
!              VECTOR PLEGHE(.).
!              THE WIDTH FOR LEGEND I WILL BE PLACED
!              IN THE I-TH ELEMENT OF THE FLOATING POINT
!              VECTOR PLEGWI(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A HOLLERITH VECTOR)
!                     --IARG   (A HOLLERITH VECTOR)
!                     --ARG    (A HOLLERITH VECTOR)
!                     --NUMARG
!                     --PDEFHE
!                     --MAXLEG
!     OUTPUT ARGUMENTS--PLEGHE (A FLOATING POINT VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              SIZE (= HEIGHT) FOR LEGEND I.
!                     --PLEGWI = LEGEND WIDTH
!                     --PLEGVG = LEGEND VERTICAL GAP
!                     --PLEHG = LEGEND GHORIZONTAL GAP
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JUNE      1980.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
!
      DIMENSION PLEGHE(*)
      DIMENSION PLEGWI(*)
      DIMENSION PLEGVG(*)
      DIMENSION PLEGHG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)GO TO 1199
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'HW')GO TO 1110
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'HW')GO TO 1140
      GO TO 1199
!
 1110 CONTINUE
      IF(NUMARG.LE.2)GO TO 1120
      IF(IHARG(3).EQ.'ON')GO TO 1120
      IF(IHARG(3).EQ.'OFF')GO TO 1120
      IF(IHARG(3).EQ.'AUTO')GO TO 1120
      IF(IHARG(3).EQ.'DEFA')GO TO 1120
      IF(NUMARG.GE.3.AND.   &
      IARGT(2).EQ.'NUMB'.AND.   &
      IARGT(3).EQ.'NUMB')GO TO 1125
!
      IERROR='YES'
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1111)
 1111 FORMAT('***** ERROR IN DPLEHW--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)
 1112 FORMAT('      IN THE LEGEND ... HW COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1113)
 1113 FORMAT('      THE HEIGHT & WIDTH IS SPECIFIED BY 2 NUMBERS, ',   &
      'AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1114)
 1114 FORMAT('      LEGEND 3 HW 1.5 1')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1120 CONTINUE
      HOLD1=PDEFHE
      HOLD2=PDEFHE*0.5
      GO TO 1130
!
 1125 CONTINUE
      HOLD1=ARG(2)
      HOLD2=ARG(3)
      GO TO 1130
!
 1130 CONTINUE
      IFOUND='YES'
      DO 1135 I=1,MAXLEG
      PLEGHE(I)=HOLD1
      PLEGWI(I)=HOLD2
      PLEGVG(I)=PLEGHE(I)*0.375
      PLEGHG(I)=PLEGWI(I)*0.250
 1135 CONTINUE
!
      IF(IFEEDB.EQ.'OFF')GO TO 1139
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1136)PLEGHE(I),PLEGWI(I)
 1136 FORMAT('ALL LEGEND HEIGHT & WIDTHS HAVE JUST BEEN SET TO ',   &
      2E15.7)
      CALL DPWRST('XXX','BUG ')
 1139 CONTINUE
      GO TO 1199
!
 1140 CONTINUE
      IF(IARGT(1).EQ.'NUMB')GO TO 1150
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('***** ERROR IN DPLEHW--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      IN THE LEGEND ... HW COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      THE LEGEND IS IDENTIFIED BY A NUMBER, AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1144)
 1144 FORMAT('      LEGEND 3 HW 1.5 1')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1150 CONTINUE
      I=IARG(1)
      IF(1.LE.I.AND.I.LE.MAXLEG)GO TO 1160
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN DPLEHW--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      IN THE LEGEND ... HW COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      THE NUMBER OF LEGENDS MUST BE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)MAXLEG
 1154 FORMAT('      BETWEEN 1 AND ',I8,' (INCLUSIVELY);')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      SUCH WAS NOT THE CASE HERE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)I
 1156 FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH ',   &
      'LEGEND.')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1160 CONTINUE
      IF(NUMARG.LE.3)GO TO 1170
      IF(IHARG(4).EQ.'ON')GO TO 1170
      IF(IHARG(4).EQ.'OFF')GO TO 1170
      IF(IHARG(4).EQ.'AUTO')GO TO 1170
      IF(IHARG(4).EQ.'DEFA')GO TO 1170
      IF(NUMARG.GE.4.AND.   &
      IARGT(3).EQ.'NUMB'.AND.   &
      IARGT(4).EQ.'NUMB')GO TO 1175
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1111)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1113)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1114)
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1170 CONTINUE
      HOLD1=PDEFHE
      HOLD2=PDEFHE*0.5
      GO TO 1180
!
 1175 CONTINUE
      HOLD1=ARG(3)
      HOLD2=ARG(4)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      PLEGHE(I)=HOLD1
      PLEGWI(I)=HOLD2
      PLEGVG(I)=PLEGHE(I)*0.375
      PLEGHG(I)=PLEGWI(I)*0.250
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1186)I,PLEGHE(I),PLEGWI(I)
 1186 FORMAT('THE HEIGHT & WIDTH FOR LEGEND ',I8,   &
      ' HAS JUST BEEN SET TO ',2E15.7)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPLEHW
      SUBROUTINE DPLEJU(IHARG,IARGT,IARG,NUMARG,IDEFJU,   &
      MAXLEG,ILEGJU,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE JUSTIFICATION FOR A LEGEND.
!              THE JUSTIFICATION FOR LEGEND I WILL BE PLACED
!              IN THE I-TH ELEMENT OF THE HOLLERITH
!              VECTOR ILEGJU(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A HOLLERITH VECTOR)
!                     --IARG   (A HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFJU
!                     --MAXLEG
!     OUTPUT ARGUMENTS--ILEGJU (A HOLLERITH VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              JUSTIFICATION FOR LEGEND I.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/2
!     ORIGINAL VERSION--JANUARY   1989.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IDEFJU
      CHARACTER*4 ILEGJU
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
!
      DIMENSION ILEGJU(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)GO TO 1199
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'JUST')GO TO 1110
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'JUST')GO TO 1140
      GO TO 1199
!
 1110 CONTINUE
      IF(NUMARG.LE.1)GO TO 1120
      IF(IHARG(2).EQ.'ON')GO TO 1120
      IF(IHARG(2).EQ.'OFF')GO TO 1120
      IF(IHARG(2).EQ.'AUTO')GO TO 1120
      IF(IHARG(2).EQ.'DEFA')GO TO 1120
      GO TO 1125
!
 1120 CONTINUE
      IHOLD=IDEFJU
      GO TO 1130
!
 1125 CONTINUE
      IHOLD=IHARG(2)
      GO TO 1130
!
 1130 CONTINUE
      IFOUND='YES'
      DO 1135 I=1,MAXLEG
      ILEGJU(I)=IHOLD
 1135 CONTINUE
!
      IF(IFEEDB.EQ.'OFF')GO TO 1139
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1136)ILEGJU(I)
 1136 FORMAT('ALL LEGEND JUSTIFICATIONS HAVE JUST BEEN SET TO ',   &
      A4)
      CALL DPWRST('XXX','BUG ')
 1139 CONTINUE
      GO TO 1199
!
 1140 CONTINUE
      IF(IARGT(1).EQ.'NUMB')GO TO 1150
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('***** ERROR IN DPLEJU--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      IN THE LEGEND ... JUSTIFICATION COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      THE LEGEND IS IDENTIFIED BY A NUMBER, AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1144)
 1144 FORMAT('      LEGEND 3 JUSTIFICATION CENTER')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1150 CONTINUE
      I=IARG(1)
      IF(1.LE.I.AND.I.LE.MAXLEG)GO TO 1160
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN DPLEJU--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      IN THE LEGEND ... JUSTIFICATION COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      THE NUMBER OF LEGENDS MUST BE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)MAXLEG
 1154 FORMAT('      BETWEEN 1 AND ',I8,' (INCLUSIVELY);')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      SUCH WAS NOT THE CASE HERE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)I
 1156 FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH ',   &
      'LEGEND.')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1160 CONTINUE
      IF(NUMARG.LE.2)GO TO 1170
      IF(IHARG(3).EQ.'ON')GO TO 1170
      IF(IHARG(3).EQ.'OFF')GO TO 1170
      IF(IHARG(3).EQ.'AUTO')GO TO 1170
      IF(IHARG(3).EQ.'DEFA')GO TO 1170
      GO TO 1175
!
 1170 CONTINUE
      IHOLD=IDEFJU
      GO TO 1180
!
 1175 CONTINUE
      IHOLD=IHARG(3)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      ILEGJU(I)=IHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1186)I,ILEGJU(I)
 1186 FORMAT('THE JUSTIFICATION FOR LEGEND ',I8,   &
      ' HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPLEJU
      SUBROUTINE DPLEPL(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--FORM A LEVEL PLOT.  THIS IS SIMILAR TO A CONTOUR
!              PLOT, EXCEPT THAT WE FILL REGIONS WITH A COLOR
!              (TYPICALLY GREY SCALE, BUT CAN ACTUALLY BE ANY
!              COLOR SCHEME SELECTED BY THE USER).
!     EXAMPLE--LEVEL PLOT Z X Y Z0
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/3
!     ORIGINAL VERSION--MARCH     2008.
!     UPDATED         --FEBRUARY  2011. USE DPPARS, DPPAR5
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOCP.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
!
!---------------------------------------------------------------------
!
      DIMENSION Z(MAXOBV)
      DIMENSION XD(MAXOBV)
      DIMENSION YD(MAXOBV)
      DIMENSION Z0(MAXOBV)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION XDIST(MAXOBV)
      DIMENSION YDIST(MAXOBV)
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(IGARB1),Z(1))
      EQUIVALENCE (GARBAG(IGARB2),XD(1))
      EQUIVALENCE (GARBAG(IGARB3),YD(1))
      EQUIVALENCE (GARBAG(IGARB4),Z0(1))
      EQUIVALENCE (GARBAG(IGARB5),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB6),XDIST(1))
      EQUIVALENCE (GARBAG(IGARB7),YDIST(1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLE'
      ISUBN2='PL  '
      IFOUND='NO'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LEPL')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLEPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IAND1,IAND2
   53   FORMAT('ICASPL,IAND1,IAND2 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)MAXN,MAXNPP
   56   FORMAT('MAXN,MAXNPP = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,57)IFOUND,IERROR
   57   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***********************************
!               **  TREAT THE LEVEL PLOT CASE    **
!               ***********************************
!
      IFOUND='YES'
      ICASPL='LPLO'
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LEPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='DISCRETE CONTOUR PLOT'
      MINNA=4
      MAXNA=100
      MINN2=2
      IFLAGE=99
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=4
      MAXNVA=4
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LEPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I),IVARTY(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I),IVARTY(I) = ',I8,2X,A4,A4,2X,3I8,2X,A4)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               **********************************************
!               **  STEP 33--                               **
!               **  FORM THE SUBSETTED VARIABLES            **
!               **       Z(.)                              **
!               **       XD(.)                              **
!               **       YD(.)                              **
!               **  CONTAINING                              **
!               **       THE RESPONSE Z VARIABLE            **
!               **       THE HORIZONTAL AXIS VARIABLE       **
!               **       THE VERTICAL AXIS VARIABLE         **
!               **  RESPECTIVELY.                           **
!               **********************************************
!
      ISTEPN='33'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LEPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOL=1
      NUMVA2=3
      CALL DPPAR5(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Z,XD,YD,YD,YD,YD,YD,NS,   &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               **********************************************
!               **  STEP 34--                               **
!               **  FORM THE FULL VARIABLE                  **
!               **       Y4(.)                              **
!               **  CONTAINING THE VALUES                   **
!               **  OF THE RESPONSE VARIABLE                **
!               **  WHERE IT IS DESIRED THAT                **
!               **  CONTOUR CURVES BE DETERMINED.           **
!               **********************************************
!
      ISTEPN='34'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LEPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOL=4
      NUMVA2=1
      NQ=NRIGHT(4)
      DO 3410 I=1,NQ
        ISUB(I)=1
 3410 CONTINUE
!
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Z0,Z0,Z0,N4,NLOCA2,NLOCA3,ICASE,   &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!               ********************************************************
!               **  STEP 41--                                          *
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS VARIABLES    *
!               **  (Y(.) AND X(.), RESPECTIVELY) FOR THE PLOT.        *
!               **  FORM THE CURVE DESIGNATION VARIABLE D(.)  .        *
!               **  THIS WILL BE BOTH ONES FOR BOTH CASES              *
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).      *
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).      *
!               ********************************************************
!
      ISTEPN='41'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LEPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPLEP2(Z,XD,YD,NS,Z0,N4,   &
                  XDIST,YDIST,TEMP1,   &
                  Y,X,D,DCOLOR,DFILL,NPLOTP,NPLOTV,   &
                  IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'LEPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLEPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',   &
               I8,I8,I8,2X,A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)ICASPL,MAXN
 9014   FORMAT('ICASPL,MAXN = ',A4,I8)
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GE.1)THEN
          DO 9020 I=1,MIN(NPLOTP,200)
            WRITE(ICOUT,9021)I,Y(I),X(I),D(I)
 9021       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9020     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPLEPL
      SUBROUTINE DPLEP2(Z,X,Y,N,Z0,NLEVEL,   &
      XDIST,YDIST,TEMP1,   &
      Y2,X2,D2,DCOLOR,DFILL,NPLOTP,NPLOTV,   &
      IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--FORM A LEVEL PLOT.  THIS IS SIMILAR TO A CONTOUR
!              PLOT, EXCEPT THAT WE FILL REGIONS WITH A COLOR
!              (TYPICALLY GREY SCALE, BUT CAN ACTUALLY BE ANY
!              COLOR SCHEME SELECTED BY THE USER).
!     EXAMPLE--LEVEL PLOT Z X Y Z0
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2008/3
!     ORIGINAL VERSION--MARCH     2008.
!     PURPOSE--GENERATE A LEVEL PLOT
!     ORIGINAL VERSION--MARCH     2008.
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOCP.INC'
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IWRITE
!
      DIMENSION Z(*)
      DIMENSION X(*)
      DIMENSION Y(*)
      DIMENSION Z0(*)
      DIMENSION XDIST(*)
      DIMENSION YDIST(*)
      DIMENSION TEMP1(*)
      DIMENSION Y2(*)
      DIMENSION X2(*)
      DIMENSION D2(*)
      DIMENSION DCOLOR(*)
      DIMENSION DFILL(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'LEP2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLEP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGG3,ISUBRO
   52   FORMAT('IBUGG3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N,NLEVEL
   53   FORMAT('N,NLEVEL = ',2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,MIN(N,100)
          WRITE(ICOUT,56)I,X(I),Y(I),Z(I)
   56     FORMAT('I,X(I),Y(I),Z(I) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 60 I=1,NLEVEL
          WRITE(ICOUT,61)I,Z0(I)
   61     FORMAT('I,Z0(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   60   CONTINUE
      ENDIF
!
!               *******************************************************
!               **  STEP 1--                                         **
!               **  COMPUTE DISTINCT VALUES FOR X AND Y.             **
!               *******************************************************
!
      ISTEPN='1'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'LEP2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
      CALL DISTIN(X,N,IWRITE,XDIST,NX,IBUGG3,IERROR)
      CALL SORT(XDIST,NX,XDIST)
      CALL DISTIN(Y,N,IWRITE,YDIST,NY,IBUGG3,IERROR)
      CALL SORT(YDIST,NY,YDIST)
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'LEP2')THEN
        DO 155 I=1,NX
          WRITE(ICOUT,156)I,XDIST(I)
  156     FORMAT('I,XDIST(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
  155   CONTINUE
        DO 165 I=1,NY
          WRITE(ICOUT,166)I,YDIST(I)
  166     FORMAT('I,YDIST(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
  165   CONTINUE
      ENDIF
!
!               *******************************************************
!               **  STEP 2--                                         **
!               **  LOOP THROUGH THE DISTINCT VALUES OF X AND Y      **
!               *******************************************************
!
      ISTEPN='2'
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'LEP2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICNT1=0
      ICNT2=0
      DO 1000 I=1,NX
!
        XTEMP=XDIST(I)
        IF(I.EQ.1)THEN
          XLOW=(XDIST(I+1) - XDIST(I))/2.0
          XHIGH=(XDIST(I+1) - XDIST(I))/2.0
        ELSEIF(I.EQ.NX)THEN
          XLOW=(XDIST(I) - XDIST(I-1))/2.0
          XHIGH=(XDIST(I) - XDIST(I-1))/2.0
        ELSE
          XLOW=(XDIST(I) - XDIST(I-1))/2.0
          XHIGH=(XDIST(I+1) - XDIST(I))/2.0
        ENDIF
        XLOW=ABS(XLOW)
        XHIGH=ABS(XHIGH)
!
        DO 2000 J=1,NY
          YTEMP=YDIST(J)
          IF(J.EQ.1)THEN
            YLOW=(YDIST(J+1) - YDIST(J))/2.0
            YHIGH=(YDIST(J+1) - YDIST(J))/2.0
          ELSEIF(J.EQ.NY)THEN
            YLOW=(YDIST(J) - YDIST(J-1))/2.0
            YHIGH=(YDIST(J) - YDIST(J-1))/2.0
          ELSE
            YLOW=(YDIST(J) - YDIST(J-1))/2.0
            YHIGH=(YDIST(J+1) - YDIST(J))/2.0
          ENDIF
          YLOW=ABS(YLOW)
          YHIGH=ABS(YHIGH)
!
          NK=0
          DO 3000 K=1,N
            IF(X(K).EQ.XTEMP .AND. Y(K).EQ.YTEMP)THEN
              NK=NK+1
              TEMP1(NK)=Z(K)
            ENDIF
 3000     CONTINUE
!
          IF(NK.GE.1)THEN
            CALL MEAN(TEMP1,NK,IWRITE,XMEAN,IBUGG3,IERROR)
            IF(XMEAN.LT.Z0(1))THEN
              ILEVEL=1
            ELSE
              DO 3100 K=1,NLEVEL-1
                IF(XMEAN.GE.Z0(K) .AND. XMEAN.LE.Z0(K+1))THEN
                  ILEVEL=K+1
                  GO TO 3109
                ENDIF
 3100         CONTINUE
              ILEVEL=NLEVEL+1
 3109         CONTINUE
            ENDIF
!
            ICNT2=ICNT2+1
!
            ICNT1=ICNT1+1
            X2(ICNT1)=XDIST(I) - XLOW
            Y2(ICNT1)=YDIST(J) - YLOW
            D2(ICNT1)=REAL(ICNT2)
            DCOLOR(ICNT1)=REAL(ILEVEL)
            DFILL(ICNT1)=REAL(ILEVEL)
            ICNT1=ICNT1+1
            X2(ICNT1)=XDIST(I) + XHIGH
            Y2(ICNT1)=YDIST(J) - YLOW
            D2(ICNT1)=REAL(ICNT2)
            DCOLOR(ICNT1)=REAL(ILEVEL)
            DFILL(ICNT1)=REAL(ILEVEL)
            ICNT1=ICNT1+1
            X2(ICNT1)=XDIST(I) + XHIGH
            Y2(ICNT1)=YDIST(J) + YHIGH
            D2(ICNT1)=REAL(ICNT2)
            DCOLOR(ICNT1)=REAL(ILEVEL)
            DFILL(ICNT1)=REAL(ILEVEL)
            ICNT1=ICNT1+1
            X2(ICNT1)=XDIST(I) - XLOW
            Y2(ICNT1)=YDIST(J) + YHIGH
            D2(ICNT1)=REAL(ICNT2)
            DCOLOR(ICNT1)=REAL(ILEVEL)
            DFILL(ICNT1)=REAL(ILEVEL)
            ICNT1=ICNT1+1
            X2(ICNT1)=XDIST(I) - XLOW
            Y2(ICNT1)=YDIST(J) - YLOW
            D2(ICNT1)=REAL(ICNT2)
            DCOLOR(ICNT1)=REAL(ILEVEL)
            DFILL(ICNT1)=REAL(ILEVEL)
          ENDIF
!
 2000   CONTINUE
 1000 CONTINUE
!
      NPLOTP=ICNT1
      NPLOTV=2
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGG3.EQ.'ON'.OR.ISUBRO.EQ.'LEP2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLEP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGG3,ISUBRO
 9012   FORMAT('IBUGG3,ISUBRO = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTP,NPLOTV
 9013   FORMAT('NPLOTP,NPLOTV = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GE.1)THEN
          DO 9015 I=1,MIN(200,NPLOTP)
            WRITE(ICOUT,9016)I,Y2(I),X2(I),D2(I),DCOLOR(I)
 9016       FORMAT('I,Y2(I),X2(I),D2(I),DCOLOR(I) = ',I8,4F10.5)
            CALL DPWRST('XXX','BUG ')
 9015     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPLEP2
      SUBROUTINE DPLESZ(IHARG,IARGT,IARG,ARG,NUMARG,   &
      PDEFHE,PDEFWI,   &
      MAXLEG,   &
      PLEGHE,PLEGWI,PLEGVG,PLEGHG,   &
      IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE SIZE FOR A LEGEND.
!              THE SIZE FOR LEGEND I WILL BE PLACED
!              IN THE I-TH ELEMENT OF THE FLOATING POINT
!              VECTOR ILEGCO(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A HOLLERITH VECTOR)
!                     --IARG   (A HOLLERITH VECTOR)
!                     --ARG    (A HOLLERITH VECTOR)
!                     --NUMARG
!                     --PDEFHE
!                     --PDEFWI
!                     --MAXLEG
!     OUTPUT ARGUMENTS--PLEGHE (A FLOATING POINT VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              SIZE (= HEIGHT) FOR LEGEND I.
!                     --PLEGWI = LEGEND WIDTH
!                     --PLEGVG = LEGEND VERTICAL GAP
!                     --PLEHG = LEGEND GHORIZONTAL GAP
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--SEPTEMBER 1980.
!     UPDATED         --MAY       1982.
!     UPDATED         --DECEMBER  1988.   DEFAULT WIDTH
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
!
      DIMENSION PLEGHE(*)
      DIMENSION PLEGWI(*)
      DIMENSION PLEGVG(*)
      DIMENSION PLEGHG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)GO TO 1199
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'SIZE')GO TO 1110
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'HEIG')GO TO 1110
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'SIZE')GO TO 1140
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'HEIG')GO TO 1140
      GO TO 1199
!
 1110 CONTINUE
      IF(NUMARG.LE.1)GO TO 1120
      IF(IHARG(2).EQ.'ON')GO TO 1120
      IF(IHARG(2).EQ.'OFF')GO TO 1120
      IF(IHARG(2).EQ.'AUTO')GO TO 1120
      IF(IHARG(2).EQ.'DEFA')GO TO 1120
      IF(NUMARG.GE.2.AND.   &
      IARGT(2).EQ.'NUMB')GO TO 1125
!
      IERROR='YES'
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1111)
 1111 FORMAT('***** ERROR IN DPLESZ--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)
 1112 FORMAT('      IN THE LEGEND ... SIZE COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1113)
 1113 FORMAT('      THE SIZE IS SPECIFIED BY 1 NUMBER, ',   &
      'AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1114)
 1114 FORMAT('      LEGEND 3 SIZE 1.5')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1120 CONTINUE
      HOLD1=PDEFHE
      HOLD2=PDEFWI
      GO TO 1130
!
 1125 CONTINUE
      HOLD1=ARG(2)
      HOLD2=HOLD1*0.5
      GO TO 1130
!
 1130 CONTINUE
      IFOUND='YES'
      DO 1135 I=1,MAXLEG
      PLEGHE(I)=HOLD1
      PLEGWI(I)=HOLD2
      PLEGVG(I)=PLEGHE(I)*0.375
      PLEGHG(I)=PLEGHE(I)*0.125
 1135 CONTINUE
!
      IF(IFEEDB.EQ.'OFF')GO TO 1139
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1136)PLEGHE(I)
 1136 FORMAT('ALL LEGEND SIZES HAVE JUST BEEN SET TO ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
 1139 CONTINUE
      GO TO 1199
!
 1140 CONTINUE
      IF(IARGT(1).EQ.'NUMB')GO TO 1150
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('***** ERROR IN DPLESZ--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      IN THE LEGEND ... SIZE COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      THE LEGEND IS IDENTIFIED BY A NUMBER, AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1144)
 1144 FORMAT('      LEGEND 3 SIZE 1.5')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1150 CONTINUE
      I=IARG(1)
      IF(1.LE.I.AND.I.LE.MAXLEG)GO TO 1160
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN DPLESZ--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      IN THE LEGEND ... SIZE COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      THE NUMBER OF LEGENDS MUST BE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)MAXLEG
 1154 FORMAT('      BETWEEN 1 AND ',I8,' (INCLUSIVELY);')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      SUCH WAS NOT THE CASE HERE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)I
 1156 FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH ',   &
      'LEGEND.')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1160 CONTINUE
      IF(NUMARG.LE.2)GO TO 1170
      IF(IHARG(3).EQ.'ON')GO TO 1170
      IF(IHARG(3).EQ.'OFF')GO TO 1170
      IF(IHARG(3).EQ.'AUTO')GO TO 1170
      IF(IHARG(3).EQ.'DEFA')GO TO 1170
      IF(NUMARG.GE.3.AND.   &
      IARGT(3).EQ.'NUMB')GO TO 1175
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1111)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1113)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1114)
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1170 CONTINUE
      HOLD1=PDEFHE
      HOLD2=PDEFWI
      GO TO 1180
!
 1175 CONTINUE
      HOLD1=ARG(3)
      HOLD2=HOLD1*0.5
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      PLEGHE(I)=HOLD1
      PLEGWI(I)=HOLD2
      PLEGVG(I)=PLEGHE(I)*0.375
      PLEGHG(I)=PLEGHE(I)*0.125
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1186)I,PLEGHE(I)
 1186 FORMAT('THE SIZE FOR LEGEND ',I8,   &
      ' HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPLESZ
