!                                       LET ROWLABEL ... COMMAND
!     UPDATED         --JUNE      2013. CALL LIST TO DPINTE
!     UPDATED         --AUGUST    2014. LET PLOT .... =
!     UPDATED         --MARCH     2015. CHECK NAMES
!     UPDATED         --MARCH     2015. CHECK EQUAL LENGTH
