!     UPDATED         --SEPTEMBER 2019. STRING VARIABLE
!     UPDATED         --NOVEMBER  2020. STRING VARIABLE
!     UPDATED         --AUGUST    2021. CALL LIST TO CKSTAT AND DPSTAC
!     UPDATED         --AUGUST    2021. STRING REPEAT
!     UPDATED         --MARCH     2022. NORMAL ORDER STATISTIC MEAN
!     UPDATED         --MARCH     2022. NORMAL ORDER STATISTIC SD
!     UPDATED         --MARCH     2022. EXPONENTIAL ORDER STATISTIC
!                                       MEDIAN
!     UPDATED         --MARCH     2022. EXPONENTIAL ORDER STATISTIC MEAN
!     UPDATED         --MARCH     2022. EXPONENTIAL ORDER STATISTIC SD
!     UPDATED         --MARCH     2022. UNIFORM ORDER STATISTIC MEAN
!     UPDATED         --MARCH     2022. UNIFORM ORDER STATISTIC SD
!     UPDATED         --MARCH     2022. LOGISTIC ORDER STATISTIC
!                                       MEDIAN
!     UPDATED         --AUGUST    2023. CALL LIST TO CKSTAT, CKMATH
!     UPDATED         --AUGUST    2023. CALL LIST TO DPSTAC, DPMATC,
!                                                    DPMAT2
!     UPDATED         --JUNE      2025. NUMBER TO CURRENCY
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IANGLU
      CHARACTER*4 IFTEXP
      CHARACTER*4 IFTORD
      CHARACTER*4 IFORSW
      CHARACTER*4 IOSMET
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASLE
      CHARACTER*4 ITYPEL
      CHARACTER*4 IFOUNZ(30)
      CHARACTER*4 ITYPE(30)
      CHARACTER*4 IHOL(30)
      CHARACTER*4 IHOL2(30)
      CHARACTER*4 IERRO1(30)
      CHARACTER*4 ITYPEH
      CHARACTER*4 IW21HO
      CHARACTER*4 IW22HO
      CHARACTER*4 IA
      CHARACTER*4 IPARN
      CHARACTER*4 IPARN2
      CHARACTER*4 IFOUNR
      CHARACTER*4 IFOUN7
      CHARACTER*4 IFOUN8
      CHARACTER*4 ICASL7
      CHARACTER*4 ICASS7
      CHARACTER*4 ISTARA
      CHARACTER*4 ICASL8
      CHARACTER*4 ICASRA
      CHARACTER*4 ITYW1L
      CHARACTER*4 ICAT1L
      CHARACTER*4 INLI1L
      CHARACTER*4 ITYW2L
      CHARACTER*4 ITYW1R
      CHARACTER*4 ICAT1R
      CHARACTER*4 INLI1R
      CHARACTER*4 ITYW2R
!
      CHARACTER*4 IHAR14
      CHARACTER*4 IHAR15
      CHARACTER*4 ICASEZ
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IMSUBC
      CHARACTER*4 IOPTME
      CHARACTER*4 IOPTHE
      CHARACTER*4 ICASAR
      CHARACTER*4 IWRITE
      CHARACTER*4 IWRIT2
!
!---------------------------------------------------------------------
!
      DIMENSION TEMP(*)
      DIMENSION TEMP2(*)
      DIMENSION XTEMP1(*)
      DIMENSION XTEMP2(*)
!
      DIMENSION IBEGIN(30)
      DIMENSION IEND(30)
      DIMENSION INT1(30)
      DIMENSION FLOAT1(30)
!
!CCCC DIMENSION ITYPEH(225)
!CCCC DIMENSION IW21HO(225)
!CCCC DIMENSION IW22HO(225)
!CCCC DIMENSION W2HOLD(225)
      DIMENSION ITYPEH(1000)
      DIMENSION IW21HO(1000)
      DIMENSION IW22HO(1000)
      DIMENSION W2HOLD(1000)
!
!     NOTE--THE DIMENSION OF IA SHOULD BE THE SAME AS
!           THE DIMENSION OF IB IN SUBROUTINE COMPIM
!           (THE DIMENSION OF IB IS 1000 (JULY 1986))
!     NOTE--IF MAKE DIMENSION ADJUSTMENTS HERE IN DPLET,
!           THEN ALSO MAKE DIMENSION ADJUSTMENTS IN
!           DPLETF, DPFIT, DPPREF, DPPLOT,
!           COMPIM, AND COMPID.
!
!CCCC DIMENSION IA(225)
      DIMENSION IA(1000)
      DIMENSION PARAM(100)
      DIMENSION IPARN(100)
      DIMENSION IPARN2(100)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
!
      INCLUDE 'DPCOZI.INC'
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZD.INC'
!
      DIMENSION XTEMP3(MAXOBV)
      DIMENSION XTEMP4(MAXOBV)
      DIMENSION XTEMP5(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(10*MAXOBV)
      INTEGER ITEMP1(MAXOBV)
      INTEGER ITEMP2(MAXOBV)
      INTEGER ITEMP3(MAXOBV)
      INTEGER ITEMP4(MAXOBV)
      INTEGER ITEMP5(MAXOBV)
      INTEGER ITEMP6(MAXOBV)
      EQUIVALENCE (IGARBG(IIGAR1),ITEMP1(1))
      EQUIVALENCE (IGARBG(IIGAR2),ITEMP2(1))
      EQUIVALENCE (IGARBG(IIGAR3),ITEMP3(1))
      EQUIVALENCE (IGARBG(IIGAR4),ITEMP4(1))
      EQUIVALENCE (IGARBG(IIGAR5),ITEMP5(1))
      EQUIVALENCE (IGARBG(IIGAR6),ITEMP6(1))
      EQUIVALENCE (GARBAG(IGARB1),XTEMP3(1))
      EQUIVALENCE (GARBAG(IGARB2),TEMP3(1))
      EQUIVALENCE (GARBAG(IGARB3),XTEMP4(1))
      EQUIVALENCE (GARBAG(IGARB4),XTEMP5(1))
      EQUIVALENCE (GARBAG(IGARB5),TEMP4(1))
!
      DOUBLE PRECISION DTEMP1(MAXOBV)
      DOUBLE PRECISION DTEMP2(MAXOBV)
      DOUBLE PRECISION DTEMP3(MAXOBV)
      EQUIVALENCE (DGARBG(IDGAR1),DTEMP1(1))
      EQUIVALENCE (DGARBG(IDGAR2),DTEMP2(1))
      EQUIVALENCE (DGARBG(IDGAR3),DTEMP3(1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLE'
      ISUBN2='T   '
      IERROR='NO'
      ICASLE='UNKN'
      IMSUBC='UNKN'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!     ***** THE FOLLOWING 6 LINES INSERTED AUGUST 1983 *****
!CCCC DO40I=1,225
      DO 40 I=1,1000
      ITYPEH(I)='    '
      IW21HO(I)='    '
      IW22HO(I)='    '
      W2HOLD(I)=0.0
   40 CONTINUE
!
!               **************************
!               **  TREAT THE LET CASE  **
!               **************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PLET')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLET--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IANGLU,IFTEXP,ISEED,MAXNXT
   52   FORMAT('IANGLU,IFTEXP,ISEED,MAXNXT = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ
   53   FORMAT('IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  CHECK THE INPUT ARGUMENTS  **
!               *********************************
!
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'=   ')GO TO 1019
      IF(NUMARG.GE.3.AND.IHARG(3).EQ.'=   ')GO TO 1019
!CCCC JULY 1993.  FOLLOWING LINE FOR SINGULAR VALUE DECOMPOSITION
      IF(NUMARG.GE.4.AND.IHARG(4).EQ.'=   ')GO TO 1019
!CCCC SEPTEMBER 2008.  FOLLOWING LINES FOR MERGE COMMAND
      DO 1003 I=1,NUMARG
        IF(IHARG(I).EQ.'=   ')GO TO 1019
 1003 CONTINUE
!
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1011)
 1011 FORMAT('***** ERROR IN DPLET--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1012)
 1012 FORMAT('      IMPROPER FORM FOR THE    LET   COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1013)
 1013 FORMAT('      NO EQUAL SIGN FOUND AFTER THE ',   &
             'VARIABLE/PARAMETER NAME.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1014)
 1014 FORMAT('      THE ENTERED COMMAND LINE IS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,1015)(IANS(I),I=1,MIN(120,IWIDTH))
 1015   FORMAT('      ',120A1)
        CALL DPWRST('XXX','BUG ')
      ELSE
        WRITE(ICOUT,1016)
 1016   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
 1019 CONTINUE
!
!CCCC IF(NUMARG.GE.3)GO TO 1029
      IF(NUMARG.GE.3.AND.IHARG(2).EQ.'=   ')GO TO 1029
      IF(NUMARG.GE.4.AND.IHARG(3).EQ.'=   ')GO TO 1029
!CCCC JULY 1993.  FOLLOWING LINE FOR SINGULAR VALUE DECOMPOSITION
      IF(NUMARG.GE.5.AND.IHARG(4).EQ.'=   ')GO TO 1029
      IF(NUMARG.GE.6.AND.IHARG(NUMARG).NE.'=   ')GO TO 1029
!
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1011)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1022)
 1022 FORMAT('      IMPROPER FORM FOR THE    LET   ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1023)
 1023 FORMAT('      NOTHING FOUND TO THE RIGHT OF THE EQUAL SIGN')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1014)
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,1015)(IANS(I),I=1,MIN(120,IWIDTH))
        CALL DPWRST('XXX','BUG ')
      ELSE
        WRITE(ICOUT,1016)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
 1029 CONTINUE
!
!               **************************************
!               **  STEP 2--                        **
!               **  TREAT THE VARIOUS LET SUBCASES  **
!               **************************************
!
!               *********************************************
!               **  STEP 2.0--                             **
!               **  TREAT THE EXPERIMENT DESIGN            **
!               **  GENERATION SUBCASE                     **
!               *********************************************
!
!CCCC IF(IHARG(NUMARG).EQ.'DESI'.AND.IHARG2(NUMARG).EQ.'GN')GO TO 1010
!CCCC GO TO 1090
!
!1010 CONTINUE
!CCCC ICASLE='DESI'
!CCCC CALL DPDESI(IBUGA3,IBUGQ,IFOUND,IERROR)
!CCCC GO TO 9000
!
!1090 CONTINUE
!
!               *********************************************
!               **  STEP 2.11--                            **
!               **  TREAT THE SEQUENCE GENERATION SUBCASE  **
!               *********************************************
!
      ISTEPN='2.11'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     2016/02: CHECK FOR NAME CONFLICTS
!     2021/05: MODIFY TO MINIMIZE POSSIBILITY OF NON-CONFLICTS
!              APPEARING TO BE CONFLICTS
!
      IF(NUMARG.GE.4.AND.IHARG(3).EQ.'SEQU')THEN
        IF(IHARG2(3).EQ.'TIAL')GO TO 1190
        IF(IHARG2(3)(1:1).EQ.'T')GO TO 1190
        IF(IHARG(4).EQ.'DIFF')GO TO 1190
        IF(IHARG(4).EQ.'PROD')GO TO 1190
        IF(IHARG(4).EQ.'SUM ')GO TO 1190
        IF(IHARG(4).EQ.'MEAN')GO TO 1190
        IF(IHARG(4).EQ.'AVER')GO TO 1190
        IF(IHARG(4).EQ.'MIN ')GO TO 1190
        IF(IHARG(4).EQ.'MAX ')GO TO 1190
        IF(IHARG(4).EQ.'MINI' .AND. IHARG2(4).EQ.'MUM ')GO TO 1190
        IF(IHARG(4).EQ.'MAXI' .AND. IHARG2(4).EQ.'MUM ')GO TO 1190
      ENDIF
      IF(IHARG(3).EQ.'SEQU'.AND.IHARG2(3).EQ.'ENCE')GO TO 1130
!CCCC THE FOLLOWING LINE WAS ADDED           (DECEMBER 1988)
!CCCC SO NEED NOT SPELL OUT    SEQUENCE     FULLY. (DECEMBER 1988)
      IF(IHARG(3).EQ.'SEQU')GO TO 1130
!CCCC THE BRANCH POINT OF THE FOLLOWING LINE (DECEMBER)
!CCCC WAS CHANGED FROM 1130 TO 1110 (DECEMBER 1988)
!CCCC TO ELIMINATE THE CONFLICT OF FUNCTION EVALUATION VERSUS (DECEMBER 1988)
!CCCC SEQUENCE GENERATION.  FOR EXAMPLE, (DECEMBER 1988)
!CCCC LET X = 1 +1 +5 YIELDING A NUMBER (1+1+5=7) (DECEMBER 1988)
!CCCC OR YIELDING A SEQUENCE 1, 2, 3, 4, 5 (DECEMBER 1988)
      IF(NUMARG.GE.5.AND.IHARG(2).EQ.'='.AND.   &
      IARGT(3).EQ.'NUMB'.AND.IARGT(4).EQ.'NUMB'.AND.   &
      IARGT(5).EQ.'NUMB')GO TO 1110
      GO TO 1190
!
 1110 CONTINUE
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,1111)
!1111 FORMAT('***** CAUTION FROM SUBROUTINE DPLET--')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,1112)
!1112 FORMAT('      DUE TO CONFLICTS WITH OTHER FORMS OF THE')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,1113)
!1113 FORMAT('      LET COMMAND, THE 3-ARGUMENT SHORT-CUT')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,1114)
!1114 FORMAT('      SYNTAX THAT YOU USED TO GENERATE A SEQUENCE')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,1115)
!1115 FORMAT('      IS NOW (JANUARY 1989) ILLEGAL.')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,1116)
!1116 FORMAT('      THE OPERATION WILL BE CARRIED OUT,')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,1117)
!1117 FORMAT('      BUT IN THE FUTURE, PLEASE USE THE')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,1118)
!1118 FORMAT('      FULL SYNTAX WHICH CONTAINS THE WORD')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,1119)
!1119 FORMAT('      SEQUENCE   EXPLICITLY.')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,1120)
!1120 FORMAT('      FOR EXAMPLE, REPLACE  LET X = 1 1 10')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,1121)
!1121 FORMAT('                   BY       LET X = SEQUENCE 1 1 10')
!CCCC CALL DPWRST('XXX','BUG ')
!
      IHAR14=IHARG(4)
      IHAR15=IHARG(5)
      IF((IHAR14(1:1).EQ.'+'.OR.IHAR14(1:1).EQ.'-').AND.   &
      (IHAR15(1:1).EQ.'+'.OR.IHAR15(1:1).EQ.'-'))GO TO 1190
      GO TO 1130
!
 1130 CONTINUE
      ICASLE='SEQU'
      CALL DPSEQU(IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IFOUND.EQ.'YES')GO TO 9000
      GO TO 9000
!
 1190 CONTINUE
!
!               ********************************************
!               **  STEP 2.12--                           **
!               **  TREAT THE PATTERN GENERATION SUBCASE  **
!               ********************************************
!
      ISTEPN='2.12'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF((IHARG(3).EQ.'PATT'.AND.IHARG2(3).EQ.'ERN ') .OR.   &
         (IHARG(3).EQ.'DATA'.AND.IHARG2(3).EQ.'    '))THEN
        IF(IHARG(1).EQ.'PLOT' .AND.   &
          (IHARG(2).EQ.'CHAR' .OR. IHARG(2).EQ.'LINE' .OR.   &
          IHARG(2).EQ.'SPIK' .OR. IHARG(2).EQ.'REGI' .OR.   &
          IHARG(2).EQ.'BAR'))GO TO 1290
        ICASLE='PATT'
        CALL DPPAT(IBUGA3,ISUBRO,IBUGQ,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
        IF(IFOUND.EQ.'YES')GO TO 9000
      ENDIF
!
 1290 CONTINUE
!
!               **************************************************
!               **  STEP 2.13--                                 **
!               **  TREAT THE RANDOM NUMBER GENERATION SUBCASE  **
!               **  (AND THE RANDOM PERMUTATION SUBCASE)        **
!               **  (AND THE BOOTSTRAP INDEX SUBCASE == THE     **
!               **  DISCRETE UNIFORM RANDOM NUMBER SUBCASE)     **
!               **************************************************
!
      ISTEPN='2.13'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(3).EQ.'RAND' .AND. IHARG(4).EQ.'COMP' .AND.   &
         IHARG(5).EQ.'BLOC')GO TO 1299
      CALL CKRAND(ICASRA,ILOCNU,NUMSHA,   &
                  SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                  SHAPE5,SHAPE6,SHAPE7,   &
                  IBUGA3,ISUBRO,IFOUNR,IERROR)
      IF(IFOUNR.EQ.'YES')THEN
        ICASLE='RAND'
        CALL DPRAND(ICASRA,ISEED,ILOCNU,NUMSHA,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                    SHAPE5,SHAPE6,SHAPE7,   &
                    IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
 1299 CONTINUE
!
!               *******************************
!               **  STEP 2.14--              **
!               **  TREAT THE ROOTS SUBCASE  **
!               *******************************
!
      ISTEPN='2.14'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(3).EQ.'ROOT'.AND.IHARG2(3).EQ.'S   ')GO TO 1400
      IF(IHARG(3).EQ.'ROOT'.AND.IHARG2(3).EQ.'    ')GO TO 1400
      IF(IHARG(3).EQ.'ZERO'.AND.IHARG2(3).EQ.'S   ')GO TO 1400
      IF(IHARG(3).EQ.'ZERO'.AND.IHARG2(3).EQ.'    ')GO TO 1400
      IF(IHARG(3).EQ.'SOLV'.AND.IHARG2(3).EQ.'E   ')GO TO 1400
      GO TO 1490
!
 1400 CONTINUE
      IF(IHARG(4).EQ.'MEAN' .AND. IHARG(5).EQ.'SQUA')GO TO 1490
      ICASLE='ROOT'
      IFOUND='YES'
      CALL DPROOT(ITYPEH,IW21HO,IW22HO,W2HOLD,NWHOLD,   &
                  PARAM,IPARN,IPARN2,   &
                  ROOTAC,IFTEXP,IFTORD,IFORSW,IANGLU,   &
                  ISUBRO,IBUGA3,IBUGCO,IBUGEV,IBUGQ,IERROR)
      GO TO 9000
!
 1490 CONTINUE
!
!               ************************************
!               **  STEP 2.15--                   **
!               **  TREAT THE DERIVATIVE SUBCASE  **
!               ************************************
!
      ISTEPN='2.15'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(3).EQ.'DERI'.AND.IHARG2(3).EQ.'VATI')GO TO 1500
      GO TO 1590
!
 1500 CONTINUE
      ICASLE='DERI'
      IFOUND='YES'
      ITYPEL='V'
      CALL DPDERV(ITYPEH,IW21HO,IW22HO,W2HOLD,NWHOLD,   &
                  IA,PARAM,IPARN,IPARN2,   &
                  IFOUNZ,IBEGIN,IEND,ITYPE,IHOL,IHOL2,   &
                  INT1,FLOAT1,IERRO1,   &
                  NUMCL,NUMPL,NUMAOL,ITYW1L,ICAT1L,INLI1L,ITYW2L,   &
                  NUMCR,NUMPR,NUMAOR,ITYW1R,ICAT1R,INLI1R,ITYW2R,   &
                  IANGLU,TEMP3,   &
                  IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,IFOUND,IERROR)
      GO TO 9000
!
 1590 CONTINUE
!
!               **********************************
!               **  STEP 2.16--                 **
!               **  TREAT THE INTEGRAL SUBCASE  **
!               **********************************
!
      ISTEPN='2.16'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(3).EQ.'INTE'.AND.IHARG2(3).EQ.'GRAL')THEN
        DO 1620 I=1,NUMARG
          IF(IHARG(I).EQ.'WRT ')THEN
            ICASLE='INTE'
            IFOUND='YES'
            ITYPEL='V'
            CALL DPINTE(ITYPEH,IW21HO,IW22HO,W2HOLD,NWHOLD,   &
                        PARAM,IPARN,IPARN2,TEMP,ITEMP1,   &
                        IANGLU,IFTEXP,IFTORD,IFORSW,   &
                        IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,IERROR)
             GO TO 9000
          ENDIF
 1620   CONTINUE
      ENDIF
!
!               **********************************************
!               **  STEP 2.16B--                            **
!               **  TREAT THE NUMERICAL DERIVATIVE SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'NUME'.AND.IHARG(4).EQ.'DERI')THEN
        ICASLE='NDER'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPNDER(ITYPEH,IW21HO,IW22HO,W2HOLD,NWHOLD,   &
                    IA,PARAM,IPARN,IPARN2,   &
                    IANGLU,IFTEXP,IFTORD,IFORSW,   &
                    IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,IERROR)
        GO TO 9000
      ENDIF
!
!
!               *************************************************
!               **  STEP 2.17--                                **
!               **  TREAT THE RUNGE-KUTTA (DIFF. EQ.) SUBCASE  **
!               *************************************************
!
      ISTEPN='2.17'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.4.AND.   &
      IHARG(3).EQ.'RUNG'.AND.IHARG(4).EQ.'KUTT')GO TO 1700
      IF(NUMARG.GE.5.AND.   &
      IHARG(4).EQ.'RUNG'.AND.IHARG(5).EQ.'KUTT')GO TO 1700
      GO TO 1790
!
 1700 CONTINUE
      ICASLE='RUNG'
      IFOUND='YES'
      ITYPEL='V'
      CALL DPRK(ITYPEH,IW21HO,IW22HO,W2HOLD,NWHOLD,   &
                PARAM,IPARN,IPARN2,IANGLU,   &
                TEMP,TEMP2,XTEMP1,   &
                IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,IERROR)
      GO TO 9000
!
 1790 CONTINUE
!
!CCCC FOLLOWING SECTION ADDED JUNE 1994.
!               **************************************
!               **  STEP 2.18--                     **
!               **  TREAT THE OPTIMIZATION SUBCASE  **
!               **************************************
!
      ISTEPN='2.18'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(3).EQ.'OPTI')THEN
        ICASLE='OPTI'
        IFOUND='YES'
        CALL DPOPT(ITYPEH,IW21HO,IW22HO,W2HOLD,NWHOLD,   &
                   IA,PARAM,IPARN,IPARN2,   &
                   OPTACC,IOPTME,IOPTHE,   &
                   IFTEXP,IFTORD,IFORSW,IANGLU,   &
                   ISUBRO,IBUGA3,IBUGCO,IBUGEV,IBUGQ,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19A--                            **
!               **  TREAT THE EXECUTE              SUBCASE  **
!               **********************************************
!
      ISTEPN='219A'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(2).EQ.'=   '.AND.IHARG(3).EQ.'EXEC')THEN
        ICASLE='EXEC'
        IFOUND='YES'
        ITYPEL='V'
        NVAL=0
        CALL DPEXFI(XTEMP1,NVAL,IBUGA3,ISUBRO,IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19B--                            **
!               **  TREAT THE INQUIRE              SUBCASE  **
!               **********************************************
!
      ISTEPN='219B'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(2).EQ.'=   '.AND.IHARG(3).EQ.'INQU')THEN
        ICASLE='INFI'
        IFOUND='YES'
        ITYPEL='P'
        NVAL=0
        CALL DPINQU(IBUGA3,ISUBRO,IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19B--                            **
!               **  TREAT THE CLOSE                SUBCASE  **
!               **********************************************
!
      ISTEPN='219B'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(2).EQ.'=   '.AND.IHARG(3).EQ.'CLOS')THEN
        ICASLE='CLOS'
        IFOUND='YES'
        ITYPEL='P'
        NVAL=0
        CALL DPCLOS(IBUGA3,ISUBRO,IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19B-                             **
!               **  TREAT THE LET PLOT ... =  CASE          **
!               **********************************************
!
      ISTEPN='219B'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(1).EQ.'PLOT' .AND.   &
        (IHARG(2).EQ.'CHAR' .OR. IHARG(2).EQ.'LINE' .OR.   &
         IHARG(2).EQ.'SPIK' .OR. IHARG(2).EQ.'REGI' .OR.   &
         IHARG(2).EQ.'BAR'))THEN
        ICASLE='PCON'
        ITYPEL='V'
        CALL DPSEPC(ITEMP1,IFOUND,ISUBRO,IBUGA3,IERROR)
        IF(IFOUND.EQ.'YES')GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19A-                             **
!               **  TREAT THE CHARACTER CODE STRING SUBCASE **
!               **********************************************
!
      IF(IHARG(3).EQ.'CHAR'.AND.IHARG(4).EQ.'CODE'.AND.   &
         IHARG(5).EQ.'STRI')THEN
        ICASLE='SCOD'
        IFOUND='YES'
        ITYPEL='V'
        CALL CODEST(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19--                             **
!               **  TREAT THE CHARACTER CODE       SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'CHAR'.AND.IHARG(4).EQ.'CODE')THEN
        ICASLE='CCOD'
        IFOUND='YES'
        ITYPEL='V'
        IWRIT2='ON  '
        CALL CODECH(XTEMP3,IWRIT2,IBUGA3,ISUBRO,IERROR)
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2.19B-                                 **
!               **  TREAT THE ALPHABETIC CHARACTER CODE SUBCASE **
!               **************************************************
!
      IF(IHARG(3).EQ.'ALPH'.AND.IHARG(4).EQ.'CHAR'.AND.   &
         IHARG(5).EQ.'CODE')THEN
        ICASLE='CCO2'
        IFOUND='YES'
        ITYPEL='V'
        IWRIT2='ON'
        CALL CODEC2(TEMP3,XTEMP3,ITEMP1,IWRIT2,IBUGA3,ISUBRO,IERROR)
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2.19C-                                 **
!               **  TREAT THE REFERENCE CHARACTER CODE SUBCASE  **
!               **************************************************
!
      IF(IHARG(3).EQ.'REFE'.AND.IHARG(4).EQ.'CHAR'.AND.   &
         IHARG(5).EQ.'CODE')THEN
        ICASLE='CCO3'
        IFOUND='YES'
        ITYPEL='V'
        IWRIT2='ON'
        CALL CODEC3(XTEMP3,IWRIT2,IBUGA3,ISUBRO,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19C--                            **
!               **  TREAT THE ROW   LABEL          SUBCASE  **
!               **********************************************
!
      IF(NUMARG.GE.3.AND.   &
        IHARG(1).EQ.'ROWL'.AND.IHARG2(1).EQ.'ABEL'.AND.   &
        IHARG(2).EQ.'=   ')THEN
        IF(IHARG(3).EQ.'STRI' .AND. IHARG(4).EQ.'TO  ' .AND.   &
           IHARG(5).EQ.'ROWL')THEN
          ICASLE='SRLA'
          IFOUND='YES'
          ITYPEL='V'
          IWRITE='ON  '
          IINDX=5
          CALL DPRWLA(IA,IPARN,IPARN2,IWRITE,IINDX,   &
                      IBUGA3,ISUBRO,IERROR)
          GO TO 9000
        ELSEIF(IHARG(3).EQ.'STRI' .AND. IHARG(4).EQ.'TO  ' .AND.   &
           IHARG(5).EQ.'ROW ' .AND. IHARG(6).EQ.'LABE')THEN
          ICASLE='SRLA'
          IFOUND='YES'
          ITYPEL='V'
          IWRITE='ON  '
          IINDX=6
          CALL DPRWLA(IA,IPARN,IPARN2,IWRITE,IINDX,   &
                      IBUGA3,ISUBRO,IERROR)
          GO TO 9000
        ELSEIF(IHARG(3).EQ.'SHIF' .AND. IHARG(4).EQ.'LEFT')THEN
          CALL DPRWSH(IBUGA3,ISUBRO,IERROR)
          IFOUND='YES'
          ICASLE='RLAS'
          ITYPEL='V'
          GO TO 9000
        ELSEIF(IHARG(3).EQ.'SHIF' .AND. IHARG(4).EQ.'RIGH')THEN
          CALL DPRWSH(IBUGA3,ISUBRO,IERROR)
          IFOUND='YES'
          ICASLE='RLAS'
          ITYPEL='V'
          GO TO 9000
        ELSEIF(NUMARG.EQ.3 .AND. IHARG(3).EQ.'DELE')THEN
          DO 1895 I=1,MAXOBV
            IROWLB(I)=' '
 1895     CONTINUE
          IFOUND='YES'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1897)
 1897     FORMAT('THE ROW LABELS HAVE BEEN CLEARED.')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ELSE
          ICASLE='RLAB'
          IFOUND='YES'
          ITYPEL='V'
          IWRIT2='ON'
          CALL DPROLA(IWRIT2,IBUGA3,ISUBRO,IERROR)
          GO TO 9000
        ENDIF
      ELSEIF(NUMARG.GE.4.AND.   &
        IHARG(1).EQ.'ROWL'.AND.IHARG2(1).EQ.'ABEL'.AND.   &
        IHARG(3).EQ.'=   ')THEN
          CALL DPRWL2(IBUGA3,ISUBRO,IERROR)
          IFOUND='YES'
          ICASLE='RLA2'
          ITYPEL='V'
          GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 2.19S-                                 **
!               **  TREAT THE GROUP LABEL TO STRINGS   SUBCASE  **
!               **************************************************
!
      IF(IHARG(3).EQ.'GROU'.AND.IHARG(4).EQ.'LABE')THEN
        IF(IHARG(5).EQ.'TO  '.AND.IHARG(6).EQ.'STRI')THEN
          ICASLE='STGL'
          IFOUND='YES'
          ITYPEL='F'
          CALL DPSTGL(ISUBRO,IBUGA3,IERROR)
          GO TO 9000
        ENDIF
      ENDIF
!
!               **********************************************
!               **  STEP 2.19D--                            **
!               **  TREAT THE GROUP LABEL          SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'GROU'.AND.IHARG(4).EQ.'LABE')THEN
        ICASLE='GLAB'
        IFOUND='YES'
        ITYPEL='V'
        IWRITE='ON  '
        CALL DPGROL(IWRITE,IBUGA3,ISUBRO,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19E-                             **
!               **  TREAT THE STRING LENGTH        SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI'.AND.IHARG(4).EQ.'LENG')THEN
        ICASLE='STLN'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPSTLN(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19F-                             **
!               **  TREAT THE STRING INDEX         SUBCASE  **
!               **********************************************
!
!     2018/09: STRING FIND AS ALIAS
!     2018/09: STRING RIGHT INDEX SEARCHES STRING FROM RIGHT TO LEFT
!
      IF(IHARG(4).EQ.'STRI' .AND.   &
        (IHARG(5).EQ.'INDE' .OR. IHARG(5).EQ.'FIND'))THEN
        ICASLE='STIN'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPSTIN(ICASLE,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ELSEIF(IHARG(4).EQ.'STRI' .AND. IHARG(5).EQ.'RIGH' .AND.   &
        (IHARG(6).EQ.'INDE' .OR. IHARG(6).EQ.'FIND'))THEN
        ICASLE='STIR'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPSTIN(ICASLE,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19G-                             **
!               **  TREAT THE STRING SUBSTRING     SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'SUBS'.AND.IHARG2(3).EQ.'TRIN')THEN
        ICASLE='STSB'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTSB(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19H-                             **
!               **  TREAT THE STRING MERGE         SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI'.AND.IHARG(4).EQ.'MERG')THEN
        ICASLE='STMR'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTMR(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19I-                             **
!               **  TREAT THE STRING REPLACE       SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI'.AND.IHARG(4).EQ.'REPL')THEN
        ICASLE='STRP'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTRP(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19J-                             **
!               **  TREAT THE STRING EDIT          SUBCASE  **
!               **********************************************
!
!     2015/02: ADD A "GLOBAL" VARIANT
!
      IF(IHARG(3).EQ.'STRI'.AND.IHARG(4).EQ.'EDIT')THEN
        ICASLE='STED'
        IFOUND='YES'
        ITYPEL='F'
        IFLAGG=0
        CALL DPSTED(IFLAGG,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ELSEIF(IHARG(3).EQ.'STRI'.AND.IHARG(4).EQ.'GLOB'.AND.   &
             IHARG(5).EQ.'EDIT')THEN
        ICASLE='STED'
        IFOUND='YES'
        ITYPEL='F'
        IFLAGG=1
        CALL DPSTED(IFLAGG,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19K-                             **
!               **  TREAT THE STRING CONCATENATE   SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI'.AND.IHARG(4).EQ.'CONC')THEN
        ICASLE='STCN'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTCN(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19L-                             **
!               **  TREAT THE CHARACTER            SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'CHAR'.AND.IHARG2(3).EQ.'ACTE')THEN
        ICASLE='STCH'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTCH(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19M-                             **
!               **  TREAT THE ICHAR                SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'ICHA')THEN
        ICASLE='ICHA'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPICHA(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19N-                             **
!               **  TREAT THE UPPER CASE           SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'UPPE'.AND.IHARG(4).EQ.'CASE')THEN
        ICASLE='STUC'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTUC(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19O-                             **
!               **  TREAT THE LOWER CASE           SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'LOWE'.AND.IHARG(4).EQ.'CASE')THEN
        ICASLE='STLC'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTLC(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19P-                             **
!               **  TREAT THE STRING WORD          SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI'.AND.IHARG(4).EQ.'WORD')THEN
        ICASLE='STWD'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTWD(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19Q-                             **
!               **  TREAT THE NUMBER OF WORDS      SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'NUMB'.AND.IHARG(4).EQ.'OF  '.AND.   &
         IHARG(5).EQ.'WORD')THEN
        ICASLE='STNW'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPSTNW(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19R-                             **
!               **  TREAT THE STRING COMPARISON    SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI'.AND.IHARG(4).EQ.'COMP')THEN
        IF(IHARG(5).NE.'AND '.OR.IHARG(6).NE.'REPL')THEN
          ICASLE='STCM'
          IFOUND='YES'
          ITYPEL='P'
          CALL DPSTCM(ISUBRO,IBUGA3,IERROR)
          GO TO 9000
        ENDIF
      ENDIF
!
!               **************************************************
!               **  STEP 2.19S-                                 **
!               **  TREAT THE STRING HAMMING DISTANCE  SUBCASE  **
!               **************************************************
!
      IF(IHARG(3).EQ.'STRI'.AND.IHARG(4).EQ.'HAMM'.AND.   &
         IHARG(5).EQ.'DIST')THEN
        ICASLE='STHD'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPSTHD(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19S-                             **
!               **  TREAT THE CONFOUND             SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'=   '.AND.IHARG(4).EQ.'CONF' .AND.   &
         IHARG2(4).EQ.'OUND')THEN
        ICASLE='CONF'
        IFOUND='YES'
        ITYPEL='F'
        CALL CONFOU(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19T--                            **
!               **  TREAT THE MERGE COMMAND                 **
!               **********************************************
!
!     2010/12: CHECK FOR CONFLICT WITH MERGE LIBRARY FUNCTION
!
      IF(NUMARG.GE.2)THEN
        DO 1990 I=1,NUMARG-1
          IF(IHARG(I).EQ.'=' .AND. IHARG(I+1).EQ.'MERG')THEN
            IF(IHARG2(I+1)(1:2).NE.'E(')THEN
              IF(IHARG2(I+1)(1:3).NE.'E3(')THEN
                CALL DPMERG(IBUGA2,IBUGA3,ISUBRO,IFOUND,IERROR)
                IFOUND='YES'
                GO TO 9000
              ENDIF
            ENDIF
          ENDIF
 1990   CONTINUE
      ENDIF
!
!               **********************************************
!               **  STEP 2.19U-                             **
!               **  TREAT THE TYPE                 SUBCASE  **
!               **********************************************
!
      IF(NUMARG.EQ.4 .AND. IHARG(3).EQ.'TYPE')THEN
        ICASLE='TYPE'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPNATY(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19V-                             **
!               **  TREAT THE CHECK NAMES          SUBCASE  **
!               **********************************************
!
      IF(NUMARG.GE.4 .AND. IHARG(3).EQ.'CHEC' .AND.   &
         IHARG(4).EQ.'NAME')THEN
        ICASLE='CNAM'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPSTCK(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19V-                             **
!               **  TREAT THE CHECK EQUAL LENGTH   SUBCASE  **
!               **********************************************
!
      IF(NUMARG.GE.5 .AND. IHARG(3).EQ.'CHEC' .AND.   &
         IHARG(4).EQ.'EQUA' .AND. IHARG(5).EQ.'LENG')THEN
        ICASLE='CLEN'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPCKEL(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19W-                             **
!               **  TREAT THE STRING REMOVE SPACES  SUBCASE **
!               **********************************************
!
!     2018/09: ADD "STRING REMOVE PUNCTUATION" AS A VARIATION
!              OF THIS COMMAND
!     2018/09: ADD "STRING REMOVE WHITESPACE" AS A VARIATION
!              OF THIS COMMAND
!
      IF(NUMARG.GE.5 .AND. IHARG(3).EQ.'STRI' .AND.   &
         IHARG(4).EQ.'REMO' .AND. IHARG(5).EQ.'SPAC')THEN
        ICASLE='RSPA'
        IFOUND='YES'
        ITYPEL='F'
        ICASEZ='ALL'
        CALL DPSTSP(ICASEZ,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ELSEIF(NUMARG.GE.6 .AND. IHARG(3).EQ.'STRI' .AND.   &
         IHARG(4).EQ.'REMO' .AND. IHARG(5).EQ.'LEAD' .AND.   &
         IHARG(6).EQ.'SPAC')THEN
        ICASLE='RSPA'
        IFOUND='YES'
        ITYPEL='F'
        ICASEZ='LEAD'
        CALL DPSTSP(ICASEZ,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ELSEIF(NUMARG.GE.6 .AND. IHARG(3).EQ.'STRI' .AND.   &
         IHARG(4).EQ.'REMO' .AND. IHARG(5).EQ.'TRAI' .AND.   &
         IHARG(6).EQ.'SPAC')THEN
        ICASLE='RSPA'
        IFOUND='YES'
        ITYPEL='F'
        ICASEZ='TRAI'
        CALL DPSTSP(ICASEZ,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ELSEIF(NUMARG.GE.5 .AND. IHARG(3).EQ.'STRI' .AND.   &
         IHARG(4).EQ.'REMO' .AND. IHARG(5).EQ.'PUNC')THEN
        ICASLE='RSPA'
        IFOUND='YES'
        ITYPEL='F'
        ICASEZ='RPUN'
        CALL DPSTSP(ICASEZ,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ELSEIF(NUMARG.GE.5 .AND. IHARG(3).EQ.'STRI' .AND.   &
         IHARG(4).EQ.'REMO' .AND. IHARG(5).EQ.'WHIT')THEN
        ICASLE='RSPA'
        IFOUND='YES'
        ITYPEL='F'
        ICASEZ='RWHI'
        CALL DPSTSP(ICASEZ,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ELSEIF(NUMARG.GE.5 .AND. IHARG(3).EQ.'STRI' .AND.   &
         IHARG(4).EQ.'EXPA' .AND. IHARG(5).EQ.'WHIT')THEN
        ICASLE='RSPA'
        IFOUND='YES'
        ITYPEL='F'
        ICASEZ='EWHI'
        CALL DPSTSP(ICASEZ,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19X-                             **
!               **  TREAT THE CHECK TYPE           SUBCASE  **
!               **********************************************
!
      IF(NUMARG.GE.4 .AND. IHARG(3).EQ.'CHEC' .AND.   &
         IHARG(4).EQ.'TYPE')THEN
        ICASEZ='UNKN'
        IF(IHARG(5).EQ.'VARI')ICASEZ='VARI'
        IF(IHARG(5).EQ.'VECT')ICASEZ='VARI'
        IF(IHARG(5).EQ.'COLU')ICASEZ='VARI'
        IF(IHARG(5).EQ.'STRI')ICASEZ='STRI'
        IF(IHARG(5).EQ.'FUNC')ICASEZ='STRI'
        IF(IHARG(5).EQ.'PARA')ICASEZ='PARA'
        IF(IHARG(5).EQ.'MATR')ICASEZ='MATR'
        IF(IHARG(5).EQ.'NUMB')ICASEZ='NUMB'
        ICASLE='CNAM'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPSTCT(ICASEZ,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19Y-                             **
!               **  TREAT THE DIGITS TO STRING     SUBCASE  **
!               **********************************************
!
      IF(NUMARG.GE.5 .AND. IHARG(3).EQ.'DIGI' .AND.   &
         IHARG(4).EQ.'TO  ' .AND. IHARG(5).EQ.'STRI')THEN
        ICASLE='DSTR'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTVS(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19Z-                             **
!               **  TREAT THE NUMBER TO STRING     SUBCASE  **
!               **  TREAT THE NUMBER TO CURRENCY   SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'NUMB' .AND. IHARG(4).EQ.'TO  ' .AND.   &
         IHARG(5).EQ.'STRI')THEN
        ICASLE='NUST'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPNUST(IFORSW,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ELSEIF(IHARG(1).EQ.'STRI' .AND. IHARG(4).EQ.'NUMB' .AND.   &
             IHARG(5).EQ.'TO  ' .AND. IHARG(6).EQ.'STRI')THEN
        ICASLE='NUST'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPNUST(IFORSW,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
      IF(IHARG(3).EQ.'NUMB' .AND. IHARG(4).EQ.'TO  ' .AND.   &
         IHARG(5).EQ.'CURR')THEN
        ICASLE='NUCU'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPNUCU(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ELSEIF(IHARG(1).EQ.'STRI' .AND. IHARG(4).EQ.'NUMB' .AND.   &
             IHARG(5).EQ.'TO  ' .AND. IHARG(6).EQ.'CURR')THEN
        ICASLE='NUCU'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPNUCU(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19AA-                            **
!               **  TREAT THE BLANK STRING         SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'BLAN'.AND.IHARG(4).EQ.'STRI')THEN
        ICASLE='STRB'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTRB(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19BB--                           **
!               **  TREAT THE STRING COMBINE       SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI'.AND.IHARG(4).EQ.'COMB')THEN
        ICASLE='STCB'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTCB(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               *****************************************************
!               **  STEP 2.19CC--                                  **
!               **  TREAT THE STRING COMPARE AND REPLACE  SUBCASE  **
!               *****************************************************
!
      IF(IHARG(3).EQ.'STRI' .AND. IHARG(4).EQ.'COMP' .AND.   &
         IHARG(5).EQ.'AND ' .AND. IHARG(6).EQ.'REPL')THEN
        ICASLE='SCAR'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTCR(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               *****************************************************
!               **  STEP 2.19DD--                                  **
!               **  TREAT THE STRING INTERACTION                   **
!               *****************************************************
!
      IF(IHARG(3).EQ.'STRI' .AND. IHARG(4).EQ.'INTE')THEN
        ICASLE='STIP'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTIP(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               *****************************************************
!               **  STEP 2.19EE--                                  **
!               **  TREAT THE STRING SPLIT                         **
!               *****************************************************
!
      IF(IHARG(3).EQ.'STRI' .AND. IHARG(4).EQ.'SPLI')THEN
        ICASLE='STSP'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSSPL(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19FF--                           **
!               **  TREAT THE STRING STARTS WITH            **
!               **            STRING ENDS   WITH   SUBCASES **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI' .AND. IHARG(4).EQ.'STAR' .AND.   &
         IHARG(5).EQ.'WITH')THEN
        ICASLE='STSW'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPSTSW(ICASLE,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ELSEIF(IHARG(3).EQ.'STRI' .AND. IHARG(4).EQ.'ENDS' .AND.   &
             IHARG(5).EQ.'WITH')THEN
        ICASLE='STEW'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPSTSW(ICASLE,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19GG--                           **
!               **  TREAT THE STRING DELETE   CASE          **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI' .AND. IHARG(4).EQ.'DELE')THEN
        ICASLE='STDE'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTDE(ICASLE,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19HH--                           **
!               **  TREAT THE STRING CONTAINS               **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI' .AND. IHARG(4).EQ.'CONT')THEN
        ICASLE='STCO'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPSTCO(ICASLE,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               ***************************************************
!               **  STEP 2.19II--                                **
!               **  TREAT THE STRING <LEFT/CENTER/RIGHT> JUSTIFY **
!               ***************************************************
!
      IF(IHARG(3).EQ.'STRI' .AND. IHARG(5).EQ.'JUST')THEN
        ICASEZ='LEFT'
        IF(IHARG(4).EQ.'LEFT')ICASEZ='LEFT'
        IF(IHARG(4).EQ.'CENT')ICASEZ='CENT'
        IF(IHARG(4).EQ.'RIGH')ICASEZ='RIGH'
        ICASLE='STJU'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTJU(ICASEZ,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19JJ--                           **
!               **  TREAT THE SWAP  CASE           SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'SWAP'.AND.IHARG(4).EQ.'CASE')THEN
        ICASLE='STSC'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTSC(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19KK--                           **
!               **  TREAT THE STRING SUBSET COUNT           **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI' .AND. IHARG(4).EQ.'SUBS' .AND.   &
         IHARG(5).EQ.'COUN')THEN
        ICASLE='STNS'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPSTNS(ICASLE,ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19LL--                           **
!               **  TREAT THE STRING VARIABLE DELETE        **
!               **  TREAT THE STRING VARIABLE         CASES **
!               **********************************************
!
      IF((IHARG(3).EQ.'STRI' .OR. IHARG(3).EQ.'CHAR') .AND.   &
          IHARG(4).EQ.'VARI')THEN
        IF(IHARG(5).EQ.'DELE')THEN
        ELSE
          ICASLE='STVA'
          IFOUND='YES'
          ITYPEL='F'
          CALL DPSTVA(ISUBRO,IBUGA3,IERROR)
          GO TO 9000
        ENDIF
      ENDIF
!
!               **********************************************
!               **  STEP 2.19MM--                           **
!               **  TREAT THE IS NUMBER            SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'IS  ' .AND. IHARG(4).EQ.'NUMB')THEN
        ICASLE='ISNU'
        IFOUND='YES'
        ITYPEL='P'
        CALL DPISNU(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.19NN--                           **
!               **  TREAT THE STRING REPEAT        SUBCASE  **
!               **********************************************
!
      IF(IHARG(3).EQ.'STRI' .AND. IHARG(4).EQ.'REPE')THEN
        ICASLE='STRE'
        IFOUND='YES'
        ITYPEL='F'
        CALL DPSTRS(ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
!               **********************************************
!               **  STEP 2.20--                             **
!               **  TREAT THE MATH CALCULATIONS SUBCASE     **
!               **   (INPUT = A VECTOR; OUTPUT = A VECTOR)  **
!               **********************************************
!
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PLET')THEN
        WRITE(ICOUT,2001)
 2001   FORMAT('BEFORE CALL CKMATH')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      CALL CKMATH(IBUGA3,ISUBRO,IFOUN7,ICASL7,ICASS7,ISTANR,ISTARA,   &
                  IMSUBC,ILOCV)
      IF(IFOUN7.EQ.'YES'.AND.ICASL7.NE.'UNKN'.AND.   &
      ILOCV.GE.1)GO TO 2000
      GO TO 2090
!
 2000 CONTINUE
      ICASLE='MANI'
!CCCC AUGUST 1995.  ADD IFTORD ARGUMENT
!CCCC OCTOBER 1998.  BREAK DPMATC INTO 2 ROUTINES (STARTING TO
!CCCC CHOKE SOME COMPILERS)
!CCCC MAY 2002.  ADD ISEED TO DPMAT2 CASE
!CCCC CALL DPMATC(ICASL7,ILOCV,IFTEXP,
      IFOUND='NO'
      CALL DPMATC(ICASL7,ICASS7,ISTANR,ISTARA,ILOCV,IFTEXP,IFTORD,ISEED,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IFOUND.EQ.'YES')GO TO 9000
      CALL DPMAT2(ICASL7,ICASS7,ISTARA,ILOCV,ISEED,IMSUBC,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      GO TO 9000
!
 2090 CONTINUE
!
!CCCC THE FOLLOWING SECTION WAS REWRITTEN    OCTOBER 1991
!               *********************************************
!               **  STEP 2.21--                            **
!               **  TREAT THE ORDER STATISTIC MEDIAN G     **
!               **  GENERATION SUBCASE                     **
!               **        UNIFORM DISTRIBUTION             **
!               **        NORMAL DISTRIBUTION              **
!               **        HALFNORMAL DISTRIBUTION          **
!               **        EV1 (GUMBEL) DISTRIBUTION        **
!               **        EV2 (FRECHET) DISTRIBUTION       **
!               **        WEIBULL  DISTRIBUTION            **
!               *********************************************
!
      ISTEPN='2.21'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     HANDLE SPECIFIC CASES WHERE ANALYTIC METHOD IS KNOWN.
!
      IF(IOSMET.EQ.'ANAL')THEN
        IF(NUMARG.GE.6.AND.   &
           IHARG(3).EQ.'UNIF'.AND.IHARG(4).EQ.'ORDE'.AND.   &
           IHARG(5).EQ.'STAT'.AND.IHARG(6).EQ.'MEDI')THEN
          ICASLE='UOSM'
        ELSEIF(NUMARG.GE.6.AND.   &
               IHARG(3).EQ.'NORM'.AND.IHARG(4).EQ.'ORDE'.AND.   &
               IHARG(5).EQ.'STAT'.AND.IHARG(6).EQ.'MEDI')THEN
          ICASLE='NOSM'
        ELSEIF(NUMARG.GE.6.AND.   &
               IHARG(3).EQ.'HALF'.AND.IHARG(4).EQ.'ORDE'.AND.   &
               IHARG(5).EQ.'STAT'.AND.IHARG(6).EQ.'MEDI')THEN
          ICASLE='HOSM'
        ELSEIF(NUMARG.GE.7.AND.   &
               IHARG(3).EQ.'HALF'.AND.IHARG(4).EQ.'NORM'.AND.   &
               IHARG(5).EQ.'ORDE'.AND.IHARG(6).EQ.'STAT'.AND.   &
               IHARG(7).EQ.'MEDI')THEN
          ICASLE='HOSM'
        ELSEIF(NUMARG.GE.6.AND.   &
               IHARG(3).EQ.'EV1'.AND.IHARG(4).EQ.'ORDE'.AND.   &
               IHARG(5).EQ.'STAT'.AND.IHARG(6).EQ.'MEDI')THEN
          ICASLE='E1OM'
        ELSEIF(NUMARG.GE.6.AND.   &
               IHARG(3).EQ.'GUMB'.AND.IHARG(4).EQ.'ORDE'.AND.   &
               IHARG(5).EQ.'STAT'.AND.IHARG(6).EQ.'MEDI')THEN
          ICASLE='E1OM'
        ELSEIF(NUMARG.GE.6.AND.   &
               IHARG(3).EQ.'EV2'.AND.IHARG(4).EQ.'ORDE'.AND.   &
               IHARG(5).EQ.'STAT'.AND.IHARG(6).EQ.'MEDI')THEN
          ICASLE='E2OM'
        ELSEIF(NUMARG.GE.6.AND.   &
               IHARG(3).EQ.'FREC'.AND.IHARG(4).EQ.'ORDE'.AND.   &
               IHARG(5).EQ.'STAT'.AND.IHARG(6).EQ.'MEDI')THEN
          ICASLE='E2OM'
        ELSEIF(NUMARG.GE.6.AND.   &
               IHARG(3).EQ.'WEIB'.AND.IHARG(4).EQ.'ORDE'.AND.   &
               IHARG(5).EQ.'STAT'.AND.IHARG(6).EQ.'MEDI')THEN
          ICASLE='WOSM'
!
        ELSEIF(NUMARG.GE.6.AND.   &
               IHARG(3).EQ.'EXPO'.AND.IHARG(4).EQ.'ORDE'.AND.   &
               IHARG(5).EQ.'STAT'.AND.IHARG(6).EQ.'MEDI')THEN
          ICASLE='EXPM'
!
        ELSEIF(NUMARG.GE.6.AND.   &
               IHARG(3).EQ.'LOGI'.AND.IHARG(4).EQ.'ORDE'.AND.   &
               IHARG(5).EQ.'STAT'.AND.IHARG(6).EQ.'MEDI')THEN
          ICASLE='LOSM'
        ELSE
!
!         MEDIAN CAN BE HANDLED GENERICALLY FOR ARBITRARY
!         DISTRIBUTION
!
          GO TO 2190
        ENDIF
!
        CALL DPOSM(ICASLE,IBUGA3,IBUGQ,IFOUND,IERROR)
        IF(IFOUND.EQ.'NO')GO TO 2190
        IF(IFOUND.EQ.'YES' .OR. IERROR.EQ.'YES')GO TO 9000
      ELSE
!
!       ARBITRARY DISTRIBUTION AND ARBITRARY STATISTIC CASE
!       (VIA SIMULATION)
!
!       STEP 1: CHECK LOCATION FOR "ORDER STATISTIC"
!
        IF(NUMARG.LT.7)GO TO 2190
        IF(IHARG(2).EQ.'=   ')THEN
          DO 2110 II=4,NUMARG
            IF(IHARG(II).EQ.'ORDE' .AND. IHARG(II+1).EQ.'STAT')THEN
              ILOCOS=II
              GO TO 2119
            ENDIF
 2110     CONTINUE
          GO TO 2190
 2119     CONTINUE
!
          DO 2120 II=ILOCOS+2,NUMARG
            IF(IHARG(II).EQ.'FOR ' .OR. IHARG(II).EQ.'SUBS' .OR.   &
               IHARG(II).EQ.'EXCE')THEN
              ILOCFO=II
              GO TO 2129
            ENDIF
 2120     CONTINUE
          GO TO 2190
 2129     CONTINUE
!
          ICASLE='OSTA'
          MAXNXT=MAXOBV
          CALL DPOSST(ICASLE,ILOCOS,ILOCFO,ISEED,MAXNXT,   &
                    TEMP,TEMP4,TEMP2,   &
                    XTEMP1,XTEMP2,XTEMP3,XTEMP4,XTEMP5,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IFOUND.EQ.'NO')GO TO 2190
          IF(IFOUND.EQ.'YES' .OR. IERROR.EQ.'YES')GO TO 9000
        ELSE
          GO TO 2190
        ENDIF
!
      ENDIF
      GO TO 9000
!
 2190 CONTINUE
!
!               *********************************************
!               **  STEP 2.22--                            **
!               **  TREAT THE ORDER STATISTIC MEAN/SD      **
!               **  GENERATION SUBCASE                     **
!               **        UNIFORM DISTRIBUTION             **
!               **        NORMAL DISTRIBUTION              **
!               **        EXPONENTIAL  DISTRIBUTION        **
!               **        LOGISTIC     DISTRIBUTION        **
!               *********************************************
!
      ISTEPN='2.22'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.6.AND.   &
         IHARG(3).EQ.'UNIF' .AND. IHARG(4).EQ.'ORDE' .AND.   &
         IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'MEAN')THEN
        ICASLE='UOSM'
      ELSEIF(NUMARG.GE.6.AND.   &
             IHARG(3).EQ.'UNIF' .AND. IHARG(4).EQ.'ORDE' .AND.   &
             IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'SD  ')THEN
        ICASLE='UOSS'
      ELSEIF(NUMARG.GE.7.AND.   &
             IHARG(3).EQ.'UNIF' .AND. IHARG(4).EQ.'ORDE' .AND.   &
             IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'STAN' .AND.   &
             IHARG(7).EQ.'DEVI')THEN
        ICASLE='UOSS'
      ELSEIF(NUMARG.GE.6.AND.   &
             IHARG(3).EQ.'NORM' .AND. IHARG(4).EQ.'ORDE' .AND.   &
             IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'MEAN')THEN
        ICASLE='NOSM'
      ELSEIF(NUMARG.GE.6.AND.   &
             IHARG(3).EQ.'NORM' .AND. IHARG(4).EQ.'ORDE' .AND.   &
             IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'SD  ')THEN
        ICASLE='NOSS'
      ELSEIF(NUMARG.GE.6.AND.   &
             IHARG(3).EQ.'EXPO' .AND. IHARG(4).EQ.'ORDE' .AND.   &
             IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'MEAN')THEN
        ICASLE='EOSM'
      ELSEIF(NUMARG.GE.6.AND.   &
             IHARG(3).EQ.'EXPO' .AND. IHARG(4).EQ.'ORDE' .AND.   &
             IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'SD  ')THEN
        ICASLE='EOSS'
      ELSEIF(NUMARG.GE.7.AND.   &
             IHARG(3).EQ.'EXPO' .AND. IHARG(4).EQ.'ORDE' .AND.   &
             IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'STAN' .AND.   &
             IHARG(7).EQ.'DEVI')THEN
        ICASLE='EOSS'
      ELSEIF(NUMARG.GE.4.AND.   &
             IHARG(3).EQ.'EXPO' .AND. IHARG(4).EQ.'SCOR')THEN
        ICASLE='SSCO'
      ELSEIF(NUMARG.GE.4.AND.   &
             IHARG(3).EQ.'SAVA' .AND. IHARG(4).EQ.'SCOR')THEN
        ICASLE='SSCO'
      ELSEIF(NUMARG.GE.6.AND.   &
             IHARG(3).EQ.'LOGI' .AND. IHARG(4).EQ.'ORDE' .AND.   &
             IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'MEAN')THEN
        ICASLE='LOSM'
      ELSEIF(NUMARG.GE.6.AND.   &
             IHARG(3).EQ.'LOGI' .AND. IHARG(4).EQ.'ORDE' .AND.   &
             IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'SD  ')THEN
        ICASLE='LOSS'
      ELSEIF(NUMARG.GE.7.AND.   &
             IHARG(3).EQ.'LOGI' .AND. IHARG(4).EQ.'ORDE' .AND.   &
             IHARG(5).EQ.'STAT' .AND. IHARG(6).EQ.'STAN' .AND.   &
             IHARG(7).EQ.'DEVI')THEN
        ICASLE='LOSS'
      ELSE
        GO TO 2290
      ENDIF
!
      CALL DPOSME(ICASLE,ISUBRO,IBUGA3,IBUGQ,IFOUND,IERROR)
      GO TO 9000
!
 2290 CONTINUE
!
!               *****************************************************
!               **  STEP 2.24--                                    **
!               **  TREAT THE WEIBULL ADJUSTED RANKS SUBCASE  ZZ   **
!               *****************************************************
!
      ISTEPN='2.24'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.5.AND.   &
         IHARG(3).EQ.'WEIB'.AND.IHARG(4).EQ.'ADJU'.AND.   &
         IHARG(5).EQ.'RANK')THEN
        ICASLE='WEAR'
        CALL DPWEAR(TEMP3,XTEMP3,IBUGA3,IBUGQ,IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
!               *************************************************
!               **  STEP 2.25--                                **
!               **  TREAT THE PRIME NUMBER GENERATION SUBCASE  **
!               *************************************************
!
      ISTEPN='2.25'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.4.AND.   &
         IHARG(3).EQ.'PRIM'.AND.IHARG(4).EQ.'NUMB')THEN
        ICASLE='PRIM'
        CALL DPGENS(ICASLE,TEMP3,DTEMP1,ISUBRO,IBUGA3,IBUGQ,   &
                    IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
!               ******************************************************
!               **  STEP 2.26--                                     **
!               **  TREAT THE FIBONNACCI NUMBER GENERATION SUBCASE  **
!               ******************************************************
!
      ISTEPN='2.26'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.4.AND.IHARG(3).EQ.'FIBO'.AND.   &
        (IHARG(4).EQ.'NUMB'.OR.IHARG(4).EQ.'SEQU'))THEN
        ICASLE='FIBO'
        CALL DPGENS(ICASLE,TEMP3,DTEMP1,ISUBRO,IBUGA3,IBUGQ,   &
                    IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING LOGISTIC SECTION WAS ADDED APRIL 1989
!               ******************************************************
!               **  STEP 2.27--                                     **
!               **  TREAT THE LOGISTIC SEQUENCE GENERATION SUBCASE  **
!               ******************************************************
!
      ISTEPN='2.27'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.4.AND.IHARG(3).EQ.'LOGI'.AND.   &
        (IHARG(4).EQ.'NUMB'.OR.IHARG(4).EQ.'SEQU'.OR.   &
         IHARG(4).EQ.'SET '))THEN
        ICASLE='LOGI'
        CALL DPGENS(ICASLE,TEMP3,DTEMP1,ISUBRO,IBUGA3,IBUGQ,   &
                    IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING CANTOR SET SECTION WAS ADDED APRIL 1989
!CCCC NOTE THAT SOME SUCCEEDING SECTIONS WERE RENUMBERED APRIL 1989
!               ******************************************************
!               **  STEP 2.28--                                     **
!               **  TREAT THE CANTOR SET GENERATION SUBCASE         **
!               ******************************************************
!
      ISTEPN='2.28'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.4.AND.IHARG(3).EQ.'CANT'.AND.   &
        (IHARG(4).EQ.'NUMB'.OR.IHARG(4).EQ.'SEQU'.OR.   &
         IHARG(4).EQ.'SET '))THEN
        ICASLE='CANT'
        CALL DPGENS(ICASLE,TEMP3,DTEMP1,ISUBRO,IBUGA3,IBUGQ,   &
                    IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
!               ******************************************************
!               **  STEP 2.29--                                     **
!               **  TREAT THE BERNOULLI  NUMBER GENERATION SUBCASE  **
!               ******************************************************
!
      ISTEPN='2.29'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.4.AND.IHARG(3).EQ.'BERN'.AND.   &
        (IHARG(4).EQ.'NUMB'.OR.IHARG(4).EQ.'SEQU'))THEN
        ICASLE='BERN'
        CALL DPGENS(ICASLE,TEMP3,DTEMP1,ISUBRO,IBUGA3,IBUGQ,   &
                    IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
!
!               ******************************************************
!               **  STEP 2.30--                                     **
!               **  TREAT THE EULER      NUMBER GENERATION SUBCASE  **
!               ******************************************************
!
      ISTEPN='2.30'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.4.AND.IHARG(3).EQ.'EULE'.AND.   &
        (IHARG(4).EQ.'NUMB'.OR.IHARG(4).EQ.'SEQU'))THEN
        ICASLE='EULE'
        CALL DPGENS(ICASLE,TEMP3,DTEMP1,ISUBRO,IBUGA3,IBUGQ,   &
                    IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
!
!               **************************************************
!               **  STEP 2.41--                                 **
!               **  TREAT THE STATISTICAL CALCULATIONS SUBCASE  **
!               **  (INPUT = A VECTOR; OUTPUT = A PARAMETER)    **
!               **************************************************
!
      ISTEPN='2.41'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DPTYP2(IANS,IWIDTH,IHNAME,IHNAM2,NUMNAM,MAXNAM,IBUGA3,   &
                 IUSE,IVALUE,VALUE,IN,   &
                 IFOUNZ,IBEGIN,IEND,   &
                 ITYPE,IHOL,IHOL2,INT1,FLOAT1,IERRO1,   &
                 NUMCL,NUMPL,NUMAOL,ITYW1L,ICAT1L,INLI1L,ITYW2L,   &
                 NUMCR,NUMPR,NUMAOR,ITYW1R,ICAT1R,INLI1R,ITYW2R)
!
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PLET')THEN
        WRITE(ICOUT,3091)
 3091   FORMAT('BEFORE CALL CKARIT')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!CCCC THE FOLLOWING 2 LINES WERE ADDED JANUARY 1988
      CALL CKARIT(IFOUNZ,IBEGIN,IANS,IWIDTH,ICASAR,IBUGA3,ISUBRO)
!CCCC THE FOLLOWING 10 LINES WERE ADDED                 FEBRUARY 1994
!CCCC TO ALLOW DETECTION OF THE                         FEBRUARY 1994
!CCCC    LET A = (TAGUCHI) SN- Y COMMAND      AND THE   FEBRUARY 1994
!CCCC    LET A = (TAGUCHI) SN+ Y COMMAND                FEBRUARY 1994
!
      IF(NUMARG.GE.3)THEN
         IF(IHARG(3).EQ.'SN- ')GO TO 4000
         IF(IHARG(3).EQ.'SN+ ')GO TO 4000
      ENDIF
      IF(NUMARG.GE.4)THEN
         IF(IHARG(3).EQ.'TAGU')THEN
            IF(IHARG(4).EQ.'SN- ')GO TO 4000
            IF(IHARG(4).EQ.'SN+ ')GO TO 4000
         ENDIF
      ENDIF
      IF(NUMARG.GE.6)THEN
         IF(IHARG(3).EQ.'CHI '.AND.IHARG(4).EQ.'SQUA'.AND.   &
            IHARG(5).EQ.'SD  '.AND.IHARG(6).EQ.'TEST')GO TO 4000
      ENDIF
      IF(NUMARG.GE.6)THEN
         IF(IHARG(3).EQ.'ONE '.AND.IHARG(4).EQ.'SAMP'.AND.   &
            IHARG(5).EQ.'T   '.AND.IHARG(6).EQ.'TEST')GO TO 4000
      ENDIF
      IF(NUMARG.GE.7)THEN
         IF(IHARG(3).EQ.'CHI '.AND.IHARG(4).EQ.'SQUA'.AND.   &
            IHARG(5).EQ.'STAN'.AND.IHARG(6).EQ.'DEVI'.AND.   &
            IHARG(7).EQ.'TEST')GO TO 4000
      ENDIF
!CCCC THE FOLLOWING SECTION  WAS  ADDED                 MARCH    2003
!CCCC TO ALLOW DETECTION OF THE HODGES-LEHMAN AND
!CCCC DIFFERENCE OF HODGES-LEHMAN
!
      IF(NUMARG.GE.4)THEN
         IF(IHARG(3).EQ.'HODG'.AND.IHARG(4).EQ.'LEHM')GO TO 4000
      ENDIF
      IF(NUMARG.GE.6)THEN
         IF(IHARG(5).EQ.'HODG'.AND.IHARG(6).EQ.'LEHM')GO TO 4000
      ENDIF
!
      IF(ICASAR.EQ.'YES')GO TO 4190
!
!CCCC THE FOLLOWING LINE WAS ADDED     FEBRUARY 1994
 4000 CONTINUE
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PLET')THEN
        WRITE(ICOUT,4001)
 4001   FORMAT('BEFORE CALL CKSTAT')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      CALL CKSTAT(IBUGA3,IFOUN8,ICASL8,ILOCV,ISTANR,ISTARA)
      IF(IFOUN8.EQ.'YES'.AND.ICASL8.NE.'UNKN'.AND.   &
         ILOCV.GE.1)THEN
        ICASLE='STAT'
        CALL DPSTAC(ICASL8,ILOCV,ISTANR,ISTARA,   &
                    IFOUNZ,IBEGIN,IEND,ITYPE,IHOL,IHOL2,   &
                    INT1,FLOAT1,IERRO1,   &
                    TEMP,TEMP2,TEMP3,XTEMP1,XTEMP2,XTEMP3,   &
                    XTEMP4,XTEMP5,MAXNXT,   &
                    ISEED,ITEMP1,ITEMP2,ITEMP3,ITEMP4,ITEMP5,ITEMP6,   &
                    DTEMP1,DTEMP2,DTEMP3,   &
                    IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
        GO TO 9000
      ENDIF
!
 4190 CONTINUE
!
!               ***************************************
!               **  STEP 2.42--                      **
!               **  TREAT THE INTERPOLATION SUBCASE  **
!               ***************************************
!
      ISTEPN='2.42'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHARG(3).EQ.'INTE'.AND.IHARG2(3).EQ.'RPOL')GO TO 4210
      GO TO 4290
!
 4210 CONTINUE
      DO 4220 I=1,NUMARG
      IF(IHARG(I).EQ.'WRT ')GO TO 4200
 4220 CONTINUE
      GO TO 4290
!
 4200 CONTINUE
      ICASLE='INTR'
      IFOUND='YES'
      ITYPEL='V'
!CCCC CALL DPINTR(ITYPEH,IW21HO,IW22HO,W2HOLD,NWHOLD,
!CCCC1IA,PARAM,IPARN,IPARN2,
!CCCC1IANGLU,IBUGA3,IBUGQ,IBUGCO,IBUGEV,IERROR)
      GO TO 9000
!
 4290 CONTINUE
!
!               ******************************************************
!               **  STEP 2.43--                                     **
!               **  TREAT THE (SIMULATED) EXPERIMENT SUBCASE        **
!               ******************************************************
!
      IF(NUMARG.GE.3.AND.IHARG(3).EQ.'EXPE')GO TO 4310
      GO TO 4390
!
 4310 CONTINUE
!CCCC ICASLE='EXPE'
!CCCC CALL DPEXPE(ICASEX,ITEXEX,IPAGEX,ISEED,
!CCCC1IBUGA3,IBUGQ,IFOUND,IERROR)
!CCCC GO TO 9000
!
 4390 CONTINUE
!
!               *********************************************
!               **  STEP 2.50--                            **
!               **  TREAT THE FUNCTION EVALUATION SUBCASE  **
!               *********************************************
!
      ISTEPN='2.50'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'PLET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASLE='FUNC'
      CALL DPFUEV(ITYPEH,IW21HO,IW22HO,W2HOLD,NWHOLD,   &
                  IA,PARAM,IPARN,IPARN2,   &
                  IFOUNZ,IBEGIN,IEND,ITYPE,IHOL,IHOL2,INT1,   &
                  FLOAT1,IERRO1,   &
                  NUMCL,NUMPL,NUMAOL,ITYW1L,ICAT1L,INLI1L,ITYW2L,   &
                  NUMCR,NUMPR,NUMAOR,ITYW1R,ICAT1R,INLI1R,ITYW2R,   &
                  IANGLU,   &
                  IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,IFOUND,IERROR)
      GO TO 9000
!
!               *********************************
!               **  STEP 80--                  **
!               **  GENERATE AN ERROR MESSAGE  **
!               **  (IF NECESSARY)             **
!               *********************************
!
!8000 CONTINUE
!CCCC IERROR='YES'
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,8071)
!8071 FORMAT('***** ERROR IN DPLET--')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,8072)
!8072 FORMAT('      IMPROPER FORM FOR THE    LET   ',
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC1'COMMAND')
!CCCC WRITE(ICOUT,8073)
!8073 FORMAT('      IMPROPER SYNTAX')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,8074)ICASLE
!8074 FORMAT('      ICASLE = ',A4)
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,8075)
!8075 FORMAT('      THE ENTERED COMMAND LINE IS AS FOLLOWS--')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC IF(IWIDTH.GE.1)WRITE(ICOUT,8076)(IANS(I),I=1,IWIDTH)
!8076 FORMAT('      ',120A1)
!CCCC IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
!CCCC IF(IWIDTH.LE.0)WRITE(ICOUT,8077)
!8077 FORMAT(1X)
!CCCC IF(IWIDTH.LE.0)CALL DPWRST('XXX','BUG ')
!CCCC GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'PLET')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLET--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IANGLU,IFTEXP,ISEED
 9012   FORMAT('IANGLU,IFTEXP,ISEED = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)ICASLE,IMSUBC,IFOUND,IERROR
 9016   FORMAT('ICASLE,IMSUBC,IFOUND,IERROR = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLET
      SUBROUTINE DPLETE(IANS,IWIDTH)
!
!     PURPOSE--GENERATE AN ERROR MESSAGE
!              IN CONNECTION WITH THE LET COMMAND.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--SEPTEMBER 1980.
!     UPDATED         --SEPTEMBER 1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IANS
!
!---------------------------------------------------------------------
!
      DIMENSION IANS(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,101)
  101 FORMAT('***** ERROR (FROM DPLETE) IN DPTYP2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,102)
  102 FORMAT('      ILLEGAL OR UNKNOWN SYNTAX FOR THE LET COMMAND')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,103)(IANS(I),I=1,MIN(80,IWIDTH))
  103 FORMAT('      COMMAND LINE--',80A1)
      CALL DPWRST('XXX','BUG ')
!
      RETURN
      END SUBROUTINE DPLETE
      SUBROUTINE DPLETF(IANGLU,IBUGA2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                        ISFLAG,IFOUND,IERROR)
!
!     PURPOSE--CARRY OUT THE LET FUNCTION COMMAND.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1977.
!     UPDATED         --OCTOBER   1978.
!     UPDATED         --NOVEMBER  1978.
!     UPDATED         --JANUARY   1979.
!     UPDATED         --FEBRUARY  1979.
!     UPDATED         --JUNE      1979.
!     UPDATED         --JULY      1979.
!     UPDATED         --SEPTEMBER 1980.
!     UPDATED         --JUNE      1981.
!     UPDATED         --JULY      1981.
!     UPDATED         --SEPTEMBER 1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --APRIL     1996.  PRESERVE CASE FOR LET STRING
!     UPDATED         --AUGUST    2005.  CODE FOR LET FUNCTION ... = DERIVATIVE
!                                        WAS NOT BEING RECOGNIZED
!     UPDATED         --JUNE      2019.  DPDERV:
!                                        MOVE DIMENSIONING OF REAL,
!                                        INTEGER SCRATCH ARRAYS TO DPLET
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IANGLU
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ICASLF
!
      CHARACTER*4 IFOUNZ
      CHARACTER*4 ITYPE
      CHARACTER*4 IHOL
      CHARACTER*4 IHOL2
      CHARACTER*4 IERRO1
      CHARACTER*4 ITYPEH
      CHARACTER*4 IW21HO
      CHARACTER*4 IW22HO
      CHARACTER*4 IA
      CHARACTER*4 IPARN
      CHARACTER*4 IPARN2
      CHARACTER*4 ITYW1L
      CHARACTER*4 ICAT1L
      CHARACTER*4 INLI1L
      CHARACTER*4 ITYW2L
      CHARACTER*4 ITYW1R
      CHARACTER*4 ICAT1R
      CHARACTER*4 INLI1R
      CHARACTER*4 ITYW2R
!
      CHARACTER*4 ITYPEL
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!CCCC APRIL 1996.  ADD FOLLOWING LINE
      CHARACTER*10 ISFLAG
      CHARACTER*4 ISTEPN
!
      DIMENSION IFOUNZ(30)
      DIMENSION IBEGIN(30)
      DIMENSION IEND(30)
      DIMENSION ITYPE(30)
      DIMENSION IHOL(30)
      DIMENSION IHOL2(30)
      DIMENSION INT1(30)
      DIMENSION FLOAT1(30)
      DIMENSION IERRO1(30)
!
!CCCC DIMENSION ITYPEH(225)
!CCCC DIMENSION IW21HO(225)
!CCCC DIMENSION IW22HO(225)
!CCCC DIMENSION W2HOLD(225)
      DIMENSION ITYPEH(1000)
      DIMENSION IW21HO(1000)
      DIMENSION IW22HO(1000)
      DIMENSION W2HOLD(1000)
!
!     NOTE--THE DIMENSION OF IA SHOULD BE THE SAME AS
!           THE DIMENSION OF IB IN SUBROUTINE COMPIM
!           (THE DIMENSION OF IB IS 1000 (JULY 1986)).
!
!CCCC DIMENSION IA(225)
      DIMENSION IA(1000)
      DIMENSION PARAM(100)
      DIMENSION IPARN(100)
      DIMENSION IPARN2(100)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOZZ.INC'
!
      DIMENSION TEMP1(MAXOBV)
      EQUIVALENCE (GARBAG(1),TEMP1(1))
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLE'
      ISUBN2='TF  '
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IERROR='NO'
!
      ICASLF='UNKN'
!
!     ***** THE FOLLOWING 6 LINES INSERTED AUGUST 1983 *****
!CCCC DO40I=1,225
      DO 40 I=1,1000
      ITYPEH(I)='    '
      IW21HO(I)='    '
      IW22HO(I)='    '
      W2HOLD(I)=0.0
   40 CONTINUE
!
!               ***********************************
!               **  TREAT THE LET FUNCTION CASE  **
!               ***********************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LETF')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLETF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3
   52   FORMAT('IBUGA2,IBUGA3 = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************
!               **  STEP 1--                   **
!               **  CHECK THE INPUT ARGUMENTS  **
!               *********************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LETF')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.3.AND.IHARG(3).EQ.'=   '.AND.   &
      IHARG2(3).EQ.'    ')GO TO 1119
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1111)
 1111 FORMAT('***** ERROR IN DPLETF--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)
 1112 FORMAT('      IMPROPER FORM FOR THE    LET FUNCTION   ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1113)
 1113 FORMAT('      NO EQUAL SIGN FOUND AFTER THE FUNCTION NAME')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1114)
 1114 FORMAT('      THE ENTERED COMMAND LINE IS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,1115)(IANS(I),I=1,MIN(120,IWIDTH))
 1115   FORMAT('      ',120A1)
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IWIDTH.LE.0)THEN
        WRITE(ICOUT,1116)
 1116   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IERROR='YES'
      GO TO 9000
 1119 CONTINUE
!
!     2018/08: IF WE HAVE
!V
!                LET STRING S =
!
!              RETURN A STRING WITH A SINGLE SPACE RATHER
!              THAN AN ERROR.
!
      IF(NUMARG.LE.3)THEN
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1111)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1112)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1123)
!1123   FORMAT('      NOTHING FOUND TO THE RIGHT OF THE EQUAL SIGN')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1114)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   IF(IWIDTH.GE.1)THEN
!CCCC     WRITE(ICOUT,1115)(IANS(I),I=1,MIN(120,IWIDTH))
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC   ELSEIF(IWIDTH.LE.0)THEN
!CCCC     WRITE(ICOUT,1116)
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC   ENDIF
!CCCC   IERROR='YES'
!CCCC   GO TO 9000
        NUMARG=NUMARG+1
        IHARG(NUMARG)='SP()'
        IANSLC(IWIDTH+1)=' '
        IANSLC(IWIDTH+2)='S'
        IANSLC(IWIDTH+3)='P'
        IANSLC(IWIDTH+4)='('
        IANSLC(IWIDTH+5)=')'
        IANS(IWIDTH+1)=' '
        IANS(IWIDTH+2)='S'
        IANS(IWIDTH+3)='P'
        IANS(IWIDTH+4)='('
        IANS(IWIDTH+5)=')'
        IWIDTH=IWIDTH+5
      ENDIF
!
!               *****************************************
!               **  STEP 2--                           **
!               **  BRANCH TO THE APPROPRIATE SUBCASE  **
!               *****************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LETF')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!CCCC FEBRUARY 2003: CHECK WHETHER FUNCTION OR STRING IS
!CCCC BEING CALLED FOR.
!CCCC AUGUST 2005: CHECK FOR 'FUNC' SHOULD BE IN IHARG(1), NOT
!CCCC              NOT IHARG(2)
!
      IF(IHARG(4).EQ.'DERI'.AND.IHARG2(4).EQ.'VATI')THEN
        IF(IHARG(1).EQ.'FUNC')GO TO 1140
      ELSEIF(IHARG(4).EQ.'DIFF'.AND.IHARG2(4).EQ.'EREN')THEN
        IF(IHARG(1).EQ.'FUNC')GO TO 1140
      ELSEIF(IHARG(4).EQ.'PART'.AND.IHARG2(4).EQ.'IAL ')THEN
        IF(IHARG(1).EQ.'FUNC')GO TO 1140
      ENDIF
!
      GO TO 1130
!
!               *********************************************
!               **  STEP 3.1--                             **
!               **  TREAT THE FUNCTION DEFINITION SUBCASE  **
!               *********************************************
!
 1130 CONTINUE
!
      ISTEPN='3.1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LETF')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFOUND='YES'
      ICASLF='DEFI'
!CCCC APRIL 1996.  ADD ISFLAG ARGUMENT
!CCCC CALL DPFUNC(IBUGA3,IERROR)
      CALL DPFUNC(IBUGA3,ISUBRO,IERROR,ISFLAG)
      GO TO 9000
!
!               *********************************************
!               **  STEP 3.2--                             **
!               **  TREAT THE ANALYTIC DERIVATIVE SUBCASE  **
!               *********************************************
!
 1140 CONTINUE
!
      ISTEPN='3.2'
      IF(IBUGA2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IFOUND='YES'
      ICASLF='DERI'
!
      ICASLF='DERI'
      IFOUND='YES'
      ITYPEL='F'
      CALL DPDERV(ITYPEH,IW21HO,IW22HO,W2HOLD,NWHOLD,   &
                  IA,PARAM,IPARN,IPARN2,   &
                  IFOUNZ,IBEGIN,IEND,ITYPE,IHOL,IHOL2,   &
                  INT1,FLOAT1,IERRO1,   &
                  NUMCL,NUMPL,NUMAOL,ITYW1L,ICAT1L,INLI1L,ITYW2L,   &
                  NUMCR,NUMPR,NUMAOR,ITYW1R,ICAT1R,INLI1R,ITYW2R,   &
                  IANGLU,TEMP1,   &
                  IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,IFOUND,IERROR)
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LETF')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLETF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)ICASLF,IFOUND,IERROR
 9015   FORMAT('ICASLF,IFOUND,IERROR = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLETF
      SUBROUTINE DPLETH(IHARG,IARGT,IARG,ARG,NUMARG,PDEFTH,   &
      MAXLEG,PLEGTH,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE THICKNESS FOR A LEGEND.
!              THE THICKNESS FOR LEGEND I WILL BE PLACED
!              IN THE I-TH ELEMENT OF THE REAL
!              VECTOR PLEGTH(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A HOLLERITH VECTOR)
!                     --IARG   (A HOLLERITH VECTOR)
!                     --ARG    (A REAL VECTOR)
!                     --NUMARG
!                     --PDEFTH
!                     --MAXLEG
!     OUTPUT ARGUMENTS--PLEGTH (A REAL VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              THICKNESS FOR LEGEND I.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 COMPUTER SERVICES DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/2
!     ORIGINAL VERSION--JANUARY   1989.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
      DIMENSION ARG(*)
!
      DIMENSION PLEGTH(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)GO TO 1199
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'THIC')GO TO 1110
      IF(NUMARG.GE.2.AND.IHARG(2).EQ.'THIC')GO TO 1140
      GO TO 1199
!
 1110 CONTINUE
      IF(NUMARG.LE.1)GO TO 1120
      IF(IHARG(2).EQ.'ON')GO TO 1120
      IF(IHARG(2).EQ.'OFF')GO TO 1120
      IF(IHARG(2).EQ.'AUTO')GO TO 1120
      IF(IHARG(2).EQ.'DEFA')GO TO 1120
      GO TO 1125
!
 1120 CONTINUE
      PHOLD=PDEFTH
      GO TO 1130
!
 1125 CONTINUE
      PHOLD=ARG(2)
      GO TO 1130
!
 1130 CONTINUE
      IFOUND='YES'
      DO 1135 I=1,MAXLEG
      PLEGTH(I)=PHOLD
 1135 CONTINUE
!
      IF(IFEEDB.EQ.'OFF')GO TO 1139
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1136)PLEGTH(I)
 1136 FORMAT('ALL LEGEND THICKNESSS HAVE JUST BEEN SET TO ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
 1139 CONTINUE
      GO TO 1199
!
 1140 CONTINUE
      IF(IARGT(1).EQ.'NUMB')GO TO 1150
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1141)
 1141 FORMAT('***** ERROR IN DPLETH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1142)
 1142 FORMAT('      IN THE LEGEND ... THICKNESS COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1143)
 1143 FORMAT('      THE LEGEND IS IDENTIFIED BY A NUMBER, AS IN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1144)
 1144 FORMAT('      LEGEND 3 THICKNESS 0.3')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1150 CONTINUE
      I=IARG(1)
      IF(1.LE.I.AND.I.LE.MAXLEG)GO TO 1160
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1151)
 1151 FORMAT('***** ERROR IN DPLETH--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1152)
 1152 FORMAT('      IN THE LEGEND ... THICKNESS COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1153)
 1153 FORMAT('      THE NUMBER OF LEGENDS MUST BE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1154)MAXLEG
 1154 FORMAT('      BETWEEN 1 AND ',I8,' (INCLUSIVELY);')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1155)
 1155 FORMAT('      SUCH WAS NOT THE CASE HERE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1156)I
 1156 FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH ',   &
      'LEGEND.')
      CALL DPWRST('XXX','BUG ')
      GO TO 1199
!
 1160 CONTINUE
      IF(NUMARG.LE.2)GO TO 1170
      IF(IHARG(3).EQ.'ON')GO TO 1170
      IF(IHARG(3).EQ.'OFF')GO TO 1170
      IF(IHARG(3).EQ.'AUTO')GO TO 1170
      IF(IHARG(3).EQ.'DEFA')GO TO 1170
      GO TO 1175
!
 1170 CONTINUE
      PHOLD=PDEFTH
      GO TO 1180
!
 1175 CONTINUE
      PHOLD=ARG(3)
      GO TO 1180
!
 1180 CONTINUE
      IFOUND='YES'
      PLEGTH(I)=PHOLD
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1186)I,PLEGTH(I)
 1186 FORMAT('THE THICKNESS FOR LEGEND ',I8,   &
      ' HAS JUST BEEN SET TO ',E15.7)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 1199
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPLETH
      SUBROUTINE DPLEUN(IHARG,IARGT,IARG,NUMARG,IDEFUZ,   &
      MAXLEG,ILEGUN,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE UNITS FOR A LEGEND (SCREEN OR DATA).
!              THE UNITS FOR LEGEND I WILL BE PLACED IN THE I-TH ELEMENT
!              OF THE HOLLERITH VECTOR ILEGUN(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A HOLLERITH VECTOR)
!                     --IARG   (A HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFUZ
!                     --MAXLEG
!     OUTPUT ARGUMENTS--ILEGUN (A HOLLERITH VECTOR
!                              WHOSE I-TH ELEMENT CONTAINS THE
!                              UNITS FOR LEGEND I.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--99/12
!     ORIGINAL VERSION--DECEMBER  1999.
!     UPDATED         --FEBRUARY  2018. ALLOW SEPARATE SPECIFICATION
!                                       FOR X AND Y AXIS.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
      CHARACTER*4 IDEFUZ
      CHARACTER*4 ILEGUN
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION IARG(*)
!
      DIMENSION ILEGUN(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(NUMARG.EQ.0)GO TO 1199
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'UNIT')THEN
        IF(NUMARG.LE.1 .OR. IHARG(2).EQ.'ON' .OR.   &
           IHARG(2).EQ.'OFF' .OR. IHARG(2).EQ.'AUTO' .OR.   &
           IHARG(2).EQ.'DEFA')THEN
          IHOLD=IDEFUZ
        ELSE
          IHOLD=IHARG(2)
          IF(IHOLD.EQ.'DATA' .OR. IHOLD.EQ.'DD  ')THEN
            IHOLD='DATA'
          ELSEIF(IHOLD.EQ.'SCRE' .OR. IHOLD.EQ.'SS')THEN
            IHOLD='SCRE'
          ELSEIF(IHOLD.EQ.'DS  ')THEN
            IHOLD='DS  '
          ELSEIF(IHOLD.EQ.'SD  ')THEN
            IHOLD='SD  '
          ELSE
            IHOLD='SCRE'
          ENDIF
        ENDIF
!
        IFOUND='YES'
        DO 1135 I=1,MAXLEG
          ILEGUN(I)=IHOLD
 1135   CONTINUE
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
  999     FORMAT(1X)
          CALL DPWRST('XXX','BUG ')
          I=1
          WRITE(ICOUT,1136)ILEGUN(I)
 1136     FORMAT('ALL LEGEND UNITSS HAVE JUST BEEN SET TO ',A4)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      ELSEIF(NUMARG.GE.2.AND.IHARG(2).EQ.'UNIT')THEN
        IF(IARGT(1).NE.'NUMB')THEN
          IERROR='YES'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1141)
 1141     FORMAT('***** ERROR IN LEGEND UNITS--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1142)
 1142     FORMAT('      IN THE LEGEND ... UNITS COMMAND,')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1143)
 1143     FORMAT('      THE LEGEND IS IDENTIFIED BY A NUMBER, AS IN--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1144)
 1144     FORMAT('      LEGEND 3 UNITS DATA')
          CALL DPWRST('XXX','BUG ')
          GO TO 1199
        ENDIF
!
        I=IARG(1)
        IF(I.LT.1 .OR. I.GT.MAXLEG)THEN
          IERROR='YES'
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1141)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1142)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1153)
 1153     FORMAT('      THE NUMBER OF LEGENDS MUST BE ')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1154)MAXLEG
 1154     FORMAT('      BETWEEN 1 AND ',I8,' (INCLUSIVELY);')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1155)
 1155     FORMAT('      SUCH WAS NOT THE CASE HERE--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1156)I
 1156     FORMAT('      A REFERENCE WAS MADE TO THE ',I8,'-TH ',   &
                 'LEGEND.')
          CALL DPWRST('XXX','BUG ')
          GO TO 1199
        ENDIF
!
        IF(NUMARG.LE.2 .OR. IHARG(3).EQ.'ON' .OR.   &
           IHARG(3).EQ.'OFF' .OR. IHARG(3).EQ.'AUTO' .OR.   &
           IHARG(3).EQ.'DEFA')THEN
          IHOLD=IDEFUZ
        ELSE
          IHOLD=IHARG(3)
          IF(IHOLD.EQ.'DATA' .OR. IHOLD.EQ.'DD  ')THEN
            IHOLD='DATA'
          ELSEIF(IHOLD.EQ.'SCRE' .OR. IHOLD.EQ.'SS')THEN
            IHOLD='SCRE'
          ELSEIF(IHOLD.EQ.'DS  ')THEN
            IHOLD='DS  '
          ELSEIF(IHOLD.EQ.'SD  ')THEN
            IHOLD='SD  '
          ELSE
            IHOLD='SCRE'
          ENDIF
        ENDIF
!
        IFOUND='YES'
        ILEGUN(I)=IHOLD
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1186)I,ILEGUN(I)
 1186     FORMAT('THE UNITS FOR LEGEND ',I8,' HAS JUST BEEN SET TO ',A4)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
 1199 CONTINUE
      RETURN
      END SUBROUTINE DPLEUN
      SUBROUTINE DPLF(IHARG,NUMARG,   &
      IDEFLF,   &
      ITEXLF,   &
      IBUGD2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LINE FEED SWITCH (ON OR OFF) FOR
!              TEXT SCRIPT.
!              THE LINE FEED SWITCH WILL BE PLACED
!              IN THE CHARACTER VARIABLE ITEXLF.
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --NUMARG
!                     --IDEFLF
!                     --IBUGD2
!     OUTPUT ARGUMENTS--ITEXLF
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--APRIL     1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IDEFLF
      CHARACTER*4 ITEXLF
      CHARACTER*4 IBUGD2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      IF(IBUGD2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPLF--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IDEFLF
   53 FORMAT('IDEFLF = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)NUMARG
   54 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,NUMARG
      WRITE(ICOUT,56)I,IHARG(I)
   56 FORMAT('I,IHARG(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
   90 CONTINUE
!
!               ********************************
!               **  TREAT THE LINE FEED CASE  **
!               ********************************
!
      IF(NUMARG.LE.0)GO TO 1161
      IF(NUMARG.EQ.1.AND.IHARG(1).EQ.'FEED')GO TO 1161
      IF(IHARG(NUMARG).EQ.'ON')GO TO 1161
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 1162
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1161
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 1165
      GO TO 1170
!
 1161 CONTINUE
      ITEXLF='ON'
      GO TO 1180
!
 1162 CONTINUE
      ITEXLF='OFF'
      GO TO 1180
!
 1165 CONTINUE
      ITEXLF=IDEFLF
      GO TO 1180
!
 1170 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,1171)
 1171 FORMAT('***** ERROR IN DPLF--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1172)
 1172 FORMAT('      ILLEGAL ENTRY FOR LINE FEED ',   &
      'COMMAND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1173)
 1173 FORMAT('      TEST EXAMPLE TO DEMONSTRATE THE ',   &
      'PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1174)
 1174 FORMAT('      SUPPOSE THE THE ANALYST WISHES ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1175)
 1175 FORMAT('      TO HAVE A LINE FEED AFTER THE TEXT ',   &
      'COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1177)
 1177 FORMAT('      THEN ALLOWABLE FORMS ARE--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1178)
 1178 FORMAT('           LINE FEED ON     (OR   LF ON) ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1179)
 1179 FORMAT('           LINE FEED        (OR   LF) ')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1180 CONTINUE
      IFOUND='YES'
!
      IF(IFEEDB.EQ.'OFF')GO TO 1189
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1181)
 1181 FORMAT('THE LINE FEED (AFTER TEXT) ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1182)ITEXLF
 1182 FORMAT('HAS JUST BEEN SET TO ',A4)
      CALL DPWRST('XXX','BUG ')
 1189 CONTINUE
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGD2.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPLF')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGD2,ISUBRO,IFOUND,IERROR
 9012 FORMAT('IBUGD2,ISUBRO,IFOUND,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IDEFLF,ITEXLF
 9013 FORMAT('IDEFLF,ITEXLF = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPLF
      SUBROUTINE DPLIB1(IH,IH2,X,SAVE1,SAVE2,SAVE3,I,IANGLU,   &
                        TERM,IBUGEV,IFOUND,IERROR)
!
!     PURPOSE--PERFORM A LIBRARY FUNCTION EVALUATION.
!     NOTE--THIS IS PART 1
!           (EVALUATE MANY OF THE USUAL FORTRAN LIBRARY FUNCTIONS)
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--JANUARY  1979.
!     UPDATED         --NOVEMBER  1979.
!     UPDATED         --FEBRUARY  1981.
!     UPDATED         --JUNE      1981.
!     UPDATED         --JULY      1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --JULY      1986.
!     UPDATED         --JUNE      1987. FRACT(.)
!     UPDATED         --SEPTEMBER 1987. ROUND(.)
!     UPDATED         --SEPTEMBER 1987. LSD(.)
!     UPDATED         --SEPTEMBER 1988. IND(.) = INDICATOR FUNCTION
!     UPDATED         --OCTOBER   1988. ROUND(.) WITH 2ND ARGUMENT
!     UPDATED         --DECEMBER  1988. LSD(.) RENAMED AS MSD(.)
!     UPDATED         --MARCH     1989. JULIA(.)
!     UPDATED         --MARCH     1989. SAVE3 AS INPUT ARGUMENT (JULIA)
!     UPDATED         --JANUARY   1990. BINPAT(.,.)
!     UPDATED         --FEBRUARY  1993. ARG CHECK FOR ROUND()
!     UPDATED         --JULY      1993. FIX JULIA (ALAN)
!     UPDATED         --SEPTEMBER 1994. ADD BETA, BETAI, LNBETA (FOR
!                                       COMPLETE, INCOMPLETE BETA,
!                                       LOG BETA)
!     UPDATED         --SEPTEMBER 1994. GAMMAI (INCOMPLETE GAMMA)
!     UPDATED         --SEPTEMBER 1994. GAMMAR (RECIPROCAL GAMMA)
!     UPDATED         --SEPTEMBER 1994. DIGAMMA (DIGAMMA)
!     UPDATED         --SEPTEMBER 1994. TRICOMI (TRICOMI GAMMA)
!     UPDATED         --SEPTEMBER 1994. GAMMAIC (COMPLEMENTARY
!                                       INCOMPLETE GAMMA)
!     UPDATED         --SEPTEMBER 1994. POCH (POCHHAMMER GENERALIZED
!                                       SYMBOL)
!     UPDATED         --SEPTEMBER 1994. POCH (POCHHAMMER GENERALIZED
!                                       SYMBOL FIRST ORDER)
!     UPDATED         --SEPTEMBER 1994. CHU (LOG CONFLUENT HYPERGE.)
!     UPDATED         --MARCH     1995. HEAVE (HEAVESIDE FUNCTION)
!     UPDATED         --MARCH     1995. STEP (STEP FUNCTION)
!     UPDATED         --MARCH     1995. CEIL (CEILING FUNCTION)
!     UPDATED         --MARCH     1995. GCD (GREATEST COMMON DIVISOR FUNCTION)
!     UPDATED         --JANUARY   1997. ADD LOGBETA AND LNGAMMA AS
!                                       SYNONYMS
!     UPDATED         --MARCH     1997. ADD LAMBDA, STRUVE FUNCTIONS
!     UPDATED         --JULY      1997. CHM (M CONFLUENT HYPERGEOMETRIC)
!     UPDATED         --AUGUST    1997. CGAMMA, CGAMMAI (COMPLEX GAMMA)
!     UPDATED         --AUGUST    1997. CLNGAM, CLNGAM (COMPLEX LOG GAMMA)
!     UPDATED         --AUGUST    1997. CPSI, CPSII (COMPLEX PSI)
!     UPDATED         --AUGUST    1997. HYPERGEO (HYPERGEOMETRIC)
!     UPDATED         --AUGUST    1997. PARABOLIC CYLINDER FUNCTIONS
!                                       PBDV, PBDV1
!                                       PBVV, PBVV1
!                                       PBWA, PBWA1
!     UPDATED         --AUGUST    1997. CLNBETA, CLNBETAI (COMPLEX
!                                       LOG BETA)
!     UPDATED         --AUGUST    1997. CBETA, CBETAI (COMPLEX BETA)
!     UPDATED         --SEPTEMBER 1997. PSI SYNONYM FOR DIGAMMA
!     UPDATED         --SEPTEMBER 1997. KELVIN FUNCTIONS
!                                       (BER, BERI, BER1, BERI1,
!                                       KER, KERI, KER1, KERI1)
!     UPDATED         --SEPTEMBER 1997. ZETA, ETA, CATLAN BETA
!     UPDATED         --OCTOBER   1997. PSIFN
!     UPDATED         --APRIL     1998. ADD IGACDF, IGAPDF, IGAPPF
!                                       (INVERTED GAMMA)
!     UPDATED         --APRIL     1998. ADD SUPPORT FOR LOCATION AND
!                                       SCALE PARAMETERS WHERE
!                                       APPROPRIATE FOR CDF, PDF,
!                                       PPF, AND SF FUNCTIONS
!     UPDATED         --MAY       2002. FERMDIRA
!     UPDATED         --MAY       2006. HARMNUMB
!     UPDATED         --DECEMBER  2010. MERGE, MERGE3
!     UPDATED         --DECEMBER  2010. RELDIF, PERCDIF
!     UPDATED         --JANUARY   2011. RELERR, PERCERR
!     UPDATED         --MAY       2014. FIX TO ROUND FUNCTION
!     UPDATED         --AUGUST    2015. RECODED A BIT TO SIMPLIFY
!     UPDATED         --AUGUST    2015. BINOCTAL, BINDEC
!     UPDATED         --AUGUST    2015. OCTALBIN, DECBIN
!     UPDATED         --AUGUST    2018. CORRECTED FORMULA FOR SIGN
!                                       FUNCTION
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IANGLU
      CHARACTER*4 IBUGEV
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISIGN
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!     FOLLOWING SECTION ADDED SEPTEMBER 1994.
!
      DOUBLE PRECISION DTEMP1(1000)
      DOUBLE PRECISION DTEMP2(1000)
!CCCC DOUBLE PRECISION DTERM
      DOUBLE PRECISION DRESLT
      DOUBLE PRECISION DRSLT2
      DOUBLE PRECISION DRSLT3
      DOUBLE PRECISION DRSLT4
      DOUBLE PRECISION DRSLT5
      DOUBLE PRECISION DRSLT6
      DOUBLE PRECISION DRSLT7
      DOUBLE PRECISION DRSLT8
      DOUBLE PRECISION DARG1
      DOUBLE PRECISION DARG2
      DOUBLE PRECISION DARG3
      DOUBLE PRECISION DARG4
      DOUBLE PRECISION DBETAI
      DOUBLE PRECISION DBETA
      DOUBLE PRECISION DLBETA
      DOUBLE PRECISION DGAMMA
      DOUBLE PRECISION DGAMI
      DOUBLE PRECISION DGAMR
      DOUBLE PRECISION DGAMIP
      DOUBLE PRECISION DGAMIC
      DOUBLE PRECISION DGAMIT
      DOUBLE PRECISION DPOCH
      DOUBLE PRECISION DPOCH1
      DOUBLE PRECISION DPSI
      DOUBLE PRECISION DCHU
      DOUBLE PRECISION FDM0P5
      DOUBLE PRECISION FDP0P5
      DOUBLE PRECISION FDP1P5
      DOUBLE PRECISION FDP2P5
!
!     FOLLOWING SECTION ADDED AUGUST 1997
!
      COMPLEX ZRESLT
      COMPLEX ZARG
      COMPLEX CPSI
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.1415926536/
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      ISUBN1='DPLI'
      ISUBN2='B1  '
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF DPLIB1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IH,IH2,IBUGEV,IANGU,X
   52   FORMAT('IH,IH2,IBUGEV,IANGU,X = ',4(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)SAVE1,SAVE2,SAVE3
   53   FORMAT('SAVE1,SAVE2,SAVE3 = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IFOUND='YES'
!
      IF(IH.EQ.'SQRT'.AND.IH2.EQ.'    ')THEN
        IF(X.LT.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1501)
 1501     FORMAT('***** ERROR IN DPLIB1--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1601)
 1601     FORMAT('      ATTEMPT TO TAKE SQUARE ROOT OF NEGATIVE NUMBER')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1701)X
 1701     FORMAT('      THE NEGATIVE NUMBER = ',E15.7)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
        ELSEIF(X.EQ.0.0)THEN
          TERM=X
        ELSE
          TERM=SQRT(X)
        ENDIF
      ELSEIF(IH.EQ.'EXP '.AND.IH2.EQ.'    ')THEN
        ARG=X
        CUTUPP=LOG(CPUMAX)
        CUTLOW=LOG(TINY(1.0D0))
        IF(ARG.GE.CUTUPP)THEN
          TERM=CPUMAX
        ELSEIF(ARG.LT.CUTLOW)THEN
          TERM=0.0
        ELSE
          TERM=EXP(ARG)
        ENDIF
      ELSEIF((IH.EQ.'LN  '.AND.IH2.EQ.'    ') .OR.   &
             (IH.EQ.'LOG '.AND.IH2.EQ.'    ') .OR.   &
             (IH.EQ.'LOGE'.AND.IH2.EQ.'    ') .OR.   &
             (IH.EQ.'LOG'.AND.IH2.EQ.'    ')  .OR.   &
             (IH.EQ.'LOG'.AND.IH2.EQ.'E   '))THEN
        IF(X.GT.0.0)THEN
          TERM=LOG(X)
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1501)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1603)
 1603     FORMAT('      ATTEMPT TO TAKE LOG OF NON-POSITIVE NUMBER')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1703)X
 1703     FORMAT('      THE NON-POSITIVE NUMBER = ',E15.7)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
        ENDIF
      ELSEIF((IH.EQ.'LOG1'.AND.IH2.EQ.'0   ') .OR.   &
             (IH.EQ.'LOG'.AND.IH2.EQ.'10  '))THEN
        IF(X.GT.0.0)THEN
          TERM=LOG10(X)
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1501)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1603)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1703)X
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
        ENDIF
      ELSEIF(IH.EQ.'LOG2'.AND.IH2.EQ.'    ')THEN
        IF(X.GT.0.0)THEN
          TERM=LOG(X)/LOG(2.0)
        ELSE
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1501)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1603)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1703)X
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
        ENDIF
      ELSEIF(IH.EQ.'ATAN'.AND.IH2.EQ.'    ')THEN
        ARG=X
        RESULT=ATAN(ARG)
        IF(IANGLU.EQ.'DEGR')RESULT=(180.0/PI)*RESULT
        IF(IANGLU.EQ.'GRAD')RESULT=(200.0/PI)*RESULT
        TERM=RESULT
      ELSEIF(IH.EQ.'ATAN'.AND.IH2.EQ.'2   ')THEN
        ARG1=X
        ARG2=SAVE1
        RESULT=ATAN2(ARG1,ARG2)
        TERM=RESULT
      ELSEIF(IH.EQ.'ABS '.AND.IH2.EQ.'    ')THEN
        TERM=ABS(X)
      ELSEIF((IH.EQ.'AINT'.AND.IH2.EQ.'    ') .OR.   &
             (IH.EQ.'INT '.AND.IH2.EQ.'    ') .OR.   &
             (IH.EQ.'INTE'.AND.IH2.EQ.'GER '))THEN
        TERM=AINT(X)
      ELSEIF((IH.EQ.'AMOD'.AND.IH2.EQ.'    ') .OR.   &
             (IH.EQ.'MOD '.AND.IH2.EQ.'    ') .OR.   &
             (IH.EQ.'MODU'.AND.IH2.EQ.'LO  '))THEN
        TERM=AMOD(X,SAVE1)
      ELSEIF(IH.EQ.'SIGN'.AND.IH2.EQ.'    ')THEN
        IF(X.LT.0.0)THEN
          TERM=-1.0
        ELSEIF(X.GT.0.0)THEN
          TERM=1.0
        ELSE
          TERM=0.
        ENDIF
      ELSEIF(IH.EQ.'FRAC'.AND.IH2.EQ.'T   ')THEN
        TERM=X-AINT(X)
        TERM=ABS(TERM)
      ELSEIF(IH.EQ.'MSD '.AND.IH2.EQ.'    ')THEN
        TERM=ABS(X)
        DO 1515 I=1,1000
          IF(TERM.GT.10.0)TERM=TERM/10.0
          IF(TERM.LT.1.0)TERM=TERM*10.0
          IF(1.0.LE.TERM.AND.TERM.LE.10.0)GO TO 1615
 1515   CONTINUE
 1615   CONTINUE
        TERM=AINT(TERM)
      ELSEIF(IH.EQ.'ROUN'.AND.IH2.EQ.'D   ')THEN
!CCCC   THE FOLLOWING ERROR CHECK SECTION WAS ADDED FEBRUARY 1993
        IF(SAVE1.LT.-10.0 .OR. SAVE1.GT.10.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1501)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2102)
 2102     FORMAT('      INVALID (OR NON-EXISTENT) SECOND ARGUMENT')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2103)
 2103     FORMAT('      FOR THE    ROUND(..,..)    FUNCTION')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2104)
 2104     FORMAT('      EXAMPLE OF PROPER FORM--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2105)
 2105     FORMAT('      LET Y2=ROUND(Y,3) TO ROUND TO 3 DEC. PLACES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2106)
 2106     FORMAT('      LET Y2=ROUND(Y,0) TO ROUND TO 0 DEC. PLACES')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
        ENDIF
!CCCC   IF(X.GE.0.0)TERM=AINT(X+0.5)
!CCCC   IF(X.LT.0.0)TERM=AINT(X-0.5)
!
!       2014/05: ALGORITHM BELOW DID NOT WORK CORRECTLY FOR INTEL 64-BIT
!                COMPILER UNDER WINDOWS.  USE A DIFFERENT ALGORITHM.
!
!CCCC   ABSX=ABS(X)
!CCCC   IPOWER=0
!CCCC   IF(SAVE1.GT.0.0)IPOWER=AINT(SAVE1+0.5)
!CCCC   AMULT=10.0**IPOWER
!CCCC   TEMP2=ABSX*AMULT
!CCCC   TEMP3=AINT(TEMP2+0.5)
!CCCC   TEMP4=TEMP3/AMULT
!CCCC   TERM=TEMP4
!CCCC   IF(X.LT.0.0)TERM=(-TEMP4)
        ABSX=ABS(X)
        IF(SAVE1.LT.0.0)SAVE1=0.0
        IPOWER=INT(AINT(SAVE1+0.5))
        TERM=FLOAT(INT(ABSX*10**IPOWER + 0.5))/10**IPOWER
        IF(X.LT.0.0)TERM=-TERM
      ELSEIF(IH.EQ.'IND '.AND.IH2.EQ.'    ')THEN
        TERM=0.0
        IF(ABS(SAVE1).EQ.0.0)EPS=0.000001
        IF(ABS(SAVE1).NE.0.0)EPS=ABS(SAVE1*0.000001)
        ALOWER=SAVE1-EPS
        AUPPER=SAVE1+EPS
        IF(ALOWER.LE.X.AND.X.LE.AUPPER)TERM=1.0
      ELSEIF((IH.EQ.'OCTA'.AND.IH2.EQ.'L   ') .OR.   &
            (IH.EQ.'OCTD'.AND.IH2.EQ.'EC  '))THEN
        IBASE1=8
        IBASE2=10
        GO TO 8010
      ELSEIF(IH.EQ.'DECO'.AND.IH2.EQ.'CT  ')THEN
        IBASE1=10
        IBASE2=8
        GO TO 8010
      ELSEIF(IH.EQ.'BIND'.AND.IH2.EQ.'EC  ')THEN
        IBASE1=2
        IBASE2=10
        GO TO 8010
      ELSEIF((IH.EQ.'BINO'.AND.IH2.EQ.'CTAL') .OR.   &
             (IH.EQ.'BINO' .AND. IH2.EQ.'CT'))THEN
!
        IBASE1=2
        IBASE2=10
        ARG=X
        IX=INT(ARG+0.5)
        ISIGN='+'
        IF(IX.LT.0)ISIGN='-'
        ISUM=0
        DO 435 IBIT=1,NUMBPW
          INEWX=IX/IBASE2
          IDIG=IX-IBASE2*INEWX
          ISUM=ISUM+IDIG*IBASE1**(IBIT-1)
          IF(INEWX.LE.0)GO TO 436
          IX=INEWX
  435   CONTINUE
  436   CONTINUE
        IF(ISIGN.EQ.'-')ISUM=-ISUM
        X=ISUM
!
        IBASE1=10
        IBASE2=8
        GO TO 8010
      ELSEIF(IH.EQ.'DECB'.AND.IH2.EQ.'IN  ')THEN
        IBASE1=10
        IBASE2=2
        GO TO 8010
      ELSEIF((IH.EQ.'OCTA'.AND.IH2.EQ.'LBIN') .OR.   &
             (IH.EQ.'OCTB'.AND.IH2.EQ.'IN  '))THEN
        IBASE1=8
        IBASE2=10
        ARG=X
        IX=INT(ARG+0.5)
        ISIGN='+'
        IF(IX.LT.0)ISIGN='-'
        ISUM=0
        DO 445 IBIT=1,NUMBPW
          INEWX=IX/IBASE2
          IDIG=IX-IBASE2*INEWX
          ISUM=ISUM+IDIG*IBASE1**(IBIT-1)
          IF(INEWX.LE.0)GO TO 446
          IX=INEWX
  445   CONTINUE
  446   CONTINUE
        IF(ISIGN.EQ.'-')ISUM=-ISUM
        X=ISUM
!
        IBASE1=10
        IBASE2=2
        GO TO 8010
      ELSEIF(IH.EQ.'ERF '.AND.IH2.EQ.'    ')THEN
!CCCC   DARG1=DBLE(X)*DSQRT(2.0D0)
!CCCC   CALL NODCDF(DARG1,DRESLT)
!CCCC   DTERM=2.0D0*DRESLT-1.0D0
!CCCC   TERM=REAL(DTERM)
        DARG1=DBLE(X)
        TERM=REAL(ERFDP(DARG1))
      ELSEIF(IH.EQ.'ERFC'.AND.IH2.EQ.'    ')THEN
!CCCC   DARG1=DBLE(X)*DSQRT(2.0D0)
!CCCC   CALL NODCDF(DARG1,DRESLT)
!CCCC   DTERM=2.0D0*DRESLT-1.0D0
!CCCC   DTERM=1.0D0-DTERM
!CCCC   TERM=REAL(DTERM)
        DARG1=DBLE(X)
        IND=0
        TERM=REAL(ERFC1(IND,DARG1))
      ELSEIF(IH.EQ.'GAMM'.AND.IH2.EQ.'A   ')THEN
        DARG1=DBLE(X)
!CCCC   CALL GAMMAF(ARG,TERM)
        DRESLT=DGAMMA(DARG1)
        TERM=REAL(DRESLT)
      ELSEIF((IH.EQ.'LOGG'.AND.IH2.EQ.'AMMA') .OR.   &
        (IH.EQ.'LNGA'.AND.IH2.EQ.'MMA '))THEN
        ARG=X
        CALL LOGGAM(ARG,TERM)
      ELSEIF(IH.EQ.'DIM '.AND.IH2.EQ.'    ')THEN
        TERM=0.0
        IF(SAVE1.LT.X)TERM=X-SAVE1
      ELSEIF(IH.EQ.'JULI'.AND.IH2.EQ.'A   ')THEN
!CCCC   THE FOLLOWING SECTION (JULIA) WAS ADDED MARCH 1989
        XCALC=X
        YCALC=SAVE1
        X0=SAVE2
        Y0=SAVE3
        IMAX=100
        ICOUNT=0
        CUT=10.0**6
        DO 511 I=1,IMAX
          ICOUNT=ICOUNT+1
!CCCC     THE FOLLOWING LINE WAS ADDED JULY 1993 (ALAN)
          XTEMP=XCALC
          XCALC=XCALC**2-YCALC**2+X0
!CCCC     THE FOLLOWING LINE WAS FIXED JULY 1993 (ALAN)
!CCCC     YCALC=2.0*XCALC*YCALC+Y0
          YCALC=2.0*XTEMP*YCALC+Y0
          IF(ABS(XCALC).GT.CUT)GO TO 515
          IF(ABS(YCALC).GT.CUT)GO TO 515
  511   CONTINUE
  515   CONTINUE
        TERM=ICOUNT
      ELSEIF(IH.EQ.'BINP'.AND.IH2.EQ.'AT  ')THEN
!CCCC   THE FOLLOWING SECTION (BINPAT(X,K)) WAS ADDED JANUARY 1990
!CCCC   BINPAT WILL OUTPUT A -1 OR +1
        IX=INT(X+0.1)
        ISAVE=INT(SAVE1+0.1)
        IMOD=2**ISAVE
        IMOD2=IMOD/2
        IX2=MOD(IX,IMOD)
        IF(IX2.EQ.0)IX2=IMOD
        IX3=1
        IF(IX2.LE.IMOD2)IX3=(-1)
        TERM=REAL(IX3)
      ELSEIF(IH.EQ.'BETA'.AND.IH2.EQ.'    ')THEN
        DARG1=DBLE(X)
        DARG2=DBLE(SAVE1)
        DRESLT=DBETA(DARG1,DARG2)
        TERM=REAL(DRESLT)
      ELSEIF(IH.EQ.'BETA'.AND.IH2.EQ.'I   ')THEN
        DARG1=DBLE(X)
        DARG2=DBLE(SAVE1)
        DARG3=DBLE(SAVE2)
        DRESLT=DBETAI(DARG1,DARG2,DARG3)
        TERM=REAL(DRESLT)
      ELSEIF((IH.EQ.'LNBE'.AND.IH2.EQ.'TA  ') .OR.   &
             (IH.EQ.'LOGB'.AND.IH2.EQ.'ETA '))THEN
        DARG1=DBLE(X)
        DARG2=DBLE(SAVE1)
        DRESLT=DLBETA(DARG1,DARG2)
        TERM=REAL(DRESLT)
      ELSEIF(IH.EQ.'GAMM'.AND.IH2.EQ.'AI  ')THEN
        DARG2=DBLE(X)
        DARG1=DBLE(SAVE1)
        DRESLT=DGAMI(DARG1,DARG2)
        TERM=REAL(DRESLT)
      ELSEIF(IH.EQ.'GAMM'.AND.IH2.EQ.'AIP ')THEN
        DARG2=DBLE(X)
        DARG1=DBLE(SAVE1)
        DRESLT=DGAMIP(DARG1,DARG2)
        TERM=REAL(DRESLT)
      ELSEIF(IH.EQ.'GAMM'.AND.IH2.EQ.'AIC ')THEN
        DARG2=DBLE(X)
        DARG1=DBLE(SAVE1)
        DRESLT=DGAMIC(DARG1,DARG2)
        TERM=REAL(DRESLT)
      ELSEIF(IH.EQ.'GAMM'.AND.IH2.EQ.'AR  ')THEN
