      ELSEIF(IH.EQ.'BERI'.AND.IH2.EQ.'    ')THEN
        DARG1=DBLE(X)
        IF(DARG1.LT.0.D0)THEN
          WRITE(ICOUT,1122)
 1122     FORMAT('***** ERROR FROM BERI: ARGUMENT MUST BE GREATER ',   &
                 'THAN OR EQUAL TO ZERO.')
          CALL DPWRST('XXX','BUG ')
          TERM=0.0
        ELSE
          CALL KLVNA(DARG1,DRESLT,DRSLT2,DRSLT3,DRSLT4,DRSLT5,   &
                     DRSLT6,DRSLT7,DRSLT8)
          TERM=SNGL(DRSLT2)
        ENDIF
      ELSEIF(IH.EQ.'BER1'.AND.IH2.EQ.'    ')THEN
        DARG1=DBLE(X)
        IF(DARG1.LT.0.D0)THEN
          WRITE(ICOUT,1132)
 1132     FORMAT('***** ERROR FROM BER1: ARGUMENT MUST BE GREATER ',   &
                 'THAN OR EQUAL TO ZERO.')
          CALL DPWRST('XXX','BUG ')
          TERM=0.0
        ELSE
          CALL KLVNA(DARG1,DRESLT,DRSLT2,DRSLT3,DRSLT4,DRSLT5,   &
                     DRSLT6,DRSLT7,DRSLT8)
          TERM=SNGL(DRSLT5)
        ENDIF
      ELSEIF(IH.EQ.'BERI'.AND.IH2.EQ.'1   ')THEN
        DARG1=DBLE(X)
        IF(DARG1.LT.0.D0)THEN
          WRITE(ICOUT,1142)
 1142     FORMAT('***** ERROR FROM BERI1: ARGUMENT MUST BE GREATER ',   &
                 'THAN OR EQUAL TO ZERO.')
          CALL DPWRST('XXX','BUG ')
          TERM=0.0
        ELSE
          CALL KLVNA(DARG1,DRESLT,DRSLT2,DRSLT3,DRSLT4,DRSLT5,   &
                     DRSLT6,DRSLT7,DRSLT8)
          TERM=SNGL(DRSLT6)
        ENDIF
      ELSEIF(IH.EQ.'KER '.AND.IH2.EQ.'    ')THEN
        DARG1=DBLE(X)
        IF(DARG1.LE.0.D0)THEN
          WRITE(ICOUT,1152)
 1152     FORMAT('***** ERROR FROM KER: ARGUMENT MUST BE POSITIVE ')
          CALL DPWRST('XXX','BUG ')
          TERM=0.0
        ELSE
          CALL KLVNA(DARG1,DRESLT,DRSLT2,DRSLT3,DRSLT4,DRSLT5,   &
                     DRSLT6,DRSLT7,DRSLT8)
          TERM=SNGL(DRSLT3)
        ENDIF
      ELSEIF(IH.EQ.'KERI'.AND.IH2.EQ.'    ')THEN
        DARG1=DBLE(X)
        IF(DARG1.LT.0.D0)THEN
          WRITE(ICOUT,1162)
 1162     FORMAT('***** ERROR FROM KERI: ARGUMENT MUST BE GREATER ',   &
                 'THAN OR EQUAL TO ZERO.')
          CALL DPWRST('XXX','BUG ')
          TERM=0.0
        ELSE
          CALL KLVNA(DARG1,DRESLT,DRSLT2,DRSLT3,DRSLT4,DRSLT5,   &
                     DRSLT6,DRSLT7,DRSLT8)
          TERM=SNGL(DRSLT4)
        ENDIF
      ELSEIF(IH.EQ.'KER1'.AND.IH2.EQ.'    ')THEN
        DARG1=DBLE(X)
        IF(DARG1.LE.0.D0)THEN
          WRITE(ICOUT,1172)
 1172     FORMAT('***** ERROR FROM KER1: ARGUMENT MUST BE POSITIVE ')
          CALL DPWRST('XXX','BUG ')
          TERM=0.0
        ELSE
          CALL KLVNA(DARG1,DRESLT,DRSLT2,DRSLT3,DRSLT4,DRSLT5,   &
                     DRSLT6,DRSLT7,DRSLT8)
          TERM=SNGL(DRSLT7)
        ENDIF
      ELSEIF(IH.EQ.'KERI'.AND.IH2.EQ.'1   ')THEN
        DARG1=DBLE(X)
        IF(DARG1.LT.0.D0)THEN
          WRITE(ICOUT,1182)
 1182     FORMAT('***** ERROR FROM KERI1: ARGUMENT MUST BE GREATER ',   &
                 'THAN OR EQUAL TO ZERO.')
          CALL DPWRST('XXX','BUG ')
          TERM=0.0
        ELSE
          CALL KLVNA(DARG1,DRESLT,DRSLT2,DRSLT3,DRSLT4,DRSLT5,   &
                     DRSLT6,DRSLT7,DRSLT8)
          TERM=SNGL(DRSLT8)
        ENDIF
      ELSEIF(IH.EQ.'ETA '.AND.IH2.EQ.'    ')THEN
        DARG1=DBLE(X)
        IF(DARG1.LT.1.0D0)THEN
          WRITE(ICOUT,1191)
          CALL DPWRST('XXX','BUG ')
          TERM=0.0
 1191     FORMAT('***** ERROR: ARGUMENT FOR ETA FUNCTION MUST ',   &
                 'BE > 1')
        ELSEIF(DARG1.EQ.1.0D0)THEN
          TERM=-0.30685281944
        ELSE
          CALL ZETA(DARG1,DRESLT)
          DARG2=2.0D0**(1.0D0-DARG1)
          DRSLT2=(1.0D0-DARG2)*DRESLT - DARG2
          TERM=SNGL(DRSLT2)
        ENDIF
      ELSEIF(IH.EQ.'CATL'.AND.IH2.EQ.'AN  ')THEN
        DARG1=DBLE(X)
        IF(DARG1.LT.1.0D0)THEN
          WRITE(ICOUT,1201)
          CALL DPWRST('XXX','BUG ')
          TERM=0.0
 1201     FORMAT('***** ERROR: ARGUMENT FOR CATLAN FUNCTION MUST ',   &
                 'BE >= 1')
        ENDIF
        CALL CATLAN(DARG1,DRESLT)
        TERM=SNGL(DRESLT)
      ELSEIF(IH.EQ.'FERM'.AND.IH2.EQ.'DIRA')THEN
        DARG1=DBLE(X)
        ARG2=SAVE1
        IF(ABS(ARG2 - (-0.5)).LE.0.01)THEN
          DRESLT=FDM0P5(DARG1)
        ELSEIF(ABS(ARG2 - 0.5).LE.0.01)THEN
          DRESLT=FDP0P5(DARG1)
        ELSEIF(ABS(ARG2 - 1.5).LE.0.01)THEN
          DRESLT=FDP1P5(DARG1)
        ELSEIF(ABS(ARG2 - 2.5).LE.0.01)THEN
          DRESLT=FDP2P5(DARG1)
        ELSE
          WRITE(ICOUT,1211)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1213)ARG2
          CALL DPWRST('XXX','BUG ')
          TERM=0.0
          GO TO 9000
 1211     FORMAT('***** ERROR: ORDER FOR FERMDIRA FUNCTION MUST BE ',   &
                 '-0.5, 0.5, 1.5, OR 2.5.')
 1213     FORMAT('      REQUESTED ORDER IS ',E15.7)
        ENDIF
        IF(DRESLT.GE.DBLE(CPUMAX))THEN
          WRITE(ICOUT,1216)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1218)REAL(DARG1)
          CALL DPWRST('XXX','BUG ')
          TERM=CPUMAX
 1216     FORMAT('***** ERROR: RESULT FOR FERMDIRA FUNCTION OVERFLOWS ',   &
                'MAXIMUM ALLOWED.')
 1218     FORMAT('      X = ',E15.7)
        ELSE
          TERM=REAL(DRESLT)
        ENDIF
      ELSEIF(IH.EQ.'HARM'.AND.IH2.EQ.'NUMB')THEN
        IARG1=INT(X + 0.5)
        DARG2=DBLE(SAVE1)
        IF(DARG2.LT.0.0D0)THEN
          CALL HN(IARG1,DRESLT)
        ELSE
          CALL HNM(IARG1,DARG2,DRESLT)
        ENDIF
        TERM=REAL(DRESLT)
      ELSEIF(IH.EQ.'MERG'.AND.IH2.EQ.'E   ')THEN
        IF(SAVE2.LE.0.0)THEN
          TERM=X
        ELSE
          TERM=SAVE1
        ENDIF
      ELSEIF(IH.EQ.'MERG'.AND.IH2.EQ.'E3  ')THEN
        IF(SAVE3.LT.0.0)THEN
          TERM=X
        ELSEIF(SAVE3.GT.0.0)THEN
          TERM=SAVE2
        ELSE
          TERM=SAVE1
        ENDIF
      ELSEIF(IH.EQ.'RELD'.AND.IH2.EQ.'IF  ')THEN
        TERM=ABS(X - SAVE1)/MAX(ABS(X),ABS(SAVE1))
      ELSEIF(IH.EQ.'RELD'.AND.IH2.EQ.'IF2 ')THEN
        TERM1=X - SAVE1
        TERM2=(X + SAVE1)/2.0
        TERM=ABS(TERM1/TERM2)
      ELSEIF(IH.EQ.'RELE'.AND.IH2.EQ.'RR  ')THEN
        TERM=(X - SAVE1)/X
      ELSEIF(IH.EQ.'PERC'.AND.IH2.EQ.'DIF ')THEN
        TERM=100.0*ABS(X - SAVE1)/MAX(ABS(X),ABS(SAVE1))
      ELSEIF(IH.EQ.'PERC'.AND.IH2.EQ.'DIF2')THEN
        TERM1=X - SAVE1
        TERM2=(X + SAVE1)/2.0
        TERM=ABS(TERM1/TERM2)*100.0
      ELSEIF(IH.EQ.'PERC'.AND.IH2.EQ.'ERR ')THEN
        TERM=((X - SAVE1)/X)*100.0
      ELSE
        IFOUND='NO'
      ENDIF
      GO TO 9000
!
 8010 CONTINUE
!
!     BASE CONVERSION FOR BINARY, OCTAL, DECIMAL
!
      ARG=X
      IX=INT(ARG+0.5)
      ISIGN='+'
      IF(IX.LT.0)ISIGN='-'
      ISUM=0
      DO 425 IBIT=1,NUMBPW
        INEWX=IX/IBASE2
        IDIG=IX-IBASE2*INEWX
        ISUM=ISUM+IDIG*IBASE1**(IBIT-1)
        IF(INEWX.LE.0)GO TO 426
        IX=INEWX
  425 CONTINUE
  426 CONTINUE
      IF(ISIGN.EQ.'-')ISUM=-ISUM
      TERM=ISUM
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('AT THE END       OF DPLIB1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)IFOUND,IERROR,TERM
 9015   FORMAT('IFOUND,IERROR,TERM = ',2(A4,2X),G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLIB1
      SUBROUTINE DPLIB2(IH,IH2,X,SAVE1,SAVE2,IANGLU,   &
                        TERM,IBUGEV,IFOUND,IERROR)
!
!     PURPOSE--PERFORM A LIBRARY FUNCTION EVALUATION.
!     NOTE--THIS IS PART 2
!          (EVALUATE TRIGONOMETRIC FUNCTIONS)
!
!     NOTE--DOMAIN OF TRIG ARGUMENT (JULY 1988)
!
!     SIN(X)       -INF < X < INF
!     COS(X)       -INF < X < INF
!     TAN(X)       NOT +-PI/2  +-3PI/2  +-5PI/2  ... (WHENEVER COS IS 0)
!     COT(X)       NOT 0  +-PI  +-2PI  +-3PI  ...    (WHENEVER SIN IS 0)
!     SEC(X)       NOT +-PI/2  +-3PI/2  +-5PI/2  ... (WHENEVER COS IS 0)
!     CSC(X)       NOT 0  +-PI  +-2PI  +-3PI  ...    (WHENEVER SIN IS 0)
!
!     ARCSIN(X)    -1 <= X <= 1      YIELDING -PI/2 <= Y <= PI/2 (PRIN. BR.)
!     ARCCOS(X)    -1 <= X <= 1      YIELDING 0 <= Y <= PI (PRIN. BR.)
!     ARCTAN(X)    -INF < X < INF    YIELDING -PI/2 < Y < PI/2 (PRIN BR.)
!     ARCCOT(X)    -INF < X < INF    YIELDING 0 < X < PI/2 (PRIN. BR.)
!     ARCSEC(X)    X>= 1   X <= -1   YIELDING 0 <= Y < PI/2   -PI <= X < -PI/2 (
!                                    COMPUTED YIELDS 0 <= Y < PI/2   PI/2 < Y <=
!     ARCCSC(X)    X>= 1   X <= -1   YIELDING 0 < Y <= PI/2    -PI < Y <= -PI/2
!                                    COMPUTED YIELDS 0 <= Y < PI/2   -PI/2 <= Y
!
!     SINH(X)      -INF < X < INF
!     COSH(X)      0 <= X < INF
!     TANH(X)      0 <= X < INF
!     COTH(X)      0 < X < INF
!     SECH(X)      0 <= X < INF
!     CSCH(X)      X NOT= 0 ?
!
!     ARCSINH(X)   -INF < X < INF
!     ARCCOSH(X)   X >= 1
!     ARCTANH(X)   -1 < X < 1
!     ARCCOTH(X)   X > 1   X < -1
!     ARCSECH(X)   0 < X <= 1
!     ARCCSCH(X)   X NOT= 0
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--JANUARY  1979.
!     UPDATED         --NOVEMBER  1979.
!     UPDATED         --FEBRUARY  1981.
!     UPDATED         --JUNE      1981.
!     UPDATED         --JULY      1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --JULY      1988.  (HEAVY RENUMBERING + 0-DIVIDE CHECKS
!                                        + PROPER DOMAIN CHECKS)
!     UPDATED         --JANUARY   1989.  ASYMPTOTIC TRAPS FOR HYP TRIG FUNC
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IANGLU
      CHARACTER*4 IBUGEV
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA PI/3.1415926536/
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
      ISUBN1='DPLI'
      ISUBN2='B1  '
!
      RESULT=0.0
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF DPLIB2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IH,IH2,IBUGEV,IANGLU
   52   FORMAT('IH,IH2,IBUGEV,IANGLU,X = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)X,SAVE1,SAVE2
   53   FORMAT('X,SAVE1,SAVE2 = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IFOUND='YES'
!
      IF(IH.EQ.'SIN '.AND.IH2.EQ.'    ')GO TO 1100
      IF(IH.EQ.'COS '.AND.IH2.EQ.'    ')GO TO 1200
      IF(IH.EQ.'TAN '.AND.IH2.EQ.'    ')GO TO 1300
      IF(IH.EQ.'COT '.AND.IH2.EQ.'    ')GO TO 1400
      IF(IH.EQ.'SEC '.AND.IH2.EQ.'    ')GO TO 1500
      IF(IH.EQ.'CSC '.AND.IH2.EQ.'    ')GO TO 1600
!
      IF(IH.EQ.'ARCS'.AND.IH2.EQ.'IN  ')GO TO 2100
      IF(IH.EQ.'ARCC'.AND.IH2.EQ.'OS  ')GO TO 2200
      IF(IH.EQ.'ARCT'.AND.IH2.EQ.'AN  ')GO TO 2300
      IF(IH.EQ.'ARCC'.AND.IH2.EQ.'OT  ')GO TO 2400
      IF(IH.EQ.'ARCS'.AND.IH2.EQ.'EC  ')GO TO 2500
      IF(IH.EQ.'ARCC'.AND.IH2.EQ.'SC  ')GO TO 2600
!
      IF(IH.EQ.'SINH'.AND.IH2.EQ.'    ')GO TO 3100
      IF(IH.EQ.'COSH'.AND.IH2.EQ.'    ')GO TO 3200
      IF(IH.EQ.'TANH'.AND.IH2.EQ.'    ')GO TO 3300
      IF(IH.EQ.'COTH'.AND.IH2.EQ.'    ')GO TO 3400
      IF(IH.EQ.'SECH'.AND.IH2.EQ.'    ')GO TO 3500
      IF(IH.EQ.'CSCH'.AND.IH2.EQ.'    ')GO TO 3600
!
      IF(IH.EQ.'ARCS'.AND.IH2.EQ.'INH ')GO TO 4100
      IF(IH.EQ.'ARCC'.AND.IH2.EQ.'OSH ')GO TO 4200
      IF(IH.EQ.'ARCT'.AND.IH2.EQ.'ANH ')GO TO 4300
      IF(IH.EQ.'ARCC'.AND.IH2.EQ.'OTH ')GO TO 4400
      IF(IH.EQ.'ARCS'.AND.IH2.EQ.'ECH ')GO TO 4500
      IF(IH.EQ.'ARCC'.AND.IH2.EQ.'SCH ')GO TO 4600
!
      IFOUND='NO'
      GO TO 9000
!
!     STEP 10--
!     EVALUATE THE CIRCULAR TRIG FUNCTIONS
!
 1100 CONTINUE
      ARG=X
      IF(IANGLU.EQ.'DEGR')ARG=(PI/180.0)*ARG
      IF(IANGLU.EQ.'GRAD')ARG=(PI/200.0)*ARG
      TERM=SIN(ARG)
      GO TO 9000
!
 1200 CONTINUE
      ARG=X
      IF(IANGLU.EQ.'DEGR')ARG=(PI/180.0)*ARG
      IF(IANGLU.EQ.'GRAD')ARG=(PI/200.0)*ARG
      TERM=COS(ARG)
      GO TO 9000
!
 1300 CONTINUE
      ARG=X
      IF(IANGLU.EQ.'DEGR')ARG=(PI/180.0)*ARG
      IF(IANGLU.EQ.'GRAD')ARG=(PI/200.0)*ARG
      TEMP=COS(ARG)
      IF(TEMP.NE.0.0)GO TO 1330
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1311)
 1311 FORMAT('***** ERROR IN DPLIB2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1312)
 1312 FORMAT('      ATTEMPT TO TAKE THE TANGENT OF A NUMBER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1313)
 1313 FORMAT('      WHICH IS AN ODD MULTIPLE OF PI/2.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1314)
 1314 FORMAT('      THIS IS ILLEGAL BECAUSE THE TANGENT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1315)
 1315 FORMAT('      IS INFINITE AT SUCH POINTS.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1316)X
 1316 FORMAT('      THE NUMBER = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 1330 CONTINUE
      TERM=SIN(ARG)/TEMP
      GO TO 9000
!
 1400 CONTINUE
      ARG=X
      IF(IANGLU.EQ.'DEGR')ARG=(PI/180.0)*ARG
      IF(IANGLU.EQ.'GRAD')ARG=(PI/200.0)*ARG
      TEMP=SIN(ARG)
      IF(TEMP.NE.0.0)GO TO 1430
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1311)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1412)
 1412 FORMAT('      ATTEMPT TO TAKE THE COTANGENT OF A NUMBER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1413)
 1413 FORMAT('      WHICH IS 0 OR A MULTIPLE OF PI.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1414)
 1414 FORMAT('      THIS IS ILLEGAL BECAUSE THE COTANGENT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1415)
 1415 FORMAT('      IS INFINITE AT SUCH POINTS.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1416)X
 1416 FORMAT('      THE NUMBER = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 1430 CONTINUE
      TERM=COS(ARG)/TEMP
      GO TO 9000
!
 1500 CONTINUE
      ARG=X
      IF(IANGLU.EQ.'DEGR')ARG=(PI/180.0)*ARG
      IF(IANGLU.EQ.'GRAD')ARG=(PI/200.0)*ARG
      TEMP=COS(ARG)
      IF(TEMP.NE.0.0)GO TO 1530
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1311)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1512)
 1512 FORMAT('      ATTEMPT TO TAKE THE SECANT OF A NUMBER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1513)
 1513 FORMAT('      WHICH IS AN ODD MULTIPLE OF PI/2.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1514)
 1514 FORMAT('      THIS IS ILLEGAL BECAUSE THE SECANT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1515)
 1515 FORMAT('      IS INFINITE AT SUCH POINTS.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1516)X
 1516 FORMAT('      THE NUMBER = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 1530 CONTINUE
      TERM=1.0/TEMP
      GO TO 9000
!
 1600 CONTINUE
      ARG=X
      IF(IANGLU.EQ.'DEGR')ARG=(PI/180.0)*ARG
      IF(IANGLU.EQ.'GRAD')ARG=(PI/200.0)*ARG
      TEMP=SIN(ARG)
      IF(TEMP.NE.0.0)GO TO 1630
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1311)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1612)
 1612 FORMAT('      ATTEMPT TO TAKE THE COSECANT OF A NUMBER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1613)
 1613 FORMAT('      WHICH IS 0 OR A MULTIPLE OF PI.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1614)
 1614 FORMAT('      THIS IS ILLEGAL BECAUSE THE COSECANT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1615)
 1615 FORMAT('      IS INFINITE AT SUCH POINTS.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1616)X
 1616 FORMAT('      THE NUMBER = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 1630 CONTINUE
      TERM=1.0/TEMP
      GO TO 9000
!
!     STEP 20--
!     EVALUATE THE INVERSE CIRCULAR TRIG FUNCTIONS
!
 2100 CONTINUE
      IF(-1.0.LE.X.AND.X.LE.1.0)GO TO 2130
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1311)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2112)
 2112 FORMAT('      ATTEMPT TO TAKE ARCSIN OF A NUMBER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2113)
 2113 FORMAT('      SMALLER THAN -1 OR LARGER THAN +1.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2114)
 2114 FORMAT('      THIS IS ILLEGAL BECAUSE THE ARCSIN')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2115)
 2115 FORMAT('      IS NOT DEFINED IN SUCH DOMAIN.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2117)X
 2117 FORMAT('      THE NUMBER = ',E15.7)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
 2130 CONTINUE
      ARG=X
      IF(ARG.EQ.-1.0)RESULT=-PI/2.0
      IF(ARG.EQ.-1.0)GO TO 2190
      IF(ARG.EQ.1.0)RESULT=PI/2.0
      IF(ARG.EQ.1.0)GO TO 2190
      ARG2=ARG/SQRT(1.0-ARG*ARG)
      RESULT=ATAN(ARG2)
 2190 CONTINUE
      IF(IANGLU.EQ.'DEGR')RESULT=(180.0/PI)*RESULT
      IF(IANGLU.EQ.'GRAD')RESULT=(200.0/PI)*RESULT
      TERM=RESULT
      GO TO 9000
!
 2200 CONTINUE
      IF(-1.0.LE.X.AND.X.LE.1.0)GO TO 2230
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1311)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2212)
 2212 FORMAT('      ATTEMPT TO TAKE ARCCOS OF A NUMBER')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2213)
 2213 FORMAT('      SMALLER THAN -1 OR LARGER THAN +1.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2214)
