      IF(SAVE2.EQ.CPUMIN)THEN
        IARG2=0
      ELSE
        IARG2=INT(SAVE2+0.5)
      ENDIF
      IARG1=0
      IARG3=IARG2
      IARG4=3
      IF(DARG2.LT.0.D0)IARG4=1
      IF(IARG2.LT.0)THEN
        IARG2=-IARG2
        IARG3=IARG2
        IARG4=1
      ENDIF
      CALL DXLEGF(DARG2,IARG1,IARG2,IARG3,DARG1,IARG4,DPN,IPN,IERR2)
      TERM=0.0
      IF(IERR2.EQ.0)THEN
        DRESLT=DPN(1)
        IF(IPN(1).EQ.0)THEN
          IF(DRESLT.GT.R1MACH(2))TERM=R1MACH(2)
          IF(DRESLT.LE.R1MACH(2))TERM=SNGL(DRESLT)
        ELSE
          TERM=R1MACH(2)
          WRITE(ICOUT,5225)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ELSEIF(IERR2.EQ.212 .OR. IERR2.EQ.213)THEN
        TERM=0.0
        WRITE(ICOUT,5226)
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IERR2.GE.201.AND.IERR2.LE.204)THEN
        TERM=0.0
        WRITE(ICOUT,5227)
        CALL DPWRST('XXX','BUG ')
      ELSE
        WRITE(ICOUT,5228)
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
      ENDIF
      GO TO 9000
 5225 FORMAT('***** WARNING FROM LEGP.  CALCULATED VALUE OUTSIDE ',   &
      'VALID MACHINE RANGE.  VALUE SET TO MACHINE MAXIMUM.')
 5226 FORMAT('***** ERROR FROM LEGP.  INVALID INPUT.')
 5227 FORMAT('***** ERROR FROM LEGP.  INVALID DXSET, CONTACT YOUR ',   &
      'LOCAL SITE INSTALLER.')
 5228 FORMAT('***** ERROR FROM LEGP.  UNABLE TO PERFORM THE ',   &
      'CALCULATIONS CORRECTLY, OUTOUT SET TO ZERO.')
!
!CCCC JULY 1995.  ADD ASSOCIATED LEGENDRE FUNCTION OF THE SECOND KIND.
!CCCC REDUCES TO LEGENDRE FUNCTION OF FIRST KIND IF M NOT SPECIFIED
!CCCC (OR IS EQUAL TO ZERO).
!CCCC NOTE THAT IN THIS CASE THE INPUT IS THEATA (I.E., THE
!CCCC ANGLE) RATHER THAN X.  THIS IS BECAUSE USING THETA GIVES
!CCCC BETTER ACCURACY.
 5240 CONTINUE
      DARG1=DBLE(X)
      IF(IANGLU.EQ.'DEGR')DARG1=DARG1*DPI/180.D0
!
      IF(DARG1.LE.0.D0.OR.DARG1.GE.DPI/2.D0)THEN
        WRITE(ICOUT,5241)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5242)X
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
        GO TO 9000
      ENDIF
 5241 FORMAT('***** ERROR FOR LEGQ.  THE FIRST INPUT ARGUMENT IS ',   &
      'OUTSIDE THE ALLOWABLE (0,PI/2) INTERVAL.')
 5242 FORMAT('      IT HAS THE VALUE ',E15.7)
!
      DARG2=DBLE(SAVE1)
      IF(DARG2.LT.-0.5D0)THEN
        WRITE(ICOUT,5243)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5244)DARG2
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
        GO TO 9000
      ENDIF
 5243 FORMAT('***** ERROR FOR LEGQ.  THE SECOND INPUT ARGUMENT IS ',   &
      'LESS THAN -0.5.')
 5244 FORMAT('      IT HAS THE VALUE ',I15)
!
      IF(SAVE2.EQ.CPUMIN)THEN
        IARG2=0
      ELSE
        IARG2=INT(SAVE2+0.5)
      ENDIF
      IF(IARG2.LT.0)THEN
        WRITE(ICOUT,5253)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5254)SAVE2
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
        GO TO 9000
      ENDIF
 5253 FORMAT('***** ERROR FOR LEGQ.  THE THIRD INPUT ARGUMENT IS ',   &
      'NEGATIVE.')
 5254 FORMAT('      IT HAS THE VALUE ',E15.7)
!
      IARG1=0
      IARG3=IARG2
      IARG4=2
      CALL DXLEGF(DARG2,IARG1,IARG2,IARG3,DARG1,IARG4,DPN,IPN,IERR2)
      TERM=0.0
      IF(IERR2.EQ.0)THEN
        DRESLT=DPN(1)
        IF(IPN(1).EQ.0)THEN
          IF(DRESLT.GT.R1MACH(2))TERM=R1MACH(2)
          IF(DRESLT.LE.R1MACH(2))TERM=SNGL(DRESLT)
        ELSE
          TERM=R1MACH(2)
          WRITE(ICOUT,5245)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ELSEIF(IERR2.EQ.212 .OR. IERR2.EQ.213)THEN
        TERM=0.0
        WRITE(ICOUT,5246)
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IERR2.GE.201.AND.IERR2.LE.204)THEN
        TERM=0.0
        WRITE(ICOUT,5247)
        CALL DPWRST('XXX','BUG ')
      ELSE
        WRITE(ICOUT,5248)
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
      ENDIF
      GO TO 9000
 5245 FORMAT('***** WARNING FROM LEGQ.  CALCULATED VALUE OUTSIDE ',   &
      'VALID MACHINE RANGE.  VALUE SET TO MACHINE MAXIMUM.')
 5246 FORMAT('***** ERROR FROM LEGQ.  INVALID INPUT.')
 5247 FORMAT('***** ERROR FROM LEGQ.  INVALID DXSET, CONTACT YOUR ',   &
      'LOCAL SITE INSTALLER.')
 5248 FORMAT('***** ERROR FROM LEGQ.  UNABLE TO PERFORM THE ',   &
      'CALCULATIONS CORRECTLY, OUTOUT SET TO ZERO.')
!
!CCCC JULY 1995.  ADD ASSOCIATED LEGENDRE POLYNOMIAL OF THE FIRST KIND.
!CCCC REDUCES TO LEGENDRE POLYNOMIAL OF FIRST KIND IF M NOT SPECIFIED
!CCCC (OR IS EQUAL TO ZERO).  THIS IS THE UNNORMALIZED CASE.
!CCCC NOTE THAT IN THIS CASE THE INPUT IS THEATA (I.E., THE
!CCCC ANGLE) RATHER THAN X.  THIS IS BECAUSE USING THETA GIVES
!CCCC BETTER ACCURACY.
 5280 CONTINUE
      DARG1=DBLE(X)
      IF(IANGLU.EQ.'DEGR')DARG1=DARG1*DPI/180.D0
!
      IF(DARG1.LE.-DPI.OR.DARG1.GE.DPI)THEN
        WRITE(ICOUT,5281)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5282)X
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
        GO TO 9000
      ENDIF
 5281 FORMAT('***** ERROR FOR LEGENDRE.  THE FIRST INPUT ARGUMENT IS ',   &
      'OUTSIDE THE ALLOWABLE (-PI,PI) INTERVAL.')
 5282 FORMAT('      IT HAS THE VALUE ',E15.7)
      ISWTCH=0
      IF(DARG1.GT.(DPI/2.D0))ISWTCH=1
      IF(ISWTCH.EQ.1)DARG1=DPI-DARG1
!
      ITEMP=INT(SAVE1+0.5)
      DARG2=DBLE(ITEMP)
      IF(DARG2.LT.-0.1D0)THEN
        WRITE(ICOUT,5283)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5284)DARG2
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
        GO TO 9000
      ENDIF
 5283 FORMAT('***** ERROR FOR LEGENDRE.  THE SECOND INPUT ARGUMENT IS',   &
      ' NEGATIVE.')
 5284 FORMAT('      IT HAS THE VALUE ',I15)
!
      IF(SAVE2.EQ.CPUMIN)THEN
        IARG2=0
      ELSE
        IARG2=INT(SAVE2+0.5)
      ENDIF
      IARG1=0
      IARG3=IARG2
      IARG4=3
      CALL DXLEGF(DARG2,IARG1,IARG2,IARG3,DARG1,IARG4,DPN,IPN,IERR2)
      IF(ISWTCH.EQ.1)DPN(1)=DPN(1)*(-1.D0)**(INT(DARG2)+IARG2)
      TERM=0.0
      IF(IERR2.EQ.0)THEN
        DRESLT=DPN(1)
        IF(IPN(1).EQ.0)THEN
          IF(DRESLT.GT.R1MACH(2))TERM=R1MACH(2)
          IF(DRESLT.LE.R1MACH(2))TERM=SNGL(DRESLT)
        ELSE
          TERM=R1MACH(2)
          WRITE(ICOUT,5285)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ELSEIF(IERR2.EQ.212 .OR. IERR2.EQ.213)THEN
        TERM=0.0
        WRITE(ICOUT,5286)
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IERR2.GE.201.AND.IERR2.LE.204)THEN
        TERM=0.0
        WRITE(ICOUT,5287)
        CALL DPWRST('XXX','BUG ')
      ELSE
        WRITE(ICOUT,5288)
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
      ENDIF
      GO TO 9000
 5285 FORMAT('***** WARNING FROM LEGENDRE.  CALCULATED VALUE OUTSIDE ',   &
      'VALID MACHINE RANGE.  VALUE SET TO MACHINE MAXIMUM.')
 5286 FORMAT('***** ERROR FROM LEGENDRE.  INVALID INPUT.')
 5287 FORMAT('***** ERROR FROM LEGENDRE.  INVALID DXSET, CONTACT YOUR',   &
      ' LOCAL SITE INSTALLER.')
 5288 FORMAT('***** ERROR FROM LEGENDRE.  UNABLE TO PERFORM THE ',   &
      'CALCULATIONS CORRECTLY, OUTOUT SET TO ZERO.')
!
!CCCC JULY 1995.  ADD SHPERICAL HARMONICS.  BASED ON ASSOCIATED
!CCCC LEGENDRE POLYNOMIALS.
 5300 CONTINUE
      DARG1=DBLE(X)
      IF(IANGLU.EQ.'DEGR')DARG1=DARG1*DPI/180.D0
!
      IF(DARG1.LT.-DPI.OR.DARG1.GT.DPI)THEN
        WRITE(ICOUT,5301)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5302)X
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
        GO TO 9000
      ENDIF
 5301 FORMAT('***** ERROR FOR SPHRHRMR.  THE FIRST INPUT ARGUMENT IS ',   &
      'OUTSIDE THE ALLOWABLE (-DPI,DPI) INTERVAL.')
 5302 FORMAT('      IT HAS THE VALUE ',E15.7)
      DARG2=DBLE(SAVE1)
      IF(IANGLU.EQ.'DEGR')DARG2=DARG2*DPI/180.D0
!
      IF(DARG2.LT.0.OR.DARG2.GT.2.0D0*DPI)THEN
        WRITE(ICOUT,5311)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5302)SAVE1
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
        GO TO 9000
      ENDIF
 5311 FORMAT('***** ERROR FOR SPHRHRMR.  THE SECOND INPUT ARGUMENT IS',   &
      ' OUTSIDE THE ALLOWABLE (0,2*PI) INTERVAL.')
!
      IARG1=INT(SAVE2+0.5)
      IF(IARG1.LT.0)THEN
        WRITE(ICOUT,5303)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5304)IARG1
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
        GO TO 9000
      ENDIF
 5303 FORMAT('***** ERROR FOR SPHRHRM.  THE THIRD INPUT ARGUMENT IS',   &
      ' NEGATIVE.')
 5304 FORMAT('      IT HAS THE VALUE ',I15)
!
      IARG2=INT(SAVE3+0.5)
      IF(ABS(IARG2).GT.IARG1)THEN
        WRITE(ICOUT,5313)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5314)IARG1,IARG2
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
        GO TO 9000
      ENDIF
 5313 FORMAT('***** ERROR FOR SPHRHRM.  THE FOURTH INPUT ARGUMENT IS ',   &
      'LARGER THAN THE THIRD ARGUMENT.')
 5314 FORMAT('      THEY HAVE THE VALUES: ',I15,1X,I15)
      IF(IARG2.LT.0)THEN
        ISWTCH=1
        IARG2=-IARG2
      ELSE
        ISWTCH=0
      ENDIF
      IARG3=IARG2
      IARG4=2
      CALL DXNRMP(IARG1,IARG2,IARG3,DARG1,IARG4,DPN,IPN,ISIG,IERR2)
!
      TERM=0.0
!
      IF(IERR2.EQ.0)THEN
        IF(IPN(1).EQ.0)THEN
          DRESLT=DPN(1)
          IF(ABS(DRESLT).GT.DBLE(R1MACH(2)))THEN
            IF(DRESLT.GE.0.D0)TERM=R1MACH(2)
            IF(DRESLT.LT.0.D0)TERM=-R1MACH(2)
          ELSE
            DTERM1=(-1.D0)**IARG2*DSQRT(1.0D0/(2.D0*DPI))
            DRESLT=DTERM1*DPN(1)
            DTERM1=DBLE(IARG2)*DARG2
            IF(ISJUNK.EQ.0)THEN
              DTERM2=DRESLT*DCOS(DTERM1)
              TERM=REAL(DTERM2)
            ELSE
              DTERM2=DRESLT*DSIN(DTERM1)
              TERM=REAL(DTERM2)
            ENDIF
            IF(ISWTCH.EQ.1)TERM=(-1.**IARG2)*TERM
          ENDIF
        ELSE
          IF(IPN(1).GT.0)THEN
            TERM=R1MACH(2)
            WRITE(ICOUT,5305)
            CALL DPWRST('XXX','BUG ')
          ELSE
            TERM=0.
            WRITE(ICOUT,5309)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ENDIF
      ELSEIF(IERR2.EQ.212 .OR. IERR2.EQ.213)THEN
        TERM=0.0
        WRITE(ICOUT,5306)
        CALL DPWRST('XXX','BUG ')
      ELSEIF(IERR2.GE.201.AND.IERR2.LE.204)THEN
        TERM=0.0
        WRITE(ICOUT,5307)
        CALL DPWRST('XXX','BUG ')
      ELSE
        WRITE(ICOUT,5308)
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
      ENDIF
      GO TO 9000
 5305 FORMAT('***** WARNING FROM SPHRHRM.  CALCULATED VALUE OUTSIDE ',   &
      'VALID MACHINE RANGE.  VALUE SET TO MACHINE MAXIMUM.')
 5306 FORMAT('***** ERROR FROM SPHRHRM.  INVALID INPUT.')
 5307 FORMAT('***** ERROR FROM SPHRHRM.  INVALID DXSET, CONTACT YOUR',   &
      ' LOCAL SITE INSTALLER.')
 5308 FORMAT('***** ERROR FROM SPHRHRM.  UNABLE TO PERFORM THE ',   &
      'CALCULATIONS CORRECTLY, OUTOUT SET TO ZERO.')
 5309 FORMAT('***** WARNING FROM SPHRHRM.  CALCULATED VALUE OUTSIDE ',   &
      'VALID MACHINE RANGE.  VALUE SET TO 0.')
!
!CCCC USE SLATEC ROUTINE SINCE IT HANDLES ANY REAL X (NOT LIMITED TO
!CCCC (-3,INF).
 6000 CONTINUE
      ARG=X
      RESULT=BESJ0DP(X)
      TERM=RESULT
!CCCC IF(-3.0.LE.ARG.AND.ARG.LE.3.0)GO TO 6001
!CCCC IF(3.0.LE.ARG)GO TO 6002
!CCCC WRITE(ICOUT,6009)
!6009 FORMAT('BESS0 BESSEL FUNCTION ARGUMENT NOT IN (-3,INFINITY) ')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC GO TO 9000
!
!6001 CONTINUE
!CCCC ARG1=ARG/3.0
!CCCC RESULT=(D012*ARG1**12)+(D010*ARG1**10)+(D08*ARG1**8)
!CCCC1       +(D06*ARG1**6)+(D04*ARG1**4)+(D02*ARG1**2)+D00
!CCCC TERM=RESULT
!CCCC GO TO 9000
!
!6002 CONTINUE
!CCCC ARG2=3.0/ARG
!CCCC F0=(F06*ARG2**6)+(F05*ARG2**5)+(F04*ARG2**4)
!CCCC1       +(F03*ARG2**3)+(F02*ARG2**2)+(F01*ARG2**1)+F00
!CCCC G0=(G06*ARG2**6)+(G05*ARG2**5)+(G04*ARG2**4)
!CCCC1       +(G03*ARG2**3)+(G02*ARG2**2)+(G01*ARG2**1)+G00
!CCCC THETA0=ARG+G0
!CCCC RESULT=(1.0/SQRT(ARG))*F0*COS(THETA0)
!CCCC TERM=RESULT
      GO TO 9000
!
!CCCC USE SLATEC ROUTINE SINCE IT HANDLES ANY REAL X (NOT LIMITED TO
!CCCC (-3,INF).
 6010 CONTINUE
      ARG=X
      RESULT=BESJ1DP(X)
      TERM=RESULT
!CCCC IF(-3.0.LE.ARG.AND.ARG.LE.3.0)GO TO 6011
!CCCC IF(3.0.LE.ARG)GO TO 6012
!CCCC WRITE(ICOUT,6019)
!6019 FORMAT('BESS1 BESSEL FUNCTION ARGUMENT NOT IN (-3,INFINITY) ')
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC GO TO 9000
!6011 CONTINUE
!CCCC ARG1=ARG/3.0
!CCCC RESULT=(D112*ARG1**12)+(D110*ARG1**10)+(D18*ARG1**8)
!CCCC1       +(D16*ARG1**6)+(D14*ARG1**4)+(D12*ARG1**2)+D10
!CCCC RESULT=ARG*RESULT
!CCCC TERM=RESULT
!CCCC GO TO 9000
!6012 CONTINUE
!CCCC ARG2=3.0/ARG
!CCCC F1=(F16*ARG2**6)+(F15*ARG2**5)+(F14*ARG2**4)
!CCCC1       +(F13*ARG2**3)+(F12*ARG2**2)+(F11*ARG2**1)+F10
!CCCC G1=(G16*ARG2**6)+(G15*ARG2**5)+(G14*ARG2**4)
!CCCC1       +(G13*ARG2**3)+(G12*ARG2**2)+(G11*ARG2**1)+G10
!CCCC THETA1=ARG+G1
!CCCC RESULT=(1.0/SQRT(ARG))*F1*COS(THETA1)
!CCCC TERM=RESULT
      GO TO 9000
!
!CCCC THE FOLLOWING SECTIONS (6100 TO 6700) WERE ADDED SEPTEMBER 1994
 6100 CONTINUE
      ARG1=X
      RESULT=BESY0DP(ARG1)
      TERM=RESULT
      GO TO 9000
!
 6150 CONTINUE
      ARG1=X
      RESULT=BESY1DP(ARG1)
      TERM=RESULT
      GO TO 9000
!
 6200 CONTINUE
      DARG1=DBLE(X)
      DRESLT=DBESI0(DARG1)
      TERM=SNGL(DRESLT)
      GO TO 9000
!
 6230 CONTINUE
      DARG1=DBLE(X)
      DRESLT=DBSI0E(DARG1)
      TERM=SNGL(DRESLT)
      GO TO 9000
!
 6250 CONTINUE
      DARG1=DBLE(X)
      DRESLT=DBESI1(DARG1)
      TERM=SNGL(DRESLT)
      GO TO 9000
!
 6280 CONTINUE
      DARG1=DBLE(X)
      DRESLT=DBSI1E(DARG1)
      TERM=SNGL(DRESLT)
      GO TO 9000
!
 6300 CONTINUE
      ARG1=X
      RESULT=BESK0(ARG1)
      TERM=RESULT
      GO TO 9000
!
 6330 CONTINUE
      ARG1=X
      RESULT=BESK0E(ARG1)
      TERM=RESULT
      GO TO 9000
!
 6350 CONTINUE
      ARG1=X
      RESULT=BESK1(ARG1)
      TERM=RESULT
      GO TO 9000
!
 6380 CONTINUE
      ARG1=X
      RESULT=BESK1E(ARG1)
      TERM=RESULT
      GO TO 9000
!
!CCCC NOTE: 2 CASES FOR BESSJ(X,ALPHA)
!CCCC       1) ALPHA IS INTEGER
!CCCC       2) ALPHA IS REAL
!CCCC       HOWEVER, CALL TO BESJ IS SAME.  BESJ ACTUALLY
!CCCC       COMPUTES A SEQUENCE OF BESJ VALUES, BUT WE ARE
!CCCC       ONLY COMPUTING 1 (SET ALPHA TO THIS VALUE).
 6400 CONTINUE
      ARG1=X
      ARG2=SAVE1
      IF(ARG2.EQ.0.0)THEN
        RESULT=BESJ0DP(ARG1)
      ELSEIF(ARG2.EQ.1.0)THEN
        RESULT=BESJ1DP(ARG1)
      ELSE
        IARG1=1
        CALL BESJ(ARG1,ARG2,IARG1,TEMP1,NZERO)
        RESULT=TEMP1(IARG1)
      ENDIF
      TERM=RESULT
      GO TO 9000
!
 6500 CONTINUE
      ARG1=X
      ARG2=SAVE1
      IF(ARG2.EQ.0.0)THEN
        RESULT=BESY0DP(ARG1)
      ELSEIF(ARG2.EQ.1.0)THEN
        RESULT=BESY1DP(ARG1)
      ELSE
        IARG1=1
        CALL BESY(ARG1,ARG2,IARG1,TEMP1)
        RESULT=TEMP1(IARG1)
      ENDIF
      TERM=RESULT
      GO TO 9000
!
 6600 CONTINUE
      DARG1=DBLE(X)
      DARG2=DBLE(SAVE1)
!CCCC APRIL 1995.  FIX BUG
!CCCC IF(ARG2.EQ.0.0)THEN
      IF(DARG2.EQ.0.D0)THEN
        DRESLT=DBESI0(DARG1)
!CCCC ELSEIF(ARG2.EQ.1.0)THEN
      ELSEIF(DARG2.EQ.1.D0)THEN
        DRESLT=DBESI1(DARG1)
      ELSE
        IARG1=1
        ISCALE=1
        CALL DBESI(DARG1,DARG2,ISCALE,IARG1,DTEMP1,NZERO)
        DRESLT=DTEMP1(IARG1)
      ENDIF
      TERM=SNGL(DRESLT)
      GO TO 9000
!
 6650 CONTINUE
      ARG1=X
      ARG2=SAVE1
      IF(ARG2.EQ.0.0)THEN
        RESULT=BESI0E(ARG1)
      ELSEIF(ARG2.EQ.1.0)THEN
        RESULT=BESI1E(ARG1)
      ELSE
        IARG1=1
        ISCALE=2
        CALL BESI(ARG1,ARG2,ISCALE,IARG1,TEMP1,NZERO)
        RESULT=TEMP1(IARG1)
      ENDIF
      TERM=RESULT
      GO TO 9000
!
 6700 CONTINUE
      ARG1=X
      ARG2=SAVE1
      IF(ARG2.EQ.0.0)THEN
        RESULT=BESK0(ARG1)
      ELSEIF(ARG2.EQ.1.0)THEN
        RESULT=BESK1(ARG1)
      ELSE
        IARG1=1
        ISCALE=1
        CALL BESK(ARG1,ARG2,ISCALE,IARG1,TEMP1,NZERO)
        RESULT=TEMP1(IARG1)
      ENDIF
      TERM=RESULT
      GO TO 9000
!
 6750 CONTINUE
      ARG1=X
      ARG2=SAVE1
      IF(ARG2.EQ.0.0)THEN
        RESULT=BESK0E(ARG1)
      ELSEIF(ARG2.EQ.1.0)THEN
        RESULT=BESK1E(ARG1)
      ELSE
        IARG1=1
        ISCALE=2
        CALL BESK(ARG1,ARG2,ISCALE,IARG1,TEMP1,NZERO)
        RESULT=TEMP1(IARG1)
      ENDIF
      TERM=RESULT
      GO TO 9000
!
 6800 CONTINUE
      ARG1=X
      RESULT=AI(ARG1)
      TERM=RESULT
      GO TO 9000
!
 6900 CONTINUE
      ARG1=X
      RESULT=BI(ARG1)
      TERM=RESULT
      GO TO 9000
!
 7000 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      IARG1=INT(SAVE2)
      ARG4=SAVE2-REAL(IARG1)
      IF(ARG4.GT.0.5)THEN
        IARG1=IARG1+1
        ARG4=-ARG4
      ENDIF
!CCCC IF(IARG1.GT.100.OR.SAVE.LT.0.0)THEN
      IF(IARG1.GT.100.OR.SAVE2.LT.0)THEN
        WRITE(ICOUT,7001)
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
        GO TO 9000
      ENDIF
 7001 FORMAT('***** ORDER OF COMPLEX BESSEL FUNCTION NOT IN THE RANGE',   &
       ' (0,100). *****')
      CALL BESJCF(Z1,ARG4,IARG1,CTEMP1)
      TERM=REAL(CTEMP1(IARG1+2))
      GO TO 9000
!
 7010 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      IARG1=INT(SAVE2)
      ARG4=SAVE2-REAL(IARG1)
      IF(ARG4.GT.0.5)THEN
        IARG1=IARG1+1
        ARG4=-ARG4
      ENDIF
      IF(IARG1.GT.100.OR.SAVE2.LT.0.0)THEN
        WRITE(ICOUT,7011)
        CALL DPWRST('XXX','BUG ')
        TERM=0.0
        GO TO 9000
      ENDIF
 7011 FORMAT('***** ORDER OF COMPLEX BESSEL FUNCTION NOT IN THE RANGE',   &
       ' (0,100). *****')
