      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      TERM=REAL(CABS(Z1))
      GO TO 9000
!
 8600 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      TERM=REAL(CCOS(Z1))
      GO TO 9000
!
 8610 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      TERM=AIMAG(CCOS(Z1))
      GO TO 9000
!
 8700 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      TERM=REAL(CEXP(Z1))
      GO TO 9000
!
 8710 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      TERM=AIMAG(CEXP(Z1))
      GO TO 9000
!
 8800 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      TERM=REAL(CLOG(Z1))
      GO TO 9000
!
 8810 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      TERM=AIMAG(CLOG(Z1))
      GO TO 9000
!
 8900 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      TERM=REAL(CSIN(Z1))
      GO TO 9000
!
 8910 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      TERM=AIMAG(CSIN(Z1))
      GO TO 9000
!
 8950 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      TERM=REAL(CSQRT(Z1))
      GO TO 9000
!
 8960 CONTINUE
      ARG1=X
      ARG2=SAVE1
      Z1=CMPLX(ARG1,ARG2)
      TERM=AIMAG(CSQRT(Z1))
      GO TO 9000
!
!CCCC JULY 1995.  ADD HERMITE POLYNOMIAL
 8970 CONTINUE
      ARG1=X
      ARG2=SAVE1
      CALL HERMIT(ARG1,ARG2,RESULT)
      TERM=RESULT
      GO TO 9000
!
!CCCC JULY 1995.  ADD LOG HERMITE POLYNOMIAL
 8975 CONTINUE
      ARG1=X
      ARG2=SAVE1
      CALL LNHERM(ARG1,ARG2,RESULT,ISIGN)
      TERM=RESULT
      GO TO 9000
!
!CCCC JULY 1995.  ADD SIGN OF LOG HERMITE POLYNOMIAL
 8978 CONTINUE
      ARG1=X
      ARG2=SAVE1
      CALL LNHERM(ARG1,ARG2,RESULT,ISIGN)
      TERM=REAL(ISIGN)
      GO TO 9000
!
!CCCC JULY 1995.  ADD LAGUERRE POLYNOMIAL
 8980 CONTINUE
      ARG1=X
      ARG2=SAVE1
      CALL LAGUE(ARG1,ARG2,RESULT)
      TERM=RESULT
      GO TO 9000
!
!CCCC JULY 1995.  ADD LEGENDRE POLYNOMIAL (UNNORMALIZED)
!CCCC NOTE THAT IN THIS CASE THE INPUT IS THETA (I.E., THE
!CCCC ANGLE) RATHER THAN X.  THIS IS TO BE CONSISTENT WITH
!CCCC ASSOCIATED LEGENDRE POLYNOMILS AND FUNCTIONS.  CONVERT
!CCCC TO (-1,1) FOR LEGNDR ROUTINE.
 8990 CONTINUE
      IF(IANGLU.EQ.'DEGR')THEN
        ARG1=COS(X*REALPI/180.)
      ELSE
        ARG1=COS(X)
      ENDIF
      ARG2=SAVE1
      CALL LEGNDR(ARG1,ARG2,RESULT)
      TERM=RESULT
      GO TO 9000
!
18090 CONTINUE
      DARG1=DBLE(X)
      DRESLT=AIRINT(DARG1)
      TERM=REAL(DRESLT)
      GO TO 9000
!
18095 CONTINUE
      DARG1=DBLE(X)
      DRESLT=AIRYGI(DARG1)
      TERM=REAL(DRESLT)
      GO TO 9000
!
18100 CONTINUE
      DARG1=DBLE(X)
      DRESLT=AIRYHI(DARG1)
      TERM=REAL(DRESLT)
      GO TO 9000
!
18105 CONTINUE
      DARG1=DBLE(X)
      DRESLT=ATNINT(DARG1)
      TERM=REAL(DRESLT)
      GO TO 9000
!
18110 CONTINUE
      DARG1=DBLE(X)
      DRESLT=BIRINT(DARG1)
      TERM=REAL(DRESLT)
      GO TO 9000
!
18115 CONTINUE
      DARG1=DBLE(X)
      DRESLT=I0INT(DARG1)
      TERM=REAL(DRESLT)
      GO TO 9000
!
18120 CONTINUE
      DARG1=DBLE(X)
      DRESLT=I0ML0(DARG1)
      TERM=REAL(DRESLT)
      GO TO 9000
!
18125 CONTINUE
      DARG1=DBLE(X)
      DRESLT=I1ML1(DARG1)
      TERM=REAL(DRESLT)
      GO TO 9000
!
18130 CONTINUE
      DARG1=DBLE(X)
      DRESLT=J0INT(DARG1)
      TERM=REAL(DRESLT)
      GO TO 9000
!
18135 CONTINUE
      DARG1=DBLE(X)
      DRESLT=K0INT(DARG1)
      TERM=REAL(DRESLT)
      GO TO 9000
!
18140 CONTINUE
      DARG1=DBLE(X)
      DRESLT=Y0INT(DARG1)
      TERM=REAL(DRESLT)
      GO TO 9000
!
18150 CONTINUE
      TERM=X
      IF(SAVE1.LT.X)TERM=SAVE1
      IF(SAVE2.NE.CPUMIN)THEN
        IF(SAVE2.LT.TERM)TERM=SAVE2
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE3.NE.CPUMIN)THEN
        IF(SAVE3.LT.TERM)TERM=SAVE3
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE4.NE.CPUMIN)THEN
        IF(SAVE4.LT.TERM)TERM=SAVE4
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE5.NE.CPUMIN)THEN
        IF(SAVE5.LT.TERM)TERM=SAVE5
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE6.NE.CPUMIN)THEN
        IF(SAVE6.LT.TERM)TERM=SAVE6
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE7.NE.CPUMIN)THEN
        IF(SAVE7.LT.TERM)TERM=SAVE7
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE8.NE.CPUMIN)THEN
        IF(SAVE8.LT.TERM)TERM=SAVE8
      ELSE
        GO TO 9000
      ENDIF
      GO TO 9000
!
18160 CONTINUE
      TERM=X
      IF(SAVE1.GT.X)TERM=SAVE1
      IF(SAVE2.NE.CPUMIN)THEN
        IF(SAVE2.GT.TERM)TERM=SAVE2
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE3.NE.CPUMIN)THEN
        IF(SAVE3.GT.TERM)TERM=SAVE3
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE4.NE.CPUMIN)THEN
        IF(SAVE4.GT.TERM)TERM=SAVE4
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE5.NE.CPUMIN)THEN
        IF(SAVE5.GT.TERM)TERM=SAVE5
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE6.NE.CPUMIN)THEN
        IF(SAVE6.GT.TERM)TERM=SAVE6
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE7.NE.CPUMIN)THEN
        IF(SAVE7.GT.TERM)TERM=SAVE7
      ELSE
        GO TO 9000
      ENDIF
      IF(SAVE8.NE.CPUMIN)THEN
        IF(SAVE8.GT.TERM)TERM=SAVE8
      ELSE
        GO TO 9000
      ENDIF
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (AGREE) WAS ADDED  AUGUST 2011.
18170 CONTINUE
      TERM=1.0
      IF(SAVE1.NE.CPUMIN)THEN
        IF(X.NE.SAVE1)TERM=0.0
      ELSE
        GO TO 18171
      ENDIF
      IF(SAVE2.NE.CPUMIN)THEN
        IF(X.NE.SAVE2)TERM=0.0
      ELSE
        GO TO 18171
      ENDIF
      IF(SAVE3.NE.CPUMIN)THEN
        IF(X.NE.SAVE3)TERM=0.0
      ELSE
        GO TO 18171
      ENDIF
      IF(SAVE4.NE.CPUMIN)THEN
        IF(X.NE.SAVE4)TERM=0.0
      ELSE
        GO TO 18171
      ENDIF
      IF(SAVE5.NE.CPUMIN)THEN
        IF(X.NE.SAVE5)TERM=0.0
      ELSE
        GO TO 18171
      ENDIF
      IF(SAVE6.NE.CPUMIN)THEN
        IF(X.NE.SAVE6)TERM=0.0
      ELSE
        GO TO 18171
      ENDIF
      IF(SAVE7.NE.CPUMIN)THEN
        IF(X.NE.SAVE7)TERM=0.0
      ELSE
        GO TO 18171
      ENDIF
      IF(SAVE8.NE.CPUMIN)THEN
        IF(X.NE.SAVE8)TERM=0.0
      ELSE
        GO TO 18171
      ENDIF
18171 CONTINUE
      IF(IH.EQ.'DISA'.AND.IH2.EQ.'GREE')TERM=1.0 - TERM
      IF(IH.EQ.'NE  '.AND.IH2.EQ.'    ')TERM=1.0 - TERM
      IF(IH.EQ.'NOTE'.AND.IH2.EQ.'QUAL')TERM=1.0 - TERM
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (DPNTLINE) WAS ADDED  OCTOBER 2012.
18180 CONTINUE
      TERM=DPNTLI(X,SAVE1,SAVE2,SAVE3,SAVE4,IBUGEV)
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (ANGRAD) WAS ADDED  OCTOBER 2012.
18190 CONTINUE
      TERM=ANGRAD(X,SAVE1,SAVE2,SAVE3,SAVE4,SAVE5,IBUGEV)
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (SLOPE) WAS ADDED  JANUARY 2013.
18200 CONTINUE
      X1TEMP=X
      Y1TEMP=SAVE1
      X2TEMP=SAVE2
      Y2TEMP=SAVE3
      IF(Y1TEMP.NE.Y2TEMP)THEN
        TERM=(Y2TEMP-Y1TEMP)/(X2TEMP-X1TEMP)
      ELSE
        TERM=CPUMIN
      ENDIF
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (LININTER) WAS ADDED  AUGUST 2013.
18210 CONTINUE
      ISUBRO='NULL'
      TERM=LININ3(X,SAVE1,SAVE2,SAVE3,SAVE4,   &
                  IBUGEV,ISUBRO,IERROR)
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (GT) WAS ADDED  JUNE 2021.
18220 CONTINUE
      TERM=0.0
      IF(X.GT.SAVE1)TERM=1.0
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (GE) WAS ADDED  JUNE 2021.
18230 CONTINUE
      TERM=0.0
      IF(X.GE.SAVE1)TERM=1.0
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (LT) WAS ADDED  JUNE 2021.
18240 CONTINUE
      TERM=0.0
      IF(X.LT.SAVE1)TERM=1.0
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (LE) WAS ADDED  JUNE 2021.
18250 CONTINUE
      TERM=0.0
      IF(X.LE.SAVE1)TERM=1.0
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (LE) WAS ADDED  JULY 2024.
18260 CONTINUE
      TERM=KINDEX(INT(X+0.5),INT(SAVE1+0.5),INT(SAVE2+0.5))
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (UNCHORW) WAS ADDED  APRIL 2025.
18270 CONTINUE
      XBAR=X
      NTEMP=INT(SAVE1+0.5)
      CALL HORW(XBAR,NTEMP,TERM,TERM2)
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION (UNCRHORW) WAS ADDED  APRIL 2025.
18280 CONTINUE
      XBAR=X
      NTEMP=INT(SAVE1+0.5)
      CALL HORW(XBAR,NTEMP,TERM2,TERM)
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('AT THE END       OF DPLIB3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IH,IH2,X
 9012   FORMAT('IH,IH2,X = ',2A4,2X,G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)SAVE1,SAVE2,RESULT,TERM,I
 9013   FORMAT('SAVE1,SAVE2,RESULT,TERM,I = ',4G15.7,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)IFOUND,IERROR,IANGLU,IBUGEV
 9015   FORMAT('IFOUND,IERROR,IANGLU,IBUGEV = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLIB3
      SUBROUTINE DPLIBF(IH,IH2,X,SAVE1,SAVE2,SAVE3,SAVE4,SAVE5,   &
                        SAVE6,SAVE7,SAVE8,   &
                        I,IANGLU,   &
                        TERM,IBUGEV,IERROR)
!
!     PURPOSE--PERFORM A LIBRARY FUNCTION EVALUATION.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION (AS A SEPARATE SUBROUTINE)--JANUARY  1979.
!     UPDATED         --NOVEMBER  1979.
!     UPDATED         --FEBRUARY  1981.
!     UPDATED         --JUNE      1981.
!     UPDATED         --JULY      1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     1989. INPUT ARG SAVE3 & SAVE3 IN CALL
!     UPDATED         --SEPTEMBER 1994. ADD SAVE3,SAVE4 TO DPLIB3.
!     UPDATED         --MAY       1998. ADD SAVE5 TO DPLIB3.
!     UPDATED         --JUNE      2003. ADD SAVE6, SAVE7, SAVE8 TO
!                                       DPLIB3.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IANGLU
      CHARACTER*4 IBUGEV
      CHARACTER*4 IERROR
!
      CHARACTER*4 IFOUNZ
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUNZ='NO'
      IERROR='NO'
      ISUBN1='DPLI'
      ISUBN2='BF  '
!
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF DPLIBF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IH,IH2,X,TERM
   52   FORMAT('IH,IH2,X,TERM = ',2(A4,2X),2E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)SAVE1,SAVE2,SAVE3,SAVE4,SAVE5,I
   53   FORMAT('SAVE1,SAVE2,SAVE3,SAVE4,SAVE5,I = ',5E15.7,I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IANGLU,IBUGEV,IERROR,NUMBPW
   54   FORMAT('IANGLU,IBUGEV,IERROR,NUMBPW = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IFOUNZ='NO'
      CALL DPLIB1(IH,IH2,X,SAVE1,SAVE2,SAVE3,I,IANGLU,   &
                  TERM,IBUGEV,IFOUNZ,IERROR)
      IF(IFOUNZ.EQ.'YES')GO TO 9000
!
      IFOUNZ='NO'
      CALL DPLIB2(IH,IH2,X,SAVE1,SAVE2,IANGLU,   &
                  TERM,IBUGEV,IFOUNZ,IERROR)
      IF(IFOUNZ.EQ.'YES')GO TO 9000
!
      IFOUNZ='NO'
      CALL DPLIB3(IH,IH2,X,SAVE1,SAVE2,SAVE3,SAVE4,SAVE5,   &
                  SAVE6,SAVE7,SAVE8,   &
                  I,IANGLU,   &
                  TERM,IBUGEV,IFOUNZ,IERROR)
      IF(IFOUNZ.EQ.'YES')GO TO 9000
!
      WRITE(ICOUT,419)
  419 FORMAT('***** ERROR IN DPLIBF--UNKNOWN LIBRARY FUNCTION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,396)I,IH,IH2
  396 FORMAT('I,IH,IH2 = ',I8,2X,A4,A4)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGEV.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('AT THE END       OF DPLIBF--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)IFOUNZ,IERROR
 9015   FORMAT('IFOUNZ,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLIBF
      SUBROUTINE DPLICA(ICAPSW,IFORSW,ISEED,ISUBRO,IBUGA2,IBUGA3,IBUGQ,   &
                        IFOUND,IERROR)
!
!     PURPOSE--PERFORM A LINEAR CALIBRATRION ANALYSIS.
!              A LINEAR CALIBRATION WILL BE PERFORMED USING THE
!              FOLLOWING TECHNIQUES:
!               1) CLASSICAL (EISENHART: INVERSE PREDICTION LIMITS)
!               2) GRAYBILL-IYER METHOD
!               3) NETER, WASSERMAN, AND KUTNER
!               4) PROPOGATION OF ERROR
!               5) INVERSE (KRUTCHKOFF)
!               6) MAXIMUM LIKELIHOOD
!               7) BOOTSTRAP (EFRON--RESAMPLE RESIDUALS)
!               8) BOOTSTRAP (WU--RESAMPLE DATA)
!               9) BAYESIAN, CONTROLLED X'S, IMPROPER PRIOR (HOADLEY)
!                  (NOT ON INITIAL IMPLEMENTATION)
!              10) BAYESIAN, RANDOM X'S, IMPROPER PRIOR (HOADLEY)
!                  (NOT ON INITIAL IMPLEMENTATION)
!              11) FIELER
!            --YOU CAN ALSO SPECIFY A QUADRATIC CALIBRATION.  THE
!              FOLLOWING TECHNIQUES ARE SUPPORTED:
!               1) INVERSE PREDICTION LIMITS
!               2) PROPOGATION OF ERROR
!               2) BOOTSTRAP (EFRON--RESAMPLE RESIDUALS)
!               3) BOOTSTRAP (WU--RESAMPLE DATA)
!     WRITTEN BY--ALAN HECKERT/JIM FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/7
!     ORIGINAL VERSION--JULY      2003.
!     UPDATED         --JULY      2010. USE DPPARS TO PARSE THE
!                                       COMMAND
!     UPDATED         --SEPTEMBER 2011. ADD FIELER METHOD
!     UPDATED         --NOVEMBER  2016. ADD FIT WITH NO INTERCEPT TERM
!     UPDATED         --NOVEMBER  2016. ADD PROPOGATION OF ERROR
!                                       FOR QUADRATIC
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES----------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 ICASEQ
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      PARAMETER (MAXSPN=20)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
      CHARACTER*40 INAME
!
      CHARACTER*4 ITYPE
      CHARACTER*4 ICASAN
      CHARACTER*10 ICALTY
!
!----------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      DIMENSION Y1(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION Y3(MAXOBV)
!
      DIMENSION Z1(MAXOBV)
      DIMENSION Z2(MAXOBV)
      DIMENSION Z3(MAXOBV)
      DIMENSION Z4(MAXOBV)
      DIMENSION Z5(MAXOBV)
      DIMENSION Z6(MAXOBV)
      DIMENSION IZ(MAXOBV)
!
!CCCC NOTE: EQUIVALENCE TO DOUBLE PRECISION COMMON SINCE DPLIC3
!CCCC CALLS DPFIT WHICH ESSENTIALLY UTILIZES ALL THE SINGLE
!CCCC PRECISION STORAGE.
!
      INCLUDE 'DPCOZD.INC'
      EQUIVALENCE (DGARBG(IDGAR2),Y1(1))
      EQUIVALENCE (DGARBG(IDGAR3),Y2(1))
      EQUIVALENCE (DGARBG(IDGAR4),Y3(1))
      EQUIVALENCE (DGARBG(IDGAR5),Z1(1))
      EQUIVALENCE (DGARBG(IDGAR6),Z2(1))
      EQUIVALENCE (DGARBG(IDGAR7),Z3(1))
      EQUIVALENCE (DGARBG(IDGAR8),Z4(1))
      EQUIVALENCE (DGARBG(IDGAR9),Z5(1))
      EQUIVALENCE (DGARBG(IDGA10),Z6(1))
!
      INCLUDE 'DPCOZI.INC'
      EQUIVALENCE (IGARBG(IIGAR1),IZ(1))
!
!-----COMMON----------------------------------------------------
!
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      ISUBN1='DPLI'
      ISUBN2='CA  '
      IERROR='NO'
      ICASEQ='UNKN'
      ICASAN='LICA'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      MAXV2=3
      MINN2=2
!
!               *****************************************
!               **  TREAT THE LINEAR CALIBRATION CASE  **
!               *****************************************
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LICA')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLICA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGA2,IBUGA3,IBUGQ
   52   FORMAT('IBUGA2,IBUGA3,IBUGQ = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***************************
!               **  STEP 1--             **
!               **  EXTRACT THE COMMAND  **
!               ***************************
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LICA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.GE.2.AND.ICOM.EQ.'LINE'.AND.   &
        IHARG(1).EQ.'CALI'.AND.IHARG(2).EQ.'ANAL')THEN
        ILASTC=2
      ELSEIF(NUMARG.GE.2.AND.ICOM.EQ.'QUAD'.AND.   &
        IHARG(1).EQ.'CALI'.AND.IHARG(2).EQ.'ANAL')THEN
        ICASAN='QUCA'
        ILASTC=2
      ELSEIF(NUMARG.GE.1.AND.ICOM.EQ.'LINE'.AND.   &
        IHARG(1).EQ.'CALI')THEN
        ILASTC=1
      ELSEIF(NUMARG.GE.1.AND.ICOM.EQ.'QUAD'.AND.   &
        IHARG(1).EQ.'CALI')THEN
        ICASAN='QUCA'
        ILASTC=1
      ELSE
        IFOUND='NO'
        GO TO 9000
      ENDIF
!
      CALL ADJUST(ILASTC,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG)
      IFOUND='YES'
!
      ICALTY='LINEAR'
      IF(ICASAN.EQ.'QUCA')ICALTY='QUADRATIC'
!
!               *********************************
!               **  STEP 2--                   **
!               **  EXTRACT THE VARIABLE LIST  **
!               *********************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LICA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='LINEAR CALIBRATION'
      IF(ICASAN.EQ.'QUCA') INAME='QUADRATIC CALIBRATION'
      MINNA=3
      MAXNA=100
      MAXVAR=3
      MINN2=2
      IFLAGE=99
      IFLAGM=0
      IFLAGP=99
      JMIN=1
      JMAX=NUMARG
      MINNVA=3
      MAXNVA=3
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXVAR,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      ITYPE='VARI'
      IF(IVARTY(3).EQ.'PARA')ITYPE='PARA'
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LICA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               *****************************************
!               **  STEP 7--                           **
!               **  BRANCH TO THE APPROPRIATE SUBCASE; **
!               **  THEN FORM THE RESPONSE VARIABLE    **
!               **  AND THE FACTORS                    **
!               *****************************************
!
      ISTEPN='7'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LICA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      J=0
      IMAX=NRIGHT(1)
      IF(NQ.LT.NRIGHT(1))IMAX=NQ
      DO 660 I=1,IMAX
        IF(ISUB(I).EQ.0)GO TO 660
        J=J+1
!
        IJ=MAXN*(ICOLR(1)-1)+I
        IF(ICOLR(1).LE.MAXCOL)Y1(J)=V(IJ)
        IF(ICOLR(1).EQ.MAXCP1)Y1(J)=PRED(I)
        IF(ICOLR(1).EQ.MAXCP2)Y1(J)=RES(I)
        IF(ICOLR(1).EQ.MAXCP3)Y1(J)=YPLOT(I)
        IF(ICOLR(1).EQ.MAXCP4)Y1(J)=XPLOT(I)
        IF(ICOLR(1).EQ.MAXCP5)Y1(J)=X2PLOT(I)
        IF(ICOLR(1).EQ.MAXCP6)Y1(J)=TAGPLO(I)
!
        IJ=MAXN*(ICOLR(2)-1)+I
        IF(ICOLR(2).LE.MAXCOL)Y2(J)=V(IJ)
        IF(ICOLR(2).EQ.MAXCP1)Y2(J)=PRED(I)
        IF(ICOLR(2).EQ.MAXCP2)Y2(J)=RES(I)
        IF(ICOLR(2).EQ.MAXCP3)Y2(J)=YPLOT(I)
        IF(ICOLR(2).EQ.MAXCP4)Y2(J)=XPLOT(I)
        IF(ICOLR(2).EQ.MAXCP5)Y2(J)=X2PLOT(I)
        IF(ICOLR(2).EQ.MAXCP6)Y2(J)=TAGPLO(I)
!
  660 CONTINUE
      NS=J
!
      IF(ITYPE.EQ.'PARA')THEN
        Y3(1)=PVAR(3)
        NCALPT=1
      ELSE
        J=0
        DO 670 I=1,NRIGHT(3)
          J=J+1
!
          IJ=MAXN*(ICOLR(3)-1)+I
          IF(ICOLR(3).LE.MAXCOL)Y3(J)=V(IJ)
          IF(ICOLR(3).EQ.MAXCP1)Y3(J)=PRED(I)
          IF(ICOLR(3).EQ.MAXCP2)Y3(J)=RES(I)
          IF(ICOLR(3).EQ.MAXCP3)Y3(J)=YPLOT(I)
          IF(ICOLR(3).EQ.MAXCP4)Y3(J)=XPLOT(I)
          IF(ICOLR(3).EQ.MAXCP5)Y3(J)=X2PLOT(I)
          IF(ICOLR(3).EQ.MAXCP6)Y3(J)=TAGPLO(I)
  670   CONTINUE
        NCALPT=NRIGHT(3)
      ENDIF
!
!
!               ***********************************************
!               **  STEP 9--                                 **
!               **  CARRY OUT THE LINEAR CALIBRATION         **
!               ***********************************************
!
      ISTEPN='9'
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LICA')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LICA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,711)
  711   FORMAT('***** FROM DPLICA, AS WE ARE ABOUT TO CALL DPLIC2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,712)NRIGHT(1),MAXN,NS,NUMVAR
  712   FORMAT('NRIGHT(1),MAXN,NS,NUMVAR = ',4I8)
        CALL DPWRST('XXX','BUG ')
        DO 715 I=1,NS
          WRITE(ICOUT,716)I,Y1(I),Y2(I)
  716     FORMAT('I,Y1(I),Y2(I) = ',I6,2X,2G15.7)
          CALL DPWRST('XXX','BUG ')
  715   CONTINUE
      ENDIF
!
      IH='ALPH'
      IH2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        ALPHA=0.05
      ELSE
        ALPHA=VALUE(ILOCP)
        IF(ALPHA.LE.0.0 .OR. ALPHA.GE.1.0)ALPHA=0.05
        IF(ALPHA.GT.0.5)ALPHA=1.0 - ALPHA
      ENDIF
!
      IWRITE='OFF'
      IF(ICASAN.EQ.'LICA')THEN
        CALL DPLIC2(Y1,Y2,Y3,NS,NCALPT,NUMVAR,   &
                    Z1,Z2,Z3,Z4,Z6,IZ,   &
                    IVARN1(1),IVARN2(1),IVARN1(2),IVARN2(2),   &
                    ALPHA,MAXOBV,ISEED,   &
                    EISEN,EISENL,EISENU,   &
                    GRAYB,GRAYBL,GRAYBU,   &
                    ANWK,ANWKL,ANWKU,   &
                    PROPE,PROPEL,PROPEU,   &
                    PRO2E,PRO2EL,PRO2EU,   &
                    AINVR,AINVRL,AINVRU,   &
                    AMLE,AMLEL,AMLEU,   &
                    BOOTE,BOOTEL,BOOTEU,   &
                    BOOTW,BOOTWL,BOOTWU,   &
                    CBAYE,CBAYEL,CBAYEU,   &
                    FBAYE,FBAYEL,FBAYEU,   &
                    FIEL,FIELL,FIELU,   &
                    FIEL2,FIEL2L,FIEL2U,   &
                    FIELS,FIELSL,FIELSU,   &
                    IWRITE,IFITAC,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    ISUBRO,IBUGA3,IERROR)
      ELSE
        CALL DPLIC3(Y1,Y2,Y3,NS,NCALPT,NUMVAR,   &
                    Z1,Z2,Z3,Z4,Z5,Z6,IZ,   &
                    IVARN1(1),IVARN2(1),IVARN1(2),IVARN2(2),   &
                    ALPHA,MAXOBV,ISEED,   &
                    EISEN,EISENL,EISENU,   &
                    GRAYB,GRAYBL,GRAYBU,   &
                    ANWK,ANWKL,ANWKU,   &
                    PROPE,PROPEL,PROPEU,   &
                    PRO2E,PRO2EL,PRO2EU,   &
                    AINVR,AINVRL,AINVRU,   &
                    AMLE,AMLEL,AMLEU,   &
                    BOOTE,BOOTEL,BOOTEU,   &
                    BOOTW,BOOTWL,BOOTWU,   &
                    CBAYE,CBAYEL,CBAYEU,   &
                    FBAYE,FBAYEL,FBAYEU,   &
                    IWRITE,IFITAC,   &
                    ICAPSW,ICAPTY,IFORSW,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
!
!               ***************************************
!               **  STEP 10--                        **
!               **  UPDATE INTERNAL DATAPLOT TABLES  **
!               ***************************************
!
      ISTEPN='10'
      IF(IBUGA2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NCALPT.GT.1)GO TO 9000
      IH='EISE'
      IH2='N   '
      VALUE0=EISEN
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='EISE'
      IH2='NLCL'
      VALUE0=EISENL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='EISE'
      IH2='NUCL'
      VALUE0=EISENU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='GRAY'
      IH2='B   '
      VALUE0=GRAYB
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='GRAY'
      IH2='BLCL'
      VALUE0=GRAYBL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='GRAY'
      IH2='BUCL'
      VALUE0=GRAYBU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='NWK '
      IH2='    '
      VALUE0=ANWK
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='NWKL'
      IH2='CL  '
      VALUE0=ANWKL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='NWKU'
      IH2='CL  '
      VALUE0=ANWKU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='PROP'
      IH2='E   '
      VALUE0=PROPE
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='PROP'
      IH2='ELCL'
      VALUE0=PROPEL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='PROP'
      IH2='EUCL'
      VALUE0=PROPEU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='PRO2'
      IH2='E   '
      VALUE0=PRO2E
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='PRO2'
      IH2='ELCL'
      VALUE0=PRO2EL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='PRO2'
      IH2='EUCL'
      VALUE0=PRO2EU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='INVE'
      IH2='R   '
      VALUE0=AINVR
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='INVE'
      IH2='RLCL'
      VALUE0=AINVRL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='INVE'
      IH2='RUCL'
      VALUE0=AINVRU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='MLE '
      IH2='    '
      VALUE0=AMLE
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='MLEL'
      IH2='CL  '
      VALUE0=AMLEL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='MLEU'
      IH2='CL  '
      VALUE0=AMLEU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='BOOT'
      IH2='E   '
      VALUE0=BOOTE
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='BOOT'
      IH2='ELCL'
      VALUE0=BOOTEL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='BOOT'
      IH2='EUCL'
      VALUE0=BOOTEU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='BOOT'
      IH2='W   '
      VALUE0=BOOTW
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='BOOT'
      IH2='WLCL'
      VALUE0=BOOTWL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='BOOT'
      IH2='WUCL'
      VALUE0=BOOTWU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='FIEL'
      IH2='LBC '
      VALUE0=FIEL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='FIEL'
      IH2='LLBC'
      VALUE0=FIELL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='FIEL'
      IH2='LUBC'
      VALUE0=FIELU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='FIEL'
      IH2='L   '
      VALUE0=FIEL2
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='FIEL'
      IH2='LLCL'
      VALUE0=FIEL2L
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='FIEL'
      IH2='LUCL'
      VALUE0=FIEL2U
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='FIEL'
      IH2='LSIM'
      VALUE0=FIELS
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='FIEL'
      IH2='SLCL'
      VALUE0=FIELSL
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
      IH='FIEL'
      IH2='SUCL'
      VALUE0=FIELSU
      CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGA3,IERROR)
!
!CCCC BAYES NOT IMPLEMENTED YET, UNCOMMENT WHEN ACTIVATED IN DPLIC2.
!
!CCCC IH='CBAY'
!CCCC IH2='E   '
!CCCC VALUE0=CBAYE
!CCCC CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,
!CCCC1IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,
!CCCC1IANS,IWIDTH,IBUGA3,IERROR)
!
!CCCC IH='CBAY'
!CCCC IH2='ELCL'
!CCCC VALUE0=CBAYEL
!CCCC CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,
!CCCC1IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,
!CCCC1IANS,IWIDTH,IBUGA3,IERROR)
!
!CCCC IH='CBAY'
!CCCC IH2='EUCL'
!CCCC VALUE0=CBAYEU
!CCCC CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,
!CCCC1IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,
!CCCC1IANS,IWIDTH,IBUGA3,IERROR)
!
!CCCC IH='FBAY'
!CCCC IH2='E   '
!CCCC VALUE0=FBAYE
!CCCC CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,
!CCCC1IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,
!CCCC1IANS,IWIDTH,IBUGA3,IERROR)
!
!CCCC IH='FBAY'
!CCCC IH2='ELCL'
!CCCC VALUE0=FBAYEL
!CCCC CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,
!CCCC1IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,
!CCCC1IANS,IWIDTH,IBUGA3,IERROR)
!
!CCCC IH='FBAY'
!CCCC IH2='EUCL'
!CCCC VALUE0=FBAYEU
!CCCC CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,
!CCCC1IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,
!CCCC1IANS,IWIDTH,IBUGA3,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LICA')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLICA--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA2,IBUGA3,IBUGQ
 9012   FORMAT('IBUGA2,IBUGA3,IBUGQ = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NS,NUMVAR
 9014   FORMAT('NS,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLICA
      SUBROUTINE DPLIC2(Y1,Y2,Y3,NPTS,NCALPT,NUMVAR,   &
                        Z1,Z2,Z3,Z4,Z6,IZ,   &
                        IHLEFT,IHLEF2,IHRIGH,IHRIG2,   &
                        ALPHA,MAXNXT,ISEED,   &
                        EISEN,EISENL,EISENU,   &
                        GRAYB,GRAYBL,GRAYBU,   &
                        ANWK,ANWKL,ANWKU,   &
                        PROPE,PROPEL,PROPEU,   &
                        PRO2E,PRO2EL,PRO2EU,   &
                        AINVR,AINVRL,AINVRU,   &
                        AMLE,AMLEL,AMLEU,   &
                        BOOTE,BOOTEL,BOOTEU,   &
                        BOOTW,BOOTWL,BOOTWU,   &
                        CBAYE,CBAYEL,CBAYEU,   &
                        FBAYE,FBAYEL,FBAYEU,   &
                        FIEL,FIELL,FIELU,   &
                        FIEL2,FIEL2L,FIEL2U,   &
                        FIELS,FIELSL,FIELSU,   &
                        IWRITE,IFITAC,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--PERFORM A LINEAR CALIBRATRION ANALYSIS.
!              A LINEAR CALIBRATION WILL BE PERFORMED USING THE
!              FOLLOWING TECHNIQUES:
!               1) CLASSICAL (EISENHART: INVERSE PREDICTION LIMITS)
!               2) GRAYBILL-IYER METHOD
!               3) NETER, WASSERMAN, AND KUTNER
!               4) PROPOGATION OF ERROR
!               5) PROPOGATION OF ERROR (AS GIVEN IN E-HANDBOOK)
!               6) INVERSE (KRUTCHKOFF)
!               7) MAXIMUM LIKELIHOOD
!               8) BOOTSTRAP (EFRON)
!               9) BOOTSTRAP (WU)
!              10) BAYESIAN, CONTROLLED X'S, IMPROPER PRIOR (HOADLEY)
!                  (NOT ON INITIAL IMPLEMENTATION)
!              11) BAYESIAN, RANDOM X'S, IMPROPER PRIOR (HOADLEY)
!                  (NOT ON INITIAL IMPLEMENTATION)
!              12) FIELER'S METHOD
!     PRINTING--YES
!     SUBROUTINES NEEDED--LINFIT, TPPF
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/7
!     ORIGINAL VERSION--JULY      2003.
!     UPDATED         --OCTOBER   2003. ADD SUPPORT FOR LATEX OUTPUT
!     UPDATED         --OCTOBER   2006. CALL LIST TO TPPF
!     UPDATED         --JULY      2010. USE DPDTA1, DPDTA2 TO PRINT
!                                       OUTPUT
!     UPDATED         --SEPTEMBER 2011. ADD FIELER'S METHOD
!     UPDATED         --NOVEMBER  2016. ADD E-HANDBOOK PROPOGATION OF
!                                       ERROR METHOD
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IFITAC
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IHLEFT
      CHARACTER*4 IHLEF2
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
      CHARACTER*4 ICASJB
      CHARACTER*4 IOP
!
      DOUBLE PRECISION DSUM
      DOUBLE PRECISION DMEAN
!
!----------------------------------------------------------------
!
      REAL Y1(*)
      REAL Y2(*)
      REAL Y3(*)
!
      REAL Z1(*)
      REAL Z2(*)
      REAL Z3(*)
      REAL Z4(*)
      REAL Z6(*)
      INTEGER IZ(*)
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=15)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITL9
      CHARACTER*40 ITEXT(MAXROW)
      INTEGER      NCTEXT(MAXROW)
!
      PARAMETER(NUMCLI=7)
      PARAMETER(MAXLIN=2)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      REAL         AVALUE(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPLI'
      ISUBN2='C2  '
!
      EISEN=0.0
      EISENL=0.0
      EISENU=0.0
      GRAYB=0.0
      GRAYBL=0.0
      GRAYBU=0.0
      ANWK=0.0
      ANWKL=0.0
      ANWKU=0.0
      PROPE=0.0
      PROPEL=0.0
      PROPEU=0.0
      PRO2E=0.0
      PRO2EL=0.0
      PRO2EU=0.0
      AINVR=0.0
      AINVRL=0.0
      AINVRU=0.0
      AMLE=0.0
      AMLEL=0.0
      AMLEU=0.0
      BOOTE=0.0
      BOOTEL=0.0
      BOOTEU=0.0
      BOOTW=0.0
      BOOTWL=0.0
      BOOTWU=0.0
      CBAYE=0.0
      CBAYEL=0.0
      CBAYEU=0.0
      FBAYE=0.0
      FBAYEL=0.0
      FBAYEU=0.0
      FIEL=0.0
      FIELL=0.0
      FIELU=0.0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LIC2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLIC2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPTS,NCALPT,NUMVAR
   52   FORMAT('NPTS,NCALPT,NUMVAR = ',3I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NPTS
          WRITE(ICOUT,56)I,Y1(I),Y2(I)
   56     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,NCALPT
          WRITE(ICOUT,66)I,Y3(I)
   66     FORMAT('I,Y3(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(NPTS.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN DPLIC2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE LINEAR ',   &
               'CALIBRATION MUST BE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)NPTS
  103   FORMAT('      AT LEAST 2; THE ENTERED NUMBER OF ',   &
               'OBSERVATIONS = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               **************************************************
!               **  STEP 1.1--                                  **
!               **   OPEN THE STORAGE FILES                     **
!               **************************************************
!
      ISTEPN='1.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOP='OPEN'
      IFLAG1=1
      IFLAG2=1
      IFLAG3=1
      IFLAG4=1
      IFLAG5=0
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  COMPUTE THE LINEAR FIT AND PRINT OUT     **
!               **  SUMMARY OF FIT INFORMATION.              **
!               ***********************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IFITAC.EQ.'OFF')THEN
        CALL LINFI3(Y1,Y2,NPTS,   &
                    A0,A1,RESSD,RESDF,CCXY,SDA0,SDA1,CCALBE,   &
                    ISUBRO,IBUGA3,IERROR)
      ELSE
        CALL LINFIT(Y1,Y2,NPTS,   &
                    A0,A1,RESSD,RESDF,CCXY,SDA0,SDA1,CCALBE,   &
                    ISUBRO,IBUGA3,IERROR)
      ENDIF
      IF(IERROR.EQ.'YES')GO TO 9000
!
!     COMPUTE SOME QUANTITIES NEEDED BY MULTIPLE METHODS
!     AND FOR SUMMARIZING THE FIT
!
      IF(SDA0.GT.0.0 .AND. SDA1.GT.0.0)THEN
        COVAB=CCALBE*SDA0*SDA1
      ELSE
        COVAB=0.0
      ENDIF
      IF(IFITAC.EQ.'OFF')THEN
        TA0=0.0
      ELSE
        TA0=A0/SDA0
      ENDIF
      TA1=A1/SDA1
      ATEMP=1.0 - (ALPHA/2.0)
      N=NPTS
      AN=REAL(N)
      NM2=N - 2
      IF(IFITAC.EQ.'OFF')NM2=N-1
      CALL TPPF(ATEMP,REAL(NM2),T)
      TSSQ=T*T*RESSD*RESSD
      CALL MEAN(Y1,N,IWRITE,YBAR,IBUGA3,IERROR)
      CALL SD(Y1,N,IWRITE,YSD,IBUGA3,IERROR)
      CALL VAR(Y1,N,IWRITE,YVAR,IBUGA3,IERROR)
      CALL MEAN(Y2,N,IWRITE,XBAR,IBUGA3,IERROR)
      CALL SD(Y2,N,IWRITE,XSD,IBUGA3,IERROR)
      CALL VAR(Y2,N,IWRITE,XVAR,IBUGA3,IERROR)
      CALL COV(Y1,Y2,N,IWRITE,COVXY,IBUGA3,IERROR)
      SSDX=(AN-1.0)*XVAR
      SSDY=(AN-1.0)*YVAR
      SSDXY=(AN-1.0)*COVXY
      RATIO=TSSQ/SSDX
!
!     COMPUTE COEFFICIENT OF VARIATION OF SLOPE
!
      CVSLOP=RESSD/(A1*SQRT(SSDX))
!
!     COMPUTE PROPOGATION OF ERROR BASED STANDARD UNCERTAINTY.
!
!
!
!     PRINT HEADER TABLE
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Linear Calibration Analysis'
      NCTITL=27
      ITITL9(1:30)='Summary of Linear Fit Between '
      ITITL9(31:34)=IHLEFT(1:4)
      ITITL9(35:38)=IHLEF2(1:4)
      ITITL9(39:43)=' and '
      ITITL9(44:47)=IHRIGH(1:4)
      ITITL9(48:51)=IHRIG2(1:4)
      NCTITZ=51
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(NPTS)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Intercept:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=A0
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='SD(Intercept):'
      NCTEXT(ICNT)=14
      AVALUE(ICNT)=SDA0
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='t(Intercept):'
      NCTEXT(ICNT)=13
      AVALUE(ICNT)=TA0
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Slope:'
      NCTEXT(ICNT)=18
      AVALUE(ICNT)=A1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='SD(Slope):'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=SDA1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='t(Slope):'
      NCTEXT(ICNT)=9
      AVALUE(ICNT)=TA1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='CV(Slope):'
      NCTEXT(ICNT)=10
      AVALUE(ICNT)=CVSLOP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Residual Standard Deviation:'
      NCTEXT(ICNT)=38
      AVALUE(ICNT)=RESSD
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 2310 I=1,NUMROW
        NTOT(I)=15
 2310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITL9,NCTITZ,ITEXT,   &
                  NCTEXT,AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!               ***********************************************
!               **  STEP 3--                                 **
!               **  COMPUTE THE LINEAR CALIBRATION ESTIMATES **
!               **  USING VARIOUS METHODS.                   **
!               ***********************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOUNT=0
 3000 CONTINUE
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.NCALPT)GO TO 3999
      Y0=Y3(ICOUNT)
      X0=(Y0 - A0)/A1
!
!               ***********************************************
!               **  STEP 3.1--                               **
!               **  CLASSICAL: EISENHART INVERTED PREDICTION **
!               **  LIMITS.                                  **
!               ***********************************************
!
      ISTEPN='3.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      A=A1*A1 - RATIO
      B=2.0*(A0*A1 - A1*Y0 + RATIO*XBAR)
      C1=Y0*Y0 + A0*A0 - 2.0*A0*Y0
      C2=TSSQ*(1.0 + (1.0/AN) + (XBAR*XBAR)/SSDX)
      C=C1 - C2
      TERM3=B*B - 4.0*A*C
      TERM4=0.0
      IF(TERM3.GT.0.0)THEN
        TERM4=SQRT(TERM3)
        EISEN=X0
        EISENL=(-B - TERM4)/(2.0*A)
        EISENU=(-B + TERM4)/(2.0*A)
!
!       COMPUTE STANDARD ERROR AND EXPANDED UNCERTAINTY
!
        EEISEN=EISENU - EISEN
        CVISEN=T
        SEISEN=EEISEN/CVISEN
      ELSE
        EISENL=CPUMIN
        EISENU=CPUMIN
        EEISEN=CPUMIN
        CVISEN=CPUMIN
        SEISEN=CPUMIN
      ENDIF
!
!               ***********************************************
!               **  STEP 3.2--                               **
!               **  GRAYBILL AND IYER METHOD.                **
!               ***********************************************
!
      ISTEPN='3.2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      TERMA=A1*A1 - RATIO
      GRAYB=X0
      IF(TERMA.NE.0.0)THEN
        TERMB=TERMA*(1.0+(1.0/AN)) + ((Y0 - YBAR)**2)/SSDX
        TERMC=A1*(Y0-YBAR)
        TERMD=RESSD*T
        GRAYBL=XBAR + (TERMC - TERMD*SQRT(TERMB))/TERMA
        GRAYBU=XBAR + (TERMC + TERMD*SQRT(TERMB))/TERMA
        EEGRAY=GRAYBU - GRAYB
        CVGRAY=T
        SEGRAY=EEGRAY/CVGRAY
      ELSE
        GRAYBL=CPUMIN
        GRAYBU=CPUMIN
        EEGRAY=CPUMIN
        CVGRAY=CPUMIN
        SEGRAY=CPUMIN
      ENDIF
!
!               ***********************************************
!               **  STEP 3.3--                               **
!               **  NETER, WASSERMAN, AND KUTNER             **
!               ***********************************************
!
      ISTEPN='3.3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      TERM=1.0 + (1.0/AN) + ((X0 - XBAR)**2)/SSDX
      SDX0=(RESSD/ABS(A1))*SQRT(TERM)
      ANWK=X0
      ANWKL=X0 - T*SDX0
      ANWKU=X0 + T*SDX0
      SENWK=SDX0
      CVNWK=T
      EENWK=CVNWK*SENWK
!
!               ***********************************************
!               **  STEP 3.4--                               **
!               **  PROPOGATION OF ERROR                     **
!               ***********************************************
!
      ISTEPN='3.4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DSUM=0.0D0
      DO 3410 I=1,N
        DSUM=DSUM+DBLE(Y2(I))**2
 3410 CONTINUE
      DMEAN=DSUM/DBLE(N)
      AMNX2=REAL(DMEAN)
      TERM=AMNX2 + X0**2 + 2.0*X0*XBAR
      SDX0=(RESSD/(ABS(A1)*SQRT(SSDX)))*SQRT(TERM)
      PROPE=X0
      PROPEL=X0 - T*SDX0
      PROPEU=X0 + T*SDX0
      SEPROP=SDX0
      CVPROP=T
      EEPROP=CVPROP*SEPROP
!
!               ***********************************************
!               **  STEP 3.5--                               **
!               **  INVERSE (KRUTCHKOFF)                     **
!               ***********************************************
!
      ISTEPN='3.5'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL LINFIT(Y2,Y1,NPTS,   &
      B0,B1,RESSDX,RESDFX,CCXY2,SDB0,SDB1,CCALB2,   &
      ISUBRO,IBUGA3,IERROR)
!
      C=T*RESSDX*(1.0 + (1.0/AN) + ((Y0-YBAR)**2)/SSDY)
      AINVR=XBAR + (SSDXY/SSDY)*(Y0-YBAR)
      AINVRL=AINVR - C
      AINVRU=AINVR + C
      SEKRUT=RESSDX*(1.0 + (1.0/AN) + ((Y0-YBAR)**2)/SSDY)
      CVKRUT=T
      EEKRUT=C
!
!               ***********************************************
!               **  STEP 3.6--                               **
!               **  MAXIMUM LIKELIHOOD                       **
!               ***********************************************
!
      ISTEPN='3.6'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 3610 I=1,NPTS
        Z1(I)=Y2(I) - XBAR
 3610 CONTINUE
!
      CALL LINFIT(Y1,Z1,NPTS,   &
      B0,B1,RESSDX,RESDFX,CCXY2,SDB0,SDB1,CCALB2,   &
      ISUBRO,IBUGA3,IERROR)
!
      AMLE=0.0
      IF(B1.NE.0.0)AMLE=(Y0 - (B0-B1*XBAR))/B1
!
      NUMSIM=10000
      CALL NORRAN(NUMSIM,ISEED,Z2)
      CALL NORRAN(NUMSIM,ISEED,Z3)
!
      DO 3620 I=1,NUMSIM
        Z2(I)=SDB0*Z2(I) + B0
        Z3(I)=SDB1*Z3(I) + B1
        IF(Z3(I).NE.0.0)THEN
          Z4(I)=(Y0 - (Z2(I) - Z3(I)*XBAR))/Z3(I)
        ELSE
          Z4(I)=0.0
        ENDIF
 3620 CONTINUE
!
      CALL SD(Z4,NUMSIM,IWRITE,SEMLE,IBUGA3,IERROR)
      P100=100.0*(ALPHA/2.0)
      CALL PERCEN(P100,Z4,NUMSIM,IWRITE,Z1,MAXNXT,   &
                  AMLEL,IBUGA3,IERROR)
      P100=100.0*(1.0 - (ALPHA/2.0))
      CALL PERCEN(P100,Z4,NUMSIM,IWRITE,Z1,MAXNXT,   &
                  AMLEU,IBUGA3,IERROR)
!
      EEMLE=MAX((AMLEU - AMLE),(AMLE - AMLEL))
      CVMLE=EEMLE/SEMLE
!
!               ***********************************************
!               **  STEP 3.7--                               **
!               **  BOOTSTRAP (EFROM RESAMPLING, I.E.,       **
!               **  RESAMPLE THE RESIDUALS)                  **
!               ***********************************************
!
      ISTEPN='3.7'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL LINFIT(Y1,Y2,NPTS,   &
                  B0,B1,XRESSD,XRESDF,CCXY,SDB0,SDB1,CCALBE,   &
                  ISUBRO,IBUGA3,IERROR)
      DO 3711 I=1,NPTS
        Z1(I)=Y1(I)-(B0+B1*Y2(I))
 3711 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')THEN
         WRITE(ICOUT,3712)B0,B1
 3712    FORMAT('B0,B1 = ',2G15.7)
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ICASJB='BOOT'
      NRESAM=1000
!
      DO 3720 IRESAM=1,NRESAM
        CALL DPJBS3(Z1,NPTS,ICASJB,IRESAM,ISEED,Z2,NPTS2,IZ,   &
                    Z6,IBUGA3,IERROR)
        DO 3722 I=1,NPTS2
          Z3(I)=(B0+B1*Y2(I))+Z2(I)
 3722   CONTINUE
        CALL LINFIT(Z3,Y2,NPTS2,   &
            C0,C1,XRESSD,XRESDF,CCXY,SDC0,SDC1,CCALBE,   &
            ISUBRO,IBUGA3,IERROR)
        Z4(IRESAM)=(Y0-C0)/C1
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')THEN
          WRITE(ICOUT,3725)IERROR,IRESAM,C0,C1,Z4(IRESAM)
 3725     FORMAT('IERROR,IRESAM,C0,C1,Z4(IRESAM) = ',A4,I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
 3720 CONTINUE
!
      BOOTE=X0
      CALL SD(Z4,NRESAM,IWRITE,SEBOOE,IBUGA3,IERROR)
      P100=100.0*(ALPHA/2.0)
      CALL PERCEN(P100,Z4,NRESAM,IWRITE,Z3,MAXNXT,   &
                  BOOTEL,IBUGA3,IERROR)
      P100=100.0*(1.0 - ALPHA/2.0)
      CALL PERCEN(P100,Z4,NRESAM,IWRITE,Z3,MAXNXT,   &
                  BOOTEU,IBUGA3,IERROR)
!
      EEBOOE=MAX((BOOTEU - BOOTE),(BOOTE - BOOTEL))
      CVBOOE=EEBOOE/SEBOOE
!
!               ***********************************************
!               **  STEP 3.8--                               **
!               **  BOOTSTRAP (WU RESAMPLING, I.E., RESAMPLE **
!               **  THE ORIGINAL (X,Y) DATA                  **
!               ***********************************************
!
      ISTEPN='3.8'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASJB='BOOT'
      NRESAM=1000
!
      DO 3810 IRESAM=1,NRESAM
        CALL DPJBS3(Y1,NPTS,ICASJB,IRESAM,ISEED,Z1,NPTS2,IZ,   &
                    Z6,IBUGA3,IERROR)
        DO 3820 IJ=1,NPTS2
          Z2(IJ)=Y2(IZ(IJ))
 3820   CONTINUE
        CALL LINFIT(Z1,Z2,NPTS2,   &
             C0,C1,XRESSD,XRESDF,CCXY,SDC0,SDC1,CCALBE,   &
             ISUBRO,IBUGA3,IERROR)
        Z4(IRESAM)=(Y0-C0)/C1
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')THEN
          WRITE(ICOUT,3822)IRESAM,C0,C1,Z4(IRESAM)
 3822     FORMAT('IRESAM,C0,C1,Z4(IRESAM) = ',I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
 3810 CONTINUE
!
      BOOTW=X0
      CALL SD(Z4,NRESAM,IWRITE,SEBOOW,IBUGA3,IERROR)
      P100=100.0*(ALPHA/2.0)
      CALL PERCEN(P100,Z4,NRESAM,IWRITE,Z3,MAXNXT,   &
                  BOOTWL,IBUGA3,IERROR)
      P100=100.0*(1.0 - ALPHA/2.0)
      CALL PERCEN(P100,Z4,NRESAM,IWRITE,Z3,MAXNXT,   &
                  BOOTWU,IBUGA3,IERROR)
!
      EEBOOW=MAX((BOOTWU - BOOTW),(BOOTW - BOOTWL))
      CVBOOW=EEBOOW/SEBOOW
!
!               ***********************************************
!               **  STEP 3.9--FIELLER'S METHOD AS DOCUMENTED **
!               **            ON PAGE 178-179 OF             **
!               **            RUPERT MILLER JR., "BEYOND     **
!               **            ANOVA, BASICS OF APPLIED       **
!               **            STATISTICS", JOHN WILEY & SONS.**
!               ***********************************************
!
      ISTEPN='3.9'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     COMPUTE BOTH THE BIAS CORRECTED AND BIAS UNCORRECTED METHODS
!
      NU1=1
      NU2=N-2
      ALPHAT=1.0 - ALPHA
      CALL FPPF(ALPHAT,NU1,NU2,FF)
      E=FF*RESSD**2/(A1**2*SSDX)
      DEN=A1*(1.0 - E)
      TERM1=(1.0/AN)*(1.0 - E) + (Y0 - YBAR)**2/(A1**2*SSDX)
      ANUM=SQRT(FF)*RESSD*SQRT(TERM1)
!
!     BIAS CORRECTED (EQUATION 5.32 IN MILLER)
!
      FIEL=X0
      ATEMP1=XBAR + ((Y0 - YBAR) - ANUM)/DEN
      ATEMP2=XBAR + ((Y0 - YBAR) + ANUM)/DEN
      FIELL=MIN(ATEMP1,ATEMP2)
      FIELU=MAX(ATEMP1,ATEMP2)
      SEFIBC=RESSD*SQRT(TERM1)/DEN
      EEFIBC=MAX((FIELU - FIEL),(FIEL - FIELL))
      CVFIBC=EEFIBC/SEFIBC
!
!     NO BIAS CORRECTION (EQUATION 5.35 IN MILLER)
!     SHOULD BE ADEQUATE IF CV(SLOPE) < 0.10
!
      TERM1=(SQRT(FF)*RESSD/ABS(A1))
      TERM2=(1.0/AN) + (Y0 - YBAR)**2/(A1**2*SSDX)
      TERM3=TERM1*SQRT(TERM2)
      FIEL2=X0
      ATEMP1=X0 - TERM3
      ATEMP2=X0 + TERM3
      FIEL2L=MIN(ATEMP1,ATEMP2)
      FIEL2U=MAX(ATEMP1,ATEMP2)
      SEFIEL=(RESSD/ABS(A1))*SQRT(TERM2)
      EEFIEL=MAX((FIEL2U - FIEL),(FIEL - FIEL2L))
      CVFIEL=EEFIEL/SEFIEL
!
!     SIMULTANEOUS CALIBRATION INTERVAL
!
      NU1=2
      NU2=N-2
      ALPHAT=1.0 - ALPHA
      CALL FPPF(ALPHAT,NU1,NU2,FF)
      E=2.0*FF*RESSD**2/(A1**2*SSDX)
      DEN=A1*(1.0 - E)
      TERM1=(1.0/AN)*(1.0 - E) + (Y0 - YBAR)**2/(A1**2*SSDX)
      ANUM=SQRT(2.0*FF)*RESSD*SQRT(TERM1)
      FIELS=X0
      ATEMP1=XBAR + ((Y0 - YBAR) - ANUM)/DEN
      ATEMP2=XBAR + ((Y0 - YBAR) + ANUM)/DEN
      FIELSL=MIN(ATEMP1,ATEMP2)
      FIELSU=MAX(ATEMP1,ATEMP2)
      SEFISM=RESSD*SQRT(TERM1)/DEN
      EEFISM=MAX((FIELSU - FIEL),(FIEL - FIELSL))
      CVFISM=EEFISM/SEFISM
!
!               ***********************************************
!               **  STEP 3.10--                              **
!               **  PROPOGATION OF ERROR AS IMPLEMENTED IN   **
!               **  E-HANDBOOK (MPC3673.HTM)                 **
!               ***********************************************
!
      ISTEPN='3.10'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      TERM1=(RESSD/A1)**2
      TERM2=(SDA0/A1)**2
      TERM3=((Y0-A0)**2)*(SDA1**2)/(A1**4)
      TERM3A=-(Y0-A0)/A1**2
      TERM3=TERM3A**2*(SDA1**2)
      TERM4=2.0*(Y0-A0)*COVAB/(A1**3)
      TERM=TERM1 + TERM2 + TERM3 + TERM4
      SDX0=SQRT(TERM)
      PRO2E=X0
      PRO2EL=X0 - T*SDX0
      PRO2EU=X0 + T*SDX0
      SEPRO2=SDX0
      CVPRO2=T
      EEPRO2=T*SDX0
!
!               ***********************************************
!               **  STEP 4--                                 **
!               **  PRINT OUT THE RESULTS.                   **
!               ***********************************************
!
      ISTEPN='4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IMETHD=1
      WRITE(IOUNI1,5401)IMETHD,Y0,EISEN,EISENL,EISENU
      IMETHD=2
      WRITE(IOUNI1,5401)IMETHD,Y0,GRAYB,GRAYBL,GRAYBU
      IMETHD=3
      WRITE(IOUNI1,5401)IMETHD,Y0,ANWK,ANWKL,ANWKU
      IMETHD=4
      WRITE(IOUNI1,5401)IMETHD,Y0,PROPE,PROPEL,PROPEU
      IMETHD=5
      WRITE(IOUNI1,5401)IMETHD,Y0,PRO2E,PRO2EL,PRO2EU
      IMETHD=6
      WRITE(IOUNI1,5401)IMETHD,Y0,AINVR,AINVRL,AINVRU
      IMETHD=7
      WRITE(IOUNI1,5401)IMETHD,Y0,AMLE,AMLEL,AMLEU
      IMETHD=8
      WRITE(IOUNI1,5401)IMETHD,Y0,BOOTE,BOOTEL,BOOTEU
      IMETHD=9
      WRITE(IOUNI1,5401)IMETHD,Y0,BOOTW,BOOTWL,BOOTWU
      IMETHD=10
      WRITE(IOUNI1,5401)IMETHD,Y0,FIEL,FIELL,FIELU
      IMETHD=11
      WRITE(IOUNI1,5401)IMETHD,Y0,FIEL2,FIEL2L,FIEL2U
      IMETHD=12
      WRITE(IOUNI1,5401)IMETHD,Y0,FIELS,FIELSL,FIELSU
 5401 FORMAT(I2,2X,4E15.7)
      WRITE(IOUNI2,5411)Y0,EISEN,GRAYB,ANWK,PROPE,PRO2E,AINVR,AMLE,   &
                        BOOTE,BOOTW,FIEL,FIEL2,FIELS
      WRITE(IOUNI3,5411)Y0,EISENL,GRAYBL,ANWKL,PROPEL,PRO2EL,AINVRL,   &
                        AMLEL,BOOTEL,BOOTWL,FIELL,FIEL2L,FIELSL
      WRITE(IOUNI4,5411)Y0,EISENU,GRAYBU,ANWKU,PROPEU,PRO2EU,AINVRU,   &
                        AMLEU,BOOTEU,BOOTWU,FIELU,FIEL2U,FIELSU
 5411 FORMAT(12E15.7)
!
      ATEMP=1.0-ALPHA
      ITEMP=INT(100.*ATEMP + 0.00001)
!
      IF(ICOUNT.EQ.1)THEN
        ITITLE(1:39)='Linear Calibration Summary'
        NCTITL=26
        ITITL9(1:6)='Y0 = '
        WRITE(ITITL9(7:21),'(G15.7)')Y0
        NCTIT9=21
      ELSE
        ITITLE(1:39)=' '
        NCTITL=0
        ITITL9(1:6)='Y0 = '
        WRITE(ITITL9(7:21),'(G15.7)')Y0
        NCTIT9=21
      ENDIF
      NUMLIN=2
      NUMCOL=6
      ITITL2(1,1)=' '
      NCTIT2(1,1)=0
      ITITL2(2,1)='Method'
      NCTIT2(2,1)=6
      ITITL2(1,2)=' '
      NCTIT2(1,2)=0
      ITITL2(2,2)='X0'
      NCTIT2(2,2)=2
      WRITE(ITITL2(1,3)(1:2),'(I2)')ITEMP
      ITITL2(1,3)(3:3)='%'
      NCTIT2(1,3)=3
      ITITL2(2,3)='Lower Limit'
      NCTIT2(2,3)=11
      WRITE(ITITL2(1,4)(1:2),'(I2)')ITEMP
      ITITL2(1,4)(3:3)='%'
      NCTIT2(1,4)=3
      ITITL2(2,4)='Upper Limit'
      NCTIT2(2,4)=11
      ITITL2(1,5)='Standard'
      NCTIT2(1,5)=8
      ITITL2(2,5)='Error'
      NCTIT2(2,5)=5
      ITITL2(1,6)=' '
      NCTIT2(1,6)=0
      ITITL2(2,6)='Coverage'
      NCTIT2(2,6)=8
      ITITL2(1,7)='Expanded'
      NCTIT2(1,7)=8
      ITITL2(2,7)='Error'
      NCTIT2(2,7)=5
!
      NMAX=0
      DO 2521 I=1,NUMCOL+1
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1)THEN
          NTOT(I)=40
          ALIGN(I)='l'
        ENDIF
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
 2521 CONTINUE
!
      ICNT=0
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' 1. Inverse Prediction Limits:'
      NCTEXT(ICNT)=30
      AMAT(ICNT,1)=EISEN
      AMAT(ICNT,2)=EISENL
      AMAT(ICNT,3)=EISENU
      AMAT(ICNT,4)=SEISEN
      AMAT(ICNT,5)=CVISEN
      AMAT(ICNT,6)=EEISEN
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' 2. Graybill-Iyer:'
      NCTEXT(ICNT)=19
      AMAT(ICNT,1)=GRAYB
      AMAT(ICNT,2)=GRAYBL
      AMAT(ICNT,3)=GRAYBU
      AMAT(ICNT,4)=SEGRAY
      AMAT(ICNT,5)=CVGRAY
      AMAT(ICNT,6)=EEGRAY
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' 3. Neter-Wasserman-Kutner:'
      NCTEXT(ICNT)=28
      AMAT(ICNT,1)=ANWK
      AMAT(ICNT,2)=ANWKL
      AMAT(ICNT,3)=ANWKU
      AMAT(ICNT,4)=SENWK
      AMAT(ICNT,5)=CVNWK
      AMAT(ICNT,6)=EENWK
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' 4. Propogation of Error:'
      NCTEXT(ICNT)=26
      AMAT(ICNT,1)=PROPE
      AMAT(ICNT,2)=PROPEL
      AMAT(ICNT,3)=PROPEU
      AMAT(ICNT,4)=SEPROP
      AMAT(ICNT,5)=CVPROP
      AMAT(ICNT,6)=EEPROP
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' 5. Propogation of Error (e-Handbook):'
      NCTEXT(ICNT)=38
      AMAT(ICNT,1)=PRO2E
      AMAT(ICNT,2)=PRO2EL
      AMAT(ICNT,3)=PRO2EU
      AMAT(ICNT,4)=SEPRO2
      AMAT(ICNT,5)=CVPRO2
      AMAT(ICNT,6)=EEPRO2
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' 6. Inverse (Krutchkoff):'
      NCTEXT(ICNT)=26
      AMAT(ICNT,1)=AINVR
      AMAT(ICNT,2)=AINVRL
      AMAT(ICNT,3)=AINVRU
      AMAT(ICNT,4)=SEKRUT
      AMAT(ICNT,5)=CVKRUT
      AMAT(ICNT,6)=EEKRUT
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' 7. Maximum Likelihood:'
      NCTEXT(ICNT)=24
      AMAT(ICNT,1)=AMLE
      AMAT(ICNT,2)=AMLEL
      AMAT(ICNT,3)=AMLEU
      AMAT(ICNT,4)=SEMLE
      AMAT(ICNT,5)=CVMLE
      AMAT(ICNT,6)=EEMLE
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' 8. Bootstrap (Residuals):'
      NCTEXT(ICNT)=27
      AMAT(ICNT,1)=BOOTE
      AMAT(ICNT,2)=BOOTEL
      AMAT(ICNT,3)=BOOTEU
      AMAT(ICNT,4)=SEBOOE
      AMAT(ICNT,5)=CVBOOE
      AMAT(ICNT,6)=EEBOOE
!
      ICNT=ICNT+1
      ITEXT(ICNT)=' 9. Bootstrap (Data):'
      NCTEXT(ICNT)=22
      AMAT(ICNT,1)=BOOTW
      AMAT(ICNT,2)=BOOTWL
      AMAT(ICNT,3)=BOOTWU
      AMAT(ICNT,4)=SEBOOW
      AMAT(ICNT,5)=CVBOOW
      AMAT(ICNT,6)=EEBOOW
!
      ICNT=ICNT+1
      ITEXT(ICNT)='10. Fieller (Bias Corrected):'
      NCTEXT(ICNT)=29
      AMAT(ICNT,1)=FIEL
      AMAT(ICNT,2)=FIELL
      AMAT(ICNT,3)=FIELU
      AMAT(ICNT,4)=SEFIBC
      AMAT(ICNT,5)=CVFIBC
      AMAT(ICNT,6)=EEFIBC
!
      ICNT=ICNT+1
      ITEXT(ICNT)='11. Fieller (No Bias Correction):'
      NCTEXT(ICNT)=33
      AMAT(ICNT,1)=FIEL2
      AMAT(ICNT,2)=FIEL2L
      AMAT(ICNT,3)=FIEL2U
      AMAT(ICNT,4)=SEFIEL
      AMAT(ICNT,5)=CVFIEL
      AMAT(ICNT,6)=EEFIEL
!
      ICNT=ICNT+1
      ITEXT(ICNT)='12. Fieller (Simultaneous):'
      NCTEXT(ICNT)=27
      AMAT(ICNT,1)=FIELS
      AMAT(ICNT,2)=FIELSL
      AMAT(ICNT,3)=FIELSU
      AMAT(ICNT,4)=SEFISM
      AMAT(ICNT,5)=CVFISM
      AMAT(ICNT,6)=EEFISM
!
      IWHTML(1)=250
      IWHTML(2)=150
      IWHTML(3)=150
      IWHTML(4)=150
      IWHTML(5)=150
      IWHTML(6)=150
      IWHTML(7)=150
      IWRTF(1)=3000
      IWRTF(2)=IWRTF(1)+2000
      IWRTF(3)=IWRTF(2)+2000
      IWRTF(4)=IWRTF(3)+2000
      IWRTF(5)=IWRTF(4)+2000
      IWRTF(6)=IWRTF(5)+2000
      IWRTF(7)=IWRTF(6)+2000
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA2(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  ITEXT,NCTEXT,AMAT,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      GO TO 3000
!
 3999 CONTINUE
!
      IF(IFEEDB.EQ.'ON')THEN
!
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8102)
 8102   FORMAT('FOLLOWING INFORMATION WRITTEN OUT TO FILES.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8112)
 8112   FORMAT('DPST1F.DAT: METHOD (1 - 8), Y0, X0, LOWER LIMIT, ',   &
               'UPPER LIMIT')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8122)
 8122   FORMAT('DPST2F.DAT: Y0 AND X0 FOR ALL EIGHT METHODS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8132)
 8132   FORMAT('DPST3F.DAT: Y0 AND LOWER LIMIT FOR ALL EIGHT METHODS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8142)
 8142   FORMAT('DPST4F.DAT: Y0 AND UPPER LIMIT FOR ALL EIGHT METHODS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
!
      ENDIF
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LIC2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLIC2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPTS,NUMVAR
 9013   FORMAT('NPTS,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLIC2
      SUBROUTINE DPLIC3(Y1,Y2,Y3,NPTS,NCALPT,NUMVAR,   &
                        Z1,Z2,Z3,Z4,Z5,Z6,IZ,   &
                        IHLEFT,IHLEF2,IHRIGH,IHRIG2,   &
                        ALPHA,MAXNXT,ISEED,   &
                        EISEN,EISENL,EISENU,   &
                        GRAYB,GRAYBL,GRAYBU,   &
                        ANWK,ANWKL,ANWKU,   &
                        PROPE,PROPEL,PROPEU,   &
                        PRO2E,PRO2EL,PRO2EU,   &
                        AINVR,AINVRL,AINVRU,   &
                        AMLE,AMLEL,AMLEU,   &
                        BOOTE,BOOTEL,BOOTEU,   &
                        BOOTW,BOOTWL,BOOTWU,   &
                        CBAYE,CBAYEL,CBAYEU,   &
                        FBAYE,FBAYEL,FBAYEU,   &
                        IWRITE,IFITAC,   &
                        ICAPSW,ICAPTY,IFORSW,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--PERFORM A QUADRATIC CALIBRATRION ANALYSIS.
!              A QUADRATIC CALIBRATION WILL BE PERFORMED USING THE
!              FOLLOWING TECHNIQUES:
!               1) CLASSICAL (EISENHART: INVERSE PREDICTION LIMITS)
!               2) PROPOGATION OF ERROR (AS GIVEN IN E-HANDBOOK)
!               2) BOOTSTRAP (EFRON)
!               3) BOOTSTRAP (WU)
!     PRINTING--YES
!     SUBROUTINES NEEDED--QUAFIT, TPPF
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2003/7
!     ORIGINAL VERSION--JULY      2003.
!     UPDATED         --OCTOBER   2003. ADD SUPPORT FOR LATEX OUTPUT
!     UPDATED         --OCTOBER   2006. CALL LIST TO TPPF
!     UPDATED         --JULY      2010. USE DPDTA1, DPDTA2 TO PRINT
!                                       OUTPUT
!     UPDATED         --NOVEMBER  2016. ADD PROPOGATION OF ERROR
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IFORSW
      CHARACTER*4 IFITAC
      CHARACTER*4 ICASAN
      CHARACTER*4 ISUBRO
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISTEPN
      CHARACTER*4 IHP
      CHARACTER*4 IHP2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 IHLEFT
      CHARACTER*4 IHLEF2
      CHARACTER*4 IHRIGH
      CHARACTER*4 IHRIG2
!
      CHARACTER*4 ICASJB
      CHARACTER*80 ISTRT
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=15)
      CHARACTER*60 ITITLE
      CHARACTER*60 ITITL9
      CHARACTER*40 ITEXT(MAXROW)
      INTEGER      NCTEXT(MAXROW)
!
      PARAMETER(NUMCLI=7)
      PARAMETER(MAXLIN=2)
      CHARACTER*60 ITITL2(MAXLIN,NUMCLI)
      INTEGER      NCTIT2(MAXLIN,NUMCLI)
      INTEGER      IWHTML(NUMCLI)
      INTEGER      IWRTF(NUMCLI)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      CHARACTER*4  ALIGN(NUMCLI)
      CHARACTER*4  VALIGN(NUMCLI)
      REAL         AMAT(MAXROW,NUMCLI)
      REAL         AVALUE(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
!
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGCO
      CHARACTER*4 IBUGEV
      CHARACTER*4 IBUGQ
      CHARACTER*4 ICOMT
      CHARACTER*4 ICOM2T
      PARAMETER (MAXART=20)
      CHARACTER*4 ITHARG
      CHARACTER*4 ITHAR2
      CHARACTER*4 ITARGT
      CHARACTER*4 IANST
      DIMENSION ITHARG(MAXART)
      DIMENSION ITHAR2(MAXART)
      DIMENSION ITARG(MAXART)
      DIMENSION TARG(MAXART)
      DIMENSION ITARGT(MAXART)
      DIMENSION IANST(MAXSTR)
!
!----------------------------------------------------------------
!
      REAL Y1(*)
      REAL Y2(*)
      REAL Y3(*)
!
      REAL Z1(*)
      REAL Z2(*)
      REAL Z3(*)
      REAL Z4(*)
      REAL Z5(*)
      REAL Z6(*)
      INTEGER IZ(*)
!
      DOUBLE PRECISION DX
      DOUBLE PRECISION DA0
      DOUBLE PRECISION DA1
      DOUBLE PRECISION DA2
      DOUBLE PRECISION DC0
      DOUBLE PRECISION DC1
      DOUBLE PRECISION DC2
      DOUBLE PRECISION DC3
      DOUBLE PRECISION DC4
      DOUBLE PRECISION DC6
      DOUBLE PRECISION DEPS
      DOUBLE PRECISION DSIG
      DOUBLE PRECISION DZERO
      DOUBLE PRECISION DY0
      DOUBLE PRECISION DXL
      DOUBLE PRECISION DXR
      DOUBLE PRECISION DTERM1
      DOUBLE PRECISION DTERM2
      DOUBLE PRECISION DTERM3
      DOUBLE PRECISION DXRML
      DOUBLE PRECISION DXTEMP
      DOUBLE PRECISION DFXL
      DOUBLE PRECISION DFXR
      DOUBLE PRECISION DFCS
      DOUBLE PRECISION DA0SD
      DOUBLE PRECISION DA1SD
      DOUBLE PRECISION DA2SD
      DOUBLE PRECISION DRESSD
      DOUBLE PRECISION XPYP
      DOUBLE PRECISION XPA0
      DOUBLE PRECISION XPA1
      DOUBLE PRECISION XPA2
      DOUBLE PRECISION DVAR1
      DOUBLE PRECISION DVAR2
      DOUBLE PRECISION DSE
!
      CHARACTER*4 IPRNT2
      CHARACTER*4 IFEED2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      IPRNT2=IPRINT
      ISUBN1='DPLI'
      ISUBN2='C3  '
      IFEED2=IFEEDB
!
      EISEN=0.0
      EISENL=0.0
      EISENU=0.0
      EEISEN=0.0
      EEBOOW=0.0
      EEBOOE=0.0
      CVISEN=0.0
      CVBOOW=0.0
      CVBOOE=0.0
      GRAYB=0.0
      GRAYBL=0.0
      GRAYBU=0.0
      ANWK=0.0
      ANWKL=0.0
      ANWKU=0.0
      PROPE=0.0
      PROPEL=0.0
      PROPEU=0.0
      AINVR=0.0
      AINVRL=0.0
      AINVRU=0.0
      AMLE=0.0
      AMLEL=0.0
      AMLEU=0.0
      BOOTE=0.0
      BOOTEL=0.0
      BOOTEU=0.0
      BOOTW=0.0
      BOOTWL=0.0
      BOOTWU=0.0
      CBAYE=0.0
      CBAYEL=0.0
      CBAYEU=0.0
      FBAYE=0.0
      FBAYEL=0.0
      FBAYEU=0.0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LIC3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLIC3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPTS,NCALPT,NUMVAR
   52   FORMAT('NPTS,NCALPT,NUMVAR = ',3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)PRO2EL,PRO2EU
   53   FORMAT('PRO2EL,PRO2EU = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,NPTS
          WRITE(ICOUT,56)I,Y1(I),Y2(I)
   56     FORMAT('I,Y1(I),Y2(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
        DO 65 I=1,NCALPT
          WRITE(ICOUT,66)I,Y3(I)
   66     FORMAT('I,Y3(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(NPTS.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN QUADRATIC CALIBRATION--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE QUADRATIC ',   &
               'CALIBRATION MUST BE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,103)NPTS
  103   FORMAT('      AT LEAST 2; THE ENTERED NUMBER OF ',   &
               'OBSERVATIONS = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!               ********************************************
!               **  STEP 1B--                             **
!               **  PERFORM A QUADRATIC FIT ON ORIGINAL   **
!               **  DATA; SAVE RELEVANT PARAMETERS        **
!               **  (COEFFICIENTS, COEFFICIENT SD'S,      **
!               **  T-VALUES, RESSD)                      **
!               ********************************************
!
      ISTEPN='1.B'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!
!  SAVE ORIGINAL COMMAND LINE
!
      ICOMT=ICOM
      ICOM2T=ICOM2
      NUMART=NUMARG
      DO 100 I=1,NUMARG
        ITHARG(I)=IHARG(I)
        ITHAR2(I)=IHARG2(I)
        ITARG(I)=IARG(I)
        TARG(I)=ARG(I)
        ITARGT(I)=IARGT(I)
  100 CONTINUE
      DO 112 I=1,MAXSTR
        IANST(I)=IANS(I)
  112 CONTINUE
      IWIDT=IWIDTH
!
!     GENERATE A "QUADRATIC FIT Y X" COMMAND
!
!     2016/11: IF INTERCEPT TERM NOT INCLUDED, THEN GENERATE
!
!                 FIT Y = A1*X + A2*X**2
!
      IF(IFITAC.EQ.'OFF')THEN
        ISTRT(1:4)='FIT '
        ISTRT(5:8)=IHLEFT
        ISTRT(9:12)=IHLEF2
        ISTRT(13:18)=' = A1*'
        ISTRT(19:22)=IHRIGH
        ISTRT(23:26)=IHRIG2
        ISTRT(27:29)=' + '
        ISTRT(30:33)=' A2*'
        ISTRT(34:37)=IHRIGH
        ISTRT(38:41)=IHRIG2
        ISTRT(42:44)='**2'
        IWIDTH=44
        DO 117 JJ=1,IWIDTH
          IANS(JJ)=ISTRT(JJ:JJ)
 117    CONTINUE
        ICOM='FIT '
        ICOM2='    '
        IHARG(1)=IHLEFT
        IHARG2(1)=IHLEF2
        IHARG(2)='=   '
        IHARG2(2)='   '
        IHARG(3)='A1* '
        IHARG(3)(4:4)=IHRIGH(1:1)
        IHARG2(3)(1:3)=IHRIGH(2:4)
        IHARG2(3)(4:4)=IHRIG2(1:1)
        IHARG(4)=' +  '
        IHARG2(4)='    '
        IHARG(5)='A2* '
        IHARG(5)(4:4)=IHRIGH(1:1)
        IHARG2(5)(1:3)=IHRIGH(2:4)
        IHARG2(5)(4:4)=IHRIG2(1:1)
        NUMARG=5
      ELSE
        ICOM='QUAD'
        ICOM2='RATI'
        IHARG(1)='FIT '
        IHARG2(1)='    '
        IHARG(2)=IHLEFT
        IHARG2(2)=IHLEF2
        IHARG(3)=IHRIGH
        IHARG2(3)=IHRIG2
        NUMARG=3
      ENDIF
      ICASAN='FIT'
      IBUGG2='OFF'
      IBUGG3='OFF'
      IBUGCO='OFF'
      IBUGEV='OFF'
      IBUGQ='OFF'
!
      IPRINT='OFF'
      IFEEDB='OFF'
      CALL DPFIT(ICAPSW,IFORSW,   &
                 IBUGG2,IBUGA3,IBUGCO,IBUGEV,IBUGQ,ISUBRO,   &
                 IFOUND,IERROR)
!
      IPRINT=IPRNT2
      IFEEDB=IFEED2
!
!  RESTORE ORIGINAL COMMAND LINE
!
      NUMARG=NUMART
      ICOM=ICOMT
      ICOM2=ICOM2T
      DO 900 I=1,NUMARG
        IHARG(I)=ITHARG(I)
        IHARG2(I)=ITHAR2(I)
        IARG(I)=ITARG(I)
        ARG(I)=TARG(I)
        IARGT(I)=ITARGT(I)
  900 CONTINUE
      DO 902 I=1,MAXSTR
        IANS(I)=IANST(I)
  902 CONTINUE
      IWIDTH=IWIDT
!
      IOP='OPEN'
      IFLAG1=1
      IFLAG2=0
      IFLAG3=1
      IFLAG4=1
      IFLAG5=0
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IFITAC.EQ.'OFF')THEN
        A0=0.0
        SDA0=0.0
        TA0=0.0
        READ(IOUNI1,*,ERR=959,END=959)A1,SDA1,TA1
        READ(IOUNI1,*,ERR=959,END=959)A2,SDA2,TA2
      ELSE
        READ(IOUNI1,*,ERR=959,END=959)A0,SDA0,TA0
        READ(IOUNI1,*,ERR=959,END=959)A1,SDA1,TA1
        READ(IOUNI1,*,ERR=959,END=959)A2,SDA2,TA2
      ENDIF
      GO TO 969
!
  959 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,963)
  963 FORMAT('      UNABLE TO PERFORM THE INITIAL QUADRATIC FIT.')
      CALL DPWRST('XXX','BUG ')
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IERROR='YES'
      GO TO 9000
!
  969 CONTINUE
      IHP='RESS'
      IHP2='D   '
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      RESSD=VALUE(ILOCP)
      IHP='RESD'
      IHP2='F   '
      IHWUSE='P'
      MESSAG='YES'
      CALL CHECKN(IHP,IHP2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      RESDF=VALUE(ILOCP)
!
      IF(IFITAC.EQ.'OFF')THEN
        B11=0.
        B12=0.
        B13=0.
        B21=0.
        B31=0.
        READ(IOUNI3,*,ERR=979,END=979)B22,B23
        READ(IOUNI3,*,ERR=979,END=979)B32,B33
      ELSE
        READ(IOUNI4,*,ERR=979,END=979)B11
        READ(IOUNI4,*,ERR=979,END=979)B21
        READ(IOUNI4,*,ERR=979,END=979)B31
        READ(IOUNI4,*,ERR=979,END=979)B12
        READ(IOUNI4,*,ERR=979,END=979)B22
        READ(IOUNI4,*,ERR=979,END=979)B32
        READ(IOUNI4,*,ERR=979,END=979)B13
        READ(IOUNI4,*,ERR=979,END=979)B23
        READ(IOUNI4,*,ERR=979,END=979)B33
      ENDIF
      GO TO 989
!
  979 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,101)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,973)
  973 FORMAT('      UNABLE TO PERFORM THE INITIAL QUADRATIC FIT.')
      CALL DPWRST('XXX','BUG ')
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IERROR='YES'
      GO TO 9000
!
  989 CONTINUE
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
!
      C0=B11
      C1=B12+B21
      C2=B13+B22+B31
      C3=B23+B32
      C4=B33
!
      IDF=NPTS-3
      IF(IFITAC.EQ.'OFF')IDF=NPTS-2
      IF(ALPHA.LT.0.5)THEN
        ALPHA2=1.0 - (ALPHA/2.0)
      ELSE
        ALPHA2=ALPHA
      ENDIF
      CALL TPPF(ALPHA2,REAL(IDF),TVAL)
      TVAL=ABS(TVAL)
      C6=TVAL*RESSD
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')THEN
        WRITE(ICOUT,991)A0,SDA0,TA0
  991   FORMAT('AFTER QUADRATIC FIT, A0,SDA0,TA0=',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,992)A1,SDA1,TA1
  992   FORMAT('AFTER QUADRATIC FIT, A1,SDA1,TA1=',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,993)A2,SDA2,TA2
  993   FORMAT('AFTER QUADRATIC FIT, A2,SDA2,TA2=',3G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,994)RESSD,RESDF
  994   FORMAT('AFTER QUADRATIC FIT, RESSD,RESDF=',2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               **************************************************
!               **  STEP 1.1--                                  **
!               **   OPEN THE STORAGE FILES                     **
!               **************************************************
!
      ISTEPN='1.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOP='OPEN'
      IFLAG1=1
      IFLAG2=1
      IFLAG3=1
      IFLAG4=1
      IFLAG5=0
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               ***********************************************
!               **  STEP 2--                                 **
!               **  PRINT OUT SUMMARY OF FIT INFORMATION     **
!               ***********************************************
!
      ISTEPN='2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     PRINT HEADER TABLE
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      NUMDIG=7
      IF(IFORSW.EQ.'1')NUMDIG=1
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=0
      IF(IFORSW.EQ.'E')NUMDIG=-2
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      ITITLE='Quadratic Calibration Analysis'
      NCTITL=30
      ITITL9(1:33)='Summary of Quadratic Fit Between '
      ITITL9(34:37)=IHLEFT(1:4)
      ITITL9(38:41)=IHLEF2(1:4)
      ITITL9(42:46)=' and '
      ITITL9(47:50)=IHRIGH(1:4)
      ITITL9(51:54)=IHRIG2(1:4)
      NCTITZ=54
      ICNT=1
      ITEXT(ICNT)=' '
      NCTEXT(ICNT)=0
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
      ICNT=ICNT+1
      ITEXT(ICNT)='Number of Observations:'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=REAL(NPTS)
      IDIGIT(ICNT)=0
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Intercept:'
      NCTEXT(ICNT)=22
      AVALUE(ICNT)=A0
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='SD(Intercept):'
      NCTEXT(ICNT)=14
      AVALUE(ICNT)=SDA0
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='t(Intercept):'
      NCTEXT(ICNT)=13
      AVALUE(ICNT)=TA0
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Linear Term:'
      NCTEXT(ICNT)=24
      AVALUE(ICNT)=A1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='SD(Linear Term):'
      NCTEXT(ICNT)=16
      AVALUE(ICNT)=SDA1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='t(Linear Term):'
      NCTEXT(ICNT)=15
      AVALUE(ICNT)=TA1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Estimate of Quadratic Term:'
      NCTEXT(ICNT)=28
      AVALUE(ICNT)=A2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='SD(Quadratic Term):'
      NCTEXT(ICNT)=20
      AVALUE(ICNT)=SDA2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='t(Quadratic Term):'
      NCTEXT(ICNT)=19
      AVALUE(ICNT)=TA2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='Residual Standard Deviation:'
      NCTEXT(ICNT)=38
      AVALUE(ICNT)=RESSD
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 2310 I=1,NUMROW
        NTOT(I)=15
 2310 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITL9,NCTITZ,ITEXT,   &
                  NCTEXT,AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      ATEMP=1.0-ALPHA
      ITEMP=INT(100.*ATEMP + 0.00001)
!
!               **************************************************
!               **  STEP 3--                                    **
!               **  COMPUTE THE QUADRATIC CALIBRATION ESTIMATES **
!               **  USING VARIOUS METHODS.                      **
!               **************************************************
!
      ISTEPN='3'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOUNT=0
 3000 CONTINUE
      ICOUNT=ICOUNT+1
      IF(ICOUNT.GT.NCALPT)GO TO 3999
      Y0=Y3(ICOUNT)
!
!  FIND X0 (THIS APPLIES TO MOST METHODS, SO DO ONCE HERE
!  RATHER THAN FOR EACH METHOD.
!
      CALL MINIM(Y2,NPTS,IWRITE,XLEFT,IBUGA3,IERROR)
      CALL MAXIM(Y2,NPTS,IWRITE,XRIGHT,IBUGA3,IERROR)
      C=A0 - Y0
      B=A1
      A=A2
      X0=0.0
      TERM1=B**2 - 4.0*A*C
!
!  FIND SOME BOUNDING PARAMETERS
!
      RIGH10=0.0
      RIGH20=0.0
      IF(TERM1.GE.0.0)THEN
        TERM1=SQRT(TERM1)
        RIGH10=(-B + TERM1)/(2*A)
        RIGH20=(-B - TERM1)/(2*A)
      ENDIF
      IF(RIGH10.GE.XLEFT .AND. RIGH10.LE.XRIGHT)THEN
        RIGHT0=RIGH10
      ELSEIF(RIGH20.GE.XLEFT .AND. RIGH20.LE.XRIGHT)THEN
        RIGHT0=RIGH20
      ELSE
        RIGHT0=RIGH10
      ENDIF
!
!  FIND ESTIMATE OF X0
!
      TERM1=B**2 - 4.0*A*C
      IF(TERM1.EQ.0.0)THEN
        RIGHT=(-B + TERM1)/(2*A)
      ELSEIF(TERM1.GT.0.0)THEN
        TERM1=SQRT(TERM1)
        RIGH1=(-B + TERM1)/(2*A)
        RIGH2=(-B - TERM1)/(2*A)
        IF(RIGH1.GE.XLEFT .AND. RIGH1.LE.XRIGHT)THEN
          IF(RIGH2.GE.XLEFT .AND. RIGH2.LE.XRIGHT)THEN
            D1DIFF=ABS(RIGH1-RIGHT0)
            D2DIFF=ABS(RIGH2-RIGHT0)
            IF(D1DIFF.LE.D2DIFF)THEN
              RIGHT=RIGH1
            ELSE
              RIGHT=RIGH2
            ENDIF
          ELSE
            RIGHT=RIGH1
          ENDIF
        ELSEIF(RIGH2.GE.XLEFT .AND. RIGH2.LE.XRIGHT)THEN
          RIGHT=RIGH2
        ELSE
          IF(RIGH1.GT.0.0 .AND. RIGH2.LE.0.0)THEN
            RIGHT=RIGH1
          ELSEIF(RIGH2.GT.0.0 .AND. RIGH1.LE.0.0)THEN
            RIGHT=RIGH2
          ELSE
            D1DIFF=ABS(RIGH1-RIGHT0)
            D2DIFF=ABS(RIGH2-RIGHT0)
            IF(D1DIFF.LE.D2DIFF)THEN
              RIGHT=RIGH1
            ELSE
              RIGHT=RIGH2
            ENDIF
          ENDIF
        ENDIF
      ELSEIF(TERM1.LT.0.0)THEN
        IERROR='YES'
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3004)
 3004   FORMAT('      ROOTS FOR QUADRATIC FIT OF ORIGINAL ',   &
               'DATA.')
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      X0=RIGHT
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')THEN
        WRITE(ICOUT,3012)RIGH10,RIGH20,RIGHT0
 3012   FORMAT('FULL SAMPLE ROOTS: RIGH10,RIGH20,RIGHT0 = ',3E15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3013)RIGHT,X0,RIGH1,RIGH2
 3013   FORMAT('RIGHT,X0,RIGH1,RIGH2 = ',4E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***********************************************
!               **  STEP 3.1--                               **
!               **  CLASSICAL: EISENHART INVERTED PREDICTION **
!               **  LIMITS.                                  **
!               ***********************************************
!
      ISTEPN='3.11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!  FIND ROOTS OF 4TH DEGREE POLYNOMIAL USING A BISECTION METHOD
!
      EISEN=X0
      DEPS=0.000001D0
      DSIG=1.0D-6
      MAXIT=2000
      DZERO=0.0D0
      IC = 0
      DXL=DBLE(XLEFT)
      DXR=DBLE(XRIGHT)
      DY0=DBLE(Y0)
      DA0=DBLE(A0)
      DA1=DBLE(A1)
      DA2=DBLE(A2)
      DC0=DBLE(C0)
      DC1=DBLE(C1)
      DC2=DBLE(C2)
      DC3=DBLE(C3)
      DC4=DBLE(C4)
      DC6=DBLE(C6)
!
      DTERM1 = DA0 + DA1*DXL + DA2*DXL*DXL - DY0
      DTERM2 = DC0 + DC1*DXL + DC2*DXL**2 + DC3*DXL**3 + DC4*DXL**4
      DFXL = DTERM1 + DC6*DSQRT(1.0D0 + DTERM2)
      DTERM1 = DA0 + DA1*DXR + DA2*DXR*DXR - DY0
      DTERM2 = DC0 + DC1*DXR + DC2*DXR**2 + DC3*DXR**3 + DC4*DXR**4
      DFXR = DTERM1 + DC6*DSQRT(1.0D0 + DTERM2)
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')THEN
        ISTEPN='3.12'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,3104)DXL,DXR,DFXL,DFXR
 3104   FORMAT('DXL,DXR,DFXL,DFXR = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 3105 CONTINUE
!
      DXTEMP = (DXL+DXR)*0.5D0
      DTERM1 = DA0 + DA1*DXTEMP + DA2*DXTEMP*DXTEMP - DY0
      DTERM2 = DC0 + DC1*DXTEMP + DC2*DXTEMP**2 + DC3*DXTEMP**3   &
               + DC4*dXTEMP**4
      DFCS = DTERM1 + DC6*DSQRT(1.0D0 + DTERM2)
      IF(DFCS*DFXL.GT.DZERO)GO TO 3110
      DXR = DXTEMP
      DFXR = DFCS
!
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')THEN
        ISTEPN='3.13'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,3124)DXL,DXR,DXTEMP,DFXL,DFXR,DFCS
 3124   FORMAT('DXL,DXR,DXTEMP,DFXL,DFXR,DFCS = ',6G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      GO TO 3115
 3110 CONTINUE
      DXL = DXTEMP
      DFXL = DFCS
 3115 CONTINUE
      DXRML = DXR - DXL
      IF(DXRML.LE.DSIG .AND. DABS(DFCS).LE.DEPS)GO TO 3149
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 3105
      WRITE(ICOUT,3130)
      CALL DPWRST('XXX','BUG ')
 3130 FORMAT('***** ERROR IN QUADRATIC CALIBRATION: NO CONVERGENCE.')
      EISENL=CPUMIN
      EISENU=CPUMIN
      SEISEN=CPUMIN
      EEISEN=CPUMIN
      CVISEN=CPUMIN
      GO TO 3199
!
 3149 CONTINUE
      EISENU=REAL(DXTEMP)
!
      IC = 0
      DXL=DBLE(XLEFT)
      DXR=DBLE(XRIGHT)
      DTERM1 = DA0 + DA1*DXL + DA2*DXL*DXL - DY0
      DTERM2 = DC0 + DC1*DXL + DC2*DXL**2 + DC3*DXL**3 + DC4*DXL**4
      DFXL = DTERM1 - DC6*DSQRT(1.0D0 + DTERM2)
      DTERM1 = DA0 + DA1*DXR + DA2*DXR*DXR - DY0
      DTERM2 = DC0 + DC1*DXR + DC2*DXR**2 + DC3*DXR**3 + DC4*DXR**4
      DFXR = DTERM1 - DC6*DSQRT(1.0D0 + DTERM2)
!
 3155 CONTINUE
!
      DXTEMP = (DXL+DXR)*0.5D0
      DTERM1 = DA0 + DA1*DXTEMP + DA2*DXTEMP*DXTEMP - DY0
      DTERM2 = DC0 + DC1*DXTEMP + DC2*DXTEMP**2 + DC3*DXTEMP**3   &
               + DC4*DXTEMP**4
      DFCS = DTERM1 - DC6*DSQRT(1.0D0 + DTERM2)
      IF(DFCS*DFXL.GT.DZERO)GO TO 3160
      DXR = DXTEMP
      DFXR = DFCS
      GO TO 3175
 3160 CONTINUE
      DXL = DXTEMP
      DFXL = DFCS
 3175 CONTINUE
      DXRML = DXR - DXL
      IF(DXRML.LE.DSIG .AND. DABS(DFCS).LE.DEPS)GO TO 3189
      IC = IC + 1
      IF(IC.LE.MAXIT)GO TO 3155
      WRITE(ICOUT,3180)
 3180 FORMAT('***** ERROR IN QUADRATIC CALIBRATION: NO CONVERGENCE ',   &
             'FOR INVERSE PREDICTION LIMITS.')
      CALL DPWRST('XXX','BUG ')
      EISENL=CPUMIN
      EISENU=CPUMIN
      SEISEN=CPUMIN
      EEISEN=CPUMIN
      CVISEN=CPUMIN
      GO TO 3199
!
 3189 CONTINUE
      EISENL=REAL(DXTEMP)
!
      IF(EISENL.GT.EISENU)THEN
        ATEMP=EISENL
        EISENL=EISENU
        EISENU=ATEMP
      ENDIF
!
!     USE DIFFERENCE BETWEEN POINT ESTIMATE AND CONFIDENCE LIMITS TO
!     DETERMINE AN APPROXIMATION OF THE STANDARD ERROR.  NOTE THAT THE
!     CONFIDENCE LIMITS ARE NOT NECESSARILY SYMMETRIC.  ALSO, POINT
!     ESTIMATE MAY NOT BE IN THE CONFIDENCE INTERVAL.  SO USE THE
!     LARGER HALF-INTERVAL.  ALSO, IF POINT ESTIMATE NOT IN THE
!     INTERVAL, THEN DO NOT COMPUTE AN ESTIMATED STANDARD ERROR.
!
      SEISEN=0.0
      IF(EISENL.LT.EISENU)THEN
        IF(X0.GT.EISENL .AND. X0.LT.EISENU)THEN
          AVAL1=ABS(EISENU - X0)
          AVAL2=ABS(X0 - EISENU)
          AVAL=MAX(AVAL1,AVAL2)
          EEISEN=AVAL
          CVISEN=ABS(TVAL)
          SEISEN=AVAL/ABS(TVAL)
        ELSE
          SEISEN=-99.0
        ENDIF
      ENDIF
!
 3199 CONTINUE
!
!               ***********************************************
!               **  STEP 3.2--                               **
!               **  PROPOGATION OF ERROR AS SPECIFIED IN     **
!               **  E-HANDBOOK (MPC3671.HTM)                 **
!               ***********************************************
!
      ISTEPN='3.11'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     DEFINE PARTIAL DERIVATIVE TERMS
!
      DY0=DBLE(Y0)
      DA0=DBLE(A0)
      DA1=DBLE(A1)
      DA2=DBLE(A2)
      DA0SD=DBLE(SDA0)
      DA1SD=DBLE(SDA1)
      DA2SD=DBLE(SDA2)
      DTERM1=DSQRT(DA1**2 - 4.0D0*DA2*(DA0-DY0))
      DRESSD=DBLE(RESSD)
!
      XPYP=1.0D0/DTERM1
      XPA0=-1.0D0/DTERM1
      DTERM2=DA1/DTERM1
      XPA1=(-1.0D0 + DTERM2)/(2.0D0*DA2)
      DTERM2=(-DA0 + DY0)/(DA2*DTERM1)
      DTERM3=(-DA1 + DTERM1)/(2.0D0*DA2**2)
      XPA2=DTERM2 - DTERM3
      DVAR1=(XPYP**2)*(DRESSD**2) + (XPA0**2)*(DA0SD**2) +   &
           (XPA1**2)*(DA1SD**2)  + (XPA2**2)*(DA2SD**2)
!
      DVAR2=2.0D0*XPA0*XPA1*DBLE(B12) +   &
            2.0D0*XPA0*XPA2*DBLE(B13) +   &
            2.0D0*XPA1*XPA2*DBLE(B23)
      DSE=DSQRT(DVAR1 + DVAR2)
!
      SEPRO2=REAL(DSE)
      CVPRO2=ABS(TVAL)
      EEPRO2=ABS(TVAL)*SEPRO2
      PRO2E=X0
      PRO2LL=X0 - EEPRO2
      PRO2UL=X0 + EEPRO2
!
!               ***********************************************
!               **  STEP 3.7--                               **
!               **  BOOTSTRAP (EFROM RESAMPLING, I.E.,       **
!               **  RESAMPLE THE RESIDUALS)                  **
!               ***********************************************
!
!     2016/11: IF NO CONSTANT TERM IN FIT, SKIP BOOTSTRAP METHODS.
!
      IF(IFITAC.EQ.'OFF')GO TO 4000
!
      ISTEPN='3.7'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,3714)A0,A1,A2
 3714   FORMAT('A0,A1,A2 = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      DO 3716 I=1,NPTS
        Z1(I)=RES(I)
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')THEN
           WRITE(ICOUT,3717)I,Y1(I),Y2(I),Z1(I)
 3717      FORMAT('I,Y1(I),Y2(I),Z1(I) (=Y,X,RES) =',I8,4G15.7)
           CALL DPWRST('XXX','BUG ')
        ENDIF
 3716 CONTINUE
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')THEN
         WRITE(ICOUT,3718)A0,A1,A2
 3718    FORMAT('A0,A1,A2 = ',3G15.7)
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
      ICASJB='BOOT'
      NRESAM=1000
      NREJ=0
      NNEG=0
      NCOUNT=0
!
      DO 3720 IRESAM=1,NRESAM
        CALL DPJBS3(Z1,NPTS,ICASJB,IRESAM,ISEED,Z2,NPTS2,IZ,   &
                    Z6,IBUGA3,IERROR)
        DO 3722 I=1,NPTS2
          DX=DBLE(Y2(I))
          DTERM1=DBLE(A0) + DBLE(A1)*DX + DBLE(A2)*DX*DX
          Z3(I)=REAL(DTERM1) + Z2(I)
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')THEN
            WRITE(ICOUT,3727)I,Y2(I),Z3(I)
 3727       FORMAT('I,Y2(I),Z3(I) (I.E., X,Y TO BE FIT) =',I8,2G15.7)
           CALL DPWRST('XXX','BUG ')
        ENDIF
 3722   CONTINUE
        CALL QUAFI2(Y2,Z3,NPTS,   &
                    Z5,B0,B1,B2,   &
                    ISUBRO,IBUGA3,IERROR)
!
!  DETERMINE APPROPRIATE ROOT
!
        C=B0 - Y0
        B=B1
        A=B2
        TERM1=B**2 - 4.0*A*C
        IF(TERM1.EQ.0.0)THEN
          RIGHT=(-B + TERM1)/(2.0*A)
        ELSEIF(TERM1.GT.0.0)THEN
          TERM1=SQRT(TERM1)
          RIGH1=(-B + TERM1)/(2.0*A)
          RIGH2=(-B - TERM1)/(2.0*A)
          IF(RIGH1.GE.XLEFT .AND. RIGH1.LE.XRIGHT)THEN
            IF(RIGH2.GE.XLEFT .AND. RIGH2.LE.XRIGHT)THEN
              D1DIFF=ABS(RIGH1-RIGHT0)
              D2DIFF=ABS(RIGH2-RIGHT0)
              IF(D1DIFF.LE.D2DIFF)THEN
                RIGHT=RIGH1
              ELSE
                RIGHT=RIGH2
              ENDIF
            ELSE
              RIGHT=RIGH1
            ENDIF
          ELSEIF(RIGH2.GE.XLEFT .AND. RIGH2.LE.XRIGHT)THEN
            RIGHT=RIGH2
          ELSE
            IF(RIGH1.GT.0.0 .AND. RIGH2.LE.0.0)THEN
              RIGHT=RIGH1
            ELSEIF(RIGH2.GT.0.0 .AND. RIGH1.LE.0.0)THEN
              RIGHT=RIGH2
            ELSE
              D1DIFF=ABS(RIGH1-RIGHT0)
              D2DIFF=ABS(RIGH2-RIGHT0)
              IF(D1DIFF.LE.D2DIFF)THEN
                RIGHT=RIGH1
              ELSE
                RIGHT=RIGH2
              ENDIF
            ENDIF
          ENDIF
          IF(RIGHT.LT.0)NNEG=NNEG+1
        ELSEIF(TERM1.LT.0.0)THEN
          NREJ=NREJ+1
          GO TO 3720
        ENDIF
!
        NCOUNT=NCOUNT+1
        Z4(NCOUNT)=RIGHT
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')THEN
          WRITE(ICOUT,3725)IERROR,NCOUNT,B0,B1,B2,Z4(NCOUNT)
 3725     FORMAT('IERROR,NCOUNT,B0,B1,B2,Z4(NCOUNT) = ',A4,I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
 3720 CONTINUE
!
      BOOTE=X0
      CALL SD(Z4,NRESAM,IWRITE,SEBOOE,IBUGA3,IERROR)
      P100=100.0*(ALPHA/2.0)
      CALL PERCEN(P100,Z4,NCOUNT,IWRITE,Z3,MAXNXT,   &
                  BOOTEL,IBUGA3,IERROR)
      P100=100.0*(1.0 - ALPHA/2.0)
      CALL PERCEN(P100,Z4,NCOUNT,IWRITE,Z3,MAXNXT,   &
                  BOOTEU,IBUGA3,IERROR)
      EEBOOE=MAX((BOOTEU - BOOTE),(BOOTE - BOOTEL))
      CVBOOE=EEBOOE/SEBOOE
!
!               ***********************************************
!               **  STEP 3.8--                               **
!               **  BOOTSTRAP (WU RESAMPLING, I.E., RESAMPLE **
!               **  THE ORIGINAL (X,Y) DATA                  **
!               ***********************************************
!
      ISTEPN='3.8'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NNEG=0
      NREJ=0
      NCOUNT=0
      ICASJB='BOOT'
      NRESAM=1000
!
      DO 3810 IRESAM=1,NRESAM
        IERROR='NO'
        CALL DPJBS3(Y1,NPTS,ICASJB,IRESAM,ISEED,Z1,NPTS2,IZ,   &
                    Z6,IBUGA3,IERROR)
        DO 3820 IJ=1,NPTS2
          Z2(IJ)=Y2(IZ(IJ))
 3820   CONTINUE
        CALL QUAFI2(Z2,Z1,NPTS,   &
                  Z5,   &
                  B0,B1,B2,   &
                  ISUBRO,IBUGA3,IERROR)
!
        IF(IERROR.EQ.'YES')GO TO 3810
!
!  DETERMINE APPROPRIATE ROOT
!
        C=B0 - Y0
        B=B1
        A=B2
        TERM1=B**2 - 4.0*A*C
        IF(TERM1.EQ.0.0)THEN
          RIGHT=(-B + TERM1)/(2*A)
        ELSEIF(TERM1.GT.0.0)THEN
          TERM1=SQRT(TERM1)
          RIGH1=(-B + TERM1)/(2*A)
          RIGH2=(-B - TERM1)/(2*A)
          IF(RIGH1.GE.XLEFT .AND. RIGH1.LE.XRIGHT)THEN
            IF(RIGH2.GE.XLEFT .AND. RIGH2.LE.XRIGHT)THEN
              D1DIFF=ABS(RIGH1-RIGHT0)
              D2DIFF=ABS(RIGH2-RIGHT0)
              IF(D1DIFF.LE.D2DIFF)THEN
                RIGHT=RIGH1
              ELSE
                RIGHT=RIGH2
              ENDIF
            ELSE
              RIGHT=RIGH1
            ENDIF
          ELSEIF(RIGH2.GE.XLEFT .AND. RIGH2.LE.XRIGHT)THEN
            RIGHT=RIGH2
          ELSE
            IF(RIGH1.GT.0.0 .AND. RIGH2.LE.0.0)THEN
              RIGHT=RIGH1
            ELSEIF(RIGH2.GT.0.0 .AND. RIGH1.LE.0.0)THEN
              RIGHT=RIGH2
            ELSE
              D1DIFF=ABS(RIGH1-RIGHT0)
              D2DIFF=ABS(RIGH2-RIGHT0)
              IF(D1DIFF.LE.D2DIFF)THEN
                RIGHT=RIGH1
              ELSE
                RIGHT=RIGH2
              ENDIF
            ENDIF
          ENDIF
          IF(RIGHT.LT.0)NNEG=NNEG+1
        ELSEIF(TERM1.LT.0.0)THEN
          NREJ=NREJ+1
          GO TO 3810
        ENDIF
!
        NCOUNT=NCOUNT+1
        Z4(NCOUNT)=RIGHT
!
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')THEN
          WRITE(ICOUT,3822)NCOUNT,B0,B1,B2,Z4(IRESAM)
 3822     FORMAT('NCOUNT,B0,B1,B2,Z4(IRESAM) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
 3810 CONTINUE
!
      BOOTW=X0
      CALL SD(Z4,NRESAM,IWRITE,SEBOOW,IBUGA3,IERROR)
      P100=100.0*(ALPHA/2.0)
      CALL PERCEN(P100,Z4,NCOUNT,IWRITE,Z3,MAXNXT,   &
                  BOOTWL,IBUGA3,IERROR)
      P100=100.0*(1.0 - ALPHA/2.0)
      CALL PERCEN(P100,Z4,NCOUNT,IWRITE,Z3,MAXNXT,   &
                  BOOTWU,IBUGA3,IERROR)
      EEBOOW=MAX((BOOTWU - BOOTW),(BOOTW - BOOTWL))
      CVBOOW=EEBOOW/SEBOOW
!
!               ***********************************************
!               **  STEP 4--                                 **
!               **  PRINT OUT THE RESULTS.                   **
!               ***********************************************
!
 4000 CONTINUE
      ISTEPN='4'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LIC3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IMETHD=1
      WRITE(IOUNI1,5401)IMETHD,Y0,EISEN,EISENL,EISENU
      IMETHD=5
      WRITE(IOUNI1,5401)IMETHD,Y0,PRO2E,PRO2LL,PRO2UL
      IMETHD=7
      IF(IFITAC.EQ.'ON')THEN
        WRITE(IOUNI1,5401)IMETHD,Y0,BOOTE,BOOTEL,BOOTEU
        IMETHD=8
        WRITE(IOUNI1,5401)IMETHD,Y0,BOOTW,BOOTWL,BOOTWU
 5401   FORMAT(I2,2X,4E15.7)
        WRITE(IOUNI2,5411)EISEN,PRO2E,BOOTE,BOOTW
        WRITE(IOUNI3,5411)EISENL,PRO2LL,BOOTEL,BOOTWL
        WRITE(IOUNI4,5411)EISENU,PRO2UL,BOOTEU,BOOTWU
 5411   FORMAT(9E15.7)
      ELSE
        WRITE(IOUNI2,5411)EISEN,PRO2E
        WRITE(IOUNI3,5411)EISENL,PRO2LL
        WRITE(IOUNI4,5411)EISENU,PRO2UL
      ENDIF
!
      ATEMP=1.0-ALPHA
      ITEMP=INT(100.*ATEMP + 0.00001)
!
      IF(ICOUNT.EQ.1)THEN
        ITITLE='Quadratic Calibration Summary'
        NCTITL=29
        ITITL9(1:6)='Y0 = '
        WRITE(ITITL9(7:21),'(G15.7)')Y0
        NCTIT9=21
      ELSE
        ITITLE=' '
        NCTITL=0
        ITITL9(1:6)='Y0 = '
        WRITE(ITITL9(7:21),'(G15.7)')Y0
        NCTIT9=21
      ENDIF
      NUMLIN=2
      NUMCOL=6
      ITITL2(1,1)=' '
      NCTIT2(1,1)=0
      ITITL2(2,1)='Method'
      NCTIT2(2,1)=6
      ITITL2(1,2)=' '
      NCTIT2(1,2)=0
      ITITL2(2,2)='X0'
      NCTIT2(2,2)=2
      WRITE(ITITL2(1,3)(1:2),'(I2)')ITEMP
      ITITL2(1,3)(3:3)='%'
      NCTIT2(1,3)=3
      ITITL2(2,3)='Lower Limit'
      NCTIT2(2,3)=11
      WRITE(ITITL2(1,4)(1:2),'(I2)')ITEMP
      ITITL2(1,4)(3:3)='%'
      NCTIT2(1,4)=3
      ITITL2(2,4)='Upper Limit'
      NCTIT2(2,4)=11
      ITITL2(1,5)='Standard'
      NCTIT2(1,5)=8
      ITITL2(2,5)='Error'
      NCTIT2(2,5)=5
      ITITL2(1,6)=' '
      NCTIT2(1,6)=0
      ITITL2(2,6)='Coverage'
      NCTIT2(2,6)=8
      ITITL2(1,7)='Expanded'
      NCTIT2(1,7)=8
      ITITL2(2,7)='Error'
      NCTIT2(2,7)=5
!
      NMAX=0
      DO 2521 I=1,NUMCOL+1
        VALIGN(I)='b'
        ALIGN(I)='r'
        NTOT(I)=15
        IF(I.EQ.1)THEN
          NTOT(I)=40
          ALIGN(I)='l'
        ENDIF
        NMAX=NMAX+NTOT(I)
        IDIGIT(I)=NUMDIG
 2521 CONTINUE
!
      ICNT=0
!
      ICNT=ICNT+1
      ITEXT(ICNT)='1. Inverse Prediction Limits:'
      NCTEXT(ICNT)=29
      AMAT(ICNT,1)=EISEN
      AMAT(ICNT,2)=EISENL
      AMAT(ICNT,3)=EISENU
      AMAT(ICNT,4)=SEISEN
      AMAT(ICNT,5)=CVISEN
      AMAT(ICNT,6)=EEISEN
!
      ICNT=ICNT+1
      ITEXT(ICNT)='2. Propogation of Error (Handbook):'
      NCTEXT(ICNT)=37
      AMAT(ICNT,1)=PRO2E
      AMAT(ICNT,2)=PRO2LL
      AMAT(ICNT,3)=PRO2UL
      AMAT(ICNT,4)=SEPRO2
      AMAT(ICNT,5)=CVPRO2
      AMAT(ICNT,6)=EEPRO2
!
      IF(IFITAC.EQ.'ON')THEN
        ICNT=ICNT+1
        ITEXT(ICNT)='7. Bootstrap (Residuals):'
        NCTEXT(ICNT)=26
        AMAT(ICNT,1)=BOOTE
        AMAT(ICNT,2)=BOOTEL
        AMAT(ICNT,3)=BOOTEU
        AMAT(ICNT,4)=SEBOOE
        AMAT(ICNT,5)=CVBOOE
        AMAT(ICNT,6)=EEBOOE
!
        ICNT=ICNT+1
        ITEXT(ICNT)='8. Bootstrap (Data):'
        NCTEXT(ICNT)=21
        AMAT(ICNT,1)=BOOTW
        AMAT(ICNT,2)=BOOTWL
        AMAT(ICNT,3)=BOOTWU
        AMAT(ICNT,4)=SEBOOW
        AMAT(ICNT,5)=CVBOOW
        AMAT(ICNT,6)=EEBOOW
      ENDIF
!
      IWHTML(1)=250
      IWHTML(2)=150
      IWHTML(3)=150
      IWHTML(4)=150
      IWHTML(5)=150
      IWHTML(6)=150
      IWHTML(7)=150
      IWRTF(1)=3000
      IWRTF(2)=IWRTF(1)+2000
      IWRTF(3)=IWRTF(2)+2000
      IWRTF(4)=IWRTF(3)+2000
      IWRTF(5)=IWRTF(4)+2000
      IWRTF(6)=IWRTF(5)+2000
      IWRTF(7)=IWRTF(6)+2000
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA2(ITITLE,NCTITL,   &
                  ITITL9,NCTIT9,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,NUMCLI,NUMCOL,   &
                  ITEXT,NCTEXT,AMAT,MAXROW,ICNT,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
!
      GO TO 3000
!
 3999 CONTINUE
!
      IF(IFEEDB.EQ.'ON')THEN
!
        WRITE(ICOUT,8102)
 8102   FORMAT('FOLLOWING INFORMATION WRITTEN OUT TO FILES.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8112)
 8112   FORMAT('DPST1F.DAT: METHOD (1, 7 - 8), Y0, X0, LOWER LIMIT, ',   &
               'UPPER LIMIT')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8122)
 8122   FORMAT('DPST2F.DAT: Y0 AND X0 FOR THREE METHODS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8132)
 8132   FORMAT('DPST3F.DAT: Y0 AND LOWER LIMIT FOR THREE METHODS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,8142)
 8142   FORMAT('DPST4F.DAT: Y0 AND UPPER LIMIT FOR THREE METHODS')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
!
      ENDIF
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LIC3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLIC3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA3,IERROR
 9012   FORMAT('IBUGA3,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPTS,NUMVAR
 9013   FORMAT('NPTS,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLIC3
      SUBROUTINE DPLICL(IHARG,IARG,NUMARG,IDEFCO,MAXLIN,ILINCO,ILINC2,   &
                        IRGBMX,ICASCL,IFOUND,IERROR)
!
!     PURPOSE--DEFINE PLOT LINE COLORS FOR USE IN MULTI-TRACE PLOTS.
!              THE COLOR FOR THE LINE FOR THE I-TH TRACE WILL BE PLACED
!              IN THE I-TH ELEMENT OF THE HOLLERITH VECTOR ILINCO(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG
!                     --IDEFCO
!                     --MAXLIN
!     OUTPUT ARGUMENTS--ILINCO  (A  HOLLERITH VECTOR
!                       WHOSE I-TH ELEMENT IS THE COLOR FOR THE LINE
!                       ASSIGNED TO THE I-TH    TRACE    IN
!                       A MULTI-TRACE PLOT.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1977.
!     UPDATED         --SEPTEMBER 1980.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --OCTOBER   2020. SUPPORT FOR RGB COLORS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IDEFCO
      CHARACTER*4 ILINCO
      CHARACTER*4 ICASCL
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IARG(*)
      DIMENSION ILINCO(*)
      DIMENSION ILINC2(MAXLIN,3)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
      NUMLIN=0
!
      IF(NUMARG.EQ.0)GO TO 9000
      IF(ICASCL.EQ.'RGB ')GO TO 2000
!
!     THIS IS FOR THE "STANDARD" CASE
!
      IF((NUMARG.EQ.1.AND.IHARG(1).EQ.'COLO') .OR.   &
        (NUMARG.EQ.2.AND.IHARG(1).EQ.'COLO'.AND.IHARG(2).EQ.'ALL'))THEN
        IFOUND='YES'
        DO 1165 I=1,MAXLIN
          ILINCO(I)=IDEFCO
 1165   CONTINUE
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          I=1
          WRITE(ICOUT,1116)ILINCO(I)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ELSEIF(NUMARG.GE.2.AND.IHARG(1).EQ.'COLO')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF' .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA')THEN
          IFOUND='YES'
          DO 1115 I=1,MAXLIN
            ILINCO(I)=IDEFCO
 1115     CONTINUE
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
  999       FORMAT(1X)
            CALL DPWRST('XXX','BUG ')
            I=1
            WRITE(ICOUT,1116)ILINCO(I)
 1116       FORMAT('ALL LINE COLORS HAVE JUST BEEN SET TO ',A4)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSEIF(NUMARG.EQ.2)THEN
          IFOUND='YES'
          ILINCO(1)=IHARG(2)
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            I=1
            WRITE(ICOUT,1126)I,ILINCO(I)
 1126       FORMAT('THE COLOR FOR LINE ',I6,' HAS JUST BEEN SET TO ',A4)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSEIF(NUMARG.GE.3.AND.IHARG(2).EQ.'ALL')THEN
          IFOUND='YES'
          DO 1135 I=1,MAXLIN
            ILINCO(I)=IHARG(3)
 1135     CONTINUE
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            I=1
            WRITE(ICOUT,1116)ILINCO(I)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSEIF(NUMARG.GE.3.AND.IHARG(3).EQ.'ALL')THEN
          IFOUND='YES'
          DO 1145 I=1,MAXLIN
            ILINCO(I)=IHARG(2)
 1145     CONTINUE
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            I=1
            WRITE(ICOUT,1116)ILINCO(I)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSE
          IFOUND='YES'
          IMAX=NUMARG-1
          IF(MAXLIN.LT.IMAX)IMAX=MAXLIN
          DO 1155 I=1,IMAX
            IP1=I+1
            ILINCO(I)=IHARG(IP1)
 1155     CONTINUE
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            DO 1156 I=1,IMAX
              WRITE(ICOUT,1126)I,ILINCO(I)
              CALL DPWRST('XXX','BUG ')
 1156       CONTINUE
          ENDIF
        ENDIF
      ENDIF
      GO TO 9000
!
!     THIS IS FOR THE "RGB" CASE
!
 2000 CONTINUE
!
      JHOLD1=-1
      JHOLD2=-1
      JHOLD3=-1
      NUMLIN=MAXLIN
!
      IF(NUMARG.EQ.1)THEN
        GO TO 2300
      ELSEIF(NUMARG.EQ.2 .AND. IHARG(2).EQ.'ALL')THEN
        GO TO 2300
      ELSEIF(NUMARG.EQ.5)THEN
        IF(IHARG(2).EQ.'ALL')THEN
          JHOLD1=IARG(3)
          JHOLD2=IARG(4)
          JHOLD3=IARG(5)
          GO TO 2300
        ELSEIF(IHARG(5).EQ.'ALL')THEN
          JHOLD1=IARG(2)
          JHOLD2=IARG(3)
          JHOLD3=IARG(4)
          GO TO 2300
        ENDIF
      ENDIF
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  TREAT THE SINGLE      SPECIFICATION  CASE  **
!               *************************************************
!
      IF(NUMARG.LE.2)THEN
        NUMLIN=1
        ILINC2(1,1)=-1
        ILINC2(1,2)=-1
        ILINC2(1,3)=-1
      ELSE
        NTEMP=NUMARG-1
        NUMLIN=NTEMP/3
        IF(NUMLIN.LT.1)THEN
          ILINC2(1,1)=-1
          ILINC2(1,2)=-1
          ILINC2(1,3)=-1
        ELSEIF(NUMLIN.GT.MAXLIN)THEN
          NUMLIN=MAXLIN
        ENDIF
        DO 2225 I=1,NUMLIN
          J1=(I-1)*3+2
          J2=J1+1
          J3=J1+2
          JHOLD1=IARG(J1)
          JHOLD2=IARG(J2)
          JHOLD3=IARG(J3)
          IF(JHOLD1.LT.0 .OR. JHOLD1.GT.IRGBMX)JHOLD1=-1
          IF(JHOLD2.LT.0 .OR. JHOLD2.GT.IRGBMX)JHOLD2=-1
          IF(JHOLD3.LT.0 .OR. JHOLD3.GT.IRGBMX)JHOLD3=-1
          ILINC2(I,1)=JHOLD1
          ILINC2(I,2)=JHOLD2
          ILINC2(I,3)=JHOLD3
 2225   CONTINUE
      ENDIF
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        DO 2278 I=1,NUMLIN
          WRITE(ICOUT,2276)I,ILINC2(I,1),ILINC2(I,2),ILINC2(I,3)
 2276     FORMAT('THE RGB COLORS OF LINE ',I6,   &
                 ' HAVE JUST BEEN SET TO ',3I8)
          CALL DPWRST('XXX','BUG ')
 2278   CONTINUE
      ENDIF
      IFOUND='YES'
      GO TO 9000
!
!               **************************
!               **  STEP 3--            **
!               **  TREAT THE ALL CASE  **
!               **************************
!
 2300 CONTINUE
      IF(JHOLD1.LT.0)JHOLD1=0
      IF(JHOLD1.GT.0)JHOLD1=0
      DO 2315 II=1,NUMLIN
        ILINC2(II,1)=JHOLD1
        ILINC2(II,2)=JHOLD2
        ILINC2(II,3)=JHOLD3
 2315 CONTINUE
!
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        I=1
        WRITE(ICOUT,2316)ILINC2(I,1),ILINC2(I,2),ILINC2(I,3)
 2316   FORMAT('THE RGB COLORS OF ALL LINES HAVE JUST ',   &
               'BEEN SET TO ',3I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IFOUND='YES'
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPLICL
      SUBROUTINE DPLICO(IHARG,NUMARG,IANSSV,IREPMX,ILISMX,IPOINT,   &
                        IHELMX,   &
                        ICPREH,NCPREH,ICPOSH,NCPOSH,   &
                        IBUGS2,ISUBRO,IFOUND,IERROR)
!CCCC 5 ARGS. (IHELMX, ICPREH, ETC.) WERE ADDED ABOVE   JULY 1993
!
!     PURPOSE--RECALL (THAT IS, LIST) THE LAST ILISMX (USUALLY 20, 30, 50)
!              COMMANDS ENTERED
!              FOR POTENTIAL USE BY A    REPEAT OR SAVE     COMMAND.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--86/1
!     ORIGINAL VERSION--MARCH     1984.
!     UPDATED         --JANUARY   1986.
!     UPDATED         --APRIL     1993. SOFT-CODE DIMEN. FOR IANSSV()
!     UPDATED         --JULY      1993.  ALLOW MORE... TO STOP LIST
!     UPDATED         --SEPTEMBER 1993.  DELETE LEAD BLANK LINES
!     UPDATED         --SEPTEMBER 1993.  ALLOW ALWAYS-PRINTING
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!CCCC THE FOLLOWING LINE WAS ADDED APRIL 1993
      INCLUDE 'DPCOPA.INC'
      CHARACTER*4 IHARG
      CHARACTER*1 IANSSV
!
!CCCC THE FOLLOWING 3 LINES WERE ADDED JULY 1993
      CHARACTER*40 ICPREH
      CHARACTER*40 ICPOSH
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 IFOUND
!
      CHARACTER*1 IC1
      CHARACTER (LEN=MAXSTR) :: ISTRIN
!
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1993
      CHARACTER*4 IRESP
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!CCCC THE FOLLOWING LINE WAS CHANGED APRIL 1993
!CCCC DIMENSION IANSSV(50,80)
      DIMENSION IANSSV(MAXLIS,MAXCIS)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLI'
      ISUBN2='CO  '
      IFOUND='NO'
      IERROR='NO'
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LICO')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF DPLICO--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGS2,ISUBRO,NUMARG
   53   FORMAT('IBUGS2,ISUBRO,NUMARG = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMARG.GT.0)THEN
          DO 55 I=1,NUMARG
            WRITE(ICOUT,56)I,IHARG(I)
   56       FORMAT('I,IHARG(I) = ',I8,2X,A4)
            CALL DPWRST('XXX','BUG ')
   55     CONTINUE
        ENDIF
        WRITE(ICOUT,61)IREPMX,ILISMX,IHELMX,IPOINT
   61   FORMAT('IREPMX,ILISMX,IHELMX,IPOINT = ',4I8)
        CALL DPWRST('XXX','BUG ')
        DO 62 J=1,IREPMX
          WRITE(ICOUT,63)(IANSSV(J,I),I=1,80)
   63     FORMAT('(IANSSV(J,I),I=1,80) = ',80A1)
          CALL DPWRST('XXX','BUG ')
   62   CONTINUE
        WRITE(ICOUT,64)NCPOSH,ICPOSH
   64   FORMAT('NCPOSH,ICPOSH = ',I5,2X,A40)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,69)IFOUND,IERROR
   69   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IFOUND='YES'
!
!               ******************************************************
!               **  STEP 1--                                        **
!               **  RECALL (= LIST OUT) THE LAST ILISMX COMMANDS    **
!               **  THE COMMAND ILISMX AGO BEING LISTED FIRST,      **
!               **  AND THE MOST RECENT COMMAND BEING LISTED LAST.  **
!               ******************************************************
!
!CCCC THE FOLLOWING 2 LINES WERE ADDED JULY 1989
      NUMLPR=0
      IRESP='YES'
!
!CCCC THE FOLLOWING 2 LINES WERE COMMENTED OUT    SEPTEMBER 1993
!CCCC WRITE(ICOUT,999)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1010)ILISMX
 1010 FORMAT('THE LAST ',I2,' COMMAND LINES--')
!CCCC THE FOLLOWING LINE WAS CHANGED TO ALLOW ALWAYS-WRITING  SEPTEMBER 1993
!CCCC CALL DPWRST('XXX','BUG ')
      CALL DPWRST('XXX','WRIT')
!CCCC THE FOLLOWING 2 LINES WERE COMMENTED OUT    SEPTEMBER 1993
!CCCC CALL DPWRST('XXX','BUG ')
!CCCC WRITE(ICOUT,999)
!
!CCCC IPOIN2=11
!CCCC IPOIN2=21
      IPOIN2=ILISMX+1
      IF(ILISMX.GT.IREPMX)IPOIN2=IREPMX+1
!
!CCCC JMIN=IPOINT
      JMIN=IPOINT+(IREPMX-ILISMX)
      JMAX=IREPMX
      IF(JMAX.LT.JMIN)GO TO 1190
      DO 1100 J=JMIN,JMAX
      IPOIN2=IPOIN2-1
      IF(IPOIN2.LE.0)GO TO 1190
!
!CCCC THE FOLLOWING 4 LINES WERE ADDED JULY 1993
      IF(NUMLPR.GE.IHELMX)   &
      CALL DPMORE(NUMLPR,NCPREH,ICPREH,IRESP,IBUGS2,IERROR)
      IF(NUMLPR.GE.IHELMX)NUMLPR=0
      IF(IRESP.EQ.'NO')GO TO 1290
!
      DO 1110 I=1,MAXSTR
      IC1=IANSSV(J,I)
      ISTRIN(I:I)=IC1
 1110 CONTINUE
      NMAX=MAXSTR
      CALL DPDB80(ISTRIN,IMAX,NMAX,IBUGS2,ISUBRO,IERROR)
      WRITE(ICOUT,1115)IPOIN2,(ISTRIN(I:I),I=1,MIN(255,IMAX))
!CCCC THE FOLLOWING LINE WAS CHANGED TO ALLOW ALWAYS-WRITING  SEPTEMBER 1993
!CCCC CALL DPWRST('XXX','BUG ')
      CALL DPWRST('XXX','WRIT')
!CCCC THE FOLLOWING LINE WAS CHANGED APRIL 1993
!1115 FORMAT(4X,I2,'--',80A1)
 1115 FORMAT(4X,I4,'--',255A1)
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1989
      NUMLPR=NUMLPR+1
 1100 CONTINUE
 1190 CONTINUE
!
!CCCC JMIN=1
      JMIN=IPOINT-ILISMX
      IF(JMIN.LE.0)JMIN=1
      JMAX=IPOINT-1
      IF(JMAX.LT.JMIN)GO TO 1290
      DO 1200 J=JMIN,JMAX
      IPOIN2=IPOIN2-1
      IF(IPOIN2.LE.0)GO TO 1290
!
!CCCC THE FOLLOWING 4 LINES WERE ADDED JULY 1993
      IF(NUMLPR.GE.IHELMX)   &
      CALL DPMORE(NUMLPR,NCPREH,ICPREH,IRESP,IBUGS2,IERROR)
      IF(NUMLPR.GE.IHELMX)NUMLPR=0
      IF(IRESP.EQ.'NO')GO TO 1290
!
      DO 1210 I=1,MAXSTR
      IC1=IANSSV(J,I)
      ISTRIN(I:I)=IC1
 1210 CONTINUE
      NMAX=MAXSTR
      CALL DPDB80(ISTRIN,IMAX,NMAX,IBUGS2,ISUBRO,IERROR)
!CCCC THE FOLLOWING SECTION HAD CHANGES MADE   SEPTEMBER 1993
      IF(J.NE.JMAX)THEN
         WRITE(ICOUT,1215)IPOIN2,(ISTRIN(I:I),I=1,MIN(255,IMAX))
 1215    FORMAT(4X,I4,'--',255A1)
         CALL DPWRST('XXX','WRIT')
      ENDIF
      IF(J.EQ.JMAX)THEN
         WRITE(ICOUT,1216)IPOIN2,(ISTRIN(I:I),I=1,MIN(255,IMAX))
 1216    FORMAT(4X,I4,'--',255A1)
         CALL DPWRST('XXX','WRIT')
      ENDIF
      NUMLPR=NUMLPR+1
 1200 CONTINUE
 1290 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LICO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('AT THE END       OF DPLICO--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9029)IFOUND,IERROR,IRESP
 9029   FORMAT('IFOUND,IERROR,IRESP = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLICO
      SUBROUTINE DPLIGR(IANSLC,IWIDTH,IHARG,IARGT,IARG,NUMARG,   &
                        IBUGS2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--LIST THE CURRENTLY SAVED PIXMAPS
!
!                  LIST PLOT  (OR LIST GRAPH, LG, LP)
!                      REPEAT PLOT -2 PLOTS THE SIXTH PIXMAP
!
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGU
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--97/4
!     ORIGINAL VERSION--APRIL     1997.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      INCLUDE 'DPCOPA.INC'
      CHARACTER*4 IANSLC(*)
      CHARACTER*4 IHARG(*)
      CHARACTER*4 IARGT(*)
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 IFOUND
!
      CHARACTER*4 ISTEPN
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*80 CTEMP
!
      DIMENSION IARG(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPM.INC'
      INCLUDE 'DPCOF2.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLI'
      ISUBN2='GR  '
      IFOUND='YES'
      IERROR='NO'
!
      IF(IBUGS2.EQ.'ON' .OR. ISUBRO.EQ.'LIGR')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF DPLIGR--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGS2,ISUBRO,IFOUND,IERROR
   52   FORMAT('IBUGS2,ISUBRO,IFOUND,IERROR = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IWIDTH,NUMARG
   53   FORMAT('IWIDTH,NUMARG = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,54)(IANSLC(I),I=1,IWIDTH)
   54     FORMAT('(IANSLC(I),I=1,IWIDTH) = ',80A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IF(NUMARG.GE.1)THEN
          DO 56 I=1,NUMARG
            WRITE(ICOUT,57)I,IHARG(I),IARGT(I),IARG(I)
   57       FORMAT('I,IHARG(I),IARGT(I),IARG(I) = ',I8,2(2X,A4),I8)
            CALL DPWRST('XXX','BUG ')
   56     CONTINUE
        ENDIF
      ENDIF
!
!               *******************************
!               **  STEP 12--                **
!               **  LOOP THROUGH LIST IN     **
!               **  DPCOPM.INC               **
!               *******************************
!
      ISTEPN='12'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'REGR')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMPXM.LT.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1203)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
 1203 FORMAT('***** THERE ARE NO PIXMAPS SAVED FROM THE CURRENT ',   &
             'DATAPLOT SESSION.')
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      DO 1220 I=1,NUMPXM
        WRITE(ICOUT,1229)I
        CALL DPWRST('XXX','BUG ')
        NCSTR=1
        DO 1230 J=128,1,-1
          NCSTR=J
          IF(IPXMFN(I)(J:J).NE.' ')GO TO 1235
 1230   CONTINUE
 1235   CONTINUE
        CTEMP(1:80)=IPXMFN(I)(1:80)
        WRITE(ICOUT,1239)CTEMP
        CALL DPWRST('XXX','BUG ')
        NCSTR=1
        DO 1240 J=128,1,-1
          NCSTR=J
          IF(IPXMCM(I)(J:J).NE.' ')GO TO 1245
 1240   CONTINUE
 1245   CONTINUE
        CTEMP(1:80)=IPXMCM(I)(1:80)
        WRITE(ICOUT,1249)CTEMP
        CALL DPWRST('XXX','BUG ')
 1220 CONTINUE
 1229 FORMAT('PIXMAP ',I5,':')
 1239 FORMAT('      FILE NAME = ',A80)
 1249 FORMAT('      FILE TITLE = ',A80)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'OFF'.AND.ISUBRO.NE.'REGR')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('AT THE END       OF DPLIGR--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGS2,ISUBRO,IFOUND,IERROR
 9012 FORMAT('IBUGS2,ISUBRO,IFOUND,IERROR = ',A4,2X,A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IWIDTH
 9013 FORMAT('IWIDTH = ',I8)
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)WRITE(ICOUT,9014)(IANSLC(I),I=1,IWIDTH)
 9014 FORMAT('(IANSLC(I),I=1,IWIDTH) = ',80A1)
      IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9015)NUMARG
 9015 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      IF(NUMARG.LE.0)GO TO 9018
      DO 9016 I=1,NUMARG
      WRITE(ICOUT,9017)I,IHARG(I)
 9017 FORMAT('I,IHARG(I) = ',I8,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9016 CONTINUE
 9018 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPLIGR
      SUBROUTINE DPLIK1(Y,Y2,N,ICASPL,   &
                        SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                        SHAPE5,SHAPE6,SHAPE7,   &
                        YLOWLM,YUPPLM,A,B,MINMAX,   &
                        IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                        ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                        IGETDF,ICONDF,IGOMDF,IKATDF,   &
                        IGIGDF,IGEODF,   &
                        KSLOC,KSSCAL,   &
                        ALIK,AIC,AICC,BIC,   &
                        IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--COMPUTE THE LOG-LIKELIHOOD FUNCTION AT A GIVEN SET
!              OF POINTS.  SPECIFICALLY,
!
!                 LOG-LIKE = SUM[i=1 to n][LOG(f(x(i);theta))]
!
!              WITH theta DENOTING THE PARAMETERS FOR THE
!              DISTRIBUTION.  THE VALUE OF THE LOG-LIKELIHOOD
!              CAN IN TURN BE USED TO COMPUTE THE AIC, AICC, AND
!              BIC GOODNESS OF FIT STATISTICS.
!
!              FOR SELECT DISTRIBUTIONS, SPECIFIC ROUTINES WILL
!              BE CALLED TO COMPUTE THE LIKELIHOOD FUNCTION
!              (THESE TYPICALLY SIMPLIFY THE LOG-LIKELIHOOD FUNCTION).
!              IF A SPECIFIC LIKELIHOOD ROUTINE HAS NOT BEEN CODED
!              FOR THE DISTRIBUTION, THEN CALL DPPDF1 TO COMPUTE
!              THE f(x(i);theta) PART, TAKE THE LOG, AND THEN
!              COMPUTE THE SUM.
!
!              THIS ROUTINE HANDLES THE UNGROUPED, UNCENSORED CASE.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/10
!     ORIGINAL VERSION--OCTOBER   2009.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 IADEDF
      CHARACTER*4 IGEPDF
      CHARACTER*4 IMAKDF
      CHARACTER*4 IBEIDF
      CHARACTER*4 ILGADF
      CHARACTER*4 ISKNDF
      CHARACTER*4 IGLDDF
      CHARACTER*4 IBGEDF
      CHARACTER*4 IGOMDF
      CHARACTER*4 IGETDF
      CHARACTER*4 ICONDF
      CHARACTER*4 IKATDF
      CHARACTER*4 IGIGDF
      CHARACTER*4 IGEODF
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 IERROR
!
      CHARACTER*4 IGAMFL
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      REAL KSLOC
      REAL KSLOCT
      REAL KSSCAL
!
!CCCC DOUBLE PRECISION DXOUT
!CCCC DOUBLE PRECISION DTERM1
!CCCC DOUBLE PRECISION DTERM2
!CCCC DOUBLE PRECISION CDFGLO
!CCCC DOUBLE PRECISION CDFWAK
!CCCC DOUBLE PRECISION XPAR(5)
!
      DOUBLE PRECISION DN
      DOUBLE PRECISION DNP
      DOUBLE PRECISION DLIK
      DOUBLE PRECISION DTERM3
!
!---------------------------------------------------------------------
!
      DIMENSION Y(*)
      DIMENSION Y2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!
      ISUBN1='DPLI'
      ISUBN2='K1  '
      IERROR='NO'
!
      DLIK=DBLE(CPUMIN)
      AIC=CPUMIN
      AICC=CPUMIN
      BIC=CPUMIN
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,31)
   31   FORMAT('***** ERROR IN DPLIK1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,32)
   32   FORMAT('      THE NUMBER OF OBSERVATIONS MUST BE AT LEAST 2.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,34)N
   34   FORMAT('      THE ENTERED NUMBER OF OBSERVATIONS HERE = ',I6)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      HOLD=Y(1)
      DO 60 I=1,N
        IF(Y(I).NE.HOLD)GO TO 69
   60 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,31)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)
   62 FORMAT('      ALL ELEMENTS IN THE RESPONSE VARIABLE ARE ',   &
             'IDENTICALLY EQUAL TO ',G15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
   69 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LIK1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,71)
   71   FORMAT('***** AT THE BEGINNING OF DPLIK1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,72)ICASPL,N,MINMAX
   72   FORMAT('ICASPL,N,MINMAX = ',A4,2X,2X,I8,I8)
        CALL DPWRST('XXX','BUG ')
        DO 85 I=1,N
          WRITE(ICOUT,86)I,Y(I)
   86     FORMAT('I,Y(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
   85   CONTINUE
      ENDIF
!
!               ****************************************************
!               **  STEP 2.1--                                    **
!               **  COMPUTE LIKELIHOOD FUNCTIION AT GIVEN POINTS  **
!               ****************************************************
!
      NP=-99
      IF(ICASPL.EQ.'UNIF')THEN
        CALL UNILI1(Y,N,A,B,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'NORM')THEN
        CALL NORLI1(Y,N,KSLOC,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'MAX')THEN
        CALL NORLI1(Y,N,KSLOC,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'FNOR')THEN
        CALL FNRLI1(Y,N,SHAPE1,SHAPE2,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'CAUC')THEN
        CALL CAULI1(Y,N,KSLOC,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'LOGI')THEN
        CALL LOGLI1(Y,N,KSLOC,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'DEXP')THEN
        CALL DEXLI1(Y,N,KSLOC,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'EXPO')THEN
        CALL EXPLI1(Y,N,ICASPL,   &
                    KSLOC,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'1EXP')THEN
        KSLOCT=0.0
        CALL EXPLI1(Y,N,ICASPL,   &
                    KSLOCT,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=1
!
      ELSEIF(ICASPL.EQ.'MAXW')THEN
        CALL MAXLI1(Y,N,ICASPL,   &
                    KSLOC,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'1MAX')THEN
        KSLOCT=0.0
        CALL MAXLI1(Y,N,ICASPL,   &
                    KSLOCT,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=1
!
      ELSEIF(ICASPL.EQ.'RAYL')THEN
        CALL RAYLI1(Y,N,ICASPL,   &
                    KSLOC,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'1RAY')THEN
        KSLOCT=0.0
        CALL RAYLI1(Y,N,ICASPL,   &
                    KSLOCT,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=1
!
      ELSEIF(ICASPL.EQ.'EXPO')THEN
        CALL EXPLI1(Y,N,ICASPL,   &
                    KSLOCT,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'SLAS')THEN
        CALL SLALI1(Y,Y2,N,KSLOC,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'CAUC')THEN
        CALL CAULI1(Y,N,KSLOC,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'EV1')THEN
        CALL EV1LI1(Y,N,MINMAX,KSLOC,KSSCAL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSEIF(ICASPL.EQ.'WEIB')THEN
        CALL WEILI1(Y,N,ICASPL,MINMAX,KSLOC,KSSCAL,SHAPE1,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
      ELSEIF(ICASPL.EQ.'3WEI')THEN
        CALL WEILI1(Y,N,ICASPL,MINMAX,KSLOC,KSSCAL,SHAPE1,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=3
!
      ELSEIF(ICASPL.EQ.'LOGN')THEN
        CALL LGNLI1(Y,N,KSLOC,KSSCAL,SHAPE1,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
      ELSEIF(ICASPL.EQ.'3LGN')THEN
        CALL LGNLI1(Y,N,KSLOC,KSSCAL,SHAPE1,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=3
!
      ELSEIF(ICASPL.EQ.'LOGN')THEN
        CALL LGNLI1(Y,N,KSLOC,KSSCAL,SHAPE1,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
      ELSEIF(ICASPL.EQ.'3LGN')THEN
        CALL LGNLI1(Y,N,KSLOC,KSSCAL,SHAPE1,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=3
!
      ELSEIF(ICASPL.EQ.'GAMM')THEN
        IGAMFL='GAMM'
        CALL GAMLI1(Y,N,ICASPL,IGAMFL,KSLOC,KSSCAL,SHAPE1,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
      ELSEIF(ICASPL.EQ.'3GAM')THEN
        IGAMFL='GAMM'
        CALL GAMLI1(Y,N,ICASPL,IGAMFL,KSLOC,KSSCAL,SHAPE1,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=3
!
      ELSEIF(ICASPL.EQ.'INGA')THEN
        SCALET=1.0
        KSLOCT=0.0
        CALL IGLI1(Y,N,ICASPL,   &
                   KSLOCT,SHAPE1,SHAPE2,   &
                   ALIK,AIC,AICC,BIC,   &
                   ISUBRO,IBUGA3,IERROR)
        NP=2
      ELSEIF(ICASPL.EQ.'3IGA')THEN
        SCALET=1.0
        CALL IGLI1(Y,N,ICASPL,   &
                   KSLOC,SHAPE1,SHAPE2,   &
                   ALIK,AIC,AICC,BIC,   &
                   ISUBRO,IBUGA3,IERROR)
        NP=3
!
      ELSEIF(ICASPL.EQ.'BU10')THEN
        CALL B10LI1(Y,N,ICASPL,KSLOC,KSSCAL,SHAPE1,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
      ELSEIF(ICASPL.EQ.'3B10')THEN
        CALL B10LI1(Y,N,ICASPL,KSLOC,KSSCAL,SHAPE1,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=3
!
      ELSEIF(ICASPL.EQ.'POWF' .OR. ICASPL.EQ.'RPOW')THEN
        CALL POWLI1(Y,N,Y2,SHAPE1,YLOWLM,YUPPLM,ICASPL,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=1
!
      ELSEIF(ICASPL.EQ.'TOPL')THEN
        CALL TOPLI1(Y,N,Y2,SHAPE1,YLOWLM,YUPPLM,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=1
      ELSEIF(ICASPL.EQ.'RGTL')THEN
        CALL RGTLI1(Y,N,   &
                    YLOWLM,YUPPLM,SHAPE1,SHAPE2,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
      ELSEIF(ICASPL.EQ.'BETA')THEN
        NP=2
        CALL BETLI1(Y,N,NP,YLOWLM,YUPPLM,SHAPE1,SHAPE2,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
      ELSEIF(ICASPL.EQ.'4BET')THEN
        NP=4
        CALL BETLI1(Y,N,NP,YLOWLM,YUPPLM,SHAPE1,SHAPE2,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
!
      ELSEIF(ICASPL.EQ.'GEV ')THEN
        CALL GEVLI1(Y,N,MINMAX,KSLOC,KSSCAL,SHAPE1,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
        IF(ABS(KSLOC).GT.0.000001)NP=3
      ELSEIF(ICASPL.EQ.'PARE')THEN
        CALL PARLI1(Y,N,   &
                    SHAPE1,SHAPE2,   &
                    ALIK,AIC,AICC,BIC,   &
                    ISUBRO,IBUGA3,IERROR)
        NP=2
!
      ELSE
        CALL DPPDF1(Y,Y2,N,ICASPL,   &
                    SHAPE1,SHAPE2,SHAPE3,SHAPE4,   &
                    SHAPE5,SHAPE6,SHAPE7,   &
                    YLOWLM,YUPPLM,A,B,MINMAX,   &
                    ICAPSW,ICAPTY,   &
                    IADEDF,IGEPDF,IMAKDF,IBEIDF,   &
                    ILGADF,ISKNDF,IGLDDF,IBGEDF,   &
                    IGETDF,ICONDF,IGOMDF,IKATDF,   &
                    IGIGDF,IGEODF,   &
                    KSLOC,KSSCAL,   &
                    IBUGA3,ISUBRO,IERROR)
        DO 1000 I=1,N
          IF(Y2(I).LE.0.0)THEN
            IERROR='YES'
!CCCC       GO TO 9000
            Y2(I)=0.0
          ELSE
            Y2(I)=LOG(Y2(I))
          ENDIF
 1000   CONTINUE
        IWRITE='OFF'
        CALL SUMDP(Y2,N,IWRITE,ALIK,IBUGA3,IERROR)
!
!       DON'T RECOMPUTE AIC, AICC, BIC IF ALREADY COMPUTED.
!
        IF(AIC.NE.CPUMIN .AND. BIC.NE.CPUMIN .AND. AICC.NE.CPUMIN)THEN
          GO TO 9000
        ENDIF
!
        IF(NP.LE.0)THEN
          NP=0
          IF(KSLOC.NE.CPUMIN .AND. KSLOC.NE.0.0)NP=NP+1
          IF(KSSCAL.NE.CPUMIN)NP=NP+1
          IF(SHAPE1.NE.CPUMIN)NP=NP+1
          IF(SHAPE2.NE.CPUMIN)NP=NP+1
          IF(SHAPE3.NE.CPUMIN)NP=NP+1
          IF(SHAPE4.NE.CPUMIN)NP=NP+1
          IF(SHAPE5.NE.CPUMIN)NP=NP+1
          IF(SHAPE6.NE.CPUMIN)NP=NP+1
          IF(SHAPE7.NE.CPUMIN)NP=NP+1
        ENDIF
!
        DN=DBLE(N)
        DLIK=DBLE(ALIK)
        DNP=DBLE(NP)
        AIC=REAL(-2.0D0*DLIK + 2.0D0*DNP)
        DTERM3=(2.0D0*DNP*(DNP+1.0D0))/(DN-DNP-1.0D0)
        AICC=REAL(-2.0D0*DLIK + 2.0D0*DNP + DTERM3)
        BIC=REAL(-2.0D0*DLIK + DNP*LOG(DN))
!
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LIK1')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLIK1--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)ICASPL,N,MINMAX,IERROR
 9012   FORMAT('ICASPL,N,MINMAX,IERROR = ',A4,2X,2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,N
          WRITE(ICOUT,9021)I,Y(I),Y2(I)
 9021     FORMAT('I,Y(I),Y2(I), = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
        WRITE(ICOUT,9031)NP
 9031   FORMAT('NP = ',I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9033)DSUM1,DTERM1,DTERM3
 9033   FORMAT('DSUM1,DTERM1,DTERM3 = ',3G15.7)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,9034)ALIK,AIC,AICC,BIC
 9034   FORMAT('ALIK,AIC,AICC,BIC = ',4G15.7)
        CALL DPWRST('XXX','WRIT')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLIK1
      SUBROUTINE DPLIM(ICOM,IHARG,IARGT,ARG,NUMARG,   &
                       GX1MIN,GX1MAX,GY1MIN,GY1MAX,   &
                       GX2MIN,GX2MAX,GY2MIN,GY2MAX,   &
                       FX1MIN,FX1MAX,FY1MIN,FY1MAX,   &
                       FX2MIN,FX2MAX,FY2MIN,FY2MAX,   &
                       IX1MIN,IX1MAX,IY1MIN,IY1MAX,   &
                       IX2MIN,IX2MAX,IY2MIN,IY2MAX,   &
                       FX1MNZ,FX1MXZ,FX2MNZ,FX2MXZ,   &
                       FY1MNZ,FY1MXZ,FY2MNZ,FY2MXZ,   &
                       GX1MNX,GX1MXX,GY1MNX,GY1MXX,   &
                       GX2MNX,GX2MXX,GY2MNX,GY2MXX,   &
                       IX1MNX,IX1MXX,IY1MNX,IY1MXX,   &
                       IX2MNX,IX2MXX,IY2MNX,IY2MXX,   &
                       IFOUND,IERROR)
!
!     PURPOSE--DEFINE AXIS LIMITS (HORIZONTAL AXIS OR VERTICAL AXIS OR
!              BOTH) WHICH IN TURN WILL DEFINE THE EXTREMES WHICH WILL
!              APPEAR ON THE PLOT.  THE LIMITS WILL BE PLACED IN THE 8
!              VARIABLES:
!                 GX1MIN,GX1MAX,GY1MIN,GY1MAX,
!                 GX2MIN,GX2MAX,GY2MIN,GY2MAX,
!              THE STATUS (FIXED OR FLOAT) WILL BE PLACED IN THE 8
!              VARIABLES:
!                 IX1MIN,IX1MAX,IY1MIN,IY1MAX,
!                 IX2MIN,IX2MAX,IY2MIN,IY2MAX
!     INPUT  ARGUMENTS--ICOM  (A  HOLLERITH VARIABLE)
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --IARGT  (A  HOLLERITH VECTOR)
!                     --ARG    (A  FLOATING POINT VECTOR)
!                     --NUMARG
!     OUTPUT ARGUMENTS--
!                     --GX1MIN = MINIMUM FOR BOTTOM HORIZONTAL AXIS
!                     --GX1MAX = MAXIMUM FOR BOTTOM HORIZONTAL AXIS
!                     --GY1MIN = MINIMUM FOR LEFT   VERTICAL   AXIS
!                     --GY1MAX = MAXIMUM FOR LEFT   VERTICAL   AXIS
!                     --GX2MIN = MINIMUM FOR TOP    HORIZONTAL AXIS
!                     --GX2MAX = MAXIMUM FOR TOP    HORIZONTAL AXIS
!                     --GX2MIN = MINIMUM FOR RIGHT  VERTICAL   AXIS
!                     --GX2MAX = MAXIMUM FOR RIGHT  VERTICAL   AXIS
!                     --IX1MIN = STATUS FOR MINIMUM FOR BOTTOM HORIZONTAL AXIS
!                     --IX1MAX = STATUS FOR MAXIMUM FOR BOTTOM HORIZONTAL AXIS
!                     --IY1MIN = STATUS FOR MINIMUM FOR LEFT   VERTICAL   AXIS
!                     --IY1MAX = STATUS FOR MAXIMUM FOR LEFT   VERTICAL   AXIS
!                     --IX2MIN = STATUS FOR MINIMUM FOR TOP    HORIZONTAL AXIS
!                     --IX2MAX = STATUS FOR MAXIMUM FOR TOP    HORIZONTAL AXIS
!                     --IX2MIN = STATUS FOR MINIMUM FOR RIGHT  VERTICAL   AXIS
!                     --IX2MAX = STATUS FOR MAXIMUM FOR RIGHT  VERTICAL   AXIS
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1978.
!     UPDATED         --SEPTEMBER 1980.
!     UPDATED         --OCTOBER   1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --NOVEMBER  1986.
!     UPDATED         --FEBRUARY  1992. FIX YLIMITS WITH NO ARGS BOMB
!     UPDATED         --JULY      1996. ALLOW UPPER AND LOWER LIMIT TO
!                                       BE SAME (FOR LOG SCALES WHICH
!                                       VARY OVER SMALL RANGE)
!     UPDATED         --NOVEMBER  1997. FIX BUG WITH TIC OFFSET AND
!                                       LIMITS FREEZE.
!     UPDATED         --OCTOBER   2018. RECODE FOR BETTER READABILITY
!     UPDATED         --MARCH     2021. ADD "SAVE" AND "RESTORE" OPTIONS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
