      SUBROUTINE DPLIN2(I,IHARG,IHARG2,ILINP2)
!
!     PURPOSE--SHORTEN 5 TO 8-CHARACTER STRINGS
!              FOR VARIOUS DASHED LINES
!              (E.G., DASH3, DASH12, ETC.)
!              INTO 1 TO 4-CHARACTER STRINGS
!              (E.G., DA3, DA12, ETC.)
!     INPUT  ARGUMENTS--I      THE ELEMENT NUMBER
!                              IN IHARG AND IHARG2 THAT IS
!                              BEING EXAMINED.
!                     --IHARG  (A  HOLLERITH VECTOR)
!                     --IHARG2 (A  HOLLERITH VECTOR)
!     OUTPUT ARGUMENTS--ILINP2 (A  HOLLERITH VARIABLE
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 ILINP2
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IHARG(I).EQ.'DASH')GO TO 1000
      GO TO 9000
!
 1000 CONTINUE
      ILINP2='DASH'
      IF(IHARG2(I).EQ.'1   ')ILINP2='DA1 '
      IF(IHARG2(I).EQ.'2   ')ILINP2='DA2 '
      IF(IHARG2(I).EQ.'3   ')ILINP2='DA3 '
      IF(IHARG2(I).EQ.'4   ')ILINP2='DA4 '
      IF(IHARG2(I).EQ.'5   ')ILINP2='DA5 '
      IF(IHARG2(I).EQ.'6   ')ILINP2='DA6 '
      IF(IHARG2(I).EQ.'7   ')ILINP2='DA7 '
      IF(IHARG2(I).EQ.'8   ')ILINP2='DA8 '
      IF(IHARG2(I).EQ.'9   ')ILINP2='DA9 '
      IF(IHARG2(I).EQ.'10  ')ILINP2='DA10'
      IF(IHARG2(I).EQ.'11  ')ILINP2='DA11'
      IF(IHARG2(I).EQ.'12  ')ILINP2='DA12'
      IF(IHARG2(I).EQ.'13  ')ILINP2='DA13'
      IF(IHARG2(I).EQ.'14  ')ILINP2='DA14'
      IF(IHARG2(I).EQ.'15  ')ILINP2='DA15'
      IF(IHARG2(I).EQ.'16  ')ILINP2='DA16'
      IF(IHARG2(I).EQ.'17  ')ILINP2='DA17'
      IF(IHARG2(I).EQ.'18  ')ILINP2='DA18'
      IF(IHARG2(I).EQ.'19  ')ILINP2='DA19'
      IF(IHARG2(I).EQ.'20  ')ILINP2='DA20'
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPLIN2
      SUBROUTINE DPLINE(IHARG,IHARG2,NUMARG,MAXLIN,ILINPA,ILINPO,   &
      IFOUND,IERROR)
!CCCC ARGUMENT LIST AUGMENTED FEBRUARY, 1998.
!CCCC SUBROUTINE DPLINE(IHARG,IHARG2,NUMARG,MAXLIN,ILINPA,IFOUND,IERROR)
!
!     PURPOSE--DEFINE PLOT LINES FOR USE IN MULTI-TRACE PLOTS.
!              THE LINE FOR THE I-TH TRACE WILL BE PLACED
!              IN THE I-TH ELEMENT OF THE HOLLERITH
!              VECTOR ILINPA(.).
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --IHARG2   (A HOLLERITH VECTOR)
!                     --NUMARG
!                     --MAXLIN
!     OUTPUT ARGUMENTS--ILINPA  (A  HOLLERITH VECTOR
!                       WHOSE I-TH ELEMENT IS THE LINE
!                       ASSIGNED TO THE I-TH    TRACE    IN
!                       A MULTI-TRACE PLOT.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1977.
!     UPDATED         --SEPTEMBER 1980.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --JULY      1983.
!     UPDATED         --AUGUST    1987.     TUFTE BOX PLOT
!     UPDATED         --NOVEMBER  1988.     ERROR BAR PLOT
!     UPDATED         --SEPTEMBER 1990.     AUGMENT CONTROL CHART
!     UPDATED         --FEBRUARY  1998.  ADD LINE SAVE/RESTORE FOR
!                                        FRONTEND.
!     UPDATED         --FEBRUARY  2003.  VIOLIN PLOT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
      CHARACTER*4 ILINPA
!CCCC ADD FOLLOWING LINE FEBRUARY 1998.
      CHARACTER*4 ILINPO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ILINP2
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
!
      DIMENSION ILINPA(*)
!CCCC ADD FOLLOWING LINE FEBRUARY 1998.
      DIMENSION ILINPO(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='NO'
      IERROR='NO'
!
!CCCC ADD FOLLOWING 2 LINES FEBRUARY 1998.
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'SAVE')GO TO 2160
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'REST')GO TO 2165
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'BOX'.AND.IHARG(2).EQ.'PLOT')   &
      GO TO 2110
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'TUFT'.AND.   &
                         IHARG(2).EQ.'BOX'.AND.IHARG(3).EQ.'PLOT')   &
      GO TO 2140
      IF(NUMARG.GE.3.AND.IHARG(1).EQ.'ERRO'.AND.   &
                         IHARG(2).EQ.'BAR'.AND.IHARG(3).EQ.'PLOT')   &
      GO TO 2150
      IF(NUMARG.GE.3.AND.IHARG(2).EQ.'BOX'.AND.IHARG(3).EQ.'PLOT')   &
      GO TO 2110
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'I'.AND.IHARG(2).EQ.'PLOT')   &
      GO TO 2120
