      SUBROUTINE DPLIPO(NLAB,AMEAN,ASD,WTS,N,   &
                        CUMWTS,YUNIF,YNORM,YSAVE,   &
                        XLP,SELIP1,ALOWLP,AUPPLP,   &
                        IWRITE,IOUNI5,   &
                        ICAPSW,ICAPTY,MAXNXT,NUMDIG,ISEED,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--IMPLEMENT LINEAR POOL APPROACH TO CONSENSUS MEANS.
!     PRINTING--YES
!     SUBROUTINES NEEDED--NONE
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     REFERENCES--KOEPKE, LAFARGE, POSSOLO AND TOMAN (2017), "CONSENSUS
!                 BUILDING FOR INTERLABORATORY STUDIES, KEY COMPARISONS,
!                 AND META-ANALYSIS", METROLOGIA 54 PP. S34-S62.
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2023/04
!     ORIGINAL VERSION--APRIL     2023.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      REAL AMEAN(*)
      REAL ASD(*)
      REAL WTS(*)
      REAL CUMWTS(*)
      REAL YUNIF(*)
      REAL YNORM(*)
      REAL YSAVE(*)
!
      INTEGER N(*)
!
      REAL YTEMP(1)
!
!----------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER (MAXROW=20)
      CHARACTER*65 ITITLE
      CHARACTER*65 ITITLZ
      CHARACTER*65 ITITL9
      CHARACTER*65 ITEXT(MAXROW)
      REAL         AVALUE(MAXROW)
      INTEGER      NCTEXT(MAXROW)
      INTEGER      IDIGIT(MAXROW)
      INTEGER      NTOT(MAXROW)
      LOGICAL IFRST
      LOGICAL ILAST
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPLI'
      ISUBN2='PO  '
!
      IINDX=0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LIPO')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLIPO--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NLAB,ISEED,ILIPSS,MAXNXT
   52   FORMAT('NLAB,ISEED,ILIPSS,MAXNXT = ',4I8)
        CALL DPWRST('XXX','BUG ')
        DO 60 I=1,NLAB
          WRITE(ICOUT,62)I,N(I),AMEAN(I),ASD(I),WTS(I)
   62     FORMAT('I,N(I),AMEAN(I),ASD(I),WTS(I) = ',2I8,3G15.7)
          CALL DPWRST('XXX','BUG ')
   60   CONTINUE
      ENDIF
!
!     STEP 1: CHECK THE WEIGHTS VECTOR
!
!             IF FIRST ENTRY IS 0, THEN ASSUME NO WEIGHT
!             VECTOR GIVEN AND DEFINE EQUAL WEIGHTS
!
      IF(WTS(1).LE.0.0)THEN
        DO 190 II=1,NLAB
          WTS(II)=1.0/REAL(NLAB)
  190   CONTINUE
      ENDIF
!
      SUM=0.0
      DO 201 II=1,NLAB
!
        IF(WTS(II).LE.0.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,202)
  202     FORMAT('***** ERROR IN LINEAR POOL CONSENSUS VALUE--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,203)II,WTS(II)
  203     FORMAT('      WEIGHT ',I6,' IS NON-POSITIVE (',G15.7,')')
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
        SUM=SUM+WTS(II)
  201 CONTINUE
!
      DO 211 II=1,NLAB
        WTS(II)=WTS(II)/SUM
        IF(II.EQ.1)THEN
          CUMWTS(II)=WTS(II)
        ELSE
          CUMWTS(II)=CUMWTS(II-1) + WTS(II)
        ENDIF
  211 CONTINUE
!
!     STEP 2: GENERATE 10,000 UNIFORM RANDOM NUMBERS
!
      NSAMP=ILIPSS
      CALL UNIRAN(NSAMP,ISEED,YUNIF)
      CALL NORRAN(NSAMP,ISEED,YNORM)
      ICNTN=0
!
!     STEP 3: LOOP TRHOUGH UNIFORM SAMPLES
!
      DO 310 II=1,NSAMP
        AVAL=YUNIF(II)
        ILAB=0
        DO 320 JJ=1,NLAB
          IF(AVAL.LT.CUMWTS(1))THEN
            ILAB=1
            GO TO 329
          ELSEIF(AVAL.GE.CUMWTS(JJ-1) .AND. AVAL.LT.CUMWTS(JJ))THEN
            ILAB=JJ
            GO TO 329
          ENDIF
  320   CONTINUE
  329   CONTINUE
        IF(ILAB.EQ.0)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,202)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,323)II
  323     FORMAT('      FOR UNIFORM SAMPLE ',I8,' NO LAB ID WAS ',   &
                 'DETERMINED.')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,325)AVAL
  325     FORMAT('      UNIFORM VALUE IS ',G15.7)
          CALL DPWRST('XXX','BUG ')
          IERROR='YES'
          GO TO 9000
        ENDIF
!
!     STEP 3B: NOW GENERATE A RANDOM SAMPLE FROM THE SPECIFIED LAB
!
        NTEMP=N(ILAB)
        IF(NTEMP.LE.1)THEN
          NTEMP2=1
          ICNTN=ICNTN+1
          XVAL=YNORM(ICNTN)
          ASE=ASD(ILAB)
        ELSE
          ADF=REAL(NTEMP-1)
          NSAMP2=1
          CALL TRAN(NSAMP2,ADF,ISEED,YTEMP)
          XVAL=YTEMP(1)
          ASE=ASD(ILAB)/SQRT(REAL(NLAB))
        ENDIF
        YSAVE(II)=AMEAN(ILAB) + ASE*XVAL
!
        IF(IBUGA3.EQ.'LIPO' .OR. IBUGA3.EQ.'ON')THEN
          WRITE(ICOUT,332)II,ILAB,XVAL,ASE
  332     FORMAT('DPLIPO: II,ILAB,XVAL,ASE = ',2I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
  310 CONTINUE
!
!     STEP 4: NOW COMPUTE STATISTICS FROM THE SAMPLES
!
      CALL MEAN(YSAVE,NSAMP,IWRITE,XLP,IBUGA3,IERROR)
      CALL SD(YSAVE,NSAMP,IWRITE,SELIP1,IBUGA3,IERROR)
      SELIP2=2.0*SELIP1
      P100=2.5
      CALL PERCEN(P100,YSAVE,NSAMP,IWRITE,CUMWTS,MAXNXT,   &
                  ALOWLP,IBUGA3,IERROR)
      P100=97.5
      CALL PERCEN(P100,YSAVE,NSAMP,IWRITE,CUMWTS,MAXNXT,   &
                  AUPPLP,IBUGA3,IERROR)
!
      IF(IOUNI5.GT.0)THEN
        WRITE(IOUNI5,412)
  412   FORMAT('VALUES FROM LINEAR POOL METHOD')
        DO 420 II=1,NSAMP
          WRITE(IOUNI5,422)YSAVE(II)
  422     FORMAT(E15.7)
  420   CONTINUE
      ENDIF
!
!     STEP 5: PRINT THE RESULTS IF REQUESTED
!
      IF(IPRINT.EQ.'OFF')GO TO 9000
!
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
!
      ICNT=1
      ITEXT(ICNT)='16. Method: Linear Pool'
      NCTEXT(ICNT)=23
      AVALUE(ICNT)=0.0
      IDIGIT(ICNT)=-1
!
      ICNT=ICNT+1
      ITEXT(ICNT)='    Linear Pool Consensus Value:'
      NCTEXT(ICNT)=32
      AVALUE(ICNT)=XLP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Standard Uncertainty (k = 1):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=SELIP1
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Expanded Uncertainty (k = 2):'
      NCTEXT(ICNT)=33
      AVALUE(ICNT)=SELIP2
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Lower 95% (normal) Confidence Limit:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=ALOWLP
      IDIGIT(ICNT)=NUMDIG
      ICNT=ICNT+1
      ITEXT(ICNT)='    Upper 95% (normal) Confidence Limit:'
      NCTEXT(ICNT)=40
      AVALUE(ICNT)=AUPPLP
      IDIGIT(ICNT)=NUMDIG
!
      NUMROW=ICNT
      DO 510 I=1,NUMROW
        NTOT(I)=15
  510 CONTINUE
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA1(ITITLE,NCTITL,ITITLZ,NCTITZ,ITEXT,NCTEXT,   &
                  AVALUE,IDIGIT,   &
                  NTOT,NUMROW,   &
                  ICAPSW,ICAPTY,ILAST,IFRST,   &
                  ISUBRO,IBUGA3,IERROR)
      ITITLE=' '
      NCTITL=0
      ITITLZ=' '
      NCTITZ=0
      ITITL9=' '
      NCTIT9=0
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LIPO')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLIPO--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)XLP,SELIP1,SELIP2,ALOWLP,AUPPLP
 9014   FORMAT('XLP,SELIP1,SELIP2,ALOWLP,AUPPLP = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLIPO
!CCCC SUBROUTINE DPLIST(ICOM,IANSLC,IWIDTH,IHARG,IHARG2,IARGT,
!CCCC1                  IARG,ARG,NUMARG,
      SUBROUTINE DPLIST(ICOM3,ICOM4,ICOM5,NUMCOM,NCOM5,   &
                        IHELMX,   &
                        ICPREH,NCPREH,ICPOSH,NCPOSH,   &
                        ILOOST,ILOOLI,NUMLIL,NUMLOS,   &
                        IANSLO,IWIDLL,   &
                        IBUGS2,IBUGQ,ISUBRO,IFOUND,IERROR)
!CCCC 5 ARGS ADDED ABOVE FOR MORE/PAUSE   JULY 1989
!CCCC ICOM WAS ADDED TO THE ARGUMENT LIST NOVEMBER 1989
!
!     PURPOSE--LIST (= DISPLAY) A USER-DEFINED FILE.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--86/1
!     ORIGINAL VERSION--JULY      1984.
!     UPDATED         --DECEMBER  1985.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --DECEMBER  1985.
!     UPDATED         --JANUARY   1987. (TO INCLUDE THE DIRECTORY FILE).
!     UPDATED         --AUGUST    1988. (TO INCLUDE DICTIONARY FILE).
!     UPDATED         --JULY      1989. MORE/PAUSE
!     UPDATED         --NOVEMBER  1989. NUMBERED LIST
!     UPDATED         --JULY      1990. ALLOW MORE... TO STOP LIST
!     UPDATED         --AUGUST    1990. EXPLICIT SETTING OF NUMLPR=0
!     UPDATED         --SEPTEMBER 1993. ALLOW ALWAYS-WRITING
!     UPDATED         --NOVEMBER  1993. PATH + DATASETS.
!     UPDATED         --NOVEMBER  1993. PATH + DESIGNS.
!     UPDATED         --NOVEMBER  1993. PATH + DISTRIBUTIONS.
!     UPDATED         --NOVEMBER  1993. PATH + COMMANDS.
!     UPDATED         --NOVEMBER  1993. PATH + SYNTAX.
!     UPDATED         --NOVEMBER  1993. PATH + FUNCTIONS.
!     UPDATED         --NOVEMBER  1993. PATH + PROGRAMS.
!     UPDATED         --NOVEMBER  1993. PATH + MACROS.
!     UPDATED         --AUGUST    1994. SIMPLIFY CODE THROUGHOUT
!     UPDATED         --JUNE      1995. REMOVE PATH INFO
!     UPDATED         --NOVEMBER  2014. LIST CLIPBOARD (FOR WINDOWS)
!     UPDATED         --SEPTEMBER 2015. LIST FUNCTION BLOCK
!     UPDATED         --AUGUST    2016. LIST STATISTIC BLOCK
!     UPDATED         --OCTOBER   2016. LIST COMMAND LINE ARGUMENTS
!     UPDATED         --JULY      2017. LIST LOOP LINES
!     UPDATED         --JUNE      2018. UP MAXIMUM LINE LENGTH FROM 80
!                                       TO 255
!     UPDATED         --OCTOBER   2019. SUPPORT HEAD/TAIL OPTIONS
!     UPDATED         --NOVEMBER  2019. LIST NEW WINDOW
!     UPDATED         --NOVEMBER  2019. LIST EXCEL/WORD/POWER POINT
!     UPDATED         --FEBRUARY  2020. IF "LIST CLIPBOARD" DETECTED,
!                                       CHECK TO SEE IF FIRST ARGUMENT
!                                       IS ACTUALLY A FILE NAME
!     UPDATED         --JUNE      2020. LIST CLIPBOARD (FOR LINUX)
!                                       THIS USES "xclip" IN THE
!                                       BACKGROUND
!     UPDATED         --FEBRUARY  2021. SOME TWEAKS FOR HELP IN NEW
!                                       WINDOW FOR MACOS
