      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IFILQ2
      CHARACTER*4 ICASEQ
      CHARACTER*4 ITYPE
      CHARACTER*4 IFLAGN
      CHARACTER*4 IFLAGE
      CHARACTER*4 IFLAGW
      CHARACTER*4 IFLAGP
