!CCCC DIMENSION ARG(*)
      DIMENSION NCOM5(*)
      DIMENSION IWIDLL(*)
!
!-----COMMON----------------------------------------------------------
!
!CCCC CHARACTER*80 IFILSV
      CHARACTER (LEN=MAXFNC) :: IFILSV
      COMMON/FILSAV/IFILSV
!
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOF2.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOFB.INC'
      INCLUDE 'DPCOSB.INC'
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
!
      DIMENSION IANSLO(MAXLIL,MAXCIL)
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLI'
      ISUBN2='ST  '
      IFOUND='YES'
      IERROR='NO'
      IFILQ2=IFILQU
      IFILQU='ON'
      IFLAGN='OFF'
      IFLAGE='OFF'
      IFLAGW='OFF'
      IFLAGP='OFF'
      IFORMT=' '
!
      MINN2=1
      NCSTRI=(-999)
      IFLAGH=0
      IFLAGT=0
      ILINE=0
      MAXLEN=MAXSTR
!
!CCCC THE FOLLOWING LINE WAS ADDED NOVEMBER 1989
      INUMSW='OFF'
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')THEN
         WRITE(ICOUT,999)
  999    FORMAT(1X)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,51)
   51    FORMAT('***** AT THE BEGINNING OF DPLIST--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,53)ICOM,ILOOST,IBUGS2,ISUBRO,IERROR
   53    FORMAT('ICOM,ILOOST,IBUGS2,ISUBRO,IERROR = ',4(A4,2X),A4)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,54)IWIDTH,ILISNU,ICONNU,IDIRNU
   54    FORMAT('IWIDTH,ILISNU,ICONNU,IDIRNU = ',4I8)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,57)ILOOLI,IWIDLL(1),NUMLOS
   57    FORMAT('ILOOLI,IWIDLL(1),NUMLOS = ',3I8)
         CALL DPWRST('XXX','BUG ')
         IF(IWIDTH.GE.1)THEN
           WRITE(ICOUT,55)(IANSLC(I),I=1,MIN(80,IWIDTH))
   55      FORMAT('(IANSLC(I),I=1,IWIDTH) = ',80A1)
           CALL DPWRST('XXX','BUG ')
         ENDIF
         WRITE(ICOUT,62)ILISNA(1:80)
   62    FORMAT('ILISNA = ',A80)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,63)ILISST,ILISFO,ILISAC,ILISFO,ILISCS
   63    FORMAT('ILISST,ILISFO,ILISAC,ILISFO,ILISCS = ',   &
                4(A12,2X),A12)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,72)ICONNA(1:80)
   72    FORMAT('ICONNA = ',A80)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,73)ICONST,ICONFO,ICONAC,ICONFO,ICONCS
   73    FORMAT('ICONST,ICONFO,ICONAC,ICONFO,ICONCS = ',   &
                4(A12,2X),A12)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,82)IDIRNA(1:80)
   82    FORMAT('IDIRNA = ',A80)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,83)IDIRST,IDIRFO,IDIRAC,IDIRFO,IDIRCS
   83    FORMAT('IDIRST,IDIRFO,IDIRAC,IDIRFO,IDIRCS = ',   &
                4(A12,2X),A12)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,91)IHELMX,NCPREH,NCPOSH
   91    FORMAT('IHELMX,NCPREH,NCPOSH = ',3I8)
         CALL DPWRST('XXX','BUG ')
!
         IF(NCPREH.GE.1)THEN
            DO 93 I=1,NCPREH
               WRITE(ICOUT,94)I,ICPREH(I:I)
   94          FORMAT('I,ICPREH(I:I) = ',I8,2X,A1,4X)
               CALL DPWRST('XXX','BUG ')
   93       CONTINUE
         ENDIF
!
         IF(NCPOSH.GE.1)THEN
            DO 97 I=1,NCPOSH
               WRITE(ICOUT,98)I,ICPOSH(I:I)
   98          FORMAT('I,ICPOSH(I:I) = ',I8,2X,A1,4X)
               CALL DPWRST('XXX','BUG ')
   97       CONTINUE
         ENDIF
!
         WRITE(ICOUT,88)NCLSVW,ILSTVW(1:80)
   88    FORMAT('NCLSVW,ILSTVW = ',I8,2X,A80)
         CALL DPWRST('XXX','BUG ')
!
      ENDIF
!
!CCCC THE FOLLOWING LINE WAS ADDED NOVEMBER 1989
      IF(ICOM.EQ.'NLIS')INUMSW='ON'
!
      IF(IHARG(1).EQ.'NEW ' .AND. IHARG(2).EQ.'WIND')THEN
        IFLAGN='ON'
        ISHIFT=2
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGS2,IERROR)
      ELSEIF(IHARG(1).EQ.'EXCE')THEN
        IFLAGE='ON'
        ISHIFT=1
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGS2,IERROR)
      ELSEIF(IHARG(1).EQ.'WORD')THEN
        IFLAGW='ON'
        ISHIFT=1
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGS2,IERROR)
      ELSEIF(IHARG(1).EQ.'POWE' .AND. IHARG(2).EQ.'POIN')THEN
        IFLAGP='ON'
        ISHIFT=2
        CALL SHIFTL(ISHIFT,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                    IBUGS2,IERROR)
      ELSEIF(ILSTNW.EQ.'ON')THEN
        IFLAGN='ON'
        ISHIFT=0
      ENDIF
!
!               **************************
!               **  STEP 11--           **
!               **  COPY OVER VARIABLES **
!               **************************
!
      ISTEPN='11'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IOUNIT=ILISNU
      IFILE=ILISNA
      ISTAT=ILISST
      IFORM=ILISFO
      IACCES=ILISAC
      IPROT=ILISPR
      ICURST=ILISCS
!
      ISUBN0='LIST'
      IERRFI='NO'
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')THEN
        WRITE(ICOUT,1193)ISUBN0,IERRFI,IOUNIT
 1193   FORMAT('ISUBN0,IERRFI,IOUNIT = ',2(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1194)IFILE(1:80)
 1194   FORMAT('IFILE = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,1195)ISTAT,IFORM,IACCES,IPROT,ICURST
 1195   FORMAT('ISTAT,IFORM,IACCES,IPROT,ICURST = ',4(A12,2X),A12)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***********************************************
!               **  STEP 12--                                **
!               **  CHECK TO SEE IF THE LIST FILE MAY EXIST  **
!               ***********************************************
!
      ISTEPN='12'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ISTAT.EQ.'NONE' .AND. IFLAGN.EQ.'OFF' .AND.   &
         IFLAGE.EQ.'OFF' .AND. IFLAGW.EQ.'OFF' .AND.   &
         IFLAGP.EQ.'OFF')THEN
         IERROR='YES'
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1211)
 1211    FORMAT('***** IMPLEMENTATION ERROR IN DPLIST--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1212)
 1212    FORMAT('      THE DESIRED LISTING CANNOT BE CARRIED OUT')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1214)
 1214    FORMAT('      BECAUSE THE INTERNAL VARIABLE    ILISST ')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1215)
 1215    FORMAT('      WHICH ALLOWS SUCH LISTING HAS BEEN SET TO ',   &
                '  NONE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1217)ISTAT,ILISST
 1217    FORMAT('ISTAT,ILISST = ',A12,2X,A12)
         CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!               ********************************
!               **  STEP 13--                 **
!               **  EXTRACT THE FILE NAME.    **
!               **  DO THE GENERAL CASE OF    **
!               **  LISTING GENERAL FILES.    **
!               **  DO ALSO THE SPECIAL CASES **
!               **  OF LISTING THE            **
!               **  CONCLUSIONS FILE,         **
!               **  AND LISTING THE           **
!               **  DIRECTORY  FILE.          **
!               ********************************
!
      ISTEPN='13'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1310 I=1,MAXLEN
         IANSI=IANSLC(I)
         ICANS(I:I)=IANSI(1:1)
 1310 CONTINUE
!
!     2014/11: CHECK FOR "LIST CLIPBOARD" CASE
!     2015/09: CHECK FOR "LIST FUNCTION BLOCK" CASE
!     2016/08: CHECK FOR "LIST STATISTIC BLOCK" CASE
!     2016/10: CHECK FOR "LIST COMMAND LINE ARGUMENTS" CASE
!     2017/07: CHECK FOR "LIST LOOP LINES" CASE
!     2019/10: CHECK FOR "HEAD" OR "TAIL" OPTION
!     2021/04: CHECK FOR "ALIAS" OPTION
!
      IF(IHARG(1).EQ.'COMM' .AND. IHARG(2).EQ.'LINE' .AND.   &
         IHARG(3).EQ.'ARGU')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(NMACAG.GE.1)THEN
          WRITE(ICOUT,317)
  317     FORMAT('CONTENTS OF ORDERED COMMAND LINE ARGUMENTS')
          CALL DPWRST('XXX','BUG ')
          DO 320 II=1,NMACAG
            WRITE(ICOUT,323)II,IMACAR(II)(1:80)
  323       FORMAT('ARGUMENT ',I2,': ',A80)
            CALL DPWRST('XXX','BUG ')
  320     CONTINUE
          IF(NMACLA.GE.1)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,337)
  337       FORMAT('CONTENTS OF NAMED COMMAND LINE ARGUMENTS')
            CALL DPWRST('XXX','BUG ')
            DO 340 II=1,NMACLA
              WRITE(ICOUT,343)IMACLA(II),IMACAR(IMACLL(II))(1:100)
  343         FORMAT('ARGUMENT ',A8,': ',A100)
              CALL DPWRST('XXX','BUG ')
  340       CONTINUE
          ENDIF
        ELSE
          WRITE(ICOUT,307)
  307     FORMAT('NO COMMAND LINE ARGUMENTS ARE CURRENTLY DEFINED.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(NUMARG.EQ.1 .AND.   &
             IHARG(1).EQ.'ALIA' .AND. IHARG2(1).EQ.'S   ')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(NUMALI.GE.1)THEN
          WRITE(ICOUT,351)
  351     FORMAT('CONTENTS OF USER DEFINED ALIASES:')
          CALL DPWRST('XXX','BUG ')
          DO 360 II=1,NUMALI
            IFORMT='(A8,": ",A    )'
            NCSTR=80
            DO 371 JJ=MAXSTR,1,-1
              IF(IALIAS(II)(JJ:JJ).NE.' ')THEN
                NCSTR=JJ
                GO TO 379
              ENDIF
  371       CONTINUE
  379       CONTINUE
            WRITE(IFORMT(11:14),'(I4)')NCSTR
            WRITE(ICOUT,IFORMT)IALNAM(II),IALIAS(II)(1:NCSTR)
!C363       FORMAT(A8,': ',A80)
            CALL DPWRST('XXX','BUG ')
  360     CONTINUE
        ELSE
          WRITE(ICOUT,377)
  377     FORMAT('NO ALIASES ARE CURRENTLY DEFINED.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ELSEIF(IHARG(1).EQ.'CLIP' .AND. IHARG2(1).EQ.'BOAR')THEN
!
!       CHECK IF ARGUMENT IS A FILE NAME STARTING WITH "CLIPBOARD".
!
        IWORD=2
        IOFILE='NO'
        CALL DPFILE(IANSLC,IWIDTH,IWORD,   &
                    IOFILE,IBUGS2,ISUBRO,IERROR)
        IF(IOFILE.EQ.'NO')THEN
          IF(IOPSY1.EQ.'UNIX' .OR. IOPSY1.EQ.'LINU')THEN
#ifdef HAVE_XCLIP
            ISTRIN=' '
            IF(IX11SE.EQ.'CLIP')THEN
              ISTRIN='xclip -o -selection clipboard'
              NCSTR=29
            ELSEIF(IX11SE.EQ.'PRIM')THEN
              ISTRIN='xclip -o -selection primary'
              NCSTR=27
            ELSE
              ISTRIN='xclip -o -selection secondary'
              NCSTR=29
            ENDIF
!
            ISSAV1=ISYSPE
            ISSAV2=ISYSHI
            ISSAV3=ICLEWT
            ISSAV4=ILINSY
            ISYSPE='ON'
            ICLEWT='OFF'
            ILINSY='COMM'
            CALL DPSYS2(ISTRIN,NCSTR,ISUBRO,IERROR)
            ISYSPE=ISSAV1
            ISYSHI=ISSAV2
            ICLEWT=ISSAV3
            ILINSY=ISSAV4
            GO TO 9000
#elif defined(CYGWIN)
!
!           FOR CYGWIN, CLIPBOARD CONTENTS ARE IN "/dev/clipboard"
!
            ISTRIN=' '
            ISTRIN='cat /dev/clipboard'
            NCSTR=18
!
            ISSAV1=ISYSPE
            ISSAV2=ISYSHI
            ISSAV3=ICLEWT
            ISSAV4=ILINSY
            ISYSPE='ON'
            ICLEWT='OFF'
            ILINSY='COMM'
            CALL DPSYS2(ISTRIN,NCSTR,ISUBRO,IERROR)
            ISYSPE=ISSAV1
            ISYSHI=ISSAV2
            ICLEWT=ISSAV3
            ILINSY=ISSAV4
            GO TO 9000
#elif defined(MACOSX)
!
!           FOR MACOS, USE PBPASTE
!
            ISTRIN=' '
            ISTRIN='pbpaste'
            NCSTR=7
!
            ISSAV1=ISYSPE
            ISSAV2=ISYSHI
            ISSAV3=ICLEWT
            ISSAV4=ILINSY
            ISYSPE='ON'
            ICLEWT='OFF'
            ILINSY='COMM'
            CALL DPSYS2(ISTRIN,NCSTR,ISUBRO,IERROR)
            ISYSPE=ISSAV1
            ISYSHI=ISSAV2
            ICLEWT=ISSAV3
            ILINSY=ISSAV4
            GO TO 9000
#else
            IERROR='YES'
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1371)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,411)
  411       FORMAT('      THE xclip COMMAND IS NOT AVAILABLE.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,413)
  413       FORMAT('      THE CONTENTS OF THE CLIPBOARD WILL NOT BE ',   &
                   'LISTED.')
            CALL DPWRST('XXX','BUG ')
#endif
          ELSE
            IOUNIT=-99
            ITYPE='VIEW'
            CALL DPCLI2(ITYPE,IOUNIT,IHELMX,ILINRD,IBUGS2,ISUBRO,IERROR)
            GO TO 9000
          ENDIF
        ENDIF
      ELSEIF(IHARG(1).EQ.'FUNC' .AND. IHARG(2).EQ.'BLOC')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(IHARG(3).EQ.'ONE' .OR. IHARG(3).EQ.'1')THEN
          WRITE(ICOUT,1317)
 1317     FORMAT('CONTENTS OF FUNCTION BLOCK ONE:')
          CALL DPWRST('XXX','BUG ')
          IF(IFBCN1.GE.1)THEN
            DO 1311 II=1,IFBCN1
              WRITE(ICOUT,1312)IFBLI1(II)(1:100)
 1312         FORMAT(A100)
              CALL DPWRST('XXX','BUG ')
 1311       CONTINUE
          ELSE
            WRITE(ICOUT,1316)
 1316       FORMAT('FUNCTION BLOCK IS EMPTY')
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          WRITE(ICOUT,11310)IFBNA1
11310     FORMAT('NAME FOR FUNCTION BLOCK ONE: ',A8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,11311)
11311     FORMAT('PARAMETER LIST FOR FUNCTION BLOCK ONE:')
          CALL DPWRST('XXX','BUG ')
          DO 11316 JJ=1,IFBCP1
            IF(IFBPL1(JJ).NE.' ')THEN
              WRITE(ICOUT,11318)JJ,IFBPL1(JJ)
11318         FORMAT('PARAMETER ',I2,': ',A8)
              CALL DPWRST('XXX','BUG ')
            ENDIF
11316     CONTINUE
!
          WRITE(ICOUT,11321)IFBAN1
11321     FORMAT('RESPONSE PARAMETER/VARIABLE: ',A8)
          CALL DPWRST('XXX','BUG ')
!
        ELSEIF(IHARG(3).EQ.'TWO' .OR. IHARG(3).EQ.'2')THEN
          WRITE(ICOUT,1318)
 1318     FORMAT('CONTENTS OF FUNCTION BLOCK TWO:')
          CALL DPWRST('XXX','BUG ')
          IF(IFBCN2.GE.1)THEN
            DO 1313 II=1,IFBCN2
              WRITE(ICOUT,1312)IFBLI2(II)(1:100)
              CALL DPWRST('XXX','BUG ')
 1313       CONTINUE
          ENDIF
!
          WRITE(ICOUT,11330)IFBNA2
11330     FORMAT('NAME FOR FUNCTION BLOCK TWO: ',A8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,11331)
11331     FORMAT('PARAMETER LIST FOR FUNCTION BLOCK TWO:')
          CALL DPWRST('XXX','BUG ')
          DO 11336 JJ=1,IFBCP2
            IF(IFBPL2(JJ).NE.' ')THEN
              WRITE(ICOUT,11318)JJ,IFBPL2(JJ)
              CALL DPWRST('XXX','BUG ')
            ENDIF
11336     CONTINUE
!
          WRITE(ICOUT,11321)IFBAN2
          CALL DPWRST('XXX','BUG ')
!
        ELSEIF(IHARG(3).EQ.'THRE' .OR. IHARG(3).EQ.'3')THEN
          WRITE(ICOUT,1319)
 1319     FORMAT('CONTENTS OF FUNCTION BLOCK THREE:')
          CALL DPWRST('XXX','BUG ')
          IF(IFBCN3.GE.1)THEN
            DO 1315 II=1,IFBCN3
              WRITE(ICOUT,1312)IFBLI3(II)(1:100)
              CALL DPWRST('XXX','BUG ')
 1315       CONTINUE
          ENDIF
!
          WRITE(ICOUT,11340)IFBNA3
11340     FORMAT('NAME FOR FUNCTION BLOCK THREE: ',A8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,11341)
11341     FORMAT('PARAMETER LIST FOR FUNCTION BLOCK THREE:')
          CALL DPWRST('XXX','BUG ')
          DO 11346 JJ=1,IFBCP3
            IF(IFBPL3(JJ).NE.' ')THEN
              WRITE(ICOUT,11318)JJ,IFBPL3(JJ)
              CALL DPWRST('XXX','BUG ')
            ENDIF
11346     CONTINUE
!
          WRITE(ICOUT,11321)IFBAN2
          CALL DPWRST('XXX','BUG ')
!
        ENDIF
        GO TO 9000
      ELSEIF(IHARG(1).EQ.'STAT' .AND. IHARG(2).EQ.'BLOC')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(IHARG(3).EQ.'ONE' .OR. IHARG(3).EQ.'1')THEN
          WRITE(ICOUT,1417)
 1417     FORMAT('CONTENTS OF STATISTIC BLOCK ONE:')
          CALL DPWRST('XXX','BUG ')
          IF(ISBCN1.GE.1)THEN
            DO 1411 II=1,ISBCN1
              WRITE(ICOUT,1412)ISBLI1(II)(1:100)
 1412         FORMAT(A100)
              CALL DPWRST('XXX','BUG ')
 1411       CONTINUE
          ELSE
            WRITE(ICOUT,1416)
 1416       FORMAT('STATISTIC BLOCK IS EMPTY')
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          WRITE(ICOUT,11410)ISBNA1
11410     FORMAT('NAME FOR STATISTIC BLOCK ONE: ',A8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,11411)
11411     FORMAT('VARIABLE LIST FOR STATISTIC BLOCK ONE:')
          CALL DPWRST('XXX','BUG ')
          DO 11416 JJ=1,ISBCP1
            IF(ISBPL1(JJ).NE.' ')THEN
              WRITE(ICOUT,11418)JJ,ISBPL1(JJ)
11418         FORMAT('PARAMETER ',I2,': ',A8)
              CALL DPWRST('XXX','BUG ')
            ENDIF
11416     CONTINUE
!
          WRITE(ICOUT,11421)ISBAN1
11421     FORMAT('RESULT PARAMETER: ',A8)
          CALL DPWRST('XXX','BUG ')
!
        ELSEIF(IHARG(3).EQ.'TWO' .OR. IHARG(3).EQ.'2')THEN
          WRITE(ICOUT,1418)
 1418     FORMAT('CONTENTS OF STATISTIC BLOCK TWO:')
          CALL DPWRST('XXX','BUG ')
          IF(ISBCN2.GE.1)THEN
            DO 1413 II=1,ISBCN2
              WRITE(ICOUT,1412)ISBLI2(II)(1:100)
              CALL DPWRST('XXX','BUG ')
 1413       CONTINUE
          ENDIF
!
          WRITE(ICOUT,11430)ISBNA2
11430     FORMAT('NAME FOR STATISTIC BLOCK TWO: ',A8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,11431)
11431     FORMAT('PARAMETER LIST FOR STATISTIC BLOCK TWO:')
          CALL DPWRST('XXX','BUG ')
          DO 11436 JJ=1,ISBCP2
            IF(ISBPL2(JJ).NE.' ')THEN
              WRITE(ICOUT,11418)JJ,ISBPL2(JJ)
              CALL DPWRST('XXX','BUG ')
            ENDIF
11436     CONTINUE
!
          WRITE(ICOUT,11321)ISBAN2
          CALL DPWRST('XXX','BUG ')
!
        ELSEIF(IHARG(3).EQ.'THRE' .OR. IHARG(3).EQ.'3')THEN
          WRITE(ICOUT,1419)
 1419     FORMAT('CONTENTS OF STATISTIC BLOCK THREE:')
          CALL DPWRST('XXX','BUG ')
          IF(ISBCN3.GE.1)THEN
            DO 1415 II=1,ISBCN3
              WRITE(ICOUT,1412)ISBLI3(II)(1:100)
              CALL DPWRST('XXX','BUG ')
 1415       CONTINUE
          ENDIF
!
          WRITE(ICOUT,11440)ISBNA3
11440     FORMAT('NAME FOR STATISTIC BLOCK THREE: ',A8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,11441)
11441     FORMAT('PARAMETER LIST FOR STATISTIC BLOCK THREE:')
          CALL DPWRST('XXX','BUG ')
          DO 11446 JJ=1,ISBCP3
            IF(ISBPL3(JJ).NE.' ')THEN
              WRITE(ICOUT,11418)JJ,ISBPL3(JJ)
              CALL DPWRST('XXX','BUG ')
            ENDIF
11446     CONTINUE
!
          WRITE(ICOUT,11321)ISBAN2
          CALL DPWRST('XXX','BUG ')
!
        ENDIF
        GO TO 9000
      ELSEIF(IHARG(1).EQ.'LOOP' .AND. IHARG(2).EQ.'LINE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        IF(NUMLIL.GE.1)THEN
          DO 11501 II=1,NUMLIL
            DO 11502 JJ=1,MAXCIL
              ICANS(JJ:JJ)=IANSLO(II,JJ)(1:1)
11502       CONTINUE
            ILAST=1
            DO 11508 JJ=MAXCIL,1,-1
              IF(ICANS(JJ:JJ).NE.' ')THEN
                ILAST=JJ
                GO TO 11509
              ENDIF
11508       CONTINUE
11509       CONTINUE
            WRITE(ICOUT,11503)II,ICANS(1:MAX(ILAST,220))
11503       FORMAT('Line ',I5,': ',A220)
            CALL DPWRST('XXX','BUG ')
11501     CONTINUE
        ELSE
          WRITE(ICOUT,11506)
11506     FORMAT('THERE ARE CURRENTLY NO SAVED LOOP LINES.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 9000
      ELSEIF(IHARG(1).EQ.'HEAD' .AND. IHARG2(1).EQ.'    ')THEN
        IFLAGH=1
      ELSEIF(IHARG(1).EQ.'TAIL' .AND. IHARG2(1).EQ.'    ')THEN
        IFLAGT=1
      ENDIF
!
      ISTART=1
      ISTOP=IWIDTH
      IWORD=2
      IF(IFLAGH.EQ.1)IWORD=IWORD+1
      IF(IFLAGT.EQ.1)IWORD=IWORD+1
      IF(IFLAGN.EQ.'ON' .AND. ISHIFT.EQ.2)IWORD=IWORD+2
      IF(IFLAGE.EQ.'ON' .AND. ISHIFT.GT.0)IWORD=IWORD+ISHIFT
      IF(IFLAGW.EQ.'ON' .AND. ISHIFT.GT.0)IWORD=IWORD+ISHIFT
      IF(IFLAGP.EQ.'ON' .AND. ISHIFT.GT.0)IWORD=IWORD+ISHIFT
      CALL DPEXWO(ICANS,ISTART,ISTOP,IWORD,   &
                  ICOL1,ICOL2,IFILE,NCFILE,   &
                  IBUGS2,ISUBRO,IERROR)
!
      IF(NCFILE.EQ.11.AND.IFILE.EQ.'CONCLUSIONS')GO TO 1320
      IF(NCFILE.EQ.10.AND.IFILE.EQ.'CONCLUSION')GO TO 1320
      IF(NCFILE.EQ.11.AND.IFILE.EQ.'conclusions')GO TO 1320
      IF(NCFILE.EQ.10.AND.IFILE.EQ.'conclusion')GO TO 1320
!
      IF(NCFILE.EQ.9.AND.IFILE.EQ.'DIRECTORY')GO TO 1330
      IF(NCFILE.EQ.9.AND.IFILE.EQ.'directory')GO TO 1330
!
      IF(NCFILE.EQ.6.AND.IFILE.EQ.'MASTER')GO TO 1330
      IF(NCFILE.EQ.6.AND.IFILE.EQ.'master')GO TO 1330
!
      IF(NCFILE.EQ.10.AND.IFILE.EQ.'DICTIONARY')GO TO 1340
      IF(NCFILE.EQ.10.AND.IFILE.EQ.'dictionary')GO TO 1340
!
      IF(NCFILE.EQ.11.AND.IFILE.EQ.'DEFINITIONS')GO TO 1350
      IF(NCFILE.EQ.10.AND.IFILE.EQ.'DEFINITION')GO TO 1350
      IF(NCFILE.EQ.4.AND.IFILE.EQ.'DEFI')GO TO 1350
      IF(NCFILE.EQ.3.AND.IFILE.EQ.'DEF')GO TO 1350
      IF(NCFILE.EQ.11.AND.IFILE.EQ.'definitions')GO TO 1350
      IF(NCFILE.EQ.10.AND.IFILE.EQ.'definition')GO TO 1350
      IF(NCFILE.EQ.4.AND.IFILE.EQ.'defi')GO TO 1350
      IF(NCFILE.EQ.3.AND.IFILE.EQ.'def')GO TO 1350
!
!CCCC THE FOLLOWING 8 SECTIONS WERE ADDED        NOVEMBER 1993
!CCCC THE FOLLOWING 8 SECTIONS WERE MODIFIED     JUNE 1993
      IF(IFILE(1:8).EQ.'DATASETS'.OR.IFILE(1:8).EQ.'datasets')THEN
         ISTART=1
         ISTOP=ISTART+8+1
         IFILE(ISTART:ISTOP)='datasets.'
         GO TO 1370
!
      ELSEIF(IFILE(1:7).EQ.'DESIGNS.'.OR.IFILE(1:7).EQ.'designs.')THEN
         ISTART=1
         ISTOP=ISTART+7+1
         IFILE(ISTART:ISTOP)='designs.'
         GO TO 1370
!
      ELSEIF(IFILE(1:8).EQ.'DISTRIBU'.OR.IFILE(1:8).EQ.'distribu')THEN
         ISTART=1
         ISTOP=ISTART+8+1
         IFILE(1:20)='                    '
         IFILE(ISTART:ISTOP)='distribu.'
         GO TO 1370
!
      ELSEIF(IFILE(1:8).EQ.'COMMANDS'.OR.IFILE(1:8).EQ.'commands')THEN
         ISTART=1
         ISTOP=ISTART+8+1
         IFILE(ISTART:ISTOP)='commands.'
         GO TO 1370
!
      ELSEIF(IFILE(1:6).EQ.'SYNTAX'.OR.IFILE(1:6).EQ.'syntax')THEN
         ISTART=1
         ISTOP=ISTART+6+1
         IFILE(ISTART:ISTOP)='syntax.'
         GO TO 1370
!
      ELSEIF(IFILE(1:8).EQ.'FUNCTION'.OR.IFILE(1:8).EQ.'function')THEN
         ISTART=1
         ISTOP=ISTART+8+1
         IFILE(ISTART:ISTOP)='function.'
         GO TO 1370
!
      ELSEIF(IFILE(1:8).EQ.'PROGRAMS'.OR.IFILE(1:8).EQ.'programs')THEN
         ISTART=1
         ISTOP=ISTART+8+1
         IFILE(ISTART:ISTOP)='programs.'
         GO TO 1370
!
      ELSEIF(IFILE(1:6).EQ.'MACROS'.OR.IFILE(1:6).EQ.'macros')THEN
         ISTART=1
         ISTOP=ISTART+6+1
         IFILE(ISTART:ISTOP)='macros.'
         GO TO 1370
      ENDIF
!
      GO TO 1370
!
 1320 CONTINUE
      IFILE=ICONNA
      GO TO 1370
!
 1330 CONTINUE
      IFILE=IDIRNA
      GO TO 1370
!
 1340 CONTINUE
      IFILE=IDICNA
      GO TO 1370
!
 1350 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1351)
 1351 FORMAT('DEFINITIONS--')
      CALL DPWRST('XXX','BUG ')
!
      IF(NUMCOM.GE.1)THEN
         DO 1352 I=1,NUMCOM
            ICJUNK=ICOM5(I)
            NCJUNK=NCOM5(I)
            IF(NCJUNK.LE.0)THEN
               WRITE(ICOUT,1353)I,ICOM3(I),ICOM4(I)
 1353          FORMAT(I8,'.  ',A4,A4,'--')
               CALL DPWRST('XXX','BUG ')
            ELSE
               WRITE(ICOUT,1354)I,ICOM3(I),ICOM4(I),   &
               (ICJUNK(J:J),J=1,NCJUNK)
 1354          FORMAT(I8,'.  ',A4,A4,'--',40(A1,1X))
               CALL DPWRST('XXX','BUG ')
            ENDIF
 1352    CONTINUE
      ENDIF
      GO TO 9000
!
!CCCC THE FOLLOWING SECTION WAS ADDED           NOVEMBER 1993
!CCCC THE FOLLOWING SECTION WAS COMMENTED OUT   JUNE 1995
!1360 CONTINUE
!CCCC IFILE=PATH
!CCCC ISTART=NCPATH+1
!CCCC ISTOP=ISTART+8+1
!CCCC IFILE(ISTART:ISTOP)='distribu.'
!CCCC GO TO 1370
!
 1370 CONTINUE
      IF(NCFILE.LE.0)THEN
         IERROR='YES'
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1371)
 1371    FORMAT('***** ERROR IN DPLIST--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1372)
 1372    FORMAT('      A USER FILE NAME IS REQUIRED')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1373)
 1373    FORMAT('      IN THE LIST COMMAND')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1374)
 1374    FORMAT('      (FOR EXAMPLE,    LIST PROG7.DP)')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1375)
 1375    FORMAT('      BUT NONE WAS GIVEN HERE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,1376)
 1376    FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
         CALL DPWRST('XXX','BUG ')
         IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,1377)(IANSLC(I),I=1,MIN(80,IWIDTH))
 1377       FORMAT('      ',80A1)
            CALL DPWRST('XXX','BUG ')
         ELSE
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
         ENDIF
         GO TO 9000
      ENDIF
!
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               *****************************************
!               **  STEP 21--                          **
!               **  CHECK TO SEE THE TYPE CASE--       **
!               **    1) UNQUALIFIED (THAT IS, FULL);  **
!               **    2) SUBSET/EXCEPT; OR             **
!               **    3) FOR.                          **
!               *****************************************
!
      ISTEPN='21'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICASEQ='FULL'
      ILOCQ=NUMARG+1
      IF(NUMARG.LT.1)GO TO 2190
      IF(IFLAGN.EQ.'ON')GO TO 2190
      IF(IFLAGE.EQ.'ON')GO TO 2190
      IF(IFLAGW.EQ.'ON')GO TO 2190
      IF(IFLAGP.EQ.'ON')GO TO 2190
      DO 2100 J=1,NUMARG
         J1=J
         IF(IHARG(J).EQ.'SUBS'.AND.IHARG2(J).EQ.'ET  ')THEN
            ICASEQ='SUBS'
            ILOCQ=J1
            GO TO 2190
         ELSEIF(IHARG(J).EQ.'EXCE'.AND.IHARG2(J).EQ.'PT  ')THEN
            ICASEQ='SUBS'
            ILOCQ=J1
            GO TO 2190
         ELSEIF(IHARG(J).EQ.'FOR '.AND.IHARG2(J).EQ.'    ')THEN
            ICASEQ='FOR'
            ILOCQ=J1
            GO TO 2190
         ENDIF
 2100 CONTINUE
 2190 CONTINUE
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')THEN
         WRITE(ICOUT,2191)NUMARG,ILOCQ
 2191    FORMAT('NUMARG,ILOCQ = ',2I8)
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *********************************************
!               **  STEP 22--                              **
!               **  BRANCH    TO THE APPROPRIATE SUBCASE   **
!               **  (FULL, SUBSET, OR FOR).                **
!               *********************************************
!
      ISTEPN='22'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IFLAGH.EQ.1)THEN
        DO 2211 I=1,MAXN
          ISUB(I)=0
 2211   CONTINUE
        DO 2212 I=1,IHEALI
          ISUB(I)=1
 2212   CONTINUE
        NQ=IHEALI
      ELSEIF(IFLAGT.EQ.1)THEN
        DO 2214 I=1,MAXN
          ISUB(I)=0
 2214   CONTINUE
         NQ=MAXN
      ELSEIF(ICASEQ.EQ.'FULL')THEN
         DO 2215 I=1,MAXN
            ISUB(I)=1
 2215    CONTINUE
         NQ=MAXN
      ELSEIF(ICASEQ.EQ.'SUBS')THEN
         NIOLD=MAXN
         CALL DPSUBS(NIOLD,ILOCS,NS,IBUGQ,IERROR)
         NQ=NIOLD
      ELSEIF(ICASEQ.EQ.'FOR')THEN
         NIOLD=MAXN
         CALL DPFOR(NIOLD,NFOR,IROW1,IROWN,   &
         NLOCAL,ILOCS,NS,IBUGQ,IERROR)
         NQ=NFOR
         NMXFOR=IROWN
      ENDIF
!
      IF(NQ.LT.MINN2)THEN
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,2271)
 2271    FORMAT('***** ERROR IN DPLIST--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,2272)
 2272    FORMAT('      AFTER THE APPROPRIATE SUBSET HAS BEEN ',   &
         'EXTRACTED,')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,2273)
 2273    FORMAT('      THE NUMBER OF SPECIFIED FILE LINES')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,2276)MINN2
 2276    FORMAT('      TO BE LISTED MUST BE ',I8,' OR LARGER;')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,2277)
 2277    FORMAT('      SUCH WAS NOT THE CASE HERE.')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,2278)
 2278    FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
         CALL DPWRST('XXX','BUG ')
         IF(IWIDTH.GE.1)THEN
            WRITE(ICOUT,2279)(IANSLC(I),I=1,MIN(80,IWIDTH))
 2279       FORMAT('      ',80A1)
            CALL DPWRST('XXX','BUG ')
         ENDIF
         IERROR='YES'
         GO TO 9000
      ENDIF
!
      NS=NQ
!
!               **************************
!               **  STEP 31--           **
!               **  OPEN  THE FILE      **
!               **  (UNLESS ITS THE     **
!               **  CONCLUSIONS FILE).  **
!               **************************
!
      ISTEPN='31'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')THEN
         CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
         WRITE(ICOUT,3111)IFILE
 3111    FORMAT('IFILE = ',A80)
         CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFILE.EQ.ICONNA)GO TO 3190
!
      IF(IFLAGE.EQ.'ON')IFORM='NULL'
      IF(IFLAGW.EQ.'ON')IFORM='NULL'
      IF(IFLAGP.EQ.'ON')IFORM='NULL'
      IREWIN='ON'
      CALL DPOPFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,   &
      IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
      IF(IERRFI.EQ.'YES')GO TO 9000
!
!     2019/11: OPEN FILE IN NEW WINDOW USING A SPECIFIED EDITOR
!
      IF(IFLAGN.EQ.'ON')THEN
!
!       CLOSE FILE
!
        IENDFI='OFF'
        IREWIN='ON'
        CALL DPCLFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,   &
                    IENDFI,IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
!
        ISTR=' '
        IFLAGQ=0
        IF(NCLSVW.GE.1)THEN
          DO 3160 II=1,NCLSVW
            IF(ILSTVW(II:II).EQ.' ')THEN
              IFLAGQ=1
              GO TO 3169
            ENDIF
 3160     CONTINUE
 3169     CONTINUE
        ENDIF
        NCSTR=0
        IF(IOPSY1.EQ.'UNIX')THEN
!CCCC     NCSTR=10
!CCCC     ISTR(1:NCSTR)='xterm -e "'
          IF(NCLSLA.GE.1)THEN
            NCSTR=NCLSLA
            ISTR(1:NCLSLA)=ILSTLA(1:NCLSLA)
            IF(IOPSY2.NE.'MAC ')THEN
              ISTR(NCSTR+1:NCSTR+2)=' "'
              NCSTR=NCSTR+2
            ENDIF
          ELSE
            IF(IOPSY2.EQ.'MAC ')THEN
              NCSTR=8
              ISTR(1:NCSTR)='open -t '
            ELSE
              NCSTR=19
              ISTR(1:NCSTR)='gnome-terminal -e "'
            ENDIF
          ENDIF
        ELSEIF(IFLAGQ.EQ.1)THEN
          NCSTR=NCSTR+1
          ISTR(NCSTR:NCSTR)='"'
        ENDIF
!
!         USE "write.exe" IF WORDPAD IS THE VIEWER
!
        IF(IOPSY1.NE.'UNIX' .AND.   &
          (ILSTVW(1:7).EQ.'WORDPAD' .OR. ILSTVW(1:7).EQ.'wordpad'))THEN
          ISTR(NCSTR+1:NCSTR+9)='write.exe'
          NCSTR=NCSTR+9
        ELSE
          IF(NCLSVW.GE.1)THEN
            ISTR(NCSTR+1:NCSTR+NCLSVW)=ILSTVW(1:NCLSVW)
            NCSTR=NCSTR+NCLSVW
          ENDIF
        ENDIF
!
        IF(IFLAGQ.EQ.1 .AND. IOPSY1.NE.'UNIX')THEN
          NCSTR=NCSTR+1
          ISTR(NCSTR:NCSTR)='"'
        ENDIF
        NCSTR=NCSTR+1
        ISTR(NCSTR:NCSTR)=' '
!
        ILAST=1
        DO 3170 II=80,1,-1
          IF(IFILSV(II:II).NE.' ')THEN
            ILAST=II
            GO TO 3179
          ENDIF
 3170   CONTINUE
 3179   CONTINUE
!
!       NOTE: FOR WINDOWS, IF NOTEPAD IS THE LIST VIEWER THEN FILE
!             NAME NEEDS TO BE QUOTED FOR "HIDDEN" MODE EVEN IF FILE
!             NAME CONTAINS NO SPACES.
!
        IF(IOPSY1.NE.'UNIX')THEN
          IFLAGQ=0
          DO 3180 II=1,ILAST
            IF(IFILSV(II:II).EQ.' ')THEN
              IFLAGQ=1
              GO TO 3189
            ENDIF
 3180     CONTINUE
 3189     CONTINUE
!
          IF(ILSTVW(1:7).EQ.'notepad'.OR.ILSTVW(1:7).EQ.'NOTEPAD')THEN
            IFLAGQ=1
          ENDIF
!
          IF(IFLAGQ.EQ.1)THEN
            NCSTR=NCSTR+1
            ISTR(NCSTR:NCSTR)='"'
          ENDIF
        ENDIF
        IF(IOPSY1.EQ.'UNIX' .AND. IOPSY2.EQ.'MAC ')THEN
          NCSTR=NCSTR+1
          ISTR(NCSTR:NCSTR)='"'
        ENDIF
        ISTR(NCSTR+1:NCSTR+ILAST)=IFILSV(1:ILAST)
        NCSTR=NCSTR+ILAST
        IF(IOPSY1.EQ.'UNIX')THEN
          NCSTR=NCSTR+1
          ISTR(NCSTR:NCSTR)='"'
        ELSE
          IF(IFLAGQ.EQ.1)THEN
            NCSTR=NCSTR+1
            ISTR(NCSTR:NCSTR)='"'
          ENDIF
        ENDIF
        ISSAV1=ISYSPE
        ISSAV2=ISYSHI
        ISSAV3=ICLEWT
        ISSAV4=ILINSY
        IF(IOPSY1.EQ.'UNIX')THEN
          ISYSPE='ON'
          ICLEWT='OFF'
          ILINSY='COMM'
        ELSE
          ISYSPE='OFF'
          ISYSHI='ON'
          ICLEWT='OFF'
        ENDIF
        CALL DPSYS2(ISTR,NCSTR,ISUBRO,IERROR)
        ISYSPE=ISSAV1
        ISYSHI=ISSAV2
        ICLEWT=ISSAV3
        ILINSY=ISSAV4
!
        GO TO 9000
!
!       2019/11: OPEN EXCEL/WORD/POWER POINT FILE.
!
!                1. FOR WINDOWS, JUST DISPLAY FILE NAME AND
!                   OPERATING SYSTEM WILL INITIATE THE APPROPRIATE
!                   APPLICATION BASED ON THE FILE EXTENSION.
!
!                2. ON LINUX, USER CAN SPECIFY THE DESIRED APPLICATION.
!                   BY DEFAULT, USE "xdg-open" WHICH WILL AUTOMATICALLY
!                   PICK THE APPLICATION BASED ON THE FILE EXTENSION.
!
!                3. ON MacOS, "open" IS EQUIVALENT TO "xdg-open".
!
      ELSEIF(IFLAGE.EQ.'ON' .OR. IFLAGW.EQ.'ON' .OR.   &
             IFLAGP.EQ.'ON')THEN
!
!       CLOSE FILE
!
        IENDFI='OFF'
        IREWIN='ON'
        CALL DPCLFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,   &
                    IENDFI,IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
!
        ISTR=' '
        NCSTR=0
        IFLAGQ=0
        IF(IFLAGE.EQ.'ON' .AND. NCEXVW.GE.1)THEN
          DO 6160 II=1,NCEXVW
            IF(IEXCVW(II:II).EQ.' ' .AND. IEXCVW(II+1:II+1).NE.'-')THEN
              IFLAGQ=1
              GO TO 6169
            ENDIF
 6160     CONTINUE
 6169     CONTINUE
          IF(IFLAGQ.EQ.1)THEN
            NCSTR=NCSTR+1
            ISTR(NCSTR:NCSTR)='"'
          ENDIF
          ISTR(NCSTR+1:NCSTR+NCEXVW)=IEXCVW(1:NCEXVW)
          NCSTR=NCSTR+NCEXVW
          IF(IFLAGQ.EQ.1)THEN
            NCSTR=NCSTR+1
            ISTR(NCSTR:NCSTR)='"'
          ENDIF
        ELSEIF(IFLAGW.EQ.'ON' .AND. NCWOVW.GE.1)THEN
          DO 6170 II=1,NCWOVW
            IF(IWORVW(II:II).EQ.' ' .AND. IWORVW(II+1:II+1).NE.'-')THEN
              IFLAGQ=1
              GO TO 6179
            ENDIF
 6170     CONTINUE
 6179     CONTINUE
          IF(IFLAGQ.EQ.1)THEN
            NCSTR=NCSTR+1
            ISTR(NCSTR:NCSTR)='"'
          ENDIF
          ISTR(NCSTR+1:NCSTR+NCWOVW)=IWORVW(1:NCWOVW)
          NCSTR=NCSTR+NCWOVW
          IF(IFLAGQ.EQ.1)THEN
            NCSTR=NCSTR+1
            ISTR(NCSTR:NCSTR)='"'
          ENDIF
        ELSEIF(IFLAGP.EQ.'ON' .AND. NCPPVW.GE.1)THEN
          DO 6180 II=1,NCPPVW
            IF(IPPTVW(II:II).EQ.' ' .AND. IPPTVW(II+1:II+1).NE.'-')THEN
              IFLAGQ=1
              GO TO 6189
            ENDIF
 6180     CONTINUE
 6189     CONTINUE
          IF(IFLAGQ.EQ.1)THEN
            NCSTR=NCSTR+1
            ISTR(NCSTR:NCSTR)='"'
          ENDIF
          ISTR(NCSTR+1:NCSTR+NCPPVW)=IPPTVW(1:NCPPVW)
          NCSTR=NCSTR+NCPPVW
          IF(IFLAGQ.EQ.1)THEN
            NCSTR=NCSTR+1
            ISTR(NCSTR:NCSTR)='"'
          ENDIF
        ENDIF
!
        NCSTR=NCSTR+1
        ISTR(NCSTR:NCSTR+1)=' "'
        NCSTR=NCSTR+1
!
        ILAST=1
        DO 6190 II=80,1,-1
          IF(IFILSV(II:II).NE.' ')THEN
            ILAST=II
            GO TO 6199
          ENDIF
 6190   CONTINUE
 6199   CONTINUE
!
        ISTR(NCSTR+1:NCSTR+ILAST)=IFILSV(1:ILAST)
        NCSTR=NCSTR+ILAST+1
        ISTR(NCSTR:NCSTR)='"'
        ISSAV1=ISYSPE
        ISSAV2=ISYSHI
        ISSAV3=ICLEWT
        ISSAV4=ILINSY
        IF(IOPSY1.EQ.'UNIX')THEN
          ISYSPE='ON'
          ICLEWT='OFF'
          ILINSY='COMM'
        ELSE
          ISYSPE='OFF'
          ISYSHI='ON'
          ICLEWT='OFF'
        ENDIF
        CALL DPSYS2(ISTR,NCSTR,ISUBRO,IERROR)
        ISYSPE=ISSAV1
        ISYSHI=ISSAV2
        ICLEWT=ISSAV3
        ILINSY=ISSAV4
!
        GO TO 9000
      ENDIF
!
!     2019/10: IF "TAIL" OPTION SET, THEN DETERMINE NUMBER OF LINES
!              IN THE FILE.
!
 3190 CONTINUE
!
      IF(IFLAGT.EQ.1)THEN
        REWIND(IOUNIT)
        DO 3120 II=1,MAXN
          READ(IOUNIT,'(A1)',END=3129)ICJUNK
          ILINE=II
 3120   CONTINUE
        ILINE=MAXN
 3129   CONTINUE
        IFRST=ILINE-ITAILI+1
        IF(IFRST.LT.1)IFRST=1
        ILAST=ILINE
        DO 3130 II=IFRST,ILAST
          ISUB(II)=1
 3130   CONTINUE
        NQ=ILAST
        REWIND(IOUNIT)
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS UPDATED JULY 1989
!CCCC THE FOLLOWING SECTION WAS UPDATED NOVEMBER 1989
!CCCC THE FOLLOWING SECTION WAS UPDATED JULY 1990
!CCCC THE FOLLOWING SECTION WAS UPDATED SEPTEMBER 1993
!
!               **********************************
!               **  STEP 41--                   **
!               **  READ A GENERAL FILE.        **
!               **  PRINT IT OUT.               **
!               **********************************
!
      ISTEPN='41'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMLPR=0
      IRESP='YES'
      IMAX=1000000
      IF(ICASEQ.EQ.'SUBS')IMAX=MAXN
      IF(ICASEQ.EQ.'FOR')IMAX=IROWN
      IF(IFLAGH.EQ.1)IMAX=IHEALI
      IF(IFLAGT.EQ.1)IMAX=NQ
!
      DO 4110 I=1,IMAX
!
!        DPWRST SUPPORTS MAXIMUM OF 240 CHARACTERS, SO TRUNCATE
!        AT 240 CHARACTERS
!
         ISTRIN=' '
         NMAX=240
         READ(IOUNIT,4111,END=4190)(ISTRIN(J:J),J=1,NMAX)
 4111    FORMAT(240A1)
!
         IF(IFLAGH.EQ.1 .AND. ISUB(I).EQ.0)GO TO 4110
         IF(IFLAGT.EQ.1 .AND. ISUB(I).EQ.0)GO TO 4110
         IF(ICASEQ.EQ.'SUBS'.AND.ISUB(I).EQ.0)GO TO 4110
         IF(ICASEQ.EQ.'FOR'.AND.ISUB(I).EQ.0)GO TO 4110
!
         ILAST=1
         DO 4112 JJ=240,1,-1
           IF(ISTRIN(JJ:JJ).NE.' ')THEN
             ILAST=JJ
             GO TO 4113
           ENDIF
 4112    CONTINUE
 4113    CONTINUE
!
         CALL DPDB80(ISTRIN,JMAX,ILAST,IBUGS2,ISUBRO,IERROR)
         NCSTRI=JMAX
         IF(NCSTRI.EQ.3.AND.ISTRIN(1:3).EQ.'EOF')GO TO 4190
!
         IF(NUMLPR.GE.IHELMX)THEN
            CALL DPMORE(NUMLPR,NCPREH,ICPREH,IRESP,IBUGS2,IERROR)
            NUMLPR=0
         ENDIF
!
         IF(IRESP.EQ.'NO')GO TO 4150
!
         IF(NCSTRI.GE.1)THEN
            IF(INUMSW.EQ.'OFF')THEN
               WRITE(ICOUT,4117)(ISTRIN(J:J),J=1,NCSTRI)
 4117          FORMAT(240A1)
               CALL DPWRST('XXX','WRIT')
            ELSE
               WRITE(ICOUT,4118)I,(ISTRIN(J:J),J=1,NCSTRI)
 4118          FORMAT(I8,'--',240A1)
               CALL DPWRST('XXX','WRIT')
            ENDIF
!
         ELSEIF(NCSTRI.LE.0)THEN
            IF(INUMSW.EQ.'OFF')THEN
               WRITE(ICOUT,999)
               CALL DPWRST('XXX','WRIT')
            ELSE
               WRITE(ICOUT,4119)I
 4119          FORMAT(I8,'--')
               CALL DPWRST('XXX','WRIT')
            ENDIF
         ENDIF
!
         NUMLPR=NUMLPR+1
 4110 CONTINUE
!
 4150 CONTINUE
!
      IF(NCPOSH.LE.0)GO TO 4159
      WRITE(ICOUT,4151)(ICPOSH(J:J),J=1,NCPOSH)
 4151 FORMAT(80A1)
      CALL DPWRST('XXX','WRIT')
 4159 CONTINUE
!
 4190 CONTINUE
!
!               **************************
!               **  STEP 51--           **
!               **  CLOSE THE FILE      **
!               **  (UNLESS ITS THE     **
!               **  CONCLUSIONS FILE).  **
!               **************************
!
      ISTEPN='51'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IFILE.EQ.ICONNA)GO TO 5190
!
      IENDFI='OFF'
      IREWIN='ON'
      CALL DPCLFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,   &
      IENDFI,IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
!
 5190 CONTINUE
!
!               ****************
!               **  STEP 90-- **
!               **  EXIT.     **
!               ****************
!
 9000 CONTINUE
!
      IFILQU=IFILQ2
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'LIST')THEN
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9011)
 9011    FORMAT('***** AT THE END       OF DPLIST--')
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9012)IBUGS2,ISUBRO,IERROR,ICASEQ,IRESP
 9012    FORMAT('IBUGS2,ISUBRO,IERROR,ICASEQ,IRESP = ',4(A4,2X),A4)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9013)ICOM,INUMSW,IENDFI,IREWIN,IOUNIT
 9013    FORMAT('ICOM,INUMSW,IENDFI,IREWIN,IOUNIT = ',4(A4,2X),I8)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9022)IFILE
 9022    FORMAT('IFILE  = ',A80)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9023)ISTAT,IFORM,IACCES,IPROT,ICURST
 9023    FORMAT('ISTAT,IFORM,IACCES,IPROT,ICURST  = ',4(A12,2X),A12)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9031)ISUBN0,IERRFI
 9031    FORMAT('ISUBN0,IERRFI = ',A12,2X,A12)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9041)NQ,NS,JMAX,NCSTRI,IHELMX,NCPREH,NCPOSH
 9041    FORMAT('NQ,NS,JMAX,NCSTRI,IHELMX,NCPREH,NCPOSH = ',3I8,4I5)
         CALL DPWRST('XXX','BUG ')
!
         IF(NCPREH.GE.1)THEN
            DO 9052 I=1,NCPREH
               WRITE(ICOUT,9053)I,ICPREH(I:I)
 9053          FORMAT('I,ICPREH(I:I) = ',I8,2X,A1,4X)
               CALL DPWRST('XXX','BUG ')
 9052       CONTINUE
         ENDIF
!
         IF(NCPOSH.GE.1)THEN
            DO 9057 I=1,NCPOSH
               WRITE(ICOUT,9058)I,ICPOSH(I:I)
 9058          FORMAT('I,ICPOSH(I:I) = ',I8,2X,A1,4X)
               CALL DPWRST('XXX','BUG ')
 9057       CONTINUE
         ENDIF
!
      ENDIF
!
      RETURN
      END SUBROUTINE DPLIST
      SUBROUTINE DPLITH(IHARG,IARGT,ARG,NUMARG,PDEFLT,MAXLIN,PLINTH,   &
                        IBUGP2,IFOUND,IERROR)
!
!     PURPOSE--DEFINE THE LINE THICKNESSES.
!              THESE ARE LOCATED IN THE VECTOR PLINTH(.).
!     INPUT  ARGUMENTS--IHARG  (A  CHARACTER VECTOR)
!                     --IARGT  (A  CHARACTER VECTOR)
!                     --ARG
!                     --NUMARG
!                     --PDEFLT
!                     --MAXLIN
!                     --IBUGP2 ('ON' OR 'OFF' )
!     OUTPUT ARGUMENTS--PLINTH (A FLOATING POINT VECTOR)
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--DECEMBER  1983.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IARGT
!
      CHARACTER*4 IBUGP2
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IHOLD1
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      DIMENSION IHARG(*)
      DIMENSION IARGT(*)
      DIMENSION ARG(*)
      DIMENSION PLINTH(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPLI'
      ISUBN2='TH  '
      IFOUND='NO'
      IERROR='NO'
!
      NUMLIN=0
      IHOLD1='-999'
      HOLD1=-999.0
      HOLD2=-999.0
!
      IF(IBUGP2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLITH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGP2,IFOUND,IERROR,IHOLD1
   52   FORMAT('IBUGP2,IFOUND,IERROR,IHOLD1 = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)MAXLIN,NUMLIN
   53   FORMAT('MAXLIN,NUMLIN = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)HOLD1,HOLD2,PDEFLT,NUMARG
   54   FORMAT('HOLD1,HOLD2,PDEFLT,NUMARG = ',3G15.7,I10)
        CALL DPWRST('XXX','BUG ')
        DO 65 I=1,NUMARG
          WRITE(ICOUT,66)IHARG(I),IARGT(I),ARG(I)
   66     FORMAT('IHARG(I),IARGT(I),ARG(I) = ',2(A4,2X),G15.7)
          CALL DPWRST('XXX','BUG ')
   65   CONTINUE
        DO 75 I=1,10
          WRITE(ICOUT,76)I,PLINTH(I)
   76     FORMAT('I,PLINTH(I) = ',I8,2X,G15.7)
          CALL DPWRST('XXX','BUG ')
   75   CONTINUE
       ENDIF
!
!               **************************************
!               **  STEP 1--                        **
!               **  BRANCH TO THE APPROPRIATE CASE  **
!               **************************************
!
      ISTEPN='1'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.0)GO TO 9000
      IF(NUMARG.EQ.1)GO TO 1110
      IF(NUMARG.EQ.2)GO TO 1120
      IF(NUMARG.EQ.3)GO TO 1130
      GO TO 1140
!
 1110 CONTINUE
      GO TO 1200
!
 1120 CONTINUE
      IF(IHARG(2).EQ.'ALL')IHOLD1='    '
      IF(IHARG(2).EQ.'ALL')HOLD1=PDEFLT
      IF(IHARG(2).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1130 CONTINUE
      IF(IHARG(2).EQ.'ALL')IHOLD1=IHARG(3)
      IF(IHARG(2).EQ.'ALL')HOLD1=ARG(3)
      IF(IHARG(2).EQ.'ALL')GO TO 1300
      IF(IHARG(3).EQ.'ALL')IHOLD1=IHARG(2)
      IF(IHARG(3).EQ.'ALL')HOLD1=ARG(2)
      IF(IHARG(3).EQ.'ALL')GO TO 1300
      GO TO 1200
!
 1140 CONTINUE
      GO TO 1200
!
!               *************************************************
!               **  STEP 2--                                   **
!               **  TREAT THE INDIVIDUAL SPECIFICATIONS CASE  **
!               *************************************************
!
 1200 CONTINUE
      ISTEPN='2'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMARG.LE.1)GO TO 1210
      GO TO 1220
!
 1210 CONTINUE
      NUMLIN=1
      PLINTH(1)=PDEFLT
      GO TO 1270
!
 1220 CONTINUE
      NUMLIN=NUMARG-1
      IF(NUMLIN.GT.MAXLIN)NUMLIN=MAXLIN
      DO 1225 I=1,NUMLIN
      J=I+1
      IHOLD1=IHARG(J)
      HOLD1=ARG(J)
      HOLD2=HOLD1
      IF(IHOLD1.EQ.'ON')HOLD2=PDEFLT
      IF(IHOLD1.EQ.'OFF')HOLD2=PDEFLT
      IF(IHOLD1.EQ.'AUTO')HOLD2=PDEFLT
      IF(IHOLD1.EQ.'DEFA')HOLD2=PDEFLT
      PLINTH(I)=HOLD2
 1225 CONTINUE
      GO TO 1270
!
 1270 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1279
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      DO 1278 I=1,NUMLIN
      WRITE(ICOUT,1276)I,PLINTH(I)
 1276 FORMAT('LINE THICKNESS ',I6,' HAS JUST BEEN SET TO ',   &
      E15.7)
      CALL DPWRST('XXX','BUG ')
 1278 CONTINUE
 1279 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               **************************
!               **  STEP 2--            **
!               **  TREAT THE ALL CASE  **
!               **************************
!
 1300 CONTINUE
      ISTEPN='3'
      IF(IBUGP2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      NUMLIN=MAXLIN
      HOLD2=HOLD1
      IF(IHOLD1.EQ.'ON')HOLD2=PDEFLT
      IF(IHOLD1.EQ.'OFF')HOLD2=PDEFLT
      IF(IHOLD1.EQ.'AUTO')HOLD2=PDEFLT
      IF(IHOLD1.EQ.'DEFA')HOLD2=PDEFLT
      DO 1315 I=1,NUMLIN
      PLINTH(I)=HOLD2
 1315 CONTINUE
      GO TO 1370
!
 1370 CONTINUE
      IF(IFEEDB.EQ.'OFF')GO TO 1319
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      I=1
      WRITE(ICOUT,1316)PLINTH(I)
 1316 FORMAT('ALL LINE THICKNESSES HAVE JUST BEEN SET TO ',   &
      A4)
      CALL DPWRST('XXX','BUG ')
 1319 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGP2.EQ.'ON')THEN
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLITH--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)IERROR,HOLD1,HOLD2
 9014   FORMAT('IERROR,HOLD1,HOLD2 = ',A4,2X,2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 9035 I=1,10
          WRITE(ICOUT,9036)I,PLINTH(I)
 9036     FORMAT('I,PLINTH(I) = ',I8,2X,G15.7)
          CALL DPWRST('XXX','BUG ')
 9035   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPLITH
      SUBROUTINE DPLIUN(IHARG,NUMARG,MAXLIN,ILINTY,IFOUND,IERROR)
!
!     PURPOSE--DEFINE PLOT LINE UNITS (DATA OR SCREEN) FOR USE IN
!              MULTI-TRACE PLOTS.  THE COLOR FOR THE LINE FOR THE I-TH
!              TRACE WILL BE PLACED IN THE I-TH ELEMENT OF THE HOLLERITH
!              VECTOR ILINTY(.).
!
!              THE UNITS ARE SPECIFIED AS:
!
!                 DD     => X AXIS = DATA UNITS,   Y AXIS = DATA UNITS
!                 DS     => X AXIS = DATA UNITS,   Y AXIS = SCREEN UNITS
!                 SD     => X AXIS = SCREEN UNITS, Y AXIS = DATA UNITS
!                 SS     => X AXIS = SCREEN UNITS, Y AXIS = SCREEN UNITS
!                 DATA   => X AXIS = DATA UNITS,   Y AXIS = DATA UNITS
!                 SCREEN => X AXIS = SCREEN UNITS, Y AXIS = SCREEN UNITS
!
!              THE DEFAULT IS DATA UNITS FOR BOTH AXES.
!
!     INPUT  ARGUMENTS--IHARG  (A  HOLLERITH VECTOR)
!                     --NUMARG
!                     --MAXLIN
!     OUTPUT ARGUMENTS--ILINTY  (A  HOLLERITH VECTOR WHOSE I-TH ELEMENT
!                       IS THE COLOR FOR THE LINE ASSIGNED TO THE I-TH
!                       TRACE IN A MULTI-TRACE PLOT.
!                     --IFOUND ('YES' OR 'NO' )
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABOARATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2018/01
!     ORIGINAL VERSION--JANUARY   2018.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 ILINTY
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IDEFUN
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
      DIMENSION ILINTY(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='YES'
      IERROR='NO'
      IDEFUN='DD  '
!
      IF((NUMARG.EQ.1.AND.IHARG(1).EQ.'UNIT') .OR.   &
         (NUMARG.EQ.2.AND.IHARG(1).EQ.'UNIT'.AND.IHARG(2).EQ.'ALL'))THEN
        IFOUND='YES'
        DO 1165 I=1,MAXLIN
          ILINTY(I)=IDEFUN
 1165   CONTINUE
!
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          I=1
          WRITE(ICOUT,1116)ILINTY(I)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ELSEIF(NUMARG.GE.2.AND.IHARG(1).EQ.'UNIT')THEN
        IF(IHARG(NUMARG).EQ.'ON'   .OR. IHARG(NUMARG).EQ.'OFF' .OR.   &
           IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA')THEN
          IFOUND='YES'
          DO 1115 I=1,MAXLIN
            ILINTY(I)=IDEFUN
 1115     CONTINUE
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
  999       FORMAT(1X)
            CALL DPWRST('XXX','BUG ')
            I=1
            WRITE(ICOUT,1116)ILINTY(I)
 1116       FORMAT('ALL LINE UNITS HAVE JUST BEEN SET TO ',A4)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSEIF(NUMARG.EQ.2)THEN
          ILINTY(1)=IHARG(2)
          IF(ILINTY(1).EQ.'SCRE' .OR. ILINTY(1).EQ.'SS  ')THEN
            ILINTY(1)='SS  '
          ELSEIF(ILINTY(1).EQ.'DATA' .OR. ILINTY(1).EQ.'DD  ')THEN
            ILINTY(1)='DD  '
          ELSE
            IF(ILINTY(1).NE.'DS  ' .AND. ILINTY(1).NE.'SD  ')THEN
              ILINTY(1)='DD'
            ENDIF
          ENDIF
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            I=1
            WRITE(ICOUT,1126)I,ILINTY(I)
 1126       FORMAT('THE UNITS FOR LINE ',I6,' HAS JUST BEEN SET TO ',A4)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSEIF(NUMARG.GE.3.AND.IHARG(2).EQ.'ALL')THEN
          IFOUND='YES'
          DO 1135 I=1,MAXLIN
            ILINTY(I)=IHARG(3)
            IF(ILINTY(I).EQ.'SCRE' .OR. ILINTY(1).EQ.'SS  ')THEN
              ILINTY(I)='SS  '
            ELSEIF(ILINTY(I).EQ.'DATA' .OR. ILINTY(I).EQ.'DD  ')THEN
              ILINTY(I)='DD  '
            ELSE
              IF(ILINTY(I).NE.'DS  ' .AND. ILINTY(I).NE.'SD  ')THEN
                ILINTY(I)='DD'
              ENDIF
            ENDIF
 1135     CONTINUE
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            I=1
            WRITE(ICOUT,1116)ILINTY(I)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSEIF(NUMARG.GE.3.AND.IHARG(3).EQ.'ALL')THEN
          IFOUND='YES'
          DO 1145 I=1,MAXLIN
            ILINTY(I)=IHARG(2)
            IF(ILINTY(I).EQ.'SCRE' .OR. ILINTY(1).EQ.'SS  ')THEN
              ILINTY(I)='SS  '
            ELSEIF(ILINTY(I).EQ.'DATA' .OR. ILINTY(I).EQ.'DD  ')THEN
              ILINTY(I)='DD  '
            ELSE
              IF(ILINTY(I).NE.'DS  ' .AND. ILINTY(I).NE.'SD  ')THEN
                ILINTY(I)='DD'
              ENDIF
            ENDIF
 1145     CONTINUE
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            I=1
            WRITE(ICOUT,1116)ILINTY(I)
            CALL DPWRST('XXX','BUG ')
          ENDIF
        ELSE
          IFOUND='YES'
          IMAX=NUMARG-1
          IF(MAXLIN.LT.IMAX)IMAX=MAXLIN
          DO 1155 I=1,IMAX
            IP1=I+1
            ILINTY(I)=IHARG(IP1)
            IF(ILINTY(I).EQ.'SCRE' .OR. ILINTY(1).EQ.'SS  ')THEN
              ILINTY(I)='SS  '
            ELSEIF(ILINTY(I).EQ.'DATA' .OR. ILINTY(I).EQ.'DD  ')THEN
              ILINTY(I)='DD  '
            ELSE
              IF(ILINTY(I).NE.'DS  ' .AND. ILINTY(I).NE.'SD  ')THEN
                ILINTY(I)='DD'
              ENDIF
            ENDIF
 1155     CONTINUE
!
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            DO 1156 I=1,IMAX
              WRITE(ICOUT,1126)I,ILINTY(I)
              CALL DPWRST('XXX','BUG ')
 1156       CONTINUE
          ENDIF
        ENDIF
      ELSE
        IFOUND='NO'
      ENDIF
!
      RETURN
      END SUBROUTINE DPLIUN
      SUBROUTINE DPLODE(ICASAN,ICAPSW,IFORSW,IMULT,IREPL,   &
                        ISUBRO,IBUGA2,IBUGA3,IBUGQ,IFOUND,IERROR)
!
!     PURPOSE--PERFORM A LIMITS OF DETECTION ANALYIS.  SPECIFICALLY,
!              WE ARE CHECKING FOR A LOWER LIMIT OF DETECTION.
!              IT IS ASSUMED THAT WE CANNOT MEASURE THE MASS BELOW
!              A CERTAIN DETECTION LIMIT AND WE NEED TO DETERMINE
!              WHAT THAT DETECTION LIMIT IS.  THERE ARE 2 CASES:
!
!                  1) FOR A ZERO MASS, THE MEASUREMENT WILL ALWAYS
!                     RETURN A ZERO VALUE.  THIS WILL BE REFERRED
!                     TO AS THE "CLEAN" CASE".
!
!                  2) FOR A ZERO MASS, THE MEASUREMENT MAY BE A
!                     NON-ZERO VALUE.  THIS WILL BE REFERRED TO AS
!                     THE DIRTY CASE.
!
!              THE DATA CONSISTS OF A MASS VALUE ("X") AND A
!              MEASURED VALUE ("Y").  THE COMMAND SYNTAX IS:
!
!                  CLEAN LIMIT OF DETECTION  Y   X
!                  DIRTY LIMIT OF DETECTION  Y   X
!                  LIMIT OF DETECTION  Y   X
!
!              IF THE CLEAN/DIRTY CASE IS NOT SPECIFIED, ASSUME
!              THE DIRTY CASE.
!
!              NOTE THAT THIS HAS BEEN MODIFIED SO THAT IT IS
!              AUTOMATICALLY DETERMINED WHETHER THE DIRTY OR THE CLEAN
!              CASE IS USED (DPLOD2 IS THE "DIRTY" CASE, THIS IS ALWAYS
!              CALLED BY DPLODE AND THEN DPLOD2 WILL CALL DPLOD3 IF THE
!              CLEAN CASE IS DETECTED.
!
!              NOTE THAT THERE ARE A NUMBER OF APPROACHES TO THE LIMITS
!              OF DETECTION.  THIS ROUTINE IMPLEMENTS THE METHOD
!              USED BY THE ASTM E2677 STANDARD.
!
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/1
!     ORIGINAL VERSION--JANUARY   2009.
!     UPDATED         --OCTOBER   2018. SUPPORT "MULTIPLE" AND
!                                       "REPLICATION" OPTIONS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES----------------
!
      CHARACTER*4 ICASAN
      CHARACTER*4 ICAPSW
      CHARACTER*4 IFORSW
      CHARACTER*4 IREPL
      CHARACTER*4 IMULT
      CHARACTER*4 ISUBRO
      CHARACTER*4 IWRITE
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 IBUGQ
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 IHWUSE
      CHARACTER*4 MESSAG
      CHARACTER*4 ICASEQ
!
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 ICASE
!
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      CHARACTER*4 IVARID(MAXSPN)
      CHARACTER*4 IVARI2(MAXSPN)
      REAL PVAR(MAXSPN)
      REAL PID(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
      CHARACTER*40 INAME
      CHARACTER*4 IFLAGU
      LOGICAL IFRST
      LOGICAL ILAST
!
!----------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
      PARAMETER (MAXRPL=1)
      DIMENSION Y1(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION Y3(MAXOBV)
      DIMENSION TEMP1(MAXOBV)
      DIMENSION TEMP2(MAXOBV)
      DIMENSION TEMP3(MAXOBV)
      DIMENSION TEMP4(MAXOBV)
      DIMENSION TEMP5(MAXOBV)
      DIMENSION TEMP6(MAXOBV)
      DIMENSION TEMP7(MAXOBV)
      DIMENSION XIDTEM(MAXOBV)
      DIMENSION XIDTE2(MAXOBV)
!
      PARAMETER (MAXMAS=1000)
      REAL DTEMP(MAXMAS)
      REAL BA(MAXMAS)
      REAL BL(MAXMAS)
      REAL SU(MAXMAS)
      REAL T(MAXMAS)
      REAL P(MAXMAS)
      REAL LO(MAXMAS)
      REAL LU(MAXMAS)
      REAL S(MAXMAS)
      REAL UN(MAXMAS)
      REAL TO(MAXMAS)
      REAL UA(MAXMAS)
      REAL SI(MAXMAS)
      REAL B1(MAXMAS)
      REAL YTT(MAXMAS)
      REAL YVAR(MAXMAS)
!
      INTEGER   ITEMP1(MAXOBV)
      INTEGER   ITEMP2(MAXOBV)
      INTEGER   ITEMP3(MAXOBV)
!
      INCLUDE 'DPCOZZ.INC'
      INCLUDE 'DPCOZI.INC'
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),Y2(1))
      EQUIVALENCE (GARBAG(IGARB3),TEMP1(1))
      EQUIVALENCE (GARBAG(IGARB4),TEMP2(1))
      EQUIVALENCE (GARBAG(IGARB5),TEMP6(1))
!
      EQUIVALENCE (GARBAG(IGARB6),DTEMP(1))
      EQUIVALENCE (GARBAG(IGARB6+MAXMAS+1),BA(1))
      EQUIVALENCE (GARBAG(IGARB6+2*MAXMAS+1),BL(1))
      EQUIVALENCE (GARBAG(IGARB6+3*MAXMAS+1),SU(1))
      EQUIVALENCE (GARBAG(IGARB6+4*MAXMAS+1),T(1))
      EQUIVALENCE (GARBAG(IGARB6+5*MAXMAS+1),P(1))
      EQUIVALENCE (GARBAG(IGARB6+6*MAXMAS+1),LO(1))
      EQUIVALENCE (GARBAG(IGARB6+7*MAXMAS+1),LU(1))
      EQUIVALENCE (GARBAG(IGARB6+8*MAXMAS+1),S(1))
      EQUIVALENCE (GARBAG(IGARB6+9*MAXMAS+1),UN(1))
      EQUIVALENCE (GARBAG(IGARB6+10*MAXMAS+1),TO(1))
      EQUIVALENCE (GARBAG(IGARB6+11*MAXMAS+1),UA(1))
      EQUIVALENCE (GARBAG(IGARB6+12*MAXMAS+1),SI(1))
      EQUIVALENCE (GARBAG(IGARB6+13*MAXMAS+1),B1(1))
      EQUIVALENCE (GARBAG(IGARB6+14*MAXMAS+1),YTT(1))
      EQUIVALENCE (GARBAG(IGARB6+15*MAXMAS+1),YVAR(1))
!
      EQUIVALENCE (GARBAG(IGARB7),TEMP4(1))
      EQUIVALENCE (GARBAG(IGARB8),TEMP5(1))
      EQUIVALENCE (GARBAG(IGARB9),XIDTEM(1))
      EQUIVALENCE (GARBAG(IGAR10),XIDTE2(1))
      EQUIVALENCE (GARBAG(JGAR11),Y3(1))
      EQUIVALENCE (GARBAG(JGAR12),TEMP3(1))
      EQUIVALENCE (GARBAG(JGAR13),TEMP7(1))
!
      EQUIVALENCE (IGARBG(IIGAR1),ITEMP1(1))
      EQUIVALENCE (IGARBG(IIGAR2),ITEMP2(1))
      EQUIVALENCE (IGARBG(IIGAR3),ITEMP3(1))
!
!-----COMMON----------------------------------------------------
!
      INCLUDE 'DPCOSU.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
      INCLUDE 'DPCOST.INC'
!
!----------------------------------------------------------------
!
!-----COMMON VARIABLES (GENERAL)---------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT------------------------------------------------
!
      ISTEPN='1'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LODE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ISUBN1='DPLO'
      ISUBN2='DE  '
      IERROR='NO'
      ICASEQ='UNKN'
      IFOUND='YES'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
!
!               **************************************************
!               **  TREAT THE LIMIT OF DETECTION          CASE  **
!               **************************************************
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LODE')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLODE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)ICASAN,IMULT,IREPL,IBUGA2,IBUGA3,IBUGQ
   52   FORMAT('ICASAN,IMULT,IREPL,IBUGA2,IBUGA3,IBUGQ = ',5(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************
!               **  STEP 1--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      INAME='LIMITS OF DETECTION ANALYSIS'
      MINNA=2
      MAXNA=100
      MINN2=10
      IFLAGE=1
      IFLAGM=0
      IFLAGP=0
      JMIN=1
      JMAX=NUMARG
      MINNVA=2
      MAXNVA=3
      IF(IMULT.EQ.'ON')THEN
        MAXNVA=MAXSPN
      ENDIF
      IF(IREPL.EQ.'ON')THEN
        MINNVA=3
      ENDIF
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGA3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LODE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I) = ',I8,2X,A4,A4,2X,3I8)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
      IF(IMULT.EQ.'OFF' .AND. NUMVAR.EQ.3)IREPL='ON'
!
!               ******************************************
!               **  STEP 2--                            **
!               **  CHECK FOR USER SETTABLE PARAMETERS  **
!               ******************************************
!
      ISTEPN='2'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LODE')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IH='ALPH'
      IH2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        ALPHA=0.10
      ELSE
        ALPHA=VALUE(ILOCP)
      ENDIF
      IF(ALPHA.LE.0.0 .OR. ALPHA.GE.1.0)ALPHA=0.05
      IF(ALPHA.GT.0.50)ALPHA=1.0 - ALPHA
!
      IH='BETA'
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        BETA=0.10
      ELSE
        BETA=VALUE(ILOCP)
      ENDIF
      IF(BETA.LE.0.0 .OR. BETA.GE.1.0)BETA=0.10
      IF(BETA.GT.0.50)BETA=1.0 - BETA
!
      IH='GAMM'
      IH2='A   '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        GAMMA=0.10
      ELSE
        GAMMA=VALUE(ILOCP)
      ENDIF
      IF(GAMMA.LE.0.0 .OR. GAMMA.GE.1.0)GAMMA=0.10
      IF(GAMMA.GT.0.50)GAMMA=1.0 - GAMMA
!
      IH='PA  '
      IH2='    '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        PA=0.10
      ELSE
        PA=VALUE(ILOCP)
      ENDIF
      IF(PA.LE.0.0 .OR. PA.GE.1.0)PA=0.10
      IF(PA.GT.0.50)PA=1.0 - PA
!
!     THRESHOLD PERCENT SHOULD BE BETWEEN 90% AND 100%.  HOWEVER,
!     ALLOW TO GO AS LOW AS 80%.  IF OUT OF 80-100% RANGE,
!     THEN SET TO DEFAULT.
!
      IH='THRE'
      IH2='SHPR'
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        THRPER=CPUMIN
      ELSE
        THRPER=VALUE(ILOCP)
      ENDIF
      IF(THRPER.NE.CPUMIN)THEN
        IF(THRPER.GT.1.0)THEN
           THRPER=THRPER/100.0
           IF(THRPER.LT.0.5)THRPER=0.9
           IF(THRPER.GT.1.0)THRPER=0.9
        ELSEIF(THRPER.LT.0.5)THEN
           THRPER=0.9
        ENDIF
      ENDIF
!
!     SPECIFY CRITICAL VALUE IF KNOWN (SOME INSTRUMENTS PROVIDE THIS
!     VALUE IN THEIR SOFTWARE).  CURRENTLY, ONLY CHECK THAT THE
!     CRITICAL VALUE IS POSITIVE.
!
      IH='CRIT'
      IH2='VAL '
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IH,IH2,IHWUSE,   &
      IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
      ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCP,IERROR)
      IF(IERROR.EQ.'YES')THEN
        CVUSER=CPUMIN
      ELSE
        CVUSER=VALUE(ILOCP)
        IF(CVUSER.LE.0.0)CVUSER=CPUMIN
      ENDIF
      CVSAVE=CVUSER
!
!               ****************************************
!               **  STEP 3--                          **
!               **  EXTRACT THE DATA                  **
!               ****************************************
!
      ISTEPN='3'
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LODE')THEN
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,323)ALPHA,BETA,GAMMA,PA,CV
  323   FORMAT('ALPHA,BETA,GAMMA,PA,CV = ',5G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     2018/10: SUPPORT FOR "REPLICATION" AND "MULTIPLE" OPTIONS.
!
!              AT ASTM D22 SYMPOSIUM ON DETECTION LIMITS, A SUGGESTION
!              WAS MADE THAT BEING ABLE TO GENERATE DETECTION LIMITS
!              FOR MULTIPLE ELEMENTS WOULD BE USEFUL ON THE WEB SITE.
!
!              TWO APPROACHES TO REPLICATION ARE SUPPORTED:
!
!              1. REPLICATION (REPLICATED LIMITS OF DETECTION Y X BATCH)
!
!                 IN THIS CASE, WE SIMPLY ADD A "BATCH" VARIABLE.
!
!              2. MULTIPLE (MULTIPLE LIMITS OF DETECTION Y1 ... YK  X)
!
!                 FOR THIS CASE, WE ASSUME
!
      IF(IREPL.EQ.'OFF' .AND. IMULT.EQ.'OFF' .AND. NUMVAR.EQ.3)   &
         IREPL='ON'
!
      IF(IMULT.EQ.'ON' .OR. NUMVAR.EQ.2)THEN
!
!       LOOP THROUGH EACH OF THE RESPONSE VARIABLES
!
!       FOR MULTIPLE CASE, LAST VARIABLE IS THE "MASS" VARIABLE AND
!       IT IS THE SAME FOR ALL RESPONSE VARIABLES.
!
        ICOL=NUMVAR
        NUMVA2=1
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y2,Y2,Y2,NLOCAL,NLOCAL,NLOCAL,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        NCURVE=0
        DO 310 IRESP=1,NUMVAR-1
          NCURVE=NCURVE+1
          CVUSER=CVSAVE
!
          IINDX=ICOLR(IRESP)
          PID(1)=CPUMIN
          IVARID(1)=IVARN1(IRESP)
          IVARI2(1)=IVARN2(IRESP)
!
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LODE')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,311)IRESP,NCURVE,IVARID(IRESP),IVARI2(IRESP)
  311       FORMAT('IRESP,NCURVE,IVARID(IRESP),IVARI2(IRESP) = ',   &
                   2I5,2X,2A4)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          ICOL=IRESP
          NUMVA2=1
          CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                      INAME,IVARN1,IVARN2,IVARTY,   &
                      ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                      MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                      MAXCP4,MAXCP5,MAXCP6,   &
                      V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                      Y1,Y1,Y1,NS,NS,NS,ICASE,   &
                      IBUGA3,ISUBRO,IFOUND,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
!
!         **************************************************
!         **  STEP 3B--                                   **
!         **  PREPARE FOR ENTRANCE INTO DPLOD2--          **
!         **************************************************
!
          ISTEPN='3B'
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LODE')   &
             CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LODE')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,321)
  321       FORMAT('***** FROM DPLODE, AS WE ARE ABOUT TO ',   &
                   'CALL DPLOD2--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,322)MAXN,NS,NUMVAR
  322       FORMAT('MAXN,NS,NUMVAR = ',3I8)
            CALL DPWRST('XXX','BUG ')
            DO 325 I=1,NS
              WRITE(ICOUT,326)I,Y1(I),Y2(I)
  326         FORMAT('I,Y1(I),Y2(I) = ',I6,2X,2G15.7)
              CALL DPWRST('XXX','BUG ')
  325       CONTINUE
          ENDIF
!
          IWRITE='OFF'
          PID(1)=CPUMIN
          PID(2)=CPUMIN
          PID(3)=CPUMIN
          IVARID(1)=IVARN1(IRESP)
          IVARI2(1)=IVARN2(IRESP)
          IVARID(2)=IVARN1(NUMVAR)
          IVARI2(2)=IVARN2(NUMVAR)
          IVARID(3)='   '
          IVARI2(3)='   '
!
          CALL DPLOD2(Y1,Y2,NS,   &
                      XIDTEM,TEMP1,TEMP2,TEMP3,TEMP4,TEMP5,   &
                      DTEMP,BA,BL,SU,T,P,LO,LU,S,UN,TO,UA,   &
                      SI,B1,YTT,YVAR,   &
                      ITEMP1,ITEMP2,ITEMP3,   &
                      ALPHA,BETA,GAMMA,PA,THRPER,CVUSER,   &
                      ALOD,ALODSE,CV,ALODLU,   &
                      IVARID,IVARI2,PID,   &
                      IWRITE,MAXOBV,   &
                      IFORSW,ICASAN,ICAPSW,ICAPTY,   &
                      ISUBRO,IBUGA3,IERROR)
!
!         ***************************************
!         **  STEP 3C--                        **
!         **  UPDATE INTERNAL DATAPLOT TABLES  **
!         ***************************************
!
          ISTEPN='3C'
          IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LODE')   &
             CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          IFLAGU='FILE'
          IF(NUMVAR.EQ.2)IFLAGU='ON'
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(NCURVE.EQ.1)IFRST=.TRUE.
          IF(NCURVE.EQ.NUMVAR-1)ILAST=.TRUE.
          CALL DPLOD5(ALOD,ALODSE,CV,ALODLU,   &
                      IFLAGU,IFRST,ILAST,ICASAN,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
          IH='LOD '
          IH2='    '
          VALUE0=ALOD
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA2,IERROR)
!
          IH='LODS'
          IH2='E   '
          VALUE0=ALODSE
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA2,IERROR)
!
          IH='LODC'
          IH2='V   '
          VALUE0=CV
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA2,IERROR)
!
          IH='LODU'
          IH2='CL  '
          VALUE0=ALODLU
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA2,IERROR)
!
  310   CONTINUE
      ELSE
!
!       REPLICATION CASE
!
        ISTEPN='4A'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LODE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ICOL=1
        CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                    INAME,IVARN1,IVARN2,IVARTY,   &
                    ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVAR,   &
                    MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                    MAXCP4,MAXCP5,MAXCP6,   &
                    V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                    Y1,Y2,Y3,NS,NS,NS,ICASE,   &
                    IBUGA3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
        NLOCAL=NS
        NREPL=1
!
        ISTEPN='4B'
        IF(IBUGA2.EQ.'ON'.OR.ISUBRO.EQ.'LODE')   &
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        PID(1)=CPUMIN
        PID(2)=CPUMIN
        IVARID(1)=IVARN1(1)
        IVARI2(1)=IVARN2(1)
        IVARID(2)=IVARN1(2)
        IVARI2(2)=IVARN2(2)
        IVARID(3)=IVARN1(3)
        IVARI2(3)=IVARN2(3)
!
!       *****************************************************
!       **  STEP 4C--                                      **
!       **                                                 **
!       **  FOR THIS CASE, WE NEED TO LOOP THROUGH THE     **
!       **  VARIOUS REPLICATIONS AND FIND THE DISTINCT     **
!       **  VALUES IN EACH OF THE REPLICATION VARIABLES.   **
!       *****************************************************
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LODE')THEN
          ISTEPN='4C'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,361)
  361     FORMAT('***** FROM THE MIDDLE  OF DPLODE--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,362)NUMVAR,NS,NREPL
  362     FORMAT('NUMVAR,NS,NREPL = ',3I8)
          CALL DPWRST('XXX','BUG ')
          IF(NS.GE.1)THEN
            DO 365 I=1,NS
              WRITE(ICOUT,366)I,Y1(I),Y2(I),Y3(I)
  366         FORMAT('I,Y1(I),Y2(I),Y3(I) = ',I8,G15.7,2F12.5)
              CALL DPWRST('XXX','BUG ')
  365       CONTINUE
          ENDIF
        ENDIF
!
        IF(NUMVAR.EQ.3)THEN
          CALL DISTIN(Y3,NS,IWRITE,XIDTE2,NUMSET,IBUGA3,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
        ELSE
          NUMSET=1
        ENDIF
!
        IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LODE')THEN
          WRITE(ICOUT,368)NUMSET
  368     FORMAT('AFTER DISTIN: NUMSET = ',I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!       *****************************************************
!       **  STEP 5D--                                      **
!       **  NOW LOOP THROUGH THE VARIOUS REPLICATIONS      **
!       *****************************************************
!
        NPLOTP=0
        NCURVE=0
        J=0
        DO 1110 ISET1=1,NUMSET
          CVUSER=CVSAVE
          K=0
          PID(3)=XIDTE2(ISET1)
!
          DO 1120 I=1,MAXOBV
            TEMP1(K)=0.0
            TEMP2(K)=0.0
 1120     CONTINUE
!
          DO 1130 I=1,NS
            IF(XIDTE2(ISET1).EQ.Y3(I))THEN
              K=K+1
              TEMP1(K)=Y1(I)
              TEMP2(K)=Y2(I)
            ENDIF
 1130     CONTINUE
!
          NTEMP=K
          NCURVE=NCURVE+1
          IF(NTEMP.GT.0)THEN
            CALL DPLOD2(TEMP1,TEMP2,NTEMP,   &
                        XIDTEM,TEMP3,TEMP4,TEMP5,TEMP6,TEMP7,   &
                        DTEMP,BA,BL,SU,T,P,LO,LU,S,UN,TO,UA,   &
                        SI,B1,YTT,YVAR,   &
                        ITEMP1,ITEMP2,ITEMP3,   &
                        ALPHA,BETA,GAMMA,PA,THRPER,CVUSER,   &
                        ALOD,ALODSE,CV,ALODLU,   &
                        IVARID,IVARI2,PID,   &
                        IWRITE,MAXOBV,   &
                        IFORSW,ICASAN,ICAPSW,ICAPTY,   &
                        ISUBRO,IBUGA3,IERROR)
          ENDIF
!
          IFLAGU='FILE'
          IFRST=.FALSE.
          ILAST=.FALSE.
          IF(NCURVE.EQ.1)IFRST=.TRUE.
          IF(NCURVE.EQ.NUMSET)ILAST=.TRUE.
          CALL DPLOD5(ALOD,ALODSE,CV,ALODLU,   &
                      IFLAGU,IFRST,ILAST,ICASAN,   &
                      IBUGA2,IBUGA3,ISUBRO,IERROR)
 1110   CONTINUE
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LODE')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLODE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGA2,IBUGA3
 9012   FORMAT('IBUGA2,IBUGA3 = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)NS,NUMVAR
 9014   FORMAT('NS,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)IFOUND,IERROR
 9016   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLODE
      SUBROUTINE DPLOD2(Y,X,N,   &
                        XIDTEM,TEMP1,TEMP2,TEMP3,YT,YM,   &
                        D,BA,BL,SU,T,P,LO,LU,S,UN,TO,UA,   &
                        SI,B1,YTT,YVAR,   &
                        NS,MU,NN,   &
                        ALPHA,BETA,GAMMA,PA,THRPER,CVUSER,   &
                        ALOD,ALODSE,CV,ALODLU,   &
                        IVARID,IVARI2,PID,   &
                        IWRITE,MAXOBV,   &
                        IFORSW,ICASAN,ICAPSW,ICAPTY,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--PERFORM A LIMITS OF DETECTION ANALYIS.  SPECIFICALLY,
!              WE ARE CHECKING FOR A LOWER LIMIT OF DETECTION.
!              IT IS ASSUMED THAT WE CANNOT MEASURE THE MASS BELOW
!              A CERTAIN DETECTION LIMIT AND WE NEED TO DETERMINE
!              WHAT THAT DETECTION LIMIT IS.  THERE ARE 2 CASES:
!
!                  1) FOR A ZERO MASS, THE MEASUREMENT WILL ALWAYS
!                     RETURN A ZERO VALUE.  THIS WILL BE REFERRED
!                     TO AS THE "CLEAN" CASE".
!
!                  2) FOR A ZERO MASS, THE MEASUREMENT MAY BE A
!                     NON-ZERO VALUE.  THIS WILL BE REFERRED TO AS
!                     THE DIRTY CASE.
!
!              THE DATA CONSISTS OF A MASS VALUE ("X") AND A
!              MEASURED VALUE ("Y").  THE COMMAND SYNTAX IS:
!
!                  CLEAN LIMIT OF DETECTION  Y   X
!                  DIRTY LIMIT OF DETECTION  Y   X
!                  LIMIT OF DETECTION  Y   X
!
!              IF THE CLEAN/DIRTY CASE IS NOT SPECIFIED, ASSUME
!              THE DIRTY CASE.
!
!     PRINTING--YES
!     SUBROUTINES NEEDED--NORPPF, CHSPPF
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/1
!     ORIGINAL VERSION--JANUARY   2009.
!     UPDATED         --APRIL     2009. IMPLEMENT NEW STOPPING RULE
!     UPDATED         --MAY       2009. SOME REFINEMENTS
!     UPDATED         --JUNE      2009. SOME ADDITINAL REFINEMENTS
!     UPDATED         --JULY      2009. COMPUTE "SECOND SMALLEST"
!                                       VALUE FROM ALL THE DATA, NOT
!                                       JUST MASS = 0 DATA
!     UPDATED         --JULY      2009. ILODCV WAS NOT INITIALIZED,
!                                       ADD TO "INITSU" ROUTINE
!     UPDATED         --JULY      2009. EXPLICIT CHECK FOR CASE WHERE
!                                       THERE ARE LESS THAN 2 POSITIVE
!                                       MEASUREMENTS FOR A GIVEN MASS
!                                       VALUE
!     UPDATED         --AUGUST    2009. FOR HIGHEST MASS LEVEL, IF
!                                       MORE THAN 10% OF RESPONSES ARE
!                                       LESS THAN CRITIVAL VALUE, THEN
!                                       PRINT AN ERROR SAYING
!                                       MEASUREMENTS AT HIGHER MASS
!                                       LEVEL REQUIRED
!     UPDATED         --JANUARY   2011. ALLOW USER-SPECIFIED CRITICAL
!                                       VALUE
!     UPDATED         --JULY      2012. OPTION WHETHER TO PRINT EACH OF
!                                       THE TABLES
!     UPDATED         --MARCH     2014. THIS LOD ANALYSIS IS NOW AN
!                                       OFFICIAL ASTM STANDARD (E2677).
!                                       A FEW TWEAKS IN THE OUTPUT TO
!                                       BE CONSISTENT WITH E2677.
!     UPDATED         --JULY      2018. IF NEGATIVE DATA ENCOUNTERED,
!                                       THEN TRANSLATE TO POSITIVE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      CHARACTER*4 IFORSW
      CHARACTER*4 ICASAN
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*1 IBASLC
!
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
!----------------------------------------------------------------
!
      REAL Y(*)
      REAL X(*)
      REAL XIDTEM(*)
      REAL TEMP1(*)
      REAL TEMP2(*)
      REAL TEMP3(*)
      REAL YT(*)
      REAL YM(*)
!
      REAL D(*)
      REAL BA(*)
      REAL BL(*)
      REAL SU(*)
      REAL T(*)
      REAL P(*)
      REAL LO(*)
      REAL LU(*)
      REAL S(*)
      REAL UN(*)
      REAL TO(*)
      REAL UA(*)
      REAL SI(*)
      REAL B1(*)
      REAL YTT(*)
      REAL YVAR(*)
      REAL PID(*)
!
      INTEGER NS(*)
      INTEGER MU(*)
      INTEGER NN(*)
!
      REAL ZERO
      REAL EPS
!
      DOUBLE PRECISION DSUM
!
      CHARACTER*4 IOP
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER(MAXLIN=4)
      PARAMETER(MAXROW=30)
      PARAMETER(MAXCOL=8)
      CHARACTER*4  ALIGN(MAXCOL)
      CHARACTER*4  VALIGN(MAXCOL)
      INTEGER      IDIGIT(MAXCOL)
      INTEGER      NTOT(MAXCOL)
      INTEGER      NCTEXT(MAXROW)
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*40 ITITL9
      CHARACTER*40 ITITLE
      CHARACTER*60 ITTEXT
      CHARACTER*40 ITITL2(MAXLIN,MAXCOL)
      INTEGER      NCTIT2(MAXLIN,MAXCOL)
      INTEGER      IWHTML(MAXCOL)
      INTEGER      IWRTF(MAXCOL)
      REAL         AMAT(MAXROW,MAXCOL)
      REAL         AVALUE(MAXROW)
!
      LOGICAL IFLAGA
      LOGICAL IFLAGB
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IRTFMD
      COMMON/COMRTF/IRTFMD
!
      LOGICAL IFLAGY
      LOGICAL IFLAGZ
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO /0.0/
      DATA EPS  /0.1E-7/
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPLO'
      ISUBN2='D2  '
!
      NUMZER=0
      NUMPOS=0
      MINPOS=0
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLOD2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,ALPHA,BETA,GAMMA,PA
   52   FORMAT('N,ALPHA,BETA,GAMMA,PA = ',I8,4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)THRPER,CVUSER
   53   FORMAT('THRPER,CVUSER = ',2G15.7)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               **  1) NEGATIVE VALUES FOR THE RESPONSE   **
!               **     ARE CONSIDERED ERRORS.             **
!               **  2) IF THERE IS NO "ZERO" MASS VALUE,  **
!               **     CONSIDER THIS AN ERROR FOR NOW.    **
!               ********************************************
!
      ISTEPN='1.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOD2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN LIMITS OF DETECTION--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE LIMITS OF ',   &
               'DETECTION')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N
  103   FORMAT('      IS LESS THAN 2;  THE ENTERED NUMBER OF ',   &
               'OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     2018/08: IF NEGATIVE DATA ENCOUNTERED FOR THE RESPONSE VALUE,
!              DON'T TREAT AS AN ERROR.  ADD AN APPROPRIATE CONSTANT
!              TO THE DATA, PERFORM THE LOD ANALYSIS, AND THEN SUBTRACT
!              THE CONSTANT FROM THE CV VALUE.
!
      YMIN=CPUMAX
      DO 200 I=1,N
        IF(ABS(X(I)).LE.EPS)X(I)=ZERO
        YMIN=MIN(YMIN,Y(I))
        IF(Y(I).LT.ZERO)THEN
!CCCC     WRITE(ICOUT,999)
!CCCC     CALL DPWRST('XXX','WRIT')
!CCCC     WRITE(ICOUT,101)
!CCCC     CALL DPWRST('XXX','WRIT')
!CCCC     WRITE(ICOUT,202)
!C202     FORMAT('      A NEGATIVE VALUE WAS ENCOUNTERED FOR ',
!CCCC1           'THE MEASURED VALUE')
!CCCC     CALL DPWRST('XXX','WRIT')
!CCCC     WRITE(ICOUT,204)I,Y(I)
  204     FORMAT('      ROW ',I8,' HAS THE VALUE ',G15.7)
!CCCC     CALL DPWRST('XXX','WRIT')
!CCCC     IERROR='YES'
!CCCC     GO TO 9000
        ELSEIF(X(I).LT.ZERO)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,212)
  212     FORMAT('      A NEGATIVE VALUE WAS ENCOUNTERED FOR ',   &
                 'THE MASS VALUE')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,204)I,X(I)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ENDIF
  200 CONTINUE
!
      IF(YMIN.LT.0.0)THEN
        YCONST=ABS(YMIN) + 1.0
        DO 208 I=1,N
          Y(I)=Y(I) + YCONST
  208   CONTINUE
      ELSE
        YCONST=0.0
      ENDIF
!
!               ********************************************
!               **  STEP 1B-                              **
!               **  CHECK FOR:                            **
!               **  1) ARE THERE ANY MEASUREMENTS FOR     **
!               **     MASS = 0?  IF NOT, THIS IS AN      **
!               **     ERROR (AT LEAST FOR NOW).          **
!               **  2) ARE ALL MEASUREMENTS FOR MASS = 0  **
!               **     EQUAL TO ZERO?  IF SO, USE THE     **
!               **     "CLEAN" ALGORITHM.                 **
!               **     IF THERE ARE LESS THAN 3 NON-ZERO  **
!               **     MEASUREMENTS FOR MASS = 0, THEN    **
!               **     REMOVE THESE FROM THE DATA AND USE **
!               **     THE CLEAN ALGORITHM.               **
!               ********************************************
!
!     MAY 2009: MICHAEL VERKOUTEREN HAS SUGGESTED THE FOLLOWING
!               MINIMUM REQUIREMENTS:
!
!               1) 10 OR MORE BLANK REPITITIONS
!               2) AT LEAST 3 LEVELS
!               3) AT LEAST 10 REPITITIONS FOR EACH LEVEL
!
!     JUNE 2009: MICHAEL VERKOUTEREN HAS MADE THE FOLLOWING ADDITIONAL
!                SUGGESTIONS:
!
!                1) IF > 90% OF MEASUREMENTS AT HIGHTEST LEVEL
!                   ARE ZERO, THEN REPORT ERROR.
!                2) IF DATA IN ALL LEVELS IS EITHER ALL ZERO'S OR
!                   ALL NON-ZEROS, THEN RECOMMEND MEASUREMENTS
!                   AT MASS VALUE NEAR MID-POINT TWO SUCCESSIVE
!                   MASS LEVELS WHERE LOWER IS ALL ZERO MEASUREMENTS
!                   AND UPPER IS ALL NON-ZERO MEASUREMENTS.
!
!                   09/2010: FOR CASE 2), MICHAEL WANTS THE
!                            RECOMMENDATION PRINTED, BUT HE STILL
!                            WANTS THE RESULTS REPORTED.
!
!     AUGUST 2009: MICHAEL VERKOUTEREN ADDED ADDITIONAL CRITIERION.
!
!                1) IF > 10% OF MEASUREMENTS ARE LESS THAN THE
!                   CRITICAL VALUE, THEN WE NEED TO REPORT AN
!                   ERROR THAT DATA NEEDS TO BE TAKEN AT A HIGHER
!                   LEVEL.
!
      ISTEPN='1.2'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOD2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
      CALL SORT(XIDTEM,NDIST,XIDTEM)
!
      IF(XIDTEM(1).NE.ZERO)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1002)
 1002   FORMAT('      THE LIMIT OF DETECTION COMMAND REQUIRES')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1003)
 1003   FORMAT('      SOME MEASUREMENTS FOR MASS = 0.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1004)XIDTEM(1)
 1004   FORMAT('      THE MINIMUM MASS VALUE  = ',G15.7)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      IF(NDIST.LT.3)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1012)
 1012   FORMAT('      AT LEAST THREE DISTINCT LEVELS REQUIRED.')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1013)NDIST
 1013   FORMAT('      THE NUMBER OF LEVELS DETECTED WAS ',I5)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NDIST.EQ.N)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1014)
 1014   FORMAT('      THE NUMBER OF DISTINCT MASS VALUES IS EQUAL TO ',   &
               'THE SAMPLE SIZE')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     MAY 2009: MOVE CODE TO DETERMINE THE NUMBER OF REPITITIONS
!               FOR EACH LEVEL HERE.  WE NEED THIS TO DETERMINE
!               IF WE HAVE SUFFICIENT REPITITIONS FOR EACH LEVEL
!               AND TO DETERMINE WHETHER WE NEED THE CLEAN OR
!               DIRTY CASE.
!
      CALL SORTC(X,Y,N,X,TEMP1)
      DO 1018 I=1,N
        Y(I)=TEMP1(I)
 1018 CONTINUE
!
!     MAY 2009: CHECK FOR MINIMUM NON-ZERO VALUE. DETERMINE
!               IF THIS IS AT A ZERO MASS CASE OR NOT.  THIS
!               IS USED TO DECIDE HOW TO COMPUTE H IN CODE
!               BELOW.
!
      YMIN=CPUMAX
      YMINMS=CPUMAX
      DO 1022 I=1,N
        IF(Y(I).GT.0.0)THEN
          IF(Y(I).LT.YMIN)THEN
            YMIN=Y(I)
            YMINMS=X(I)
          ENDIF
        ENDIF
 1022 CONTINUE
!
!     JULY 2009: DETERMINE "SECOND SMALLEST VALUE" FROM ALL THE
!                DATA, NOT JUST THE MASS = 0 DATA.
!
      YMIN2=CPUMAX
      DO 1024 I=1,N
        IF(Y(I).GT.YMIN)THEN
          IF(Y(I).LT.YMIN2)THEN
            YMIN2=Y(I)
          ENDIF
        ENDIF
 1024 CONTINUE
!
      DO 1030 I=1,NDIST
!
        HOLD=XIDTEM(I)
        NREP=0
        NZERO=0
        NPLUS=0
!
        DO 1040 J=1,N
          IF(X(J).EQ.HOLD)THEN
            NREP=NREP+1
            IF(Y(J).LE.0.0)THEN
              NZERO=NZERO+1
            ELSE
              NPLUS=NPLUS+1
            ENDIF
          ENDIF
 1040   CONTINUE
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
          WRITE(ICOUT,1041)I,XIDTEM(I),NREP,NZERO,NPLUS
 1041     FORMAT('I,XIDTEM(I),NREP,NZERO,NPLUS=',I5,G15.7,3I5)
          CALL DPWRST('XXX','WRIT')
        ENDIF
!
        IF(NREP.LT.10)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1032)
 1032     FORMAT('      AT LEAST 10 REPITITIONS ARE REQUIRED FOR ',   &
                 'EACH LEVEL.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,1033)I,HOLD,NREP
 1033     FORMAT('      LEVEL ',I5,' (= ',G15.7,') ONLY HAS ',I5,   &
                 'REPITITIONS.')
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(I.EQ.1)THEN
          NUMZER=NZERO
          NUMPOS=NPLUS
        ENDIF
!
 1030 CONTINUE
!
!     THE THRESHOLD FOR USING THE "CLEAN" ALGORITHM IS THAT
!     >= 90% OF THE BLANK CASES MUST BE ZERO.
!
!     SET AN ADDITIONAL THRESHOLD OF >= 50% OF BLANKS ARE
!     NON-ZERO.
!
!     SET IFLAG = 0 FOR CLEAN CASE, IFLAG = 1 FOR DIRTY CASE,
!     AND IFLAG = 2 FOR CASE WHERE WE NEED TO CHECK FOR SUFFICIENT
!     NUMBER OF BLANKS (REQUIRE AT LEAST 20).
!
      ATEMP=REAL(NUMZER+NUMPOS)*0.9 + 0.000001
      MINZER=INT(ATEMP)
      ATEMP=REAL(NUMZER+NUMPOS)*0.5 + 0.000001
      MINPOS=INT(ATEMP)
      IF(NUMZER.GE.MINZER)THEN
        IFLAG=0
      ELSEIF(NUMPOS.GE.MINPOS)THEN
        IFLAG=1
      ELSE
        IFLAG=2
      ENDIF
!
!     CHECK FOR SUFFICIENT NUMBER OF BLANK CASES
!
      IF(IFLAG.EQ.2 .AND. NUMZER+NUMPOS.LT.20)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1052)
 1052   FORMAT('      WHEN THE PERCENTAGE OF NON-ZERO MEASUREMENTS ',   &
                 'FOR BLANKS')
          CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1053)
 1053   FORMAT('      IS LESS THAN 50%, AT LEAST 20 BLANK ',   &
               'MEASUREMENTS ARE REQUIRED.')
        CALL DPWRST('XXX','WRIT')
        NADD=20 - (NUMZER+NUMPOS)
        WRITE(ICOUT,1054)NADD
 1054   FORMAT('      AT LEAST ',I5,' ADDITIONAL BLANK MEASUREMENTS ',   &
               'ARE REQUIRED.')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
!     FOR CLEAN CASE, REMOVE ANY POSITIVE MEASUREMENTS
!
      IF(IFLAG.EQ.0 .AND.NUMPOS.GT.0)THEN
        ICNT=0
        DO 1065 I=1,N
          IF(X(I).EQ.XIDTEM(1) .AND. Y(I).GT.ZERO)THEN
            GO TO 1065
          ELSE
            ICNT=ICNT+1
            X(ICNT)=X(I)
            Y(ICNT)=Y(I)
          ENDIF
 1065   CONTINUE
        N=ICNT
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,1031)NUMPOS
!1031   FORMAT('***** THE ',I5,' POSITIVE MEASUREMENTS FOR THE ',
!CCCC1         'ZERO MASS CASE')
!CCCC   CALL DPWRST('XXX','WRIT')
!CCCC   WRITE(ICOUT,1033)
!1033   FORMAT('      WILL NOT BE USED IN THE ANALYSIS.')
!CCCC   CALL DPWRST('XXX','WRIT')
      ENDIF
!
      IF(IFLAG.EQ.0)THEN
        CALL DPLOD3(Y,X,N,   &
                    XIDTEM,TEMP1,YT,YM,   &
                    D,BA,BL,SU,T,P,LO,LU,S,UN,TO,UA,SI,B1,YTT,YVAR,   &
                    NS,MU,NN,   &
                    ALPHA,BETA,GAMMA,PA,THRPER,CVUSER,   &
                    ALOD,ALODSE,CV,ALODLU,   &
                    IVARID,IVARI2,PID,   &
                    IWRITE,MAXOBV,   &
                    IFORSW,YMIN,YMIN2,   &
                    ICASAN,ICAPSW,ICAPTY,   &
                    ISUBRO,IBUGA3,IERROR)
        GO TO 9000
      ENDIF
!
      IF(THRPER.EQ.CPUMIN)THRPER=0.9
!
!               ***********************************************
!               **  STEP 2.1--                               **
!               **  PERFORM THE BASIC CALCULATIONS.          **
!               ***********************************************
!
      ISTEPN='2.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOD2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
!
!     ALPHA   = PROBABILITY OF FALSE POSITIVE READINGS
!               (NO SIGNIFICANCE, BUT ALARM SOUNDS)
!     BETA    = PROBABILITY OF FALSE NEGATIVE READINGS
!               (SIGNAL, BUT NO ALARM)
!     GAMMA   = DEFINES CONFIDENCE LIMIT FOR LOD
!               (ALSO DEFINES THE CONFIDENCE FOR THE TOLERANCE
!               LIMIT)
!     PA      = DEFINES THE COVERAGE FACTOR FOR THE TOLERANCE
!               LIMIT
!
      CALL NORPPF(1.0-ALPHA,ZA)
!
!CCCC NOTE 6/2010: ACCORDING TO ANDREW, THE ZA TERM SHOULD NOT
!CCCC              BE SQUARED.
!CCCC ZA=ZA**2
!CCCC AZ=ZA**2
      AZ=ZA
      CALL NORPPF(1.0-BETA,ZB)
      CALL NORPPF(1.0-PA,ZP)
      GA=GAMMA
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
        ISTEPN='2.2'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)
   61   FORMAT('***** FROM DPLOD2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)ZA,GA,ZB,ZP
   62   FORMAT('ZA,GA,ZB,ZP = ',4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     COMPUTE:
!
!       1)  NUMBER OF BLANK (ZERO) MASS VALUES           (M)
!       2)  NUMBER OF DISTINCT MASS VALUES               (NDIST)
!       3)  SAMPLE SIZES FOR EACH GROUP                  (NS)
!       4)  NUMBER OF ZERO RESPONSES IN EACH GROUP       (MU)
!       5)  NUMBER OF NON-ZERO RESPONSES IN EACH GROUP   (NN)
!       6)  MEAN OF NON-ZERO RESPONSES IN EACH GROUP     (YM)
!
!     FOR THE MASS = 0 CASE, COMPUTE SOME STATISTICS
!
      NFINAL=0
      IFLAGY=.FALSE.
      IFLAGZ=.TRUE.
      IALLZ=-99
      IALLP=-99
!
      DO 1100 I=1,NDIST
!
        D(I)=0.0
        BL(I)=0.0
        SU(I)=0.0
        T(I)=0.0
        P(I)=0.0
        MU(I)=0
        NN(I)=0
        IF(I.GT.1)THEN
          LO(I)=0.0
          LU(I)=0.0
          BA(I)=0.0
          UN(I)=0.0
          S(I)=0.0
          TO(I)=0.0
        ELSE
          LO(I)=99.0
          LU(I)=99.0
          BA(I)=99.0
          UN(I)=99.0
          S(I)=99.0
          TO(I)=99.0
        ENDIF
!
        NZERO=0
        NPLUS=0
        NABOVE=0
        NBELOW=0
        HOLD=XIDTEM(I)
        DSUM=0.0D0
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
          ISTEPN='2.30'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,11108)I,HOLD
11108     FORMAT('11108: I,HOLD = ',I6,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        DO 1110 J=1,N
          IF(X(J).EQ.HOLD)THEN
            IF(Y(J).LE.0.0)THEN
              NZERO=NZERO+1
            ELSE
              NPLUS=NPLUS+1
              TEMP1(NPLUS)=Y(J)
              DSUM=DSUM + DBLE(Y(J))
              IF(I.GT.1 .AND. TEMP1(NPLUS).GE.CV)NABOVE=NABOVE+1
            ENDIF
!
            IF(I.EQ.NDIST)THEN
              IF(Y(J).LT.CV)NBELOW=NBELOW+1
            ENDIF
!
            IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
              WRITE(ICOUT,11109)J,X(J),Y(J),NZERO,NPLUS
11109         FORMAT('11109: J,X(J),Y(J),NZERO,NPLUS = ',I6,2G15.7,2I6)
              CALL DPWRST('XXX','BUG ')
            ENDIF
!
          ENDIF
!
 1110   CONTINUE
        NTOTZ=NZERO+NPLUS
        MU(I)=NZERO
        NN(I)=NPLUS
        NS(I)=NTOTZ
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
          ISTEPN='2.3'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1111)I,NZERO,NPLUS,MU(I),NN(I)
 1111     FORMAT('AFTER 1110: I,NZERO,NPLUS,MU(I),NN(I) = ',5I6)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IF(NZERO.GE.1 .AND. NPLUS.GE.1)IFLAGZ=.FALSE.
        IF(IFLAGZ)THEN
          IF(NZERO.EQ.NTOTZ)IALLZ=I
          IF(NPLUS.EQ.NTOTZ .AND. IALLP.LT.0)IALLP=I
        ENDIF
        IF(I.EQ.NDIST)THEN
          NTEMPZ=INT(0.90*REAL(NTOTZ)+0.1)
          NTEMPB=INT(0.10*REAL(NTOTZ)+0.1)
          IF(NZERO.GT.NTEMPZ)THEN
            IFLAGY=.TRUE.
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,101)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7071)
 7071       FORMAT('      More than 90% of the measurements at the')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7072)
 7072       FORMAT('      highest mass level are zero.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7073)
 7073       FORMAT('      The LOD analysis will not be performed.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ELSEIF(NBELOW.GT.NTEMPB)THEN
            IFLAGY=.TRUE.
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,101)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7076)
 7076       FORMAT('      More than 10% of the measurements at the')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7077)
 7077       FORMAT('      highest mass level are less than the ',   &
                   'critical value..')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7073)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7078)
 7078       FORMAT('      It is recommended that you take ',   &
                   'measurements at a higher mass level.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ENDIF
        ELSEIF(I.EQ.2)THEN
          AVAL=REAL(NABOVE)/REAL(NTOTZ)
          IF(AVAL.GT.0.90)THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7180)
 7180       FORMAT('***** WARNING IN LIMITS OF DETECTION--')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7181)
 7181       FORMAT('      More than 90% of the measurements at the ',   &
                   'lowest non-zero')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7183)
 7183       FORMAT('      mass level are greater than the critical ',   &
                   'value.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7185)
 7185       FORMAT('      Although the LOD analysis will still be ',   &
                   'performed,')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7187)
 7187       FORMAT('      it is recommended that measurements be ',   &
                   'taken')
            CALL DPWRST('XXX','WRIT')
            AJUNK=XIDTEM(2)/2.0
            WRITE(ICOUT,7189)AJUNK
 7189       FORMAT('      in the vicinity of ',F12.3)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
          ENDIF
        ENDIF
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
          ISTEPN='2.3B'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,11112)I,NZERO,NPLUS,MU(I),NN(I)
11112     FORMAT('AFTER 7189: I,NZERO,NPLUS,MU(I),NN(I) = ',5I6)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        ATEMP=REAL(NTOTZ)*THRPER + 0.00001
        MINTHR=INT(ATEMP)
        IF(NABOVE.GE.MINTHR)THEN
          IF(NFINAL.EQ.0)THEN
            NFINAL=I
          ELSE
            NFINAL=MIN(I,NFINAL)
          ENDIF
        ELSE
          NFINAL=0
        ENDIF
        IF(NN(I).GT.0)THEN
          YM(I)=REAL(DSUM/DBLE(NN(I)))
          CALL SORT(TEMP1,NPLUS,TEMP1)
        ELSE
          YM(I)=0.0
        ENDIF
!CCCC   IF(I.EQ.1 .AND. NPLUS.LE.4)THEN
!CCCC     CALL MEDIAN(TEMP1,NPLUS,IWRITE,TEMP2,MAXOBV,ZMED,
!CCCC1                IBUGA3,IERROR)
!CCCC     HH=ZMED
!CCCC   ELSEIF(I.EQ.1)THEN
!CCCC     HH=2.0*TEMP1(1) - TEMP1(2)
!CCCC   ENDIF
        IF(I.EQ.1)THEN
          IF(YMINMS.LE.0.0)THEN
            HH=YMIN
          ELSE
!CCCC       HH=2.0*YMIN - TEMP1(2)
            HH=2.0*YMIN - YMIN2
          ENDIF
!
          NUMPAD=NTOTZ-NPLUS
          ICNT=0
          IF(NUMPAD.GT.0)THEN
            DO 1112 II=1,NUMPAD
              ICNT=ICNT+1
              TEMP3(ICNT)=0.0
 1112       CONTINUE
          ENDIF
          DO 1113 II=1,NPLUS
            ICNT=ICNT+1
            TEMP3(ICNT)=TEMP1(II)
 1113     CONTINUE
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
            ISTEPN='2.3C'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,11113)I,NZERO,NPLUS,MU(I),NN(I)
11113       FORMAT('AFTER 7189: I,NZERO,NPLUS,MU(I),NN(I) = ',5I6)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
!CCCC     P100=95.0
          P100=(1.0 - ALPHA)*100.
          CALL PERCEN(P100,TEMP3,NTOTZ,IWRITE,TEMP2,MAXOBV,CV1,   &
                      IBUGA3,IERROR)
        ENDIF
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
          ISTEPN='3.1'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1161)
 1161     FORMAT('***** DPLOD2: AFTER COMPUTE SAMPLE SIZES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1162)I,MU(I),NN(I),NS(I),YM(I)
 1162     FORMAT('I,MU(I),NN(I),NS(I),YM(I) = ',4I8,G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1163)HH,THRPER,NABOVE,NFINAL,MINTHR,CV
 1163     FORMAT('HH,THRPER,NABOVE,NFINAL,MINTHR,CV = ',   &
                 2F10.5,3I8,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!       STATISTICS FOR MASS = 0 VALUES
!
        IF(I.EQ.1)THEN
!
!         IF TOO FEW POSITIVE VALUES, THEN CLEAN CASE IS CALLED.
!
!CCCC     IF(NN(I).LT.2)THEN
!CCCC       WRITE(ICOUT,999)
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC       WRITE(ICOUT,101)
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC       WRITE(ICOUT,1002)
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC       WRITE(ICOUT,1023)
!1023       FORMAT('      AT LEAST TWO NON-ZERO MEASUREMENTS FOR ',
!CCCC1             'MASS = 0.')
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC       WRITE(ICOUT,1024)NN(I)
!1024       FORMAT('      ONLY ',I8,' NON-ZERO MEASUREMENTS FOUND.')
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC       IERROR='YES'
!CCCC       GO TO 9000
!CCCC     ENDIF
          YM1=YM(I)
          CALL VAR(TEMP1,NPLUS,IWRITE,VYN,IBUGA3,IERROR)
          NU1=NN(I)-1
          YV=REAL(NU1)*VYN/REAL(NN(I))
          CALL NORPPF((REAL(MU(I))+0.5)/(REAL(NS(I))+1.0),ZZ)
          QQ=MAX(ZA,ZZ)
          FT=0.5*ZZ*(YM(1)-HH)
          SIG0=FT + SQRT((FT**2) + YV + (YM(I)-HH)**2)
          CV2=YM1 + QQ*SIG0
          AF=HH - SIG0*ZZ
          IF(NU1.GE.1)THEN
            CALL CHSPPF(GA,NU1,GB1)
            GB=SQRT(REAL(NU1)/GB1)
            SU1=GB*SIG0
          ELSE
            GB=CPUMIN
            SU1=CPUMIN
          ENDIF
          SN=((QQ*SIG0)**2)/REAL(NN(I))
          IF(CVUSER.GT.0.0)THEN
            CV=CVUSER
          ELSE
            IF(ILODCV.EQ.'QUAN')THEN
              CV=CV1
            ELSE
              CV=CV2
            ENDIF
          ENDIF
!
          IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
            ISTEPN='3.1'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1171)
 1171       FORMAT('***** DPLOD2: MASS = 0 CASE')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1172)HH,YM(1),VYN,YV,ZZ
 1172       FORMAT('HH,YM(1),VYN,YV,ZZ = ',5G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1173)QQ,FT,SIG0,AF,GA
 1173       FORMAT('QQ,FT,SIG0,AF,GA = ',5G15.7)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1174)NU1,GB1,GB,SU1,SN
 1174       FORMAT('NU1,GB1,GB,SU1,SN = ',I8,4G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
        ENDIF
!
!       COMPUTE MEAN OF Y - AF FOR NON-ZERO VALUES
!
        IF(NPLUS.GE.1)THEN
          CALL SD(TEMP1,NPLUS,IWRITE,XVAR,IBUGA3,IERROR)
        ELSE
          XVAR=0.0
        ENDIF
        YVAR(I)=XVAR
        SUM=0.0
        DO 1180 J=1,NPLUS
          TEMP1(J)=TEMP1(J) - AF
          SUM=SUM + TEMP1(J)**2
 1180   CONTINUE
        IF(NPLUS.GE.1)THEN
          CALL MEAN(TEMP1,NPLUS,IWRITE,YTTM,IBUGA3,IERROR)
        ELSE
          YTTM=0.0
        ENDIF
        YT(I)=YTTM
        YTT(I)=SUM
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
          ISTEPN='3.3'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1192)I,YT(I),YTT(I)
 1192     FORMAT('I,YT(I),YTT(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 1100 CONTINUE
!
      DO 2000 J=2,NDIST
!
        XXNN=0.0
        BAK=0.0
        SYY2=0.0
        ITN=0
        DO 2010 I=2,J
          XXNN=XXNN + XIDTEM(I)**2*REAL(NN(I))
          BAK=BAK + XIDTEM(I)*YT(I)*REAL(NN(I))
          SYY2=SYY2 + YTT(I)
          ITN=ITN + NN(I)
 2010   CONTINUE
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
          ISTEPN='4.1'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2061)
 2061     FORMAT('***** DPLOD2: AT 2010')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2062)J,XXNN,BAK,SYY2,ITN
 2062     FORMAT('J,XXNN,BAK,SYY2,ITN = ',I8,3G15.7,I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2063)J,SIG0,ZB,QQ,GA
 2063     FORMAT('J,SIG0,ZB,QQ,GA = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!CCCC   MAY 2009: IF B1K1 IS NEGATIVE, THEN VALUES COMPUTED
!CCCC             FOR LU(J) AND TO(J) TEND TO BE NONSENSE.
!CCCC             SO IN THIS CASE, SET THEM TO "CPUMIN" (THESE
!CCCC             WILL BE PRINTED AS "**").
!CCCC
!CCCC   JULY 2009: IF GB (COMPUTED ABOVE) = CPUMIN, THEN LIKEWISE
!CCCC              SET LU(J) AND TO(J) TO CPUMIN.
!
        ITN=ITN-1
        IF(GB.EQ.CPUMIN .OR. ITN.LT.1)THEN
          BA(J)=CPUMIN
          SI(J)=CPUMIN
          LO(J)=CPUMIN
          UN(J)=CPUMIN
          LU(J)=CPUMIN
          TO(J)=CPUMIN
        ELSE
          DD=1.0/SQRT(XXNN)
          BA(J)=BAK/XXNN
          UA(J)=(SYY2 - BA(J)*BAK)/REAL(ITN)
          SI(J)=SQRT(UA(J))
          CALL TPPF(1.0 - 0.5*GA,REAL(ITN),TTK)
          T(J)=TTK
          B1K1=BA(J)-(DD*T(J)*SI(J))
          B1K2=0.000001
          B1(J)=MAX(B1K1,0.000001)
          CALL CHSPPF(GA/2.0,ITN,PPK)
          P(J)=PPK
          SU(J)=SI(J)*SQRT(REAL(ITN)/P(J))
          LO(J)=(QQ*SIG0 + ZB*SI(J))/BA(J)
          LU(J)=(QQ*SU1 + ZB*SU(J))/B1(J)
          S(J)=(SN + (AZ*UA(J)/REAL(ITN)) + UA(J)*(DD**2)*   &
               (LO(J)**2))/BA(J)/BA(J)
          UN(J)=SQRT(S(J))
          TO(J)=(QQ*SU1 + (ZB+ZP)*SU(J))/B1(J)
!
          IF(B1(J).EQ.B1K2)THEN
            LU(J)=CPUMIN
            TO(J)=CPUMIN
          ENDIF
!
        ENDIF
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
          ISTEPN='4.2'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2072)J,DD,BA(J),UA(J),SI(J),TTK,B1K1
 2072     FORMAT('J,DD,BA(J),UA(J),SI(J),TTK,B1K1 = ',I8,6G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2073)J,B1(J),P(J),SU(J),LO(J)
 2073     FORMAT('J,B1(J),P(J),SU(J),LO(J) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2074)J,LU(J),S(J),UN(J),TO(J)
 2074     FORMAT('J,LU(J),S(J),UN(J),TO(J) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!
 2000 CONTINUE
!
      SI(1)=SIG0
!
!     NOTE 4/2009: CHECK IF MORE BLANK MEASUREMENTS NEEDED.
!
!     NOTE 5/2009: THIS RULE CHANGED SO THAT A MAXIMUM OF 20
!                  BLANKS CALLED FOR ABOVE.
!
!CCCC DELTA=0.8
!CCCC M0=NN(1)
!CCCC CALL CHSPPF(DELTA,M0,ATEMP)
!CCCC STEMP=(SIG0/ATEMP) - 1.0
!CCCC IF(STEMP.LE.0.0)THEN
!CCCC   IFLAG9=0
!CCCC   NFINAL=NFINAL+1
!CCCC   IF(NFINAL.GT.NDIST)NFINAL=NDIST
!CCCC   ALOD=LO(NFINAL)
!CCCC   ALODSE=UN(NFINAL)
!CCCC ELSE
!CCCC   IFLAG9=1
!CCCC   AMORE=REAL(M0)*STEMP
!CCCC   NMORE=INT(AMORE+0.99)
!CCCC ENDIF
!
      IF(NFINAL.EQ.0)NFINAL=NDIST
      IFLAG9=0
      ALOD=LO(NFINAL)
      ALODSE=UN(NFINAL)
      ALODLU=LU(NFINAL)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
        ISTEPN='4.3'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2082)NFINAL
 2082   FORMAT('NFINAL,ALOD,ALODSE = ',I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IVAL1=INT(100.0*(1.0 - GAMMA)+0.1)
      IVAL2=INT(100.0*(1.0 - GAMMA)+0.1)
      IVAL3=INT(100.0*(1.0 - PA)+0.1)
!
!               **************************************************
!               **  STEP 5--                                    **
!               **   OPEN THE STORAGE FILES, WRITE RELEVANT     **
!               **   QUANTITIES TO FILE, AND THEN CLOSE         **
!               **   STORAGE FILES.                             **
!               **************************************************
!
      ISTEPN='5'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOD2')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ILODOF.EQ.'OFF')GO TO 3019
!
      IOP='OPEN'
      IFLG1=1
      IFLG2=1
      IFLG3=0
      IFLG4=0
      IFLG5=0
      CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      DO 3010 I=1,NDIST
        WRITE(IOUNI1,3012)XIDTEM(I),REAL(MU(I)),REAL(NN(I)),YT(I),   &
                          YVAR(I)
        WRITE(IOUNI2,3012)XIDTEM(I),BA(I),SI(I),LO(I),UN(I),LU(I),   &
                          TO(I)
 3012   FORMAT(7E15.7)
 3010 CONTINUE
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
!
 3019 CONTINUE
!
      NUMDIG=4
      IF(IFORSW.EQ.'1')NUMDIG=2
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=10
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      CALL DPCONA(92,IBASLC)
!
      IF(YCONST.GT.0.5)THEN
        CV=CV - YCONST
      ENDIF
!
!     WRITE "FINAL" ESTIMATES SEPARATELY
!
!     2014/03: TO BE CONSISTENT WITH ASTM E2677 STANDARD, CHANGE
!              "Scxx.x"  to   "CVxx.x" AND CHANGE  "LDxx"  TO  "LODxx".
!
      IF(IPRINT.EQ.'ON')THEN
!
        ITITLE='Limits of Detection Analysis'
        NCTITL=28
        ITITL9='(Based on ASTM E-2677 Standard)'
        NCTIT3=31
!
        ICNT=1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Response Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Mass Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(2)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(2)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        IF(PID(3).NE.CPUMIN)THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Group-ID Variable: '
          WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(3)(1:4)
          WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(3)(1:4)
          NCTEXT(ICNT)=27
          AVALUE(ICNT)=PID(3)
          IDIGIT(ICNT)=0
        ENDIF
!
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        IF(IFLAG9.EQ.0)THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Final Estimate:'
          NCTEXT(ICNT)=15
          AVALUE(ICNT)=0.0
          IDIGIT(ICNT)=-1
          IF(ILODPC.EQ.'ON')THEN
            ICNT=ICNT+1
            IF(ALPHA.EQ.0.05)THEN
              ITEXT(ICNT)='Critical Value (Cv95):'
              NCTEXT(ICNT)=22
            ELSEIF(ALPHA.EQ.0.10)THEN
              ITEXT(ICNT)='Critical Value (Cv90):'
              NCTEXT(ICNT)=22
            ELSEIF(ALPHA.EQ.0.01)THEN
              ITEXT(ICNT)='Critical Value (Cv99):'
              NCTEXT(ICNT)=22
            ELSE
              ITEXT(ICNT)='Critical Value (Cvxx.x):'
              ATEMP=100.*(1.0 - ALPHA)
              WRITE(ITEXT(ICNT)(19:22),'(F4.1)')ATEMP
              NCTEXT(ICNT)=24
            ENDIF
            AVALUE(ICNT)=CV
            IDIGIT(ICNT)=NUMDIG
          ENDIF
!
          ICNT=ICNT+1
          IF(ALPHA.EQ.0.05)THEN
            ITEXT(ICNT)='Detection Limit (LOD95):'
            NCTEXT(ICNT)=24
          ELSEIF(ALPHA.EQ.0.10)THEN
            ITEXT(ICNT)='Detection Limit (LOD90):'
            NCTEXT(ICNT)=24
          ELSEIF(ALPHA.EQ.0.01)THEN
            ITEXT(ICNT)='Detection Limit (LOD99):'
            NCTEXT(ICNT)=24
          ELSE
            ITEXT(ICNT)='Detection Limit (LODxx.x):'
            NCTEXT(ICNT)=26
            ATEMP=100.*(1.0 - ALPHA)
            WRITE(ITEXT(ICNT)(21:24),'(F4.1)')ATEMP
          ENDIF
          AVALUE(ICNT)=ALOD
          IDIGIT(ICNT)=NUMDIG
!
          ICNT=ICNT+1
          IF(GAMMA.EQ.0.05)THEN
            ITEXT(ICNT)='95% Upper Confidence Limit on LOD:'
            NCTEXT(ICNT)=34
          ELSEIF(ALPHA.EQ.0.10)THEN
            ITEXT(ICNT)='90% Upper Confidence Limit on LOD:'
            NCTEXT(ICNT)=34
          ELSEIF(ALPHA.EQ.0.01)THEN
            ITEXT(ICNT)='99% Upper Confidence Limit on LOD:'
            NCTEXT(ICNT)=34
          ELSE
            ITEXT(ICNT)='xx.x% Upper Confidence Limit on LOD:'
            NCTEXT(ICNT)=36
            ATEMP=100.*(1.0 - GAMMA)
            WRITE(ITEXT(ICNT)(1:4),'(F4.1)')ATEMP
          ENDIF
          AVALUE(ICNT)=ALODLU
          IDIGIT(ICNT)=NUMDIG
!
          NUMROW=ICNT
          DO 4210 I=1,NUMROW
            NTOT(I)=15
 4210     CONTINUE
!
          IFRST=.TRUE.
          ILAST=.TRUE.
!
          ISTEPN='42A'
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOD2')   &
             CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
          CALL DPDTA1(ITITLE,NCTITL,ITITL9,NCTIT3,ITEXT,NCTEXT,   &
                      AVALUE,IDIGIT,   &
                      NTOT,NUMROW,   &
                      ICAPSW,ICAPTY,ILAST,IFRST,   &
                      ISUBRO,IBUGA3,IERROR)
!
          ISTEPN='42B'
          IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'GRU2')   &
             CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        ELSEIF(IFLAGZ)THEN
          ATEMP=0.0
          NUMDIG=-1
          ISIZE=0
          IRTFMD='OFF'
          IFLAGA=.TRUE.
          IFLAGB=.FALSE.
          NTOTAL=50
          NBLNK1=0
          NBLNK2=0
          ITYPE2=2
          ITTEXT(1:42)='Measurements at each mass level are either'
          NCTEMP=42
          CALL DPDTXT(ITTEXT,NCTEMP,ATEMP,NUMDIG,NTOTAL,   &
                      NBLNK1,NBLNK2,IFLAGA,IFLAGB,ISIZE,   &
                      ICAPSW,ICAPTY,ITYPE2,ISUBRO,IBUGA3,IERROR)
          IFLAGA=.FALSE.
          ITTEXT(1:44)='all zero or all non-zero.  It is recommended'
          NCTEMP=44
          CALL DPDTXT(ITTEXT,NCTEMP,ATEMP,NUMDIG,NTOTAL,   &
                      NBLNK1,NBLNK2,IFLAGA,IFLAGB,ISIZE,   &
                      ICAPSW,ICAPTY,ITYPE2,ISUBRO,IBUGA3,IERROR)
          ITTEXT(1:44)='that you take additional measurements in the'
          NCTEMP=44
          CALL DPDTXT(ITTEXT,NCTEMP,ATEMP,NUMDIG,NTOTAL,   &
                      NBLNK1,NBLNK2,IFLAGA,IFLAGB,ISIZE,   &
                      ICAPSW,ICAPTY,ITYPE2,ISUBRO,IBUGA3,IERROR)
          ITTEXT(1:12)='vicinity of '
          NCTEMP=12
          ATEMP=(XIDTEM(IALLZ)+XIDTEM(IALLP))/2.0
          NTOTAL=25
          NBLNK1=0
          NBLNK2=1
          IFLAGB=.TRUE.
          CALL DPDTXT(ITTEXT,NCTEMP,ATEMP,NUMDIG,NTOTAL,   &
                      NBLNK1,NBLNK2,IFLAGA,IFLAGB,ISIZE,   &
                      ICAPSW,ICAPTY,ITYPE2,ISUBRO,IBUGA3,IERROR)
!CCCC   ELSE
!CCCC     ISIZE=0
!CCCC     IRTFMD='OFF'
!CCCC     IFLAGA=.TRUE.
!CCCC     IFLAGB=.FALSE.
!CCCC     NTOTAL=40
!CCCC     NBLNK1=0
!CCCC     NBLNK2=0
!CCCC     ITYPE2=2
!CCCC     ITTEXT(1:33)='It is recommended that you take '
!CCCC     NCTEMP=33
!CCCC     ATEMP=REAL(NMORE)
!CCCC     NUMDIG=0
!CCCC     CALL DPDTXT(ITTEXT,NCTEMP,ATEMP,NUMDIG,NTOTAL,
!CCCC1                NBLNK1,NBLNK2,IFLAGA,IFLAGB,ISIZE,
!CCCC1                ICAPSW,ICAPTY,ITYPE2,ISUBRO,IBUGA3,IERROR)
!CCCC     IFLAGA=.FALSE.
!CCCC     ITTEXT(1:30)='additional blank measurements.'
!CCCC     NCTEMP=30
!CCCC     NBLNK1=0
!CCCC     NBLNK2=1
!CCCC     IFLAGB=.TRUE.
!CCCC     ATEMP=0.0
!CCCC     NUMDIG=-1
!CCCC     CALL DPDTXT(ITTEXT,NCTEMP,ATEMP,NUMDIG,NTOTAL,
!CCCC1                NBLNK1,NBLNK2,IFLAGA,IFLAGB,ISIZE,
!CCCC1                ICAPSW,ICAPTY,ITYPE2,ISUBRO,IBUGA3,IERROR)
        ENDIF
!
      ENDIF
!
!     PRINT TABLES
!
      IF(ILODST.EQ.'OFF' .OR. IPRINT.EQ.'OFF')GO TO 4199
!
!CCCC NCTIT9=28
!CCCC ITITL9(1:NCTIT9)='LIMITS OF DETECTION ANALYSIS'
      NCTIT9=0
      ITITL9=' '
      NCTITL=13
      ITITLE(1:NCTITL)='Summary Table'
      NUMLIN=2
      NUMCOL=5
      ITITL2(1,1)='Mass'
      ITITL2(2,1)='Values'
      ITITL2(1,2)='Number of'
      ITITL2(2,2)='Zero Values'
      ITITL2(1,3)='Number of'
      ITITL2(2,3)='Non-Zero Values'
      ITITL2(1,4)='Mean of'
      ITITL2(2,4)='Non-Zero Values'
      ITITL2(1,5)='SD of'
      ITITL2(2,5)='Non-Zero Values'
      NCTIT2(1,1)=4
      NCTIT2(2,1)=6
      NCTIT2(1,2)=9
      NCTIT2(2,2)=11
      NCTIT2(1,3)=9
      NCTIT2(2,3)=15
      NCTIT2(1,4)=7
      NCTIT2(2,4)=15
      NCTIT2(1,5)=5
      NCTIT2(2,5)=15
      NMAX=0
      NTOT(1)=15
      NTOT(2)=15
      NTOT(3)=19
      NTOT(4)=19
      NTOT(5)=18
      DO 4010 J=1,NUMCOL
        VALIGN(J)='b'
        ALIGN(J)='r'
        NMAX=NMAX+NTOT(J)
        IDIGIT(J)=NUMDIG
        IWHTML(J)=125
 4010 CONTINUE
      IWHTML(NUMCOL+1)=125
      VALIGN(NUMCOL+1)='b'
      ALIGN(NUMCOL+1)='r'
      IDIGIT(2)=0
      IDIGIT(3)=0
      DO 4020 I=1,NDIST
        NCTEXT(I)=0
        ITEXT(I)=' '
        AMAT(I,1)=XIDTEM(I)
        AMAT(I,2)=REAL(MU(I))
        AMAT(I,3)=REAL(NN(I))
        AMAT(I,4)=YM(I) - YCONST
        AMAT(I,5)=YVAR(I)
 4020 CONTINUE
      IWRTF(1)=1400
      IWRTF(2)=IWRTF(1)+1600
      IWRTF(3)=IWRTF(2)+1600
      IWRTF(4)=IWRTF(3)+1600
      IWRTF(5)=IWRTF(4)+1600
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
        ISTEPN='4.4'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4111)
 4111   FORMAT('BEFORE PRINT SUMMARY TABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4112)NCTIT9,NCTITL,MAXLIN,NUMLIN,NUMCOL,MAXROW
 4112   FORMAT('NCTIT9,NCTITL,MAXLIN,NUMLIN,NUMCOL,MAXROW = ',6I6)
        CALL DPWRST('XXX','BUG ')
        DO 4120 I=1,NUMLIN
          DO 4130 J=1,NUMCOL
            WRITE(ICOUT,4122)I,J,ITITL2(I,J),NCTIT2(I,J),AMAT(I,J)
 4122       FORMAT('I,J,ITITL2(I,J),NCTIT2(I,J),AMAT(I,J) = ',   &
                   2I6,A40,I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 4130     CONTINUE
 4120   CONTINUE
      ENDIF
!
      CALL DPDTA2(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,MAXCOL,NUMCOL,   &
                  ITEXT,NCTEXT,AMAT,MAXROW,NDIST,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
        WRITE(ICOUT,4132)
 4132   FORMAT('RETURN FROM DPDTA2')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 4199 CONTINUE
!
      IF(ILODTA.EQ.'OFF' .OR. IPRINT.EQ.'OFF')GO TO 5199
!
      NCTIT9=0
      ITITL9(1:NCTIT9)=' '
      NCTITL=9
      ITITLE(1:NCTITL)='LOD Table'
      NUMLIN=4
      NUMCOL=7
!
      ITITL2(1,1)=' '
      ITITL2(2,1)=' '
      ITITL2(3,1)='Mass'
      ITITL2(4,1)='Values'
      NCTIT2(1,1)=0
      NCTIT2(2,1)=0
      NCTIT2(3,1)=4
      NCTIT2(4,1)=6
!
      ITITL2(1,2)='Linear'
      ITITL2(2,2)='Least Squares'
      ITITL2(3,2)='Slope'
      ITITL2(4,2)='Estimates'
      NCTIT2(1,2)=6
      NCTIT2(2,2)=13
      NCTIT2(3,2)=5
      NCTIT2(4,2)=9
!
      ITITL2(1,3)='StdDev of'
      ITITL2(2,3)='Errors From'
      ITITL2(3,3)='Linear'
      ITITL2(4,3)='Model'
      NCTIT2(1,3)=9
      NCTIT2(2,3)=11
      NCTIT2(3,3)=6
      NCTIT2(4,3)=5
!
      ITITL2(1,4)='LOD Estimate'
      ITITL2(2,4)='Based On'
      ITITL2(3,4)='Cumulated'
      ITITL2(4,4)='Sample'
      NCTIT2(1,4)=12
      NCTIT2(2,4)=8
      NCTIT2(3,4)=9
      NCTIT2(4,4)=6
!
      ITITL2(1,5)='1-Sigma'
      ITITL2(2,5)='Uncertainty'
      ITITL2(3,5)='on LOD'
      ITITL2(4,5)='Estimate'
      NCTIT2(1,5)=7
      NCTIT2(2,5)=11
      NCTIT2(3,5)=6
      NCTIT2(4,5)=8
!
!     BASE ON ACTUAL VALUE OF GAMMA
!
      ITITL2(1,6)=' '
      IF(GAMMA.EQ.0.05)THEN
        ITITL2(2,6)='95% Upper'
        NCTIT2(2,6)=9
      ELSEIF(GAMMA.EQ.0.10)THEN
        ITITL2(2,6)='90% Upper'
        NCTIT2(2,6)=9
      ELSEIF(GAMMA.EQ.0.01)THEN
        ITITL2(2,6)='99% Upper'
        NCTIT2(2,6)=9
      ELSE
        ATEMP=100.*(1.0 - GAMMA)
        ITITL2(2,6)='xx.x% Upper'
        WRITE(ITITL2(2,6)(1:4),'(F4.1)')ATEMP
        NCTIT2(2,6)=11
      ENDIF
      ITITL2(3,6)='Confidence'
      ITITL2(4,6)='Limit on LOD'
      NCTIT2(1,6)=0
      NCTIT2(3,6)=10
      NCTIT2(4,6)=12
!
      IF(GAMMA.EQ.0.05.AND.PA.EQ.0.05)THEN
        ITITL2(1,7)='95%-95%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.10.AND.PA.EQ.0.05)THEN
        ITITL2(1,7)='90%-95%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.01.AND.PA.EQ.0.05)THEN
        ITITL2(1,7)='99%-95%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.10.AND.PA.EQ.0.10)THEN
        ITITL2(1,7)='90%-90%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.05.AND.PA.EQ.0.10)THEN
        ITITL2(1,7)='95%-90%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.01.AND.PA.EQ.0.10)THEN
        ITITL2(1,7)='99%-90%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.10.AND.PA.EQ.0.01)THEN
        ITITL2(1,7)='90%-99%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.05.AND.PA.EQ.0.01)THEN
        ITITL2(1,7)='95%-99%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.01.AND.PA.EQ.0.01)THEN
        ITITL2(1,7)='99%-99%'
        NCTIT2(1,7)=7
      ELSE
        ITITL2(1,7)='xx.x%-xx.x%'
        ATEMP=100.*(1.0 - GAMMA)
        WRITE(ITITL2(1,7)(1:4),'(F4.1)')ATEMP
        ATEMP=100.*(1.0 - PA)
        WRITE(ITITL2(1,7)(7:10),'(F4.1)')ATEMP
        NCTIT2(1,7)=11
      ENDIF
      ITITL2(2,7)='Upper'
      ITITL2(3,7)='Tolerance'
      ITITL2(4,7)='Limit on LOD'
      NCTIT2(2,7)=5
      NCTIT2(3,7)=9
      NCTIT2(4,7)=12
!
      NMAX=0
      DO 5010 J=1,NUMCOL
        NTOT(J)=15
        VALIGN(J)='b'
        ALIGN(J)='r'
        NMAX=NMAX+NTOT(J)
        IDIGIT(J)=NUMDIG
        IWHTML(J)=150
 5010 CONTINUE
      IWHTML(1)=125
      IWHTML(2)=175
      IWHTML(4)=175
      IWHTML(NUMCOL+1)=150
      VALIGN(NUMCOL+1)='b'
      ALIGN(NUMCOL+1)='r'
      DO 5020 I=1,NDIST
        NCTEXT(I)=0
        AMAT(I,1)=XIDTEM(I)
        IF(I.EQ.1)THEN
          AMAT(I,2)=CPUMIN
          AMAT(I,3)=CPUMIN
          AMAT(I,4)=CPUMIN
          AMAT(I,5)=CPUMIN
          AMAT(I,6)=CPUMIN
          AMAT(I,7)=CPUMIN
        ELSE
          AMAT(I,2)=BA(I)
          AMAT(I,3)=SI(I)
          AMAT(I,4)=LO(I)
          AMAT(I,5)=UN(I)
          AMAT(I,6)=LU(I)
          AMAT(I,7)=TO(I)
        ENDIF
 5020 CONTINUE
      IWRTF(1)=900
      IWRTF(2)=IWRTF(1)+1150
      IWRTF(3)=IWRTF(2)+1150
      IWRTF(4)=IWRTF(3)+1150
      IWRTF(5)=IWRTF(4)+1150
      IWRTF(6)=IWRTF(5)+1150
      IWRTF(7)=IWRTF(6)+1150
      IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF ')THEN
        IPTSZ=14
        CALL DPCONA(92,IBASLC)
        WRITE(ICOUT,8199)IBASLC,IPTSZ
 8199   FORMAT(A1,'fs',I2)
        CALL DPWRST(ICOUT,'WRIT')
      ENDIF
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
        ISTEPN='4.4'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5111)
 5111   FORMAT('BEFORE PRINT LOD TABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4112)NCTIT9,NCTITL,MAXLIN,NUMLIN,NUMCOL,MAXROW
        CALL DPWRST('XXX','BUG ')
        DO 5120 I=1,NUMLIN
          DO 5130 J=1,NUMCOL
            WRITE(ICOUT,4122)I,J,ITITL2(I,J),NCTIT2(I,J),AMAT(I,J)
            CALL DPWRST('XXX','BUG ')
 5130     CONTINUE
 5120   CONTINUE
      ENDIF
!
      IFRST=.TRUE.
      ILAST=.TRUE.
      CALL DPDTA2(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,MAXCOL,NUMCOL,   &
                  ITEXT,NCTEXT,AMAT,MAXROW,NDIST,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
 5199 CONTINUE
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
        WRITE(ICOUT,4132)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF ')THEN
        IPTSZ=IRTFPS
        WRITE(ICOUT,8199)IBASLC,IPTSZ
        CALL DPWRST(ICOUT,'WRIT')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD2')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLOD2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,IBUGA3
 9012   FORMAT('IERROR,IBUGA3 = ',A4,1X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N
 9013   FORMAT('N = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLOD2
      SUBROUTINE DPLOD3(Y,X,N,   &
                        XIDTEM,TEMP1,YT,YM,   &
                        D,BA,BL,SU,T,P,LO,LU,S,UN,TO,UA,SI,B1,YTT,YVAR,   &
                        NS,MU,NN,   &
                        ALPHA,BETA,GAMMA,PA,THRPER,CVUSER,   &
                        ALOD,ALODSE,CV,ALODLU,   &
                        IVARID,IVARI2,PID,   &
                        IWRITE,MAXOBV,   &
                        IFORSW,YMIN,YMIN2,   &
                        ICASAN,ICAPSW,ICAPTY,   &
                        ISUBRO,IBUGA3,IERROR)
!
!     PURPOSE--PERFORM A LIMITS OF DETECTION ANALYIS.  SPECIFICALLY,
!              WE ARE CHECKING FOR A LOWER LIMIT OF DETECTION.
!              IT IS ASSUMED THAT WE CANNOT MEASURE THE MASS BELOW
!              A CERTAIN DETECTION LIMIT AND WE NEED TO DETERMINE
!              WHAT THAT DETECTION LIMIT IS.  THERE ARE 2 CASES:
!
!                  1) FOR A ZERO MASS, THE MEASUREMENT WILL ALWAYS
!                     RETURN A ZERO VALUE.  THIS WILL BE REFERRED
!                     TO AS THE "CLEAN" CASE".
!
!                  2) FOR A ZERO MASS, THE MEASUREMENT MAY BE A
!                     NON-ZERO VALUE.  THIS WILL BE REFERRED TO AS
!                     THE DIRTY CASE.
!
!              THE DATA CONSISTS OF A MASS VALUE ("X") AND A
!              MEASURED VALUE ("Y").  THE COMMAND SYNTAX IS:
!
!                  CLEAN LIMIT OF DETECTION  Y   X
!                  DIRTY LIMIT OF DETECTION  Y   X
!                  LIMIT OF DETECTION  Y   X
!
!              IF THE CLEAN/DIRTY CASE IS NOT SPECIFIED, ASSUME
!              THE DIRTY CASE.  THIS SUBROUTINE PERFORMS THE
!              COMPUTATIONS FOR THE "CLEAN" CASE.  PERFORM A CHECK
!              THAT ALL MEASUREMENTS FOR THE ZERO MASS ARE INDEED
!              ZERO (IF NOT, PRINT AN ERROR AND RETURN).
!
!     PRINTING--YES
!     SUBROUTINES NEEDED--NORPPF, CHSPPF
!     WRITTEN BY--JAMES FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL BUREAU OF STANDARDS.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2009/1
!     ORIGINAL VERSION--JANUARY   2009.
!     UPDATED         --MAY       2009. SOME REFINEMENTS
!     UPDATED         --JUNE      2009. SOME ADDITINAL REFINEMENTS
!     UPDATED         --APRIL     2010. NEED TO CORRECT COMPUTATION
!                                       OF "LO" FOR THE CASE WHERE
!                                       WE HAVE ALL ZERO RESPONSES
!                                       FOR A NON-ZERO MASS
!     UPDATED         --JANUARY   2011. ALLOW USER-SPECIFIED CRITICAL
!                                       VALUE
!     UPDATED         --JULY      2012. USER OPTION AS TO WHETHER TO
!                                       PRINT EACH OF THE TABLES
!     UPDATED         --MARCH     2014. THIS LOD ANALYSIS IS NOW AN
!                                       OFFICIAL ASTM STANDARD (E2677).
!                                       A FEW TWEAKS IN THE OUTPUT TO
!                                       BE CONSISTENT WITH E2677.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES--------------
!
      CHARACTER*4 IVARID(*)
      CHARACTER*4 IVARI2(*)
!
      CHARACTER*4 IFORSW
      CHARACTER*4 ICASAN
      CHARACTER*4 ICAPSW
      CHARACTER*4 ICAPTY
      CHARACTER*4 ISUBRO
      CHARACTER*4 IBUGA3
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*1 IBASLC
      CHARACTER*4 IOP
!
!----------------------------------------------------------------
!
      REAL Y(*)
      REAL X(*)
      REAL TEMP1(*)
      REAL YT(*)
      REAL YM(*)
      REAL XIDTEM(*)
!
      INTEGER NS(*)
      INTEGER MU(*)
      INTEGER NN(*)
!
      REAL D(*)
      REAL BA(*)
      REAL BL(*)
      REAL SU(*)
      REAL T(*)
      REAL P(*)
      REAL LO(*)
      REAL LU(*)
      REAL S(*)
      REAL UN(*)
      REAL TO(*)
      REAL UA(*)
      REAL SI(*)
      REAL B1(*)
      REAL YTT(*)
      REAL YVAR(*)
      REAL PID(*)
!
      REAL ZERO
      REAL EPS
!
      DOUBLE PRECISION DSUM
!
      INCLUDE 'DPCOST.INC'
!
      PARAMETER(MAXLIN=4)
      PARAMETER(MAXROW=30)
      PARAMETER(MAXCOL=8)
      CHARACTER*4  ALIGN(MAXCOL)
      CHARACTER*4  VALIGN(MAXCOL)
      INTEGER      IDIGIT(MAXCOL)
      INTEGER      NTOT(MAXCOL)
      INTEGER      NCTEXT(MAXROW)
      CHARACTER*60 ITEXT(MAXROW)
      CHARACTER*40 ITITL9
      CHARACTER*40 ITITLE
      CHARACTER*60 ITTEXT
      CHARACTER*40 ITITL2(MAXLIN,MAXCOL)
      INTEGER      NCTIT2(MAXLIN,MAXCOL)
      INTEGER      IWHTML(MAXCOL)
      INTEGER      IWRTF(MAXCOL)
      REAL         AMAT(MAXROW,MAXCOL)
      REAL         AVALUE(MAXROW)
!
      LOGICAL IFLAGA
      LOGICAL IFLAGB
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IRTFMD
      COMMON/COMRTF/IRTFMD
!
      LOGICAL IFLAGY
      LOGICAL IFLAGZ
!
      INCLUDE 'DPCOP2.INC'
!
      DATA ZERO /0.0/
      DATA EPS  /0.1E-7/
!
!-----START POINT------------------------------------------------
!
      IERROR='NO'
      ISUBN1='DPLO'
      ISUBN2='D3  '
!
      SIG0=0.0
      AZ=0.0
!
      NUMDIG=4
      IF(IFORSW.EQ.'1')NUMDIG=2
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=7
      IF(IFORSW.EQ.'9')NUMDIG=7
      IF(IFORSW.EQ.'0')NUMDIG=7
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      IF(THRPER.EQ.CPUMIN)THRPER=0.6
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLOD3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)N,ALPHA,BETA,GAMMA,PA
   52   FORMAT('N,ALPHA,BETA,GAMMA,PA = ',I8,4G15.7)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASAN,THRPER,CVUSER,MAXOBV
   53   FORMAT('ICASAN,THRPER,CVUSER,MAXOBV = ',A4,2X,2G15.7,I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,N
          WRITE(ICOUT,56)I,Y(I),X(I)
   56     FORMAT('I,Y(I),X(I) = ',I8,2G15.7)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               **  BASICALLY, NEGATIVE VALUES ARE        **
!               **  CONSIDERED ERRORS.                    **
!               ********************************************
!
      IF(N.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
  101   FORMAT('***** ERROR IN LIMITS OF DETECTION--')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,102)
  102   FORMAT('      THE NUMBER OF OBSERVATIONS FOR THE LIMITS OF ',   &
               'DETECTION')
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,103)N
  103   FORMAT('      MUST BE AT LEAST 2;  THE ENTERED NUMBER OF ',   &
               'OBSERVATIONS = ',I8)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      DO 200 I=1,N
        IF(ABS(X(I)).LE.EPS)X(I)=ZERO
        IF(Y(I).LT.ZERO)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,202)
  202     FORMAT('      A NEGATIVE VALUE WAS ENCOUNTERED FOR ',   &
                 'THE MEASURED VALUE')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,204)I,Y(I)
  204     FORMAT('      ROW ',I8,' HAS THE VALUE ',G15.7)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(X(I).LT.ZERO)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,212)
  212     FORMAT('      A NEGATIVE VALUE WAS ENCOUNTERED FOR ',   &
                 'THE MASS VALUE')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,204)I,X(I)
          CALL DPWRST('XXX','WRIT')
          IERROR='YES'
          GO TO 9000
        ELSEIF(X(I).EQ.ZERO .AND. Y(I).GT.EPS)THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,101)
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,222)
  222     FORMAT('      FOR A ZERO MASS VALUE, A NON-ZERO ',   &
                 'MEASUREMENT WAS DETECTED.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,223)
  223     FORMAT('      FOR THIS CASE, YOU NEED TO USE THE DIRTY ',   &
                 'LIMITS OF DETECTION COMMAND')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,224)
  224     FORMAT('      RATHER THAN THE CLEAN LIMITS OF DETECTION ',   &
                 'COMMAND.')
          CALL DPWRST('XXX','WRIT')
          WRITE(ICOUT,228)I,X(I),Y(I)
  228     FORMAT('      ROW ',I8,' HAS MASS VALUE ',G15.7, ' AND ',   &
                 'MEASUREMENT ',G15.7)
          IERROR='YES'
          GO TO 9000
        ENDIF
  200 CONTINUE
!
!               ***********************************************
!               **  STEP 2.1--                               **
!               **  PERFORM THE BASIC CALCULATIONS.          **
!               ***********************************************
!
      ISTEPN='2.1'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOD3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
      CALL SORTC(X,Y,N,X,TEMP1)
      DO 1005 I=1,N
        Y(I)=TEMP1(I)
 1005 CONTINUE
!
!     ALPHA   = CRITICAL LEVEL
!     BETA    = LOD UNCERTAINTY CONFIDENCE
!     GAMMA   = UPPER CONFIDENCE BOUND
!     PA      = TOLERANCE BOUND SIGNIFICANCE
!
!CCCC NOTE 6/2010: ACCORDING TO ANDREW RUKHIN, THE ZA TERM SHOULD NOT BE
!CCCC              SQUARED.
!
      CALL NORPPF(1.0-ALPHA,ZA)
!CCCC AZ=ZA**2
!CCCC ZA=ZA**2
      AZ=ZA
      CALL NORPPF(1.0-BETA,ZB)
      CALL NORPPF(1.0-PA,ZP)
      GA=GAMMA
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD3')THEN
        ISTEPN='2.2'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)
   61   FORMAT('***** FROM DPLOD3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)ZA,ZB,ZP
   62   FORMAT('ZA,ZB,ZP = ',3G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     COMPUTE:
!
!       1)  NUMBER OF BLANK (ZERO) MASS VALUES           (M)
!       2)  NUMBER OF DISTINCT MASS VALUES               (NDIST)
!       3)  SAMPLE SIZES FOR EACH GROUP                  (NS)
!       4)  NUMBER OF ZERO RESPONSES IN EACH GROUP       (MU)
!       5)  NUMBER OF NON-ZERO RESPONSES IN EACH GROUP   (NN)
!       6)  MEAN OF NON-ZERO RESPONSES IN EACH GROUP     (YM)
!
!     FOR THE MASS = 0 CASE, COMPUTE SOME STATISTICS
!
      CALL DISTIN(X,N,IWRITE,XIDTEM,NDIST,IBUGA3,IERROR)
!
      IF(NDIST.LT.2)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1012)
 1012   FORMAT('      THE NUMBER OF DISTINCT MASS VALUES IS LESS ',   &
               'THAN 2')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ELSEIF(NDIST.EQ.N)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,101)
        CALL DPWRST('XXX','WRIT')
        WRITE(ICOUT,1013)
 1013   FORMAT('      THE NUMBER OF DISTINCT MASS VALUES IS EQUAL TO ',   &
               'THE SAMPLE SIZE')
        CALL DPWRST('XXX','WRIT')
        IERROR='YES'
        GO TO 9000
      ENDIF
!
      NFINAL=0
      IFLAGY=.FALSE.
      IFLAGZ=.TRUE.
      IALLZ=-99
      IALLP=-99
      ISTRT=2
!
!CCCC IF(XIDTEM(1).EQ.ZERO)ISTRT=1
!
      DO 1100 I=1,NDIST
!
!       NOTE: IF THERE ARE "ZERO" MASS VALUES (I.E., BLANKS),
!             THEN THESE NEED TO BE HANDLED SEPARATELY.
!
        HOLD=XIDTEM(I)
!
        D(I)=0.0
        BL(I)=0.0
        SU(I)=0.0
        T(I)=0.0
        P(I)=0.0
        IF(I.GT.1 .OR. (I.EQ.1 .AND. HOLD.EQ.ZERO))THEN
          LO(I)=0.0
          LU(I)=0.0
          BA(I)=0.0
          UN(I)=0.0
          S(I)=0.0
          TO(I)=0.0
        ELSE
          LO(I)=99.0
          LU(I)=99.0
          BA(I)=99.0
          UN(I)=99.0
          S(I)=99.0
          TO(I)=99.0
        ENDIF
!
        NZERO=0
        NPLUS=0
        DSUM=0.0D0
        DO 1110 J=1,N
          IF(X(J).EQ.HOLD)THEN
            IF(Y(J).LE.EPS)THEN
              NZERO=NZERO+1
            ELSE
              NPLUS=NPLUS+1
              TEMP1(NPLUS)=Y(J)
              DSUM=DSUM + DBLE(Y(J))
            ENDIF
          ENDIF
 1110   CONTINUE
        NTOTZ=NZERO+NPLUS
        ATEMP=REAL(NTOTZ)*(1.0 - THRPER)+0.00001
        MINZER=INT(ATEMP)
        MU(I)=NZERO
        NN(I)=NPLUS
        NS(I)=NTOTZ
!
        IF(NZERO.GE.1 .AND. NPLUS.GE.1)IFLAGZ=.FALSE.
        IF(IFLAGZ)THEN
          IF(NZERO.EQ.NTOTZ)IALLZ=I
          IF(NPLUS.EQ.NTOTZ .AND. IALLP.LT.0)IALLP=I
        ENDIF
        IF(I.EQ.NDIST)THEN
          NTEMPZ=INT(0.90*REAL(NTOTZ)+0.1)
          IF(NZERO.GT.NTEMPZ)THEN
            IFLAGY=.TRUE.
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,101)
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7071)
 7071       FORMAT('      More than 90% of the measurements at the')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7073)
 7073       FORMAT('      highest mass level are zero.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,7075)
 7075       FORMAT('      The LOD analysis will not be performed.')
            CALL DPWRST('XXX','WRIT')
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','WRIT')
            IERROR='YES'
            GO TO 9000
          ENDIF
!CCCC   ELSEIF(I.EQ.2)THEN
!CCCC     AVAL=REAL(NABOVE)/REAL(NTOTZ)
!CCCC     IF(AVAL.GT.0.90)THEN
!CCCC       WRITE(ICOUT,999)
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC       WRITE(ICOUT,101)
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC       WRITE(ICOUT,7181)
!7181       FORMAT('      More than 90% of the measurements at the ',
!CCCC1             'lowest non-zero')
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC       WRITE(ICOUT,7183)
!7183       FORMAT('      mass level are greater than the critical ',
!CCCC1             'value.')
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC       WRITE(ICOUT,7185)
!7185       FORMAT('      Although the LOD analysis will still be ',
!CCCC1             'performed,')
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC       WRITE(ICOUT,7187)
!7187       FORMAT('      it is recommended that measurements be ',
!CCCC1             'performed,')
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC       WRITE(ICOUT,999)
!CCCC       CALL DPWRST('XXX','WRIT')
!CCCC     ENDIF
        ENDIF
!
        IF(NZERO.GT.MINZER)NFINAL=I
        IF(NN(I).GT.0)THEN
          YM(I)=REAL(DSUM/DBLE(NN(I)))
          CALL SORT(TEMP1,NPLUS,TEMP1)
        ELSE
          YM(I)=0.0
        ENDIF
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD3')THEN
          ISTEPN='3.1'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1061)
 1061     FORMAT('***** DPLOD3: AFTER COMPUTE SAMPLE SIZES')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1062)I,MU(I),NN(I),NS(I),YM(I)
 1062     FORMAT('I,MU(I),NN(I),NS(I),YM(I) = ',4I8,G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1063)NZERO,MINZER,NFINAL
 1063     FORMAT('NZERO,MINZER,NFINAL = ',3I8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
!       STATISTICS FOR MASS = 0 VALUES
!
!CCCC   IF(I.EQ.1 .AND. HOLD.EQ.ZERO)THEN
!CCCC     CALL NORPPF((REAL(MU(I))+0.5)/(REAL(NS(I))+1.0),ZZ)
!CCCC     QQ=MAX(ZA,ZZ)
!CCCC     SIG0=0.0
!CCCC     AF=0.0
!CCCC     SN=((QQ*SIG0)**2)/REAL(NN(I))
!
!CCCC     IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD3')THEN
!CCCC       ISTEPN='3.1'
!CCCC       CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!CCCC       WRITE(ICOUT,999)
!CCCC       CALL DPWRST('XXX','BUG ')
!CCCC       WRITE(ICOUT,1071)
!1071       FORMAT('***** DPLOD3: MASS = 0 CASE')
!CCCC       CALL DPWRST('XXX','BUG ')
!CCCC       WRITE(ICOUT,1073)ZZ,QQ,SIG0,AF,SN
!1073       FORMAT('ZZ,QQ,SIG0,AF,SN = ',5G15.7)
!CCCC       CALL DPWRST('XXX','BUG ')
!CCCC     ENDIF
!
!CCCC   ELSEIF(I.EQ.1 .AND. HOLD.NE.ZERO)THEN
!CCCC     CALL NORPPF((REAL(MU(I))+0.5)/(REAL(NS(I))+1.0),ZZ)
!CCCC     QQ=MAX(ZA,ZZ)
!CCCC   ENDIF
!
!       COMPUTE SUM OF Y**2 FOR NON-ZERO VALUES
!
        IF(NPLUS.GE.1)THEN
          CALL SD(TEMP1,NPLUS,IWRITE,XVAR,IBUGA3,IERROR)
          CALL MEAN(TEMP1,NPLUS,IWRITE,XMEAN,IBUGA3,IERROR)
        ELSE
          XVAR=0.0
          XMEAN=0.0
        ENDIF
        YM(I)=XMEAN
        YVAR(I)=XVAR
        SUM=0.0
        DO 1030 J=1,NPLUS
          SUM=SUM + TEMP1(J)**2
 1030   CONTINUE
        YTT(I)=SUM
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD3')THEN
          ISTEPN='3.3'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1082)I,YTT(I)
 1082     FORMAT('I,YTT(I) = ',I8,G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 1100 CONTINUE
!
!
!CCCC   APRIL 2010: X1 SHOULD BE SET TO X(1) IF ALL
!CCCC               NON-ZERO MASSES HAVE AT LEAST ONE NON-ZERO
!CCCC               RESPONSE.  HOWEVER, IF SOME NON-ZERO MASSES
!CCCC               HAVE ALL ZERO RESPONSES, THEN SET X1 TO X(K)
!CCCC               WHERE K IS THE SMALLEST MASS LEVEL WITH AT LEAST
!CCCC               ONE NON-ZERO RESPONSE.
!CCCC
!CCCC   MAY 2010:   NOTE THAT DEGREES OF FREEDOM FOR CHI-SQUARE AND
!CCCC               T PERCENT POINT ROUTINES BELOW REQUIRES THAT CUMULATIVE
!CCCC               NUMBER OF NON-ZERO VALUES BE AT LEAST TWO.  SO
!CCCC               ACTUALLY LOOK FOR FIRST MASS LEVEL WITH AT LEAST TWO
!CCCC               NON-ZERO RESPONSES.
!CCCC
!CCCC   MAY 2010:   ACTUALLY NEED TO SET X1 TO X(K) WHERE K IS THE
!CCCC               THE SMALLEST MASS LEVEL WITH A NON-ZERO VARIANCE
!CCCC               (I.E., IF HAVE 2 POINTS BUT THEY HAVE THE SAME VALUE,
!CCCC               CANNOT COMPUTE A NON-ZERO VARIANCE).
!CCCC
!CCCC X1=X(1)
      KTEMP=1
      DO 1907 II=2,NDIST
!CCCC   IF(NN(II).GE.2)THEN
        IF(YVAR(II).GT.0.0)THEN
!CCCC     IF(II.EQ.2)GO TO 1908
          KTEMP=II
          GO TO 1908
        ENDIF
 1907 CONTINUE
 1908 CONTINUE
      X1=XIDTEM(KTEMP)
      IF(KTEMP.GT.ISTRT)ISTRT=KTEMP
!
      CALL NORPPF((REAL(MU(KTEMP))+0.5)/(REAL(NS(KTEMP))+1.0),ZZ)
      QQ=MAX(ZA,ZZ)
!
!     COMPUTE CRITICAL VALUE FOR CLEAN CASE.
!
!     NOTE: CLARIFICATION FROM MICHAEL VERKOUTEREN - FOR CLEAN CASE,
!           THE REPORTED CRITICAL VALUE IS THE "THRESHOLD" (THE HH
!           TERM BELOW), NOT THE 95-TH PERCENTILE OF THE FIRST MASS
!           LEVEL WHERE WE HAVE DATA.
!
      KTEMP2=KTEMP
      IF(KTEMP.EQ.1)KTEMP2=2
!CCCC IF(ILODCV.EQ.'QUAN' .OR. NN(KTEMP).LT.3)THEN
!CCCC   ICNT=0
!CCCC   DO1910II=1,N
!CCCC     IF(X(II).EQ.XIDTEM(KTEMP2))THEN
!CCCC       ICNT=ICNT+1
!CCCC       TEMP3(ICNT)=Y(II)
!CCCC     ENDIF
!1910   CONTINUE
!CCCC   P100=95.0
!CCCC   CALL PERCEN(P100,TEMP3,ICNT,IWRITE,TEMP2,MAXOBV,CV,
!CCCC1              IBUGA3,IERROR)
!CCCC ELSE
!CCCC   ICNT=0
!CCCC   DO1920II=1,N
!CCCC     IF(X(II).EQ.XIDTEM(KTEMP2) .AND. Y(I).GT.0.0)THEN
!CCCC       ICNT=ICNT+1
!CCCC       TEMP3(ICNT)=Y(II)
!CCCC     ENDIF
!1920   CONTINUE
!CCCC   IF(YMINMS.LE.0.0)THEN
!CCCC     HH=YMIN
!CCCC   ELSE
          IF(CVUSER.GT.0.0)THEN
            HH=CVUSER
          ELSE
            HH=2.0*YMIN - YMIN2
          ENDIF
!CCCC   ENDIF
!CCCC   YM1=YM(KTEMP2)
!CCCC   CALL VAR(TEMP3,ICNT,IWRITE,VYN,IBUGA3,IERROR)
!CCCC   NU1=NN(KTEMP2)-1
!CCCC   YV=REAL(NU1)*VYN/REAL(NN(KTEMP2))
!CCCC   CALL NORPPF((REAL(MU(KTEMP2))+0.5)/(REAL(NS(KTEMP2))+1.0),ZZ)
!CCCC   QQ=MAX(ZA,ZZ)
!CCCC   FT=0.5*ZZ*(YM(KTEMP2)-HH)
!CCCC   SIG0=FT + SQRT((FT**2) + YV + (YM(I)-HH)**2)
!CCCC   CV=YM1 + QQ*SIG0
!CCCC ENDIF
!
      DO 2000 J=ISTRT,NDIST
!
        XXNN=0.0
        BAK=0.0
        SYY2=0.0
        ITN=0
        DO 2010 I=ISTRT,J
          XXNN=XXNN + XIDTEM(I)**2*REAL(NN(I))
          BAK=BAK + XIDTEM(I)*YM(I)*REAL(NN(I))
          SYY2=SYY2 + YTT(I)
          ITN=ITN + NN(I)
 2010   CONTINUE
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD3')THEN
          ISTEPN='4.1'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2061)
 2061     FORMAT('***** DPLOD3: AT 2010')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2062)J,XXNN,BAK,SYY2,ITN
 2062     FORMAT('J,XXNN,BAK,SYY2,ITN = ',I8,3G15.7,I8)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2063)ZA,ZB,QQ,X1
 2063     FORMAT('ZA,ZB,QQ,X1 = ',4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        DD=1.0/SQRT(XXNN)
        BA(J)=BAK/XXNN
        ITN=ITN-1
        UA(J)=(SYY2 - BA(J)*BAK)/REAL(ITN)
        SI(J)=SQRT(UA(J))
        CALL TPPF(1.0 - 0.5*GA,REAL(ITN),TTK)
        T(J)=TTK
        B1K1=BA(J)-(DD*T(J)*SI(J))
        B1K2=0.000001
        B1(J)=MAX(B1K1,0.000001)
        CALL CHSPPF(GA/2.0,ITN,PPK)
        P(J)=PPK
        SU(J)=SI(J)*SQRT(REAL(ITN)/P(J))
        LO(J)=X1 + ((QQ + ZB)*SI(J))/BA(J)
        LU(J)=X1 + ((QQ+ZB)*SU(J))/B1(J)
        S(J)=((AZ*UA(J)/REAL(ITN)) + UA(J)*(DD**2)*(LO(J)**2))/   &
             BA(J)/BA(J)
        UN(J)=SQRT(S(J))
        TO(J)=X1 + ((QQ+ZB+ZP)*SU(J))/B1(J)
!
        IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD3')THEN
          ISTEPN='4.2'
          CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2072)J,DD,BA(J),UA(J),SI(J),TTK
 2072     FORMAT('J,DD,BA(J),UA(J),SI(J),TTK = ',I8,5G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2073)J,B1(J),P(J),SU(J),LO(J)
 2073     FORMAT('J,B1(J),P(J),SU(J),LO(J) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2074)J,LU(J),S(J),UN(J),TO(J)
 2074     FORMAT('J,LU(J),S(J),UN(J),TO(J) = ',I8,4G15.7)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
 2000 CONTINUE
!
      SI(1)=SIG0
!
      NFINAL=NFINAL+1
      IF(NFINAL.GT.NDIST)NFINAL=NDIST
      ALOD=LO(NFINAL)
      ALODSE=UN(NFINAL)
      ALODLU=LU(NFINAL)
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD3')THEN
        ISTEPN='4.3'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,2082)NFINAL
 2082   FORMAT('NFINAL,ALOD,ALODSE = ',I8,2G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IVAL1=INT(100.0*(1.0 - GAMMA)+0.1)
      IVAL2=INT(100.0*(1.0 - GAMMA)+0.1)
      IVAL3=INT(100.0*(1.0 - PA)+0.1)
!
!               **************************************************
!               **  STEP 5--                                    **
!               **   OPEN THE STORAGE FILES, WRITE RELEVANT     **
!               **   QUANTITIES TO FILE, AND THEN CLOSE         **
!               **   STORAGE FILES.                             **
!               **************************************************
!
      ISTEPN='5'
      IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOD3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ILODOF.EQ.'OFF')GO TO 3019
!
      IOP='OPEN'
      IFLG1=1
      IFLG2=1
      IFLG3=0
      IFLG4=0
      IFLG5=0
      CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      DO 3010 I=1,NDIST
        WRITE(IOUNI1,3012)XIDTEM(I),REAL(MU(I)),REAL(NN(I)),YT(I),   &
                          YVAR(I)
        WRITE(IOUNI2,3012)XIDTEM(I),BA(I),SI(I),LO(I),UN(I),LU(I),   &
                          TO(I)
 3012   FORMAT(7E15.7)
 3010 CONTINUE
!
      IOP='CLOS'
      CALL DPAUFI(IOP,IFLG1,IFLG2,IFLG3,IFLG4,IFLG5,   &
                  IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                  IBUGA3,ISUBRO,IERROR)
!
 3019 CONTINUE
!
      NUMDIG=4
      IF(IFORSW.EQ.'1')NUMDIG=2
      IF(IFORSW.EQ.'2')NUMDIG=2
      IF(IFORSW.EQ.'3')NUMDIG=3
      IF(IFORSW.EQ.'4')NUMDIG=4
      IF(IFORSW.EQ.'5')NUMDIG=5
      IF(IFORSW.EQ.'6')NUMDIG=6
      IF(IFORSW.EQ.'7')NUMDIG=7
      IF(IFORSW.EQ.'8')NUMDIG=8
      IF(IFORSW.EQ.'9')NUMDIG=9
      IF(IFORSW.EQ.'0')NUMDIG=10
      IF(IFORSW.EQ.'-2')NUMDIG=-2
      IF(IFORSW.EQ.'-3')NUMDIG=-3
      IF(IFORSW.EQ.'-4')NUMDIG=-4
      IF(IFORSW.EQ.'-5')NUMDIG=-5
      IF(IFORSW.EQ.'-6')NUMDIG=-6
      IF(IFORSW.EQ.'-7')NUMDIG=-7
      IF(IFORSW.EQ.'-8')NUMDIG=-8
      IF(IFORSW.EQ.'-9')NUMDIG=-9
!
      CALL DPCONA(92,IBASLC)
      CV=HH
!
!     WRITE "FINAL" ESTIMATES SEPARATELY
!
!     2014/03: TO BE CONSISTENT WITH ASTM E2677 STANDARD, CHANGE
!              "Scxx.x"  to   "CVxx.x" AND CHANGE  "LDxx"  TO  "LODxx".
!
      IF(IPRINT.EQ.'ON')THEN
!
        ITITLE='Limits of Detection Analysis'
        NCTITL=28
        ITITL9='(Based on ASTM E-2677 Standard)'
        NCTIT3=31
!
        ICNT=1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Response Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(1)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(1)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        ICNT=ICNT+1
        ITEXT(ICNT)='Mass Variable: '
        WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(2)(1:4)
        WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(2)(1:4)
        NCTEXT(ICNT)=27
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        IF(PID(3).NE.CPUMIN)THEN
          ICNT=ICNT+1
          ITEXT(ICNT)='Group-ID Variable: '
          WRITE(ITEXT(ICNT)(20:23),'(A4)')IVARID(3)(1:4)
          WRITE(ITEXT(ICNT)(24:27),'(A4)')IVARI2(3)(1:4)
          NCTEXT(ICNT)=27
          AVALUE(ICNT)=PID(3)
          IDIGIT(ICNT)=0
        ENDIF
!
        ICNT=ICNT+1
        ITEXT(ICNT)=' '
        NCTEXT(ICNT)=0
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
!
        ICNT=ICNT+1
        ITEXT(ICNT)='Final Estimate:'
        NCTEXT(ICNT)=15
        AVALUE(ICNT)=0.0
        IDIGIT(ICNT)=-1
        IF(ILODPC.EQ.'ON')THEN
          ICNT=ICNT+1
          IF(ALPHA.EQ.0.05)THEN
            ITEXT(ICNT)='Critical Value (Cv95):'
            NCTEXT(ICNT)=22
          ELSEIF(ALPHA.EQ.0.10)THEN
            ITEXT(ICNT)='Critical Value (Cv90):'
            NCTEXT(ICNT)=22
          ELSEIF(ALPHA.EQ.0.01)THEN
            ITEXT(ICNT)='Critical Value (Cv99):'
            NCTEXT(ICNT)=22
          ELSE
            ITEXT(ICNT)='Critical Value (Cvxx.x):'
            ATEMP=100.*(1.0 - ALPHA)
            WRITE(ITEXT(ICNT)(19:22),'(F4.1)')ATEMP
            NCTEXT(ICNT)=24
          ENDIF
          AVALUE(ICNT)=CV
          IDIGIT(ICNT)=NUMDIG
        ENDIF
!
        ICNT=ICNT+1
        IF(ALPHA.EQ.0.05)THEN
          ITEXT(ICNT)='Detection Limit (LOD95):'
          NCTEXT(ICNT)=24
        ELSEIF(ALPHA.EQ.0.10)THEN
          ITEXT(ICNT)='Detection Limit (LOD90):'
          NCTEXT(ICNT)=24
        ELSEIF(ALPHA.EQ.0.01)THEN
          ITEXT(ICNT)='Detection Limit (LOD99):'
          NCTEXT(ICNT)=24
        ELSE
          ITEXT(ICNT)='Detection Limit (LODxx.x):'
          NCTEXT(ICNT)=26
          ATEMP=100.*(1.0 - ALPHA)
          WRITE(ITEXT(ICNT)(21:24),'(F4.1)')ATEMP
        ENDIF
        AVALUE(ICNT)=ALOD
        IDIGIT(ICNT)=NUMDIG
!
        ICNT=ICNT+1
        IF(GAMMA.EQ.0.05)THEN
          ITEXT(ICNT)='95% Upper Confidence Limit on LOD:'
          NCTEXT(ICNT)=34
        ELSEIF(ALPHA.EQ.0.10)THEN
          ITEXT(ICNT)='90% Upper Confidence Limit on LOD:'
          NCTEXT(ICNT)=34
        ELSEIF(ALPHA.EQ.0.01)THEN
          ITEXT(ICNT)='99% Upper Confidence Limit on LOD:'
          NCTEXT(ICNT)=34
        ELSE
          ITEXT(ICNT)='xx.x% Upper Confidence Limit on LOD:'
          NCTEXT(ICNT)=36
          ATEMP=100.*(1.0 - GAMMA)
          WRITE(ITEXT(ICNT)(1:4),'(F4.1)')ATEMP
        ENDIF
        AVALUE(ICNT)=ALODLU
        IDIGIT(ICNT)=NUMDIG
!
        NUMROW=ICNT
        DO 4210 I=1,NUMROW
          NTOT(I)=15
 4210   CONTINUE
!
        IFRST=.TRUE.
        ILAST=.TRUE.
!
        ISTEPN='42A'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOD2')   &
             CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        CALL DPDTA1(ITITLE,NCTITL,ITITL9,NCTIT3,ITEXT,NCTEXT,   &
                    AVALUE,IDIGIT,   &
                    NTOT,NUMROW,   &
                    ICAPSW,ICAPTY,ILAST,IFRST,   &
                    ISUBRO,IBUGA3,IERROR)
!
        ISTEPN='42B'
        IF(IBUGA3.EQ.'ON'.OR.ISUBRO.EQ.'LOD2')   &
             CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
        IF(IFLAGZ)THEN
          ATEMP=0.0
          NUMDIG=-1
          ISIZE=0
          IRTFMD='OFF'
          IFLAGA=.TRUE.
          IFLAGB=.FALSE.
          NTOTAL=50
          NBLNK1=0
          NBLNK2=0
          ITYPE2=2
          ITTEXT(1:42)='Measurements at each mass level are either'
          NCTEMP=42
          CALL DPDTXT(ITTEXT,NCTEMP,ATEMP,NUMDIG,NTOTAL,   &
                      NBLNK1,NBLNK2,IFLAGA,IFLAGB,ISIZE,   &
                      ICAPSW,ICAPTY,ITYPE2,ISUBRO,IBUGA3,IERROR)
          IFLAGA=.FALSE.
          ITTEXT(1:44)='all zero or all non-zero.  It is recommended'
          NCTEMP=44
          CALL DPDTXT(ITTEXT,NCTEMP,ATEMP,NUMDIG,NTOTAL,   &
                      NBLNK1,NBLNK2,IFLAGA,IFLAGB,ISIZE,   &
                      ICAPSW,ICAPTY,ITYPE2,ISUBRO,IBUGA3,IERROR)
          ITTEXT(1:44)='that you take additional measurements in the'
          NCTEMP=44
          CALL DPDTXT(ITTEXT,NCTEMP,ATEMP,NUMDIG,NTOTAL,   &
                      NBLNK1,NBLNK2,IFLAGA,IFLAGB,ISIZE,   &
                      ICAPSW,ICAPTY,ITYPE2,ISUBRO,IBUGA3,IERROR)
          ITTEXT(1:12)='vicinity of '
          NCTEMP=12
          ATEMP=(XIDTEM(IALLZ)+XIDTEM(IALLP))/2.0
          NTOTAL=25
          NBLNK1=0
          NBLNK2=1
          IFLAGB=.TRUE.
          CALL DPDTXT(ITTEXT,NCTEMP,ATEMP,NUMDIG,NTOTAL,   &
                      NBLNK1,NBLNK2,IFLAGA,IFLAGB,ISIZE,   &
                      ICAPSW,ICAPTY,ITYPE2,ISUBRO,IBUGA3,IERROR)
        ENDIF
!
      ENDIF
!
!     PRINT TABLES
!
      IF(ILODST.EQ.'OFF' .OR. IPRINT.EQ.'OFF')GO TO 4199
!
      NCTIT9=0
!CCCC ITITL9(1:NCTIT9)='LIMITS OF DETECTION ANALYSIS'
      ITITL9(1:NCTIT9)=' '
      NCTITL=13
      ITITLE(1:NCTITL)='Summary Table'
      NUMLIN=2
      NUMCOL=5
      ITITL2(1,1)='Mass'
      ITITL2(2,1)='Values'
      ITITL2(1,2)='Number of'
      ITITL2(2,2)='Zero Values'
      ITITL2(1,3)='Number of'
      ITITL2(2,3)='Non-Zero Values'
      ITITL2(1,4)='Mean of'
      ITITL2(2,4)='Non-Zero Values'
      ITITL2(1,5)='SD of'
      ITITL2(2,5)='Non-Zero Values'
      NCTIT2(1,1)=4
      NCTIT2(2,1)=6
      NCTIT2(1,2)=9
      NCTIT2(2,2)=11
      NCTIT2(1,3)=9
      NCTIT2(2,3)=15
      NCTIT2(1,4)=7
      NCTIT2(2,4)=15
      NCTIT2(1,5)=5
      NCTIT2(2,5)=15
      NMAX=0
      NTOT(1)=15
      NTOT(2)=15
      NTOT(3)=19
      NTOT(4)=19
      NTOT(5)=18
      DO 4010 J=1,NUMCOL
        VALIGN(J)='b'
        ALIGN(J)='r'
        NMAX=NMAX+NTOT(J)
        IDIGIT(J)=NUMDIG
        IWHTML(J)=125
 4010 CONTINUE
      IWHTML(NUMCOL+1)=125
      VALIGN(NUMCOL+1)='b'
      ALIGN(NUMCOL+1)='r'
      IDIGIT(2)=0
      IDIGIT(3)=0
      DO 4020 I=1,NDIST
        NCTEXT(I)=0
        ITEXT(I)=' '
        AMAT(I,1)=XIDTEM(I)
        AMAT(I,2)=REAL(MU(I))
        AMAT(I,3)=REAL(NN(I))
        AMAT(I,4)=YM(I)
        AMAT(I,5)=YVAR(I)
 4020 CONTINUE
      IWRTF(1)=1400
      IWRTF(2)=IWRTF(1)+1600
      IWRTF(3)=IWRTF(2)+1600
      IWRTF(4)=IWRTF(3)+1600
      IWRTF(5)=IWRTF(4)+1600
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD3')THEN
        ISTEPN='4.4'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4111)
 4111   FORMAT('BEFORE PRINT SUMMARY TABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4112)NCTIT9,NCTITL,MAXLIN,NUMLIN,NUMCOL,MAXROW
 4112   FORMAT('NCTIT9,NCTITL,MAXLIN,NUMLIN,NUMCOL,MAXROW = ',6I6)
        CALL DPWRST('XXX','BUG ')
        DO 4120 I=1,NUMLIN
          DO 4130 J=1,NUMCOL
            WRITE(ICOUT,4122)I,J,ITITL2(I,J),NCTIT2(I,J),AMAT(I,J)
 4122       FORMAT('I,J,ITITL2(I,J),NCTIT2(I,J),AMAT(I,J) = ',   &
                   2I6,A40,I8,G15.7)
            CALL DPWRST('XXX','BUG ')
 4130     CONTINUE
 4120   CONTINUE
      ENDIF
!
      CALL DPDTA2(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,MAXCOL,NUMCOL,   &
                  ITEXT,NCTEXT,AMAT,MAXROW,NDIST,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
!
 4199 CONTINUE
!
      IF(ILODTA.EQ.'OFF' .OR. IPRINT.EQ.'OFF')GO TO 5199
!
      NCTIT9=0
      ITITL9(1:NCTIT9)=' '
      NCTITL=9
      ITITLE(1:NCTITL)='LOD Table'
      NUMLIN=4
      NUMCOL=7
!
      ITITL2(1,1)=' '
      ITITL2(2,1)=' '
      ITITL2(3,1)='Mass'
      ITITL2(4,1)='Values'
      NCTIT2(1,1)=0
      NCTIT2(2,1)=0
      NCTIT2(3,1)=4
      NCTIT2(4,1)=6
!
      ITITL2(1,2)='Linear'
      ITITL2(2,2)='Least Squares'
      ITITL2(3,2)='Slope'
      ITITL2(4,2)='Estimates'
      NCTIT2(1,2)=6
      NCTIT2(2,2)=13
      NCTIT2(3,2)=5
      NCTIT2(4,2)=9
!
      ITITL2(1,3)='StdDev of'
      ITITL2(2,3)='Errors From'
      ITITL2(3,3)='Linear'
      ITITL2(4,3)='Model'
      NCTIT2(1,3)=9
      NCTIT2(2,3)=11
      NCTIT2(3,3)=6
      NCTIT2(4,3)=5
!
      ITITL2(1,4)='LOD Estimate'
      ITITL2(2,4)='Based On'
      ITITL2(3,4)='Cumulated'
      ITITL2(4,4)='Sample'
      NCTIT2(1,4)=12
      NCTIT2(2,4)=8
      NCTIT2(3,4)=9
      NCTIT2(4,4)=6
!
      ITITL2(1,5)='1-Sigma'
      ITITL2(2,5)='Uncertainty'
      ITITL2(3,5)='on LOD'
      ITITL2(4,5)='Estimate'
      NCTIT2(1,5)=7
      NCTIT2(2,5)=11
      NCTIT2(3,5)=6
      NCTIT2(4,5)=8
!
      IF(GAMMA.EQ.0.05)THEN
        ITITL2(2,6)='95% Upper'
        NCTIT2(2,6)=9
      ELSEIF(GAMMA.EQ.0.10)THEN
        ITITL2(2,6)='90% Upper'
        NCTIT2(2,6)=9
      ELSEIF(GAMMA.EQ.0.01)THEN
        ITITL2(2,6)='99% Upper'
        NCTIT2(2,6)=9
      ELSE
        ATEMP=100.*(1.0 - GAMMA)
        ITITL2(2,6)='xx.x% Upper'
        WRITE(ITITL2(2,6)(1:4),'(F4.1)')ATEMP
        NCTIT2(2,6)=11
      ENDIF
      ITITL2(1,6)=' '
      ITITL2(3,6)='Confidence'
      ITITL2(4,6)='Limit on LOD'
      NCTIT2(1,6)=0
      NCTIT2(3,6)=10
      NCTIT2(4,6)=12
!
      IF(GAMMA.EQ.0.05.AND.PA.EQ.0.05)THEN
        ITITL2(1,7)='95%-95%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.10.AND.PA.EQ.0.05)THEN
        ITITL2(1,7)='90%-95%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.01.AND.PA.EQ.0.05)THEN
        ITITL2(1,7)='99%-95%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.10.AND.PA.EQ.0.10)THEN
        ITITL2(1,7)='90%-90%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.05.AND.PA.EQ.0.10)THEN
        ITITL2(1,7)='95%-90%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.01.AND.PA.EQ.0.10)THEN
        ITITL2(1,7)='99%-90%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.10.AND.PA.EQ.0.01)THEN
        ITITL2(1,7)='90%-99%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.05.AND.PA.EQ.0.01)THEN
        ITITL2(1,7)='95%-99%'
        NCTIT2(1,7)=7
      ELSEIF(GAMMA.EQ.0.01.AND.PA.EQ.0.01)THEN
        ITITL2(1,7)='99%-99%'
        NCTIT2(1,7)=7
      ELSE
        ITITL2(1,7)='xx.x%-xx.x%'
        ATEMP=100.*(1.0 - GAMMA)
        WRITE(ITITL2(1,7)(1:4),'(F4.1)')ATEMP
        ATEMP=100.*(1.0 - PA)
        WRITE(ITITL2(1,7)(7:10),'(F4.1)')ATEMP
        NCTIT2(1,7)=11
      ENDIF
      ITITL2(2,7)='Upper'
      ITITL2(3,7)='Tolerance'
      ITITL2(4,7)='Limit on LOD'
      NCTIT2(2,7)=5
      NCTIT2(3,7)=9
      NCTIT2(4,7)=12
!
      NMAX=0
      DO 5010 J=1,NUMCOL
        NTOT(J)=15
        VALIGN(J)='b'
        ALIGN(J)='r'
        NMAX=NMAX+NTOT(J)
        IDIGIT(J)=NUMDIG
        IWHTML(J)=150
 5010 CONTINUE
      IWHTML(1)=125
      IWHTML(2)=175
      IWHTML(4)=175
      IWHTML(NUMCOL+1)=150
      VALIGN(NUMCOL+1)='b'
      ALIGN(NUMCOL+1)='r'
      DO 5020 I=1,NDIST
        NCTEXT(I)=0
        AMAT(I,1)=XIDTEM(I)
!CCCC   IF(I.EQ.1)THEN
        IF(I.EQ.1 .OR. I.LT.ISTRT)THEN
          AMAT(I,2)=CPUMIN
          AMAT(I,3)=CPUMIN
          AMAT(I,4)=CPUMIN
          AMAT(I,5)=CPUMIN
          AMAT(I,6)=CPUMIN
          AMAT(I,7)=CPUMIN
        ELSE
          AMAT(I,2)=BA(I)
          AMAT(I,3)=SI(I)
          AMAT(I,4)=LO(I)
          AMAT(I,5)=UN(I)
          AMAT(I,6)=LU(I)
          AMAT(I,7)=TO(I)
        ENDIF
 5020 CONTINUE
      IWRTF(1)=900
      IWRTF(2)=IWRTF(1)+1150
      IWRTF(3)=IWRTF(2)+1150
      IWRTF(4)=IWRTF(3)+1150
      IWRTF(5)=IWRTF(4)+1150
      IWRTF(6)=IWRTF(5)+1150
      IWRTF(7)=IWRTF(6)+1150
      IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF ')THEN
        IPTSZ=14
        CALL DPCONA(92,IBASLC)
        WRITE(ICOUT,8199)IBASLC,IPTSZ
 8199   FORMAT(A1,'fs',I2)
        CALL DPWRST(ICOUT,'WRIT')
      ENDIF
      IFRST=.TRUE.
      ILAST=.TRUE.
!
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD3')THEN
        ISTEPN='4.4'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5111)
 5111   FORMAT('BEFORE PRINT LOD TABLE')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,4112)NCTIT9,NCTITL,MAXLIN,NUMLIN,NUMCOL,MAXROW
        CALL DPWRST('XXX','BUG ')
        DO 5120 I=1,NUMLIN
          DO 5130 J=1,NUMCOL
            WRITE(ICOUT,4122)I,J,ITITL2(I,J),NCTIT2(I,J),AMAT(I,J)
            CALL DPWRST('XXX','BUG ')
 5130     CONTINUE
 5120   CONTINUE
      ENDIF
!
      CALL DPDTA2(ITITL9,NCTIT9,   &
                  ITITLE,NCTITL,ITITL2,NCTIT2,   &
                  MAXLIN,NUMLIN,MAXCOL,NUMCOL,   &
                  ITEXT,NCTEXT,AMAT,MAXROW,NDIST,   &
                  IDIGIT,NTOT,IWHTML,IWRTF,VALIGN,ALIGN,NMAX,   &
                  ICAPSW,ICAPTY,IFRST,ILAST,   &
                  ISUBRO,IBUGA3,IERROR)
      IF(ICAPSW.EQ.'ON' .AND. ICAPTY.EQ.'RTF ')THEN
        IPTSZ=IRTFPS
        WRITE(ICOUT,8199)IBASLC,IPTSZ
        CALL DPWRST(ICOUT,'WRIT')
      ENDIF
!
 5199 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGA3.EQ.'ON' .OR. ISUBRO.EQ.'LOD3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLOD3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,IBUGA3
 9012   FORMAT('IERROR,IBUGA3 = ',A4,1X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N
 9013   FORMAT('N = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLOD3
      SUBROUTINE DPLOD5(ALOD,ALODSE,CV,ALODLU,   &
                        IFLAGU,IFRST,ILAST,ICASPL,   &
                        IBUGA2,IBUGA3,ISUBRO,IERROR)
!
!     PURPOSE--UTILITY ROUTINE USED BY DPLODE.  THIS ROUTINE
!              UPDATES THE PARAMETERS "LOD", LODSE", "LODCV", AND
!              "LODUCL" AFTER PERFORMING A LIMITS OF DETECTION
!              COMMAND.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORAOTRY
!                 NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS OF TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2018/10
!     ORIGINAL VERSION--OCTOBER   2018.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IFLAGU
      CHARACTER*4 ICASPL
      CHARACTER*4 IBUGA2
      CHARACTER*4 IBUGA3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      LOGICAL IFRST
      LOGICAL ILAST
!
      CHARACTER*4 IH
      CHARACTER*4 IH2
      CHARACTER*4 ISUBN0
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IOP
!
      SAVE IOUNI1
!
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOF2.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LOD5')THEN
        ISTEPN='1'
        CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLOD5--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)ICASPL,ALOD,ALODSE,CV,ALODLU
   54   FORMAT('ICASPL,ALOD,ALODSE,CV,ALODLU = ',A4,2X,4G15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(IFRST)THEN
          IOP='OPEN'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LOD5')THEN
            ISTEPN='2A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,201)IOUNI1
  201       FORMAT('AFTER CALL DPOPFI, IOUNI1 = ',I8)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          WRITE(IOUNI1,295)
  295     FORMAT(12X,'LOD',10X,'LODSE',10X,'LODCV',9X,'LODUCL')
        ENDIF
        WRITE(IOUNI1,299)ALOD,ALODSE,CV,ALODLU
  299   FORMAT(4E15.7)
      ELSEIF(IFLAGU.EQ.'ON')THEN
!
        IF(ALOD.NE.CPUMIN)THEN
          IH='LOD '
          IH2='    '
          VALUE0=ALOD
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(ALODSE.NE.CPUMIN)THEN
          IH='LODS'
          IH2='E   '
          VALUE0=ALODSE
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(CV.NE.CPUMIN)THEN
          IH='LODC'
          IH2='V   '
          VALUE0=CV
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
        IF(ALODLU.NE.CPUMIN)THEN
          IH='LODU'
          IH2='CL  '
          VALUE0=ALODLU
          CALL DPADDP(IH,IH2,VALUE0,IHOST1,ISUBN0,   &
                      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                      IANS,IWIDTH,IBUGA3,IERROR)
        ENDIF
!
      ENDIF
!
      IF(IFLAGU.EQ.'FILE')THEN
        IF(ILAST)THEN
          IOP='CLOS'
          IFLAG1=1
          IFLAG2=0
          IFLAG3=0
          IFLAG4=0
          IFLAG5=0
          CALL DPAUFI(IOP,IFLAG1,IFLAG2,IFLAG3,IFLAG4,IFLAG5,   &
                      IOUNI1,IOUNI2,IOUNI3,IOUNI4,IOUNI5,   &
                      IBUGA3,ISUBRO,IERROR)
          IF(IERROR.EQ.'YES')GO TO 9000
!
          IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LOD5')THEN
            ISTEPN='3A'
            CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,301)IERROR,IOUNI1
  301       FORMAT('AFTER CALL DPCLFI: IERROR,IOUNI1 = ',A4,2X,I5)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
!
      IF(IBUGA2.EQ.'ON' .OR. ISUBRO.EQ.'LOD5')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END OF DPLOD5--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLOD5
